# V9: "Why this card?" explainer.
# _build_card_explanation requires an AI provider and surfaces an honest
# "AI unavailable: configure a provider" message when none is configured —
# never a hardcoded type-phrase template. (The old rule-based explainer
# module was deleted once the AI surface replaced it.)


# LLM-derived performance-context sentence, keyed by
# (swimmer, event, time, meet level) so page re-renders are cheap.
# Bounded LRU so a busy day can't fill RAM with cache strings.
_perf_context_cache: BoundedCache = BoundedCache(max_size=512)


def _llm_performance_context(achievement: dict, meet_context: Optional[dict] = None) -> str:
    """Return a 1-sentence LLM judgement on whether this swim is good *for this swimmer's level*.

    The model gets a natural-language description of the swim (no JSON
    blob) plus a `research_web` tool it can call on its own to verify
    elite recognition. Honours the user's provider preference
    (Claude / Gemini); empty string when none is configured.
    """
    try:
        from mediahub.ai_core import (
            ask_with_tools,
            narrate_achievement,
            narrate_meet,
            ProviderNotConfigured,
            ProviderError,
        )
    except Exception:
        return ""

    swimmer = (achievement.get("swimmer_name") or "").strip()
    event = (achievement.get("event") or "").strip()
    time_s = (achievement.get("time") or "").strip()
    if not (swimmer and event and time_s):
        return ""

    meet = meet_context or {}
    cache_key = "|".join(
        [
            swimmer.lower(),
            event.lower(),
            time_s,
            str(meet.get("level", "")),
            str(meet.get("governing_body", "")),
        ]
    )
    cached = _perf_context_cache.get(cache_key)
    if cached is not None:
        return cached

    # Natural-language prompt — no JSON. The model reads it and uses
    # research_web on its own if it wants to verify elite recognition.
    swim_prose = narrate_achievement(achievement, meet=meet or None)
    meet_prose = narrate_meet(meet or None)
    user = swim_prose + (("\n\nMeet context: " + meet_prose) if meet_prose else "")
    user += (
        "\n\nWrite ONE short sentence (max 25 words) putting this time in "
        "context FOR THIS SWIMMER'S LEVEL. Use research_web if you need "
        "to verify whether the swimmer is recognisably elite. If neither "
        "the details above nor fetched evidence support a concrete "
        "statement, reply with exactly NO_CONTEXT."
    )

    system = (
        "You are a swimming performance analyst. Output exactly one sentence "
        "putting a swim in context for the swimmer's level. No questions, "
        "no lists, no markdown, no preamble. Reason only from the swim "
        "details I give you and any web evidence you fetch via "
        "research_web. Never invent PBs, ages, clubs, rankings, or "
        "biographical facts, and never estimate how rare or competitive "
        "a result is — you have no field data. An unsupported judgement "
        "is worse than none: reply NO_CONTEXT when you cannot ground the "
        "sentence in given details or fetched evidence. If you cite a "
        "research result, mention the domain in parentheses, e.g. "
        "'(swimmingresults.org)'."
    )

    research_tool = [
        {
            "name": "research_web",
            "description": (
                "Search the web for evidence about this swimmer (elite "
                "recognition, PB history). Returns title/url/snippet/domain."
            ),
            "input_schema": {
                "type": "object",
                "properties": {
                    "query": {"type": "string"},
                },
                "required": ["query"],
            },
        }
    ]

    def _tool(name, inp):
        if name != "research_web":
            return "(unknown tool)"
        q = (inp.get("query") or "").strip()
        if not q:
            return "(empty query)"
        try:
            from mediahub.context_engine.research import ResearchClient

            client = ResearchClient(num_results=4)
            hits = client.search(q, num=4)
        except Exception as e:
            return f"(search failed: {e})"
        evidence = []
        for h in hits:
            snip = (h.snippet or "").strip()
            if not snip:
                continue
            evidence.append(
                {
                    "title": (h.title or "")[:160],
                    "url": h.url,
                    "snippet": snip[:300],
                    "domain": h.domain,
                }
            )
        return json.dumps({"hits": evidence}, ensure_ascii=False)

    out = ""
    try:
        convo = ask_with_tools(
            system=system,
            user=user,
            tools=research_tool,
            on_tool_call=_tool,
            max_tokens=200,
            max_rounds=3,
        )
        out = (convo.text or "").strip()
    except (ProviderNotConfigured, ProviderError):
        out = ""
    except Exception:
        out = ""
    if out:
        for ln in out.splitlines():
            ln = ln.strip().lstrip("-* ").strip()
            if ln:
                out = ln
                break
    if out.lower().startswith(
        ("i need", "i'd need", "please provide", "can you provide", "could you", "i don't have")
    ):
        out = ""
    # Honest-silence sentinel: the model judged it had nothing grounded to
    # say. An absent context line is better than a speculative one.
    if "NO_CONTEXT" in out.upper():
        out = ""
    _perf_context_cache[cache_key] = out
    return out


# "Why this card?" LLM cache, keyed by (swim_id, swimmer_name, event,
# time, rank, meet_level). Bounded LRU — values are small dicts.
_explanation_cache: BoundedCache = BoundedCache(max_size=512)


def _llm_build_explanation(
    achievement: dict,
    factors: list,
    rank: Optional[int] = None,
    meet_context: Optional[dict] = None,
) -> tuple[Optional[dict], Optional[str]]:
    """Have the LLM write the headline + bullets for "Why this card?"
    based on the achievement and the ranker's factors.

    Returns (result, error). ``result`` is ``{"headline", "bullets"}``
    on success; ``error`` is a human-readable string explaining WHY the
    AI didn't answer (no provider configured, rate-limit, etc.) so the
    UI can show "your AI is unavailable: configure a provider in
    Settings" instead of falling back to a hardcoded template.
    """
    try:
        from mediahub.ai_core import (
            ask_with_tools,
            narrate_achievement,
            narrate_meet,
            ProviderNotConfigured,
            ProviderError,
        )
    except Exception as e:
        return None, f"ai_core import failed: {e}"
    a = achievement or {}
    swim_prose = narrate_achievement(a, meet=meet_context or None)
    if not swim_prose:
        return None, "not enough achievement detail to narrate"

    # English summary of the factors — no JSON dump.
    factor_lines: list[str] = []
    for f in factors or []:
        if hasattr(f, "to_dict"):
            try:
                f = f.to_dict()
            except Exception:
                pass
        if not isinstance(f, dict):
            continue
        ps = (f.get("plain_summary") or f.get("reason") or "").strip()
        if not ps:
            continue
        try:
            val = float(f.get("value", 0.0) or 0.0)
            wt = float(f.get("weight", 0.0) or 0.0)
            contrib = val * wt
        except (TypeError, ValueError):
            contrib = 0.0
        factor_lines.append(f"- {ps} (contribution {contrib:.2f})")
    factors_prose = "\n".join(factor_lines[:8]) or "(no factor list)"

    meet_prose = narrate_meet(meet_context or None)
    user_prose = (
        swim_prose
        + (("\n\nMeet context: " + meet_prose) if meet_prose else "")
        + "\n\nRanker factors that contributed (highest first):\n"
        + factors_prose
        + (f"\n\nThis swim ranked #{int(rank)} overall." if isinstance(rank, int) else "")
        + "\n\nPlease emit one `submit_explanation` call with a "
        "headline of at most 14 words plus 2-4 bullets of at most "
        "12 words each. Every bullet must restate one listed factor or "
        "stated fact — if there are only two real reasons, write two "
        "bullets. Never pad."
    )

    system = (
        "You are MediaHub's content-rationale writer. Tell the user, in "
        "plain English, why a specific swim was selected as a content "
        "card. Hard rules: every claim must come from the facts and "
        "factors provided — if it isn't in the input, it doesn't exist. "
        "You have NO data about how rare, difficult, or competitive a "
        "result is, so never comment on rarity, field strength, or how "
        "common a time/medal is at this kind of meet. A gold medal or a "
        "personal best is self-evidently good — state it plainly, don't "
        "dress it up. Short beats thorough; never say the same thing "
        "twice in different words. Always emit exactly one "
        "`submit_explanation` tool call."
    )
    tool = [
        {
            "name": "submit_explanation",
            "description": (
                "Submit the final explanation: a one-sentence headline plus "
                "3-5 short factor bullets."
            ),
            "input_schema": {
                "type": "object",
                "properties": {
                    "headline": {"type": "string"},
                    "bullets": {"type": "array", "items": {"type": "string"}},
                },
                "required": ["headline", "bullets"],
            },
        }
    ]

    captured: dict[str, Any] = {}

    def _tool(name, inp):
        if name == "submit_explanation":
            hl = (inp.get("headline") or "").strip()
            bullets = inp.get("bullets") or []
            if isinstance(bullets, str):
                bullets = [bullets]
            bullets = [str(b).strip() for b in bullets if str(b).strip()]
            captured["headline"] = hl
            captured["bullets"] = bullets[:6]
            return "ok"
        return "(unknown tool)"

    try:
        ask_with_tools(
            system=system,
            user=user_prose,
            tools=tool,
            on_tool_call=_tool,
            max_tokens=500,
            max_rounds=2,
        )
    except ProviderNotConfigured as e:
        return None, str(e)
    except ProviderError as e:
        return None, f"AI provider error: {e}"
    except Exception as e:
        return None, f"AI call failed: {e}"
    if not captured.get("headline"):
        return None, "AI returned no explanation."
    return (
        {
            "headline": captured["headline"],
            "bullets": captured.get("bullets") or [],
        },
        None,
    )


def _build_source_lines_from_evidence(achievement: dict) -> list[dict]:
    """Pull up to 3 verbatim evidence quotes off the achievement."""
    out: list[dict] = []
    for ev in (achievement.get("evidence") or [])[:3]:
        if not isinstance(ev, dict):
            try:
                ev = ev.to_dict()
            except Exception:
                continue
        statement = (ev.get("statement") or "").strip()
        if not statement:
            continue
        source_name = (ev.get("source_name") or "").strip()
        source_type = (ev.get("source_type") or "").strip()
        if source_name and source_type and source_name != source_type:
            label = f"{source_type} ({source_name.replace('_', ' ')})"
        elif source_name:
            label = source_name
        elif source_type:
            label = source_type.replace("_", " ")
        else:
            label = "source"
        out.append(
            {
                "file_offset": ev.get("file_offset"),
                "raw_text": statement,
                "label": label,
            }
        )
    return out


def _build_card_explanation(ra: dict, meet_context: Optional[dict] = None) -> dict:
    """Build the "Why this card?" explanation dict for a ranked-achievement.

    Headline + bullets are written by the active LLM (Claude /
    Gemini) using a `submit_explanation` tool — no template strings,
    no hardcoded type-phrase dictionary. Source lines remain verbatim
    quotes from evidence (no LLM reasoning involved). Performance
    context is the LLM's level-context sentence.

    Falls back to the legacy rule-based explainer ONLY when no LLM
    provider is configured at all, so tests + offline dev still work.
    """
    achievement = ra.get("achievement") or {}
    factors = ra.get("factors") or []
    rank = ra.get("rank")

    cache_key_parts = [
        (achievement.get("swim_id") or ""),
        (achievement.get("swimmer_name") or ""),
        (achievement.get("event") or ""),
        (achievement.get("time") or ""),
        str(rank or ""),
        str((meet_context or {}).get("level", "")),
    ]
    cache_key = "|".join(cache_key_parts)
    cached = _explanation_cache.get(cache_key)
    if cached is not None:
        # Re-read perf context separately — its cache key is finer-grained.
        exp = dict(cached)
        try:
            ctx = _llm_performance_context(achievement, meet_context)
            if ctx:
                exp["performance_context"] = ctx
        except Exception:
            pass
        return exp

    llm_exp, llm_error = _llm_build_explanation(achievement, factors, rank, meet_context)
    if llm_exp is not None:
        exp = {
            "headline": llm_exp["headline"],
            "bullets": llm_exp["bullets"],
            "source_lines": _build_source_lines_from_evidence(achievement),
        }
    else:
        # No hardcoded template here — the user explicitly wants the AI
        # to do the reasoning, full stop. If no provider can answer we
        # tell them why and how to fix it.
        exp = {
            "headline": "AI explanation unavailable.",
            "bullets": [],
            "source_lines": _build_source_lines_from_evidence(achievement),
            "ai_error": llm_error or "No AI provider is configured.",
        }
    _explanation_cache[cache_key] = exp

    try:
        ctx = _llm_performance_context(achievement, meet_context)
        if ctx:
            exp["performance_context"] = ctx
    except Exception:
        pass
    return exp


# --------------------------------------------------------------------------- #
# U.7 — "Focus the facts" caption / explainability highlight.
#
# In captions and the "Why this card?" review UI, the source-grounded entities
# (athlete / event / time / PB-medal-record) are pill-highlighted and sharp; the
# connective filler around them recedes. This is *server-side span injection* —
# no client JS — so it works the moment the HTML lands (and inside the lazily
# fetched why-card body).
#
# Critically it is SOURCE-GROUNDED, not a regex guess: every highlighted phrase
# is built from the structured achievement the deterministic engine already
# produced (`swimmer_name`, `event`, the result time, and the detected
# achievement `type`). We never light up a number that "looks like a time" or a
# word that "looks like a medal" — only text that matches a fact on the card.
# So the highlight can't drift from the data, and it reinforces the moat (the
# intelligence layer) rather than faking it. Inspired by Pedro Duarte (ped.ro);
# supports U.3.
# --------------------------------------------------------------------------- #

# Swim-stroke long↔short forms, so a canonical "100m Freestyle" also lights up a
# caption that wrote "100m Free" / "100 Free". Deterministic string expansion of
# the *real* event label — not a new parser, not an AI surface.
_STROKE_SHORT_FORMS: dict[str, tuple[str, ...]] = {
    "freestyle": ("free",),
    "backstroke": ("back",),
    "breaststroke": ("breast",),
    "butterfly": ("fly",),
    "individual medley": ("im", "medley"),
}


def _event_variants(event: str) -> list[str]:
    """Grounded display variants of one event label for fact-matching.

    Returns the full label, the course-tag-stripped base ("100m Freestyle (LC)"
    → "100m Freestyle"), the stroke short-forms ("100m Free"), and the
    distance-without-``m`` forms ("100 Free") — all derived from the real event
    string, so every variant is still source-grounded. Distance alone ("100") is
    deliberately never emitted: a bare number would match stray figures.
    """
    ev = " ".join(str(event or "").split())
    if not ev:
        return []
    out: list[str] = [ev]
    base = re.sub(r"\s*\([^)]*\)\s*$", "", ev).strip()  # drop a trailing "(LC)" etc.
    if base and base not in out:
        out.append(base)

    # Stroke short-forms, applied to the lowercased base (matching is
    # case-insensitive; output casing is taken from the matched text, not these).
    low = base.lower()
    stroked = [low]
    for long_form, shorts in _STROKE_SHORT_FORMS.items():
        if long_form in low:
            for short in shorts:
                stroked.append(low.replace(long_form, short))

    # Distance "100m" → "100" companion of each stroked form.
    expanded = list(stroked)
    for form in stroked:
        no_m = re.sub(r"(?<=\d)m\b", "", form)
        if no_m != form:
            expanded.append(no_m)

    for form in expanded:
        form = form.strip()
        # Only keep forms that still carry a stroke word — a bare distance
        # ("100") is not grounded enough to highlight safely.
        if form and form not in out and not form.replace(" ", "").isdigit():
            out.append(form)
    return out


def _card_facts(achievement: Optional[dict]) -> list[tuple[str, str]]:
    """Source-grounded ``(phrase, kind)`` pairs for "focus the facts" highlighting.

    Every phrase is derived from the structured achievement — never guessed.
    ``kind`` is one of ``athlete`` / ``event`` / ``time`` / ``pb`` (the last
    covers PB **and** medal/record markers, gated by the detected achievement
    ``type`` so e.g. "gold" is only ever lit on an actual medal).
    """
    if not isinstance(achievement, dict):
        return []
    phrases: list[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()

    def add(phrase: str, kind: str) -> None:
        p = " ".join(str(phrase or "").split())
        if len(p) < 2:  # never light up a stray single character
            return
        key = (p.lower(), kind)
        if key in seen:
            return
        seen.add(key)
        phrases.append((p, kind))

    # Athlete — full name, plus the first name (captions usually go first-name).
    name = " ".join(str(achievement.get("swimmer_name") or "").split())
    if name:
        add(name, "athlete")
        parts = name.split()
        if len(parts) > 1:
            add(parts[0], "athlete")

    # Event — the label and its grounded short-forms.
    for variant in _event_variants(achievement.get("event") or ""):
        add(variant, "event")

    # Time — the result string(s); exact and highly distinctive.
    raw_facts = achievement.get("raw_facts")
    time_sources = [achievement.get("time"), achievement.get("time_str"), achievement.get("result")]
    if isinstance(raw_facts, dict):
        time_sources += [
            raw_facts.get("time"),
            raw_facts.get("time_str"),
            raw_facts.get("result"),
            raw_facts.get("final_time"),
        ]
    for t in time_sources:
        add(str(t or "").strip(), "time")

    # PB / medal / record markers — gated by the engine's AUTHORITATIVE detected
    # type / post_angle (not the free-text angle_hint, which can mention "first"
    # or "gold" metaphorically), so we never light up "gold" or "record" on a
    # card the detector didn't actually flag as one.
    type_blob = " ".join(str(achievement.get(k) or "") for k in ("type", "post_angle")).lower()
    is_pb = bool(achievement.get("pb") or achievement.get("is_pb")) or any(
        tok in type_blob for tok in ("pb", "personal_best", "best_time", "lifetime")
    )
    markers: list[str] = []
    if is_pb:
        markers += ["personal best", "lifetime best", "new best", "PB"]
    if any(tok in type_blob for tok in ("medal", "podium", "gold", "silver", "bronze")):
        markers += ["medal", "podium"]
        for metal in ("gold", "silver", "bronze"):
            if metal in type_blob:
                markers.append(metal)
    if "record" in type_blob:
        markers += [
            "club record",
            "county record",
            "regional record",
            "national record",
            "meet record",
            "record",
        ]
    if "first" in type_blob:
        markers.append("first")
    for m in markers:
        add(m, "pb")

    return phrases


# Fact kinds are a fixed internal vocabulary — never user text — so they are safe
# to interpolate straight into a class name.
_FOCUS_KINDS = {"athlete", "event", "time", "pb"}


def _focus_facts_html(
    text: str,
    achievement: Optional[dict] = None,
    *,
    phrases: Optional[list[tuple[str, str]]] = None,
) -> str:
    """Server-side span injection for U.7.

    Wrap every source-grounded fact found in ``text`` in a ``<span class="mh-fact
    mh-fact--KIND">`` pill and de-emphasise the rest, returning safe HTML. Every
    segment is HTML-escaped via ``_h`` — only the highlight ``<span>`` tags are
    markup — so this is XSS-safe even on attacker-controlled caption text.

    When nothing matches (or there are no facts) the text is returned plainly
    escaped, with **no** de-emphasis wrapper, so non-grounded copy still reads at
    full strength rather than being greyed out for nothing.
    """
    s = str(text or "")
    if not s.strip():
        return str(_h(s))
    if phrases is None:
        phrases = _card_facts(achievement or {})
    if not phrases:
        return str(_h(s))

    # Longest phrases first so "100m Freestyle" beats "Freestyle" and
    # "Emma Davies" beats "Emma" when both could match at the same spot.
    ordered = sorted(phrases, key=lambda pk: len(pk[0]), reverse=True)
    kind_of: dict[str, str] = {}
    for phrase, kind in ordered:
        kind_of.setdefault(phrase.lower(), kind if kind in _FOCUS_KINDS else "event")
    alternation = "|".join(re.escape(p) for p, _ in ordered)
    # Boundary = not flanked by an alphanumeric. Handles "PB", "Emma" and times
    # like "58.21" / "1:02.34" (whose internal "." / ":" are non-alphanumeric).
    pattern = re.compile(r"(?<![A-Za-z0-9])(" + alternation + r")(?![A-Za-z0-9])", re.IGNORECASE)

    chunks: list[str] = []
    pos = 0
    matched_any = False
    for m in pattern.finditer(s):
        if m.start() > pos:
            chunks.append(str(_h(s[pos : m.start()])))
        hit = m.group(1)
        kind = kind_of.get(hit.lower(), "event")
        chunks.append(f'<span class="mh-fact mh-fact--{kind}">{_h(hit)}</span>')
        pos = m.end()
        matched_any = True
    if not matched_any:
        return str(_h(s))
    if pos < len(s):
        chunks.append(str(_h(s[pos:])))
    return '<span class="mh-focus">' + "".join(chunks) + "</span>"


def _render_why_inner(
    exp: dict,
    *,
    ra: Optional[dict] = None,
    run_id: str = "",
    card_uuid: str = "",
) -> str:
    """Render the explanation-dependent body of a "Why this card?"
    disclosure from a pre-built explanation dict.

    Split out of ``_render_why_this_card`` so the (LLM-backed) explanation
    can be built lazily, one card at a time via ``api_why_card``, rather
    than synchronously for every card during the review render. The block
    stays grounded: headline / bullets come from the ranker + LLM, source
    lines are quoted verbatim from the achievement's evidence.
    """
    # U.7 — light up the source-grounded facts (athlete / event / time / PB) in
    # the LLM's reasoning. Phrases are derived once from this card's achievement
    # so the headline and every bullet highlight the same grounded entities; if
    # there's no achievement in scope, _focus_facts_html falls back to plain
    # escaped text.
    _facts = _card_facts((ra or {}).get("achievement") if isinstance(ra, dict) else None)
    headline = _focus_facts_html(exp.get("headline", ""), phrases=_facts)
    bullets = exp.get("bullets") or []
    source_lines = exp.get("source_lines") or []

    bullets_html = ""
    for b in bullets:
        bullets_html += f'<li style="margin-bottom:3px">{_focus_facts_html(b, phrases=_facts)}</li>'
    if not bullets_html:
        bullets_html = ""

    src_html = ""
    for sl in source_lines:
        label = _h(sl.get("label", "source"))
        raw = _h(sl.get("raw_text", ""))
        offset = sl.get("file_offset")
        offset_tag = (
            f'<span class="muted" style="font-size:10px;margin-left:6px">#{int(offset)}</span>'
            if isinstance(offset, int)
            else ""
        )
        src_html += (
            f'<li style="margin-bottom:6px">'
            f'<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px">'
            f"{label}{offset_tag}</div>"
            f'<blockquote style="margin:2px 0 0 0;padding:6px 10px;border-left:2px solid var(--accent);'
            f"background:color-mix(in oklab, var(--lane) 5%, transparent);font-family:ui-monospace,Menlo,monospace;font-size:12px;"
            f'color:var(--ink)">{raw}</blockquote>'
            f"</li>"
        )
    if not src_html:
        src_html = (
            '<li class="muted" style="font-size:12px">'
            "No source lines available &mdash; explanation is based on the ranker only."
            "</li>"
        )

    # Plain-text payload for the "Copy reasoning" button (kept in a hidden textarea
    # so the copy works without an extra round-trip to the server).
    plain_lines = [exp.get("headline", "")]
    for b in bullets:
        plain_lines.append(f"- {b}")
    if source_lines:
        plain_lines.append("")
        plain_lines.append("Source lines:")
        for sl in source_lines:
            plain_lines.append(f"  [{sl.get('label', 'source')}] {sl.get('raw_text', '')}")
    plain_text = _h("\n".join(p for p in plain_lines if p is not None))

    bullets_block = (
        f'<ul style="margin:6px 0 10px 0;padding-left:20px;font-size:12px;color:var(--ink-dim)">{bullets_html}</ul>'
        if bullets_html
        else ""
    )

    # LLM-derived performance context (Olympic-level vs county-level
    # judgement). Rendered as a distinct callout so reviewers can see at a
    # glance that this is the LLM's read, not a grounded factor.
    perf_ctx = (exp.get("performance_context") or "").strip()
    perf_block = ""
    if perf_ctx:
        perf_block = (
            '<div style="margin:8px 0 10px 0;padding:8px 10px;background:color-mix(in oklab, var(--lane) 6%, transparent);'
            'border-left:2px solid var(--lane);border-radius:4px">'
            '<div style="font-size:10px;text-transform:uppercase;color:var(--lane);letter-spacing:0.5px;'
            'margin-bottom:2px">Performance context (AI)</div>'
            f'<div style="font-size:12px;color:var(--ink);line-height:1.4">{_h(perf_ctx)}</div>'
            "</div>"
        )

    # Phase 1.4 — "Use in next caption" button. Only rendered when
    # the caller passed run_id (so legacy callers without a run
    # context don't break). The button piggybacks on the existing
    # /api/runs/<run>/swim/<swim>/caption?include_why=1 channel.
    _swim_id_for_btn = ""
    try:
        ach_for_btn = ra.get("achievement") if isinstance(ra, dict) else None
        if isinstance(ach_for_btn, dict):
            _swim_id_for_btn = str(ach_for_btn.get("swim_id") or ra.get("id") or "")
        elif isinstance(ra, dict):
            _swim_id_for_btn = str(ra.get("id") or ra.get("swim_id") or "")
    except Exception:
        _swim_id_for_btn = ""
    use_in_caption_btn, use_in_caption_panel = _use_in_caption_html(
        run_id,
        _swim_id_for_btn,
        card_uuid,
    )

    return f"""
  <div style="margin-top:8px">
    <div style="font-size:13px;color:var(--ink);line-height:1.45;margin-bottom:6px">{headline}</div>
    {bullets_block}
    {perf_block}
    <div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;
      margin-bottom:4px">Source lines (verbatim)</div>
    <ul style="list-style:none;margin:0;padding:0">{src_html}</ul>
    <div style="margin-top:8px;display:flex;gap:6px;align-items:center;flex-wrap:wrap">
      <button class="btn secondary" type="button" style="font-size:11px;padding:4px 10px"
        onclick="copyWhyCard(this, 'why-text-{card_uuid}')">Copy reasoning</button>
      <textarea id="why-text-{card_uuid}" style="display:none">{plain_text}</textarea>
      {use_in_caption_btn}
    </div>
    {use_in_caption_panel}
  </div>"""


def _why_card_cuid(card_uuid: str) -> str:
    """DOM-id-safe slug for a card_uuid (shared by the lazy shell and the
    api_why_card endpoint so the rendered element ids line up)."""
    return "".join(ch if (ch.isalnum() or ch in "_-") else "_" for ch in str(card_uuid))[:80]


def _render_why_this_card(
    ra: dict,
    *,
    card_uuid: str,
    run_id: str = "",
    ach_index: Optional[int] = None,
    lazy: bool = False,
) -> str:
    """Render the "Why this card?" disclosure.

    The explanation (headline + bullets + performance context) is written
    by the active LLM — the ONLY LLM-backed surface on the review render
    path. A typical meet produces 150+ cards, so building every card's
    explanation inline made the review page fire 300+ blocking LLM calls
    and take many minutes to render (long enough to block the gunicorn
    worker until --max-requests recycled it). When ``lazy`` is set and an
    ``ach_index`` + ``run_id`` are available, emit a placeholder instead
    and let the page fetch each card's reasoning on demand via
    ``api_why_card``; the disclosure stays default-open, the reasoning
    just streams in. Eager mode (the default) is preserved for callers
    and tests that want the fully-rendered block.
    """
    # The explainer is visible-by-default (the Phase 1.4 "visible intelligence"
    # invariant) on focused / eager single-card surfaces. On the LAZY review
    # list, though, every one of a meet's 150-250 cards rendering its full
    # reasoning open produced a ~70,000px wall the reviewer had to scroll past
    # (Council UI verdict, 2026-05-31). There we collapse-by-default for scroll
    # relief, keeping the reasoning exactly one click away with a clear "show
    # reasoning" affordance — deferred, never hidden. Eager callers (and the
    # test_visible_intelligence invariant) keep <details open>.
    _open_attr = "" if lazy else " open"
    _summary_label = (
        'Why this card? <span class="why-peek">Show reasoning'
        '<span class="why-chev" aria-hidden="true">&#x25BE;</span></span>'
        if lazy
        else "Why this card?"
    )
    shell_open = (
        f'<details{_open_attr} class="why-card" style="margin-top:10px;padding:10px 12px;'
        'background:color-mix(in oklab, var(--lane) 6%, transparent);border:1px solid color-mix(in oklab, var(--lane) 25%, transparent);border-radius:8px">'
        '<summary style="cursor:pointer;font-size:12px;font-weight:600;color:var(--lane);'
        'user-select:none;list-style:none;display:flex;align-items:center;gap:6px">'
        f'<span aria-hidden="true">&#9432;</span> {_summary_label}</summary>'
    )
    if lazy and ach_index is not None and run_id:
        why_url = url_for("api_why_card", run_id=run_id, ach_index=int(ach_index))
        return (
            f"{shell_open}"
            f'<div class="why-body" data-why-url="{_h(why_url)}" '
            f'data-why-cuid="{_h(_why_card_cuid(card_uuid))}">'
            f'<div class="muted" style="margin-top:8px;font-size:12px;color:var(--ink-muted)">'
            f"Loading reasoning&hellip;</div></div></details>"
        )
    exp = _build_card_explanation(ra)
    return (
        f"{shell_open}{_render_why_inner(exp, ra=ra, run_id=run_id, card_uuid=card_uuid)}</details>"
    )


def _use_in_caption_html(run_id: str, swim_id: str, card_uuid: str) -> tuple[str, str]:
    """Return (button_html, panel_html) for the "Use in next caption"
    affordance. Empty strings when ``run_id`` / ``swim_id`` are missing.

    The button POSTs to /api/runs/<run>/swim/<swim>/caption with
    ?include_why=1 — the endpoint then builds the same explanation,
    injects it as `_extra_instructions`, and returns the regenerated
    caption. The result lands in a small panel below the explainer.
    """
    if not run_id or not swim_id:
        return "", ""
    panel_id = f"why-cap-{card_uuid}"
    # JSON-encode the URLs so Jinja-style interpolation can't be
    # tricked by a card_id containing quotes — defence-in-depth.
    cap_url = url_for("api_live_caption", run_id=run_id, swim_id=swim_id)
    btn = (
        f'<button class="btn secondary" type="button" '
        f'style="font-size:11px;padding:4px 10px;'
        f'background:color-mix(in oklab, var(--lane) 15%, transparent);border-color:color-mix(in oklab, var(--lane) 40%, transparent);color:var(--lane)" '
        f'onclick="mhUseWhyInCaption(this, {json.dumps(cap_url)}, {json.dumps(panel_id)})">'
        f"Use in next caption</button>"
    )
    panel = (
        f'<div id="{panel_id}" data-mh-why-caption '
        f'style="display:none;margin-top:8px;padding:8px 10px;'
        f"background:color-mix(in oklab, var(--lane) 4%, transparent);border:1px dashed color-mix(in oklab, var(--lane) 30%, transparent);"
        f'border-radius:6px;font-size:12px;color:var(--ink);line-height:1.45"></div>'
    )
    return btn, panel


def _reveal_lines(
    lines: list[str], *, tag: str = "h2", cls: str = "mh-section-title", el_id: str = ""
) -> str:
    """U.5 — render an editorial heading as stacked lines that reveal
    one-by-one on scroll (inspired by Opal, op.al).

    Each entry in ``lines`` becomes a ``.mh-line`` span inside a
    ``.mh-reveal-lines`` heading. The Phase-10 IntersectionObserver
    (``bindReveals`` in the layout) observes every line *individually* and adds
    ``.is-in`` as it scrolls up through the viewport, so a section's headline
    surfaces line after line instead of all at once; a small per-line CSS delay
    keeps the cascade gentle when the lines cross the trigger together.

    ``lines`` are pre-built, trusted HTML fragments — the static landing copy
    here, including its ``<em class="editorial">`` accents. There is no user
    data on this path, so the helper does not re-escape; any caller that ever
    feeds it dynamic text MUST pass already-escaped fragments. No-JS and
    reduced-motion visitors see every line immediately (the ``.mh-js`` /
    ``prefers-reduced-motion`` gate in the CSS), so this is pure progressive
    enhancement — content is never hidden without JavaScript able to reveal it.

    ``el_id`` (optional) stamps an ``id`` on the heading element so a section
    can name itself via ``aria-labelledby`` (e.g. the UI 1.22 FAQ region);
    when omitted the output is byte-identical to the original helper.
    """
    spans = "".join(f'<span class="mh-line">{ln}</span>' for ln in lines)
    id_attr = f' id="{el_id}"' if el_id else ""
    return f'<{tag}{id_attr} class="{cls} mh-reveal-lines">{spans}</{tag}>'


def _drag_hint(label: str = "Drag to explore") -> str:
    """UI 1.27 — the "drag to explore" affordance shown beside a
    ``.mh-drag-scroll`` gallery (Media Library filmstrip + landing
    sample-output showcase).

    It ships ``hidden``; ui-kit.js ``bindDragScroll`` reveals it only while
    the row actually overflows (and hides it again after the first drag), so
    the hint never promises a drag the row can't deliver. It is a pure cue:
    the gallery scrolls with wheel / trackpad / touch / focused-arrow keys
    even with no JS and no hint. The grip glyph is a static, first-party
    inline SVG (no icon font, no CDN).
    """
    return (
        '<p class="mh-ds-hint" hidden style="margin-top:var(--sp-3)">'
        '<span class="mh-ds-hint__grip" aria-hidden="true">'
        '<svg viewBox="0 0 24 24" width="14" height="14" fill="none" '
        'stroke="currentColor" stroke-width="1.8" stroke-linecap="round" '
        'stroke-linejoin="round"><path d="m9 6-4 4 4 4M15 6l4 4-4 4"/></svg>'
        f"</span> {_h(label)}</p>"
    )


def _chart_card(eyebrow: str, title: str, chart_html: str) -> str:
    """UI 1.6 — wrap a chart in a labelled panel (eyebrow + title) for the
    landing sample-outputs grid and the in-app Review "Meet at a glance" card.

    ``eyebrow`` and ``title`` are trusted static copy and may carry HTML
    entities (``&middot;``, ``&amp;``), exactly like ``_reveal_lines`` — there
    is no user data on this path, so they are not re-escaped. ``chart_html`` is
    the already-rendered, already-escaped figure from ``web/charts.py``.
    """
    return (
        '<div class="mh-chart-card">'
        '<div class="mh-chart-card-head">'
        f'<span class="mh-chart-card-eyebrow">{eyebrow}</span>'
        f'<h3 class="mh-chart-card-title">{title}</h3>'
        "</div>"
        f"{chart_html}"
        "</div>"
    )


# --------------------------------------------------------------------------- #
# U.3 — Explainability & confidence surfaces.
#
# The deterministic engine (detectors + ranker) decides *whether* a swim is a
# PB / medal / record and *how content-worthy* it is. Those outputs —
# ``confidence_label``, ``quality_band``, ``priority``, the ranker ``factors``
# and the near-miss category — are never recomputed or re-judged here; U.3 only
# makes them *read* as the trustworthy intelligence they already are. The
# plain-English glosses below are fixed UI legends for those deterministic
# enums (the same pattern U.2 used to humanise parse-note codes) — NOT an AI
# surface and NOT a heuristic stand-in for one. The LLM-written "Why this card?"
# prose stays the only judgement surface on the review path; if no provider is
# configured it still says so honestly rather than fabricate.
# --------------------------------------------------------------------------- #

# What each deterministic confidence band means, in a volunteer's words.
_CONFIDENCE_MEANING: dict[str, str] = {
    "high": "We're confident in the facts on this card — the result line is "
    "clear and the achievement is directly supported by the data.",
    "medium": "The facts look right, but one input is softer (for example a "
    "prior best we couldn't fully confirm). Worth a quick glance "
    "before you post it.",
    "low": "We're less sure here — the source data was ambiguous or "
    "incomplete. Check it against the original results before approving.",
}
_CONFIDENCE_CLS: dict[str, str] = {"high": "good", "medium": "warn", "low": "bad"}


def _confidence_chip(label: str, *, numeric: Optional[float] = None) -> str:
    """A labelled, self-explaining confidence chip for a review card.

    Replaces the bare ``conf: medium`` tag. Carries the plain-English meaning
    in a ``title=`` tooltip so a first-time reviewer understands what the
    engine is telling them: confidence is "how sure we are the facts are
    right" — a separate axis from content-worthiness (the worthiness meter).
    """
    lab = (str(label or "medium")).strip().lower()
    cls = _CONFIDENCE_CLS.get(lab, "warn")
    meaning = _CONFIDENCE_MEANING.get(lab, _CONFIDENCE_MEANING["medium"])
    pct = ""
    if isinstance(numeric, (int, float)) and 0.0 < float(numeric) <= 1.0:
        pct = f'&nbsp;<span class="mh-conf-chip-pct">{float(numeric) * 100:.0f}%</span>'
    return (
        f'<span class="mh-conf-chip {cls}" title="{_h(meaning)}" data-conf="{_h(lab)}">'
        f'<span class="mh-conf-chip-dot" aria-hidden="true"></span>'
        f"Confidence&nbsp;&middot;&nbsp;{_h(lab.capitalize())}{pct}</span>"
    )


# What each deterministic quality band means.
_BAND_MEANING: dict[str, str] = {
    "elite": "Elite — a standout moment (gold, a record, a huge PB). Lead with these.",
    "strong": "Strong — a clear, postable achievement.",
    "story": "Story — a result with a good angle worth telling.",
    "nice": "Nice — a genuine positive, lower in the running order.",
    "not_worthy": "Below the bar — kept for the record, not suggested for posting.",
}
_BAND_CLS: dict[str, str] = {
    "elite": "warn",
    "strong": "info",
    "story": "",
    "nice": "",
    "not_worthy": "bad",
}


def _band_chip(band: str) -> str:
    """The quality-band tag, with its meaning in a tooltip (was a bare tag)."""
    b = (str(band or "nice")).strip().lower()
    cls = _BAND_CLS.get(b, "")
    meaning = _BAND_MEANING.get(b, "")
    return (
        f'<span class="tag {cls}" style="font-size:10px" title="{_h(meaning)}">'
        f"{_h(b.upper().replace('_', ' '))}</span>"
    )


def _worthiness_meter(priority: float) -> str:
    """The content-worthiness (ranking) meter — a *different* axis from
    confidence, labelled so the bare 0–1 score isn't read as a second
    confidence number. The value comes straight from the deterministic ranker.
    """
    try:
        p = max(0.0, min(1.0, float(priority)))
    except (TypeError, ValueError):
        p = 0.0
    pct = int(round(p * 100))
    return (
        '<span class="mh-worth" title="Content-worthiness — the engine&#39;s ranking '
        'of how postable this is, used to order the queue. Separate from confidence.">'
        '<span class="mh-worth-label">Worth</span>'
        '<span class="mh-worth-track">'
        f'<span class="mh-worth-fill mh-bar-fill" style="width:{pct}%"></span></span>'
        f'<span class="mh-worth-num">{pct}%</span></span>'
    )


def _avatar_initials(name: str) -> str:
    """One- or two-letter initials for an athlete avatar chip.

    First+last initial for a full name, the first two letters for a single
    token, ``?`` for an empty name. Mirrors the sign-in card initials.
    """
    parts = [p for p in (name or "").strip().split() if p]
    if not parts:
        return "?"
    if len(parts) == 1:
        return parts[0][:2].upper()
    return (parts[0][0] + parts[-1][0]).upper()


def _athlete_avatar(
    name: str,
    *,
    club: str = "",
    stat: str = "",
    focusable: bool = False,
    size: int = 34,
) -> str:
    """An athlete avatar chip carrying a hover/focus Animated-Tooltip (the kit
    ``.mh-tooltip``) that shows the athlete's name, club and a key stat.

    Used on the review queue and the athlete-spotlight surfaces (UI2.2). The
    tooltip is a decorative progressive enhancement: the chip is fully usable
    with the effect absent (no-JS / reduced-motion), and every value shown is a
    real, grounded fact already in the recognition report — never fabricated.

    ``focusable=True`` makes the chip keyboard-reachable and exposes the same
    name/club/stat to assistive tech via ``aria-label`` (use for standalone
    placements). ``focusable=False`` keeps it decorative + ``aria-hidden`` (use
    when the chip sits inside another link/control, or the same facts are
    already visible as text beside it).
    """
    nm = (name or "").strip()
    club = (club or "").strip()
    stat = (stat or "").strip()
    initials = _h(_avatar_initials(nm))

    # Meta line: "Club · stat", dropping either empty half cleanly.
    meta_inner = ""
    if club:
        meta_inner += f'<span class="mh-tooltip__club">{_h(club)}</span>'
    if club and stat:
        meta_inner += '<span class="mh-tooltip__sep" aria-hidden="true"> · </span>'
    if stat:
        meta_inner += f'<span class="mh-tooltip__stat">{_h(stat)}</span>'
    meta_html = f'<span class="mh-tooltip__meta">{meta_inner}</span>' if meta_inner else ""

    if focusable:
        # Standalone, keyboard-reachable: AT gets the whole summary from the
        # avatar's aria-label; the visual pop is a decorative duplicate.
        aria = _h(" · ".join(p for p in (nm, club, stat) if p) or (nm or "Athlete"))
        avatar_attrs = f'tabindex="0" role="img" aria-label="{aria}"'
    else:
        avatar_attrs = 'aria-hidden="true"'

    return (
        f'<span class="mh-tooltip" style="--mh-tip-size:{int(size)}px">'
        f'<span class="mh-tooltip__avatar" {avatar_attrs}>{initials}</span>'
        f'<span class="mh-tooltip__pop" role="tooltip" aria-hidden="true">'
        f'<span class="mh-tooltip__name">{_h(nm)}</span>{meta_html}'
        f"</span></span>"
    )


def _factor_to_dict(f: Any) -> dict:
    """A ranker factor may arrive as a ``RankFactor`` dataclass or a plain dict
    (persisted run JSON). Normalise to a dict; non-factors become ``{}``."""
    if hasattr(f, "to_dict"):
        try:
            f = f.to_dict()
        except Exception:
            pass
    return f if isinstance(f, dict) else {}


def _render_factor_breakdown(factors: Any) -> str:
    """Plain-English "how the ranking added up", replacing the raw
    name/value/weight debug table.

    Each row leads with the ranker's own grounded ``plain_summary`` (falling
    back to ``reason``) and shows how much that reason counted, as a bar
    normalised to the strongest contributor. Every number is read verbatim
    from the deterministic ranker — nothing here re-judges the result. The
    multiplicative ``profile_priority`` factor is shown as a ×multiplier rather
    than a contribution bar, mirroring how the ranker actually applies it.
    """
    rows: list[tuple[str, str, float, float, bool]] = []
    for f in factors or []:
        d = _factor_to_dict(f)
        if not d:
            continue
        name = str(d.get("name") or "")
        try:
            val = float(d.get("value") or 0.0)
            wt = float(d.get("weight") or 0.0)
        except (TypeError, ValueError):
            val, wt = 0.0, 0.0
        summary = (str(d.get("plain_summary") or d.get("reason") or "")).strip()
        is_priority = name == "profile_priority"
        contrib = 0.0 if is_priority else val * wt
        # Skip a factor that neither contributed nor carries a human summary,
        # and a no-op club override (×1.00) — they add noise, not trust.
        if is_priority and abs(val - 1.0) <= 0.01:
            continue
        if not is_priority and contrib <= 0 and not summary:
            continue
        rows.append((name, summary, contrib, val, is_priority))

    if not rows:
        return (
            '<p class="muted" style="font-size:12px;margin:0">'
            "No ranking factors were recorded for this card.</p>"
        )

    top = max((c for _, _, c, _, p in rows if not p), default=0.0)
    items = ""
    for name, summary, contrib, val, is_priority in rows:
        label = _h(_humanise(name))
        text = _h(summary) if summary else label
        if is_priority:
            meter = (
                f'<span class="mh-factor-mult" title="Club priority multiplier '
                f'(set in your profile)">&times;{val:.2f}</span>'
            )
        else:
            w = int(round((contrib / top) * 100)) if top > 0 else 0
            meter = (
                f'<span class="mh-factor-track" title="How much this reason '
                f'counted (contribution {contrib:.2f})">'
                f'<span class="mh-factor-fill" style="width:{w}%"></span></span>'
            )
        items += (
            f'<li class="mh-factor"><span class="mh-factor-name">{label}</span>'
            f'<span class="mh-factor-why">{text}</span>{meter}</li>'
        )
    return f'<ul class="mh-factor-list">{items}</ul>'


# Plain-English for the deterministic near-miss categories the explainer
# assigns to swims that produced no card (legacy/swim_content_v5/explainer.py).
# (label, blurb) — the genuine close calls first in _NEAR_MISS_ORDER below.
_NEAR_MISS: dict[str, tuple[str, str]] = {
    "almost_pb": (
        "Almost a PB",
        "Just off a personal best — close enough that we flagged it.",
    ),
    "possible_pb_uncertain": (
        "Possible PB — unconfirmed",
        "This might be a PB, but there's no prior best on file to prove it.",
    ),
    "possible_barrier_no_history": (
        "Possible first — no history",
        "Could be a first-time barrier, but we have no past times to confirm it.",
    ),
    "ambiguous_swimmer_match": (
        "Swimmer unconfirmed",
        "We couldn't be sure which swimmer this was, so we held it back rather than guess.",
    ),
    "good_placing_weak_field": (
        "Good place, light field",
        "A good finish, but the field was small — so it scored lower.",
    ),
    "relay_mention_only": (
        "Relay — mention only",
        "Part of a relay; noted, but not made into its own card.",
    ),
    "lower_priority": (
        "Outranked",
        "A real result — just outranked by stronger swims at this meet.",
    ),
}
# Genuine close calls first, the plain "outranked" bucket last.
_NEAR_MISS_ORDER: list[str] = [
    "almost_pb",
    "possible_pb_uncertain",
    "possible_barrier_no_history",
    "ambiguous_swimmer_match",
    "good_placing_weak_field",
    "relay_mention_only",
    "lower_priority",
]


def _near_miss_label(category: str) -> tuple[str, str]:
    """(label, blurb) in plain English for a deterministic near-miss category."""
    return _NEAR_MISS.get((str(category or "")).strip().lower(), _NEAR_MISS["lower_priority"])


def _near_miss_is_close_call(category: str) -> bool:
    """A 'close call' is any near-miss except the plain 'outranked' bucket —
    the ones genuinely worth a reviewer's glance."""
    return (str(category or "")).strip().lower() not in ("", "lower_priority")


def _render_explainability_key() -> str:
    """The "how to read these cards" guide, as a side-anchored popup.

    A slim tab pinned to the right edge of the screen opens a slide-in panel
    explaining how to read the review surface — so the explainer is always one
    click away without taking a column of vertical space at the top of the page.
    Every gloss describes the deterministic engine's own outputs — it makes
    nothing up. The panel is reduced-motion-safe and closes on the ✕, a click on
    the backdrop, or Escape."""

    def _row(term: str, body: str) -> str:
        return (
            f'<div class="mh-key-row"><span class="mh-key-term">{term}</span>'
            f'<span class="mh-key-body">{body}</span></div>'
        )

    rows = (
        _row(
            "Band",
            "How big the moment is — <b>Elite</b> (gold, a record, a huge PB) "
            "down through <b>Strong</b>, <b>Story</b> and <b>Nice</b>. It sets "
            "the running order.",
        )
        + _row(
            "Confidence",
            "How sure we are the <b>facts</b> are right — computed by our engine "
            "and checked against the source line, never guessed. "
            "<b>High</b> / <b>Medium</b> / <b>Low</b>.",
        )
        + _row(
            "Worth",
            "How <b>postable</b> the engine rates it — a separate ranking used to "
            "order the queue. A high-worth card can still be Medium confidence, "
            "and the other way round.",
        )
        + _row(
            "Why this card?",
            "Written by AI from the <b>verified</b> facts and the ranking factors "
            "— never invented. If no AI is configured it tells you so, rather "
            "than make something up.",
        )
        + _row(
            "Why not",
            "Swims that didn&rsquo;t make a card are kept under <b>Run detail "
            "&amp; diagnostics</b> with the reason in plain English — so you can "
            "see nothing good was dropped silently.",
        )
    )

    # The launcher tab (fixed to the right edge), the dimming backdrop and the
    # slide-in dialog. Markup + a small self-contained controller; the look
    # lives in the shared stylesheet (.mh-guide-*). The panel starts `hidden`
    # so it is out of the a11y tree and never flashes before JS wires it up.
    return (
        '<button type="button" class="mh-guide-tab" id="mh-guide-open" '
        'aria-haspopup="dialog" aria-controls="mh-guide-panel" aria-expanded="false">'
        '<span class="mh-guide-tab-icon" aria-hidden="true">&#9432;</span>'
        "<span>How to read these cards</span></button>"
        '<div class="mh-guide-overlay" id="mh-guide-overlay" hidden></div>'
        '<aside class="mh-guide-panel" id="mh-guide-panel" role="dialog" '
        'aria-modal="true" aria-labelledby="mh-guide-title" hidden>'
        '<div class="mh-guide-panel-head">'
        '<h2 id="mh-guide-title"><span aria-hidden="true">&#9432;</span> '
        "How to read these cards</h2>"
        '<button type="button" class="mh-guide-close" id="mh-guide-close" '
        'aria-label="Close guide">&times;</button>'
        "</div>"
        '<div class="mh-key-grid">' + rows + "</div></aside>"
        "<script>(function(){"
        "var openBtn=document.getElementById('mh-guide-open');"
        "var panel=document.getElementById('mh-guide-panel');"
        "var overlay=document.getElementById('mh-guide-overlay');"
        "var closeBtn=document.getElementById('mh-guide-close');"
        "if(!openBtn||!panel||!overlay){return;}"
        "var lastFocus=null,hideTimer=null;"
        "function open(){"
        "if(hideTimer){clearTimeout(hideTimer);hideTimer=null;}"
        "lastFocus=document.activeElement;"
        "panel.hidden=false;overlay.hidden=false;"
        "requestAnimationFrame(function(){requestAnimationFrame(function(){"
        "panel.classList.add('is-open');overlay.classList.add('is-open');});});"
        "openBtn.setAttribute('aria-expanded','true');"
        "if(closeBtn){closeBtn.focus();}"
        "document.addEventListener('keydown',onKey);}"
        "function close(){"
        "panel.classList.remove('is-open');overlay.classList.remove('is-open');"
        "openBtn.setAttribute('aria-expanded','false');"
        "document.removeEventListener('keydown',onKey);"
        "hideTimer=setTimeout(function(){panel.hidden=true;overlay.hidden=true;},280);"
        "if(lastFocus&&lastFocus.focus){lastFocus.focus();}}"
        "function onKey(e){if(e.key==='Escape'||e.key==='Esc'){close();}}"
        "openBtn.addEventListener('click',open);"
        "if(closeBtn){closeBtn.addEventListener('click',close);}"
        "overlay.addEventListener('click',close);"
        "})();</script>"
    )


def _render_meet_recap_tabs(run_id: str, active: str) -> str:
    """A segmented control that switches a processed meet between its two recap
    surfaces: **Review & approve all achievements** (the full ranked queue) and
    **Athlete spotlight** (one swimmer's story). ``active`` is ``"review"`` or
    ``"spotlight"``.

    Both tabs are real navigation — clicking one opens that page scoped to this
    run (``/review/<id>`` and ``/spotlight?run_id=<id>``) — so the two surfaces
    live on one screen the user can click between, within the meet-recap flow.
    """
    review_url = url_for("review", run_id=run_id)
    spotlight_url = url_for("spotlight_landing", run_id=run_id)
    _check_svg = (
        '<svg viewBox="0 0 24 24" width="16" height="16" fill="none" '
        'stroke="currentColor" stroke-width="2" stroke-linecap="round" '
        'stroke-linejoin="round" aria-hidden="true">'
        '<polyline points="9 11 12 14 22 4"/>'
        '<path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg>'
    )
    _person_svg = (
        '<svg viewBox="0 0 24 24" width="16" height="16" fill="none" '
        'stroke="currentColor" stroke-width="2" stroke-linecap="round" '
        'stroke-linejoin="round" aria-hidden="true">'
        '<circle cx="12" cy="8" r="4"/><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7"/></svg>'
    )

    def _tab(href: str, label: str, icon: str, is_active: bool) -> str:
        cls = "mh-recap-tab is-active" if is_active else "mh-recap-tab"
        cur = ' aria-current="page"' if is_active else ""
        return f'<a class="{cls}"{cur} href="{href}">{icon}<span>{label}</span></a>'

    return (
        '<nav class="mh-recap-tabs" aria-label="Meet recap views">'
        + _tab(review_url, "Review &amp; approve all achievements", _check_svg, active == "review")
        + _tab(spotlight_url, "Athlete spotlight", _person_svg, active == "spotlight")
        + "</nav>"
    )


def _render_near_miss_hint(n_not_generated: int, n_close_calls: int) -> str:
    """A slim, trustworthy "why not" pointer under the decision list.

    Reassures the reviewer that the swims which produced no card weren't
    silently dropped — they're traced, in plain English, under the diagnostics
    section — and surfaces how many were genuine close calls worth a glance.
    Empty when every swim produced a card.
    """
    if n_not_generated <= 0:
        return ""
    swims = f"{n_not_generated} swim{'' if n_not_generated == 1 else 's'}"
    if n_close_calls > 0:
        calls = (
            f"{n_close_calls} {'was a close call' if n_close_calls == 1 else 'were close calls'}"
        )
        body = (
            f"We also looked at <b>{swims}</b> that didn&rsquo;t make a card &mdash; "
            f"<b>{calls}</b> worth a glance."
        )
        pip = '<span class="mh-nm-pip" aria-hidden="true"></span>'
    else:
        body = (
            f"We also looked at <b>{swims}</b> that didn&rsquo;t make a card &mdash; "
            "none were close calls, but the reason for each is recorded."
        )
        pip = ""
    return (
        f'<div class="mh-nearmiss-hint">{pip}<span>{body}</span>'
        '<a href="#mh-not-generated">See why &rarr;</a></div>'
    )


