def _db():
    # timeout + busy_timeout: with two gunicorn workers writing the same
    # SQLite file (run-status updates, workflow state, progress streaming)
    # a naive connect raises "database is locked" the instant they overlap.
    # Waiting up to 5s for the lock turns those collisions into a brief
    # stall instead of a 500 that the status poller would silently retry.
    conn = sqlite3.connect(DB_PATH, timeout=5.0)
    conn.row_factory = sqlite3.Row
    try:
        conn.execute("PRAGMA busy_timeout=5000")
    except Exception:
        pass
    return conn


def _iso_age_secs(iso_str: Optional[str]) -> Optional[float]:
    """Seconds elapsed since an ISO-8601 timestamp, or None if unparseable."""
    if not iso_str:
        return None
    try:
        dt = datetime.fromisoformat(iso_str)
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=timezone.utc)
        return (datetime.now(timezone.utc) - dt).total_seconds()
    except (ValueError, TypeError):
        return None


def _cadence_activity_counts(profile_id: str, end):
    """Per-day content activity for one organisation over the heatmap window.

    Returns ``(generated, posted)`` — two ``{YYYY-MM-DD: count}`` dicts scoped
    to ``profile_id``: ``generated`` is pipeline runs created that day (the
    run history that grounds UI 1.17). ``posted`` is always empty now that
    MediaHub no longer schedules posts onto social channels; the second slot
    is kept so the heatmap renderer's shape is unchanged. ISO-8601 timestamps
    sort lexically, so a ``>= start`` prefix compare bounds the scan to the
    rendered year and ``substr(...,1,10)`` buckets by date in-engine.
    Fail-soft: any DB trouble yields empty dicts so the Activity page never
    500s over its decoration.
    """
    generated: dict[str, int] = {}
    posted: dict[str, int] = {}
    if not profile_id:
        return generated, posted
    start_iso = _cadence_window_start(end).isoformat()
    try:
        conn = _db()
        try:
            for r in conn.execute(
                "SELECT substr(created_at, 1, 10) AS d, COUNT(*) AS n FROM runs "
                "WHERE profile_id = ? AND created_at >= ? GROUP BY d",
                (profile_id, start_iso),
            ).fetchall():
                if r["d"]:
                    generated[r["d"]] = int(r["n"] or 0)
        finally:
            conn.close()
    except Exception as e:  # pragma: no cover - defensive
        log.warning("cadence: activity counts unavailable: %s", e)
    return generated, posted


def _persist_run_progress(
    run_id: str, status: str, log_list: list, error: Optional[str] = None
) -> None:
    """Best-effort stream of a run's status + progress log + heartbeat to
    the DB. Polls that land on the gunicorn worker NOT running the
    pipeline read this (the in-memory log lives only in the worker that
    spawned the thread). Failures are swallowed — the in-memory entry
    remains the primary source for same-worker polls."""
    try:
        conn = _db()
        conn.execute(
            "UPDATE runs SET status=?, progress_log=?, heartbeat_at=?, "
            "error=COALESCE(?, error) WHERE id=?",
            (
                status,
                json.dumps((log_list or [])[-_RUN_LOG_LIMIT:]),
                datetime.now(timezone.utc).isoformat(),
                error,
                run_id,
            ),
        )
        conn.commit()
        conn.close()
    except Exception:
        pass


def _advance_run_heartbeat(run_id: str) -> bool:
    """Advance a running run's liveness heartbeat (in-memory + DB) without
    touching its progress log.

    Called on a timer by the run worker's heartbeat ticker so a long,
    progress-silent step — e.g. the heavy LLM interpretation of a large fresh
    PDF, which can run past ``_RUN_STALE_SECS`` without emitting a progress
    line — keeps the heartbeat fresh instead of being mistaken for a dead
    worker. A no-op for a run that is missing or already terminal, so a
    finished/evicted run is never resurrected and a genuinely dead worker
    (whose ticker has stopped with it) still goes stale. Returns True if a
    heartbeat was advanced.
    """
    with _active_lock:
        entry = _active_runs.get(run_id)
        if entry is None or entry.get("status") not in ("queued", "running"):
            return False
        entry["heartbeat"] = time.time()
    # Mirror to the DB so polls that land on the *other* gunicorn worker (which
    # read heartbeat_at, not the in-memory entry) also see the run is alive.
    try:
        conn = _db()
        conn.execute(
            "UPDATE runs SET heartbeat_at=? WHERE id=? AND status IN ('queued','running')",
            (datetime.now(timezone.utc).isoformat(), run_id),
        )
        conn.commit()
        conn.close()
    except Exception:
        pass
    return True


def _init_db():
    conn = _db()
    conn.executescript("""
        CREATE TABLE IF NOT EXISTS runs (
            id TEXT PRIMARY KEY,
            created_at TEXT,
            finished_at TEXT,
            status TEXT,             -- queued | running | done | error
            profile_id TEXT,
            meet_name TEXT,
            our_swims INTEGER,
            n_cards INTEGER,         -- legacy V4 content-card count (≈0 in the V5 recognition-first flow)
            n_queue INTEGER,
            n_achievements INTEGER,  -- V5 recognition output: the REAL engine output a run produced
            error TEXT,
            file_name TEXT,
            progress_log TEXT,       -- JSON array, streamed for cross-worker polls
            heartbeat_at TEXT        -- ISO ts, advanced while the pipeline runs
        );
        -- UI 1.25 — emoji reactions on generated cards + the review queue.
        -- One row per (card, emoji, anonymous reactor): the per-card tally is
        -- COUNT(*) grouped by emoji, so a reactor counts once per emoji and a
        -- second tap toggles their row off. The composite PK is the only index
        -- needed — its (run_id, card_id) leftmost prefix covers both the
        -- per-card tally and the per-run "my reactions" lookup. `emoji` is
        -- constrained to a server-side allowlist before any INSERT, so no
        -- arbitrary user string ever lands here.
        CREATE TABLE IF NOT EXISTS card_reactions (
            run_id     TEXT NOT NULL,
            card_id    TEXT NOT NULL,
            emoji      TEXT NOT NULL,
            reactor_id TEXT NOT NULL,
            created_at TEXT,
            PRIMARY KEY (run_id, card_id, emoji, reactor_id)
        );
        -- One-time purge of the orphaned legacy posting-log table. Pre-PR-779
        -- data.db files still hold `posting_attempts` rows with caption excerpts
        -- and athlete names, but every erasure path (org-delete, athlete-erase,
        -- run-erasure) stopped touching it once the table left the scrub set.
        -- Nothing reads it at HEAD, so dropping it on init purges that
        -- unreachable personal data for good.
        DROP TABLE IF EXISTS posting_attempts;
    """)
    # Additive migration for DBs created before progress_log / heartbeat_at /
    # n_achievements. Old rows keep NULL n_achievements until they are listed
    # (the Activity page lazily backfills from the run JSON) or re-run.
    cols = {r[1] for r in conn.execute("PRAGMA table_info(runs)").fetchall()}
    if "progress_log" not in cols:
        conn.execute("ALTER TABLE runs ADD COLUMN progress_log TEXT")
    if "heartbeat_at" not in cols:
        conn.execute("ALTER TABLE runs ADD COLUMN heartbeat_at TEXT")
    if "n_achievements" not in cols:
        conn.execute("ALTER TABLE runs ADD COLUMN n_achievements INTEGER")
    # QA-015 — how many times a stale (interrupted) run has been auto-resumed.
    # Old rows keep NULL (treated as 0); bounded by _RUN_MAX_RESUMES.
    if "resume_count" not in cols:
        conn.execute("ALTER TABLE runs ADD COLUMN resume_count INTEGER")
    # Re-run detection — content_hash (exact same file/source) + meet_fingerprint
    # (same meet via any tool). Old rows keep NULL until re-run, so they simply
    # don't participate in duplicate badging/warnings; new runs stamp both.
    if "content_hash" not in cols:
        conn.execute("ALTER TABLE runs ADD COLUMN content_hash TEXT")
    if "meet_fingerprint" not in cols:
        conn.execute("ALTER TABLE runs ADD COLUMN meet_fingerprint TEXT")
    conn.commit()
    conn.close()


def _reconcile_interrupted_runs():
    """Resume — or, failing that, stamp as failed — interrupted runs at startup.

    The pipeline runs in a daemon thread inside a gunicorn worker. When a
    worker is recycled (--max-requests) or the container restarts (deploy/OOM),
    that thread dies WITHOUT running _persist_run or the error handler, leaving
    the DB row stuck at 'queued'/'running' forever — the status poller would
    otherwise spin indefinitely. A daemon thread never survives its process, so
    any non-terminal run whose heartbeat has gone stale (or was never set) is
    definitively dead. Gate strictly on staleness so a run still in flight on
    the *other* live worker (fresh heartbeat) is never wrongly killed.

    QA-015: a dead run with its launch input still on disk is RESUMED (re-run
    from the same input) instead of lost — this is what makes a 500+-swim meet
    interrupted by a recycle/deploy finish on its own. A dead run with no stored
    input (a run from before this fix, or one whose input was cleaned up) or one
    that has used up its resume budget gets the honest "upload again" error.
    """
    try:
        conn = _db()
        rows = conn.execute(
            "SELECT id, heartbeat_at, created_at, resume_count "
            "FROM runs WHERE status IN ('queued','running')"
        ).fetchall()
        conn.close()
    except Exception:
        return
    for r in rows:
        age = _iso_age_secs(r["heartbeat_at"] or r["created_at"])
        if not (age is None or age > _RUN_STALE_SECS):
            continue  # still in flight on a live worker — leave it alone
        # _maybe_resume_stale_run resumes when it can and stamps the honest
        # error when it cannot, with an atomic claim so two booting workers
        # never resume the same run twice.
        try:
            _maybe_resume_stale_run(r["id"])
        except Exception:
            pass


_init_db()
# _reconcile_interrupted_runs() is invoked AFTER the run-worker / resume helpers
# are defined (see below _start_run), so a startup sweep can re-launch the
# interrupted runs it finds.


def _prune_orphaned_runs():
    """Remove finished rows from `runs` whose JSON file no longer exists.

    The published sandbox is ephemeral, so when we redeploy the database may
    survive while the runs/<id>.json files are gone. Without this prune the
    home page lists dozens of broken /review/<id> links.

    Scoped to status='done': a 'queued'/'running' row is an in-flight run
    whose JSON hasn't been written yet (deleting it here — which the previous
    unscoped query did on every worker restart — is exactly what made an
    active run vanish into a "run not found" spinner), and a freshly-failed
    'error' row is kept so the polling user still sees the failure reason.
    """
    try:
        conn = _db()
        rows = conn.execute("SELECT id FROM runs WHERE status='done'").fetchall()
        stale = []
        for r in rows:
            run_id = r["id"] if hasattr(r, "keys") else r[0]
            json_path = RUNS_DIR / f"{run_id}.json"
            if not json_path.exists():
                stale.append(run_id)
        if stale:
            conn.executemany("DELETE FROM runs WHERE id = ?", [(s,) for s in stale])
            conn.commit()
        conn.close()
    except Exception:
        pass


_prune_orphaned_runs()
# V8.2: seed_default_profiles is a no-op since the profiles UI was removed.
seed_default_profiles()


# ---------------------------------------------------------------------
# V6 PB audit serialisation helper
# ---------------------------------------------------------------------


def _serialise_pb_audit(pb_audit) -> Optional[dict]:
    """Serialise a V6 RunPBAudit to a JSON-safe dict.
    Returns None if pb_audit is None or serialisation fails — but never
    silently: a swallowed failure here is what renders the misleading
    "audit wasn't saved, re-run the meet" card on the review page.
    """
    if pb_audit is None:
        return None
    try:
        from swim_content_pb.audit import run_audit_to_dict

        return run_audit_to_dict(pb_audit)
    except Exception:
        log.warning("PB audit serialisation failed — run will persist without it", exc_info=True)
        return None


def _deserialise_pb_audit(data: dict) -> Optional[dict]:
    """Return the pb_audit dict as-is (already deserialised from JSON)."""
    return data or None


# ---------------------------------------------------------------------
# Run persistence helpers
# ---------------------------------------------------------------------


def _persist_run(run: PipelineRunV4, file_name: str) -> None:
    """Persist a finished run to runs_v4/<id>.json + DB row."""
    payload = {
        "run_id": run.run_id,
        "started_at": run.started_at,
        "finished_at": run.finished_at,
        "profile_id": run.profile_id,
        "profile_display": run.profile_display,
        "file_name": file_name,
        "meet": run.canonical_meet.to_dict() if run.canonical_meet else None,
        "dispatch_log": run.dispatch_log.to_dict() if run.dispatch_log else None,
        "parse_warnings": run.parse_warnings,
        "parsed_swim_count": run.parsed_swim_count,
        "our_swim_count": run.our_swim_count,
        "other_swim_count": run.other_swim_count,
        "n_swimmers_ours": run.n_swimmers_ours,
        "pb_fetch_ok": run.pb_fetch_ok,
        "pb_fetch_failed": run.pb_fetch_failed,
        "pb_fetch_errors": run.pb_fetch_errors,
        "detector_summary": run.detector_summary,
        "self_check": run.self_check,
        "standards_meta": run.standards_meta,
        "cards": [c.to_dict() for c in run.cards],
        "trust": run.trust.to_dict() if run.trust else None,
        "ground_truth_report": run.ground_truth_report,
        "recognition_report": run.recognition_report,
        "recognition_error": run.recognition_error,
        "progress_log": run.progress_log,
        "error": run.error,
        # V6 PB audit (optional &mdash; None when fetch_pbs=False)
        "pb_audit": _serialise_pb_audit(getattr(run, "pb_audit", None)),
    }
    out = RUNS_DIR / f"{run.run_id}.json"
    out.write_text(json.dumps(payload, indent=2, default=str))

    n_cards = len(run.cards)
    n_queue = sum(1 for c in run.cards if c.bucket == "queue")
    # The real engine output is the V5 recognition count, not the legacy V4
    # cards (which the recognition-first pipeline leaves empty). Persist it so
    # Activity can surface "Achievements detected" instead of "Cards: 0".
    n_achievements = int(
        (getattr(run, "recognition_report", None) or {}).get("n_achievements", 0) or 0
    )
    meet_name = run.canonical_meet.name if run.canonical_meet else "(unknown)"
    status = "error" if run.error else "done"
    conn = _db()
    # Re-run detection: INSERT OR REPLACE rewrites the whole row, so carry the
    # content hash captured at queue time forward (else it would be lost), and
    # stamp the meet fingerprint now the canonical meet (name + date) is known.
    prior_hash = ""
    try:
        _hr = conn.execute("SELECT content_hash FROM runs WHERE id = ?", (run.run_id,)).fetchone()
        if _hr and _hr["content_hash"]:
            prior_hash = _hr["content_hash"]
    except Exception:  # noqa: BLE001
        prior_hash = ""
    meet_date = run.canonical_meet.start_date if run.canonical_meet else ""
    # Fingerprint on the REAL canonical name ('' when there's none) — never the
    # "(unknown)" display placeholder, which _normalize_meet_name reduces to
    # "unknown" and would make every unnamed/error run in an org share one
    # fingerprint and falsely badge each other as re-runs. '' → no fp.
    meet_fp = _meet_fingerprint(
        run.profile_id,
        run.canonical_meet.name if run.canonical_meet else "",
        meet_date,
    )
    conn.execute(
        """INSERT OR REPLACE INTO runs
           (id, created_at, finished_at, status, profile_id, meet_name,
            our_swims, n_cards, n_queue, n_achievements, error, file_name,
            content_hash, meet_fingerprint)
           VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
        (
            run.run_id,
            run.started_at,
            run.finished_at,
            status,
            run.profile_id,
            meet_name,
            run.our_swim_count,
            n_cards,
            n_queue,
            n_achievements,
            run.error,
            file_name,
            prior_hash,
            meet_fp,
        ),
    )
    conn.commit()
    conn.close()

    # W.1: log this run's swims into the athlete registry so identity,
    # milestones, consent and wraps accumulate. Best-effort and idempotent —
    # registry trouble must never fail a run.
    if run.profile_id and not run.error:
        try:
            from mediahub.athletes import sync_run_payload as _ath_sync

            _prof = None
            try:
                _prof = load_profile(run.profile_id)
            except Exception:
                _prof = None

            def _is_ours(code):
                return _prof.is_ours(code, None) if _prof else True

            _ath_sync(run.profile_id, payload, is_ours=_is_ours)
        except Exception:
            log.warning("athlete registry sync failed for run %s", run.run_id, exc_info=True)


def _load_run(run_id: str) -> Optional[dict]:
    p = RUNS_DIR / f"{run_id}.json"
    if not p.exists():
        return None
    try:
        return json.loads(p.read_text())
    except (json.JSONDecodeError, OSError, UnicodeDecodeError) as e:
        # A corrupted run JSON would otherwise 500 every route that
        # reads it (/review, /pack, /audit, /drafts/<pack_id>). Surface
        # "run not found" instead so the recovery_page renders cleanly;
        # the operator can find the offending file in the log.
        # UnicodeDecodeError covers files written in a non-UTF-8 encoding.
        log.warning("run %s on disk but unreadable: %s", run_id, e)
        return None


def _machine_readable_run(data: Optional[dict], run_id: str, *, max_achievements: int = 60) -> str:
    """UI2.8 — assemble the curated, machine-readable JSON shown inline on the
    review page's Recognition-summary card (rendered through the first-party
    Codeblock highlighter, ``code_highlight.code_block`` — the "raw parsed-data
    view" host surface the kit's Codeblock effect was waiting for).

    This is the *explainability* payload: meet context, the parsed/matched swim
    counts, and the ranked achievements the engine decided on — each with its
    confidence and suggested post type — in the same JSON shape the export and
    the downstream content steps consume. It is built from an explicit field
    **whitelist**, so no filesystem path under ``DATA_DIR``, provider key or
    internal blob can leak onto the page, and the achievements list is capped so
    a large meet can't render a multi-megabyte block. Never raises: on any error
    it returns a small, honest error document instead of breaking the review
    page.
    """
    try:
        data = data or {}
        meet = data.get("meet") or {}
        rr = data.get("recognition_report") or {}
        ranked = rr.get("ranked_achievements") or []
        total = len(ranked)
        shown = ranked[: max(0, int(max_achievements))]
        achievements = []
        for ra in shown:
            ra = ra if isinstance(ra, dict) else {}
            a = ra.get("achievement") or {}
            achievements.append(
                {
                    "rank": ra.get("rank"),
                    "type": a.get("type"),
                    "swimmer": a.get("swimmer_name"),
                    "event": a.get("event"),
                    "time": a.get("time") or a.get("swim_time") or a.get("result_time"),
                    "quality_band": ra.get("quality_band"),
                    "confidence": a.get("confidence_label"),
                    "suggested_post_type": ra.get("suggested_post_type"),
                }
            )
        doc = {
            "run_id": run_id,
            "meet": {
                "name": meet.get("name"),
                "date": meet.get("date"),
                "course": meet.get("course"),
                "venue": meet.get("venue"),
            },
            "counts": {
                "parsed_swims": data.get("parsed_swim_count"),
                "club_swims": data.get("our_swim_count"),
                "achievements": rr.get("n_achievements", total),
            },
            "achievements": achievements,
            "parse_warnings": [str(w) for w in (data.get("parse_warnings") or [])][:50],
        }
        if total > len(shown):
            doc["achievements_truncated"] = {"shown": len(shown), "total": total}
        return json.dumps(doc, indent=2, ensure_ascii=False, default=str)
    except Exception as exc:  # noqa: BLE001 — a preview must never 500 /review
        return json.dumps(
            {
                "error": "could not assemble machine-readable view",
                "detail": str(exc)[:200],
            },
            indent=2,
        )


def _run_owner_id(run_id: str, run_data: Optional[dict]) -> str:
    """Resolve the owning profile_id for a run.

    Prefers the JSON's stamped owner, falls back to the runs DB row so
    legacy files that pre-date the JSON-side stamp still attribute
    correctly. Returns "" when no owner is recorded anywhere.

    Sibling of ``_run_owner_profile_id``: that one is DB-only and
    distinguishes "no such run" (None) from "legacy untagged" ("") for
    the privacy-delete 404 contract. This one is fail-closed for the
    read/mutate isolation guard — it trusts the on-disk JSON first and
    collapses both "missing" and "legacy" to "".
    """
    if run_data:
        pid = (run_data.get("profile_id") or "").strip()
        if pid:
            return pid
    try:
        conn = _db()
        row = conn.execute("SELECT profile_id FROM runs WHERE id = ?", (run_id,)).fetchone()
        conn.close()
    except Exception:
        return ""
    if not row:
        return ""
    return (row["profile_id"] or "").strip()


def _can_access_run(run_id: str, run_data: Optional[dict], active_pid: Optional[str]) -> bool:
    """Tenant isolation guard for run-scoped routes.

    A run that records an owning ``profile_id`` is only accessible to
    that organisation's session — direct hits from another org return
    "not found" (per-route). Runs with no owner stamped (legacy /
    pre-multi-tenant) stay readable so we don't orphan historical data.

    ``active_pid`` of ``None`` means the deployment has no organisations
    configured at all (the org gate would have caught a real user before
    they reached any of these routes, so this code path only fires in
    test fixtures and pre-onboarding sandboxes). Treat that as a single-
    tenant sandbox where nothing to isolate exists yet.
    """
    if active_pid is None:
        return True
    owner = _run_owner_id(run_id, run_data)
    if not owner:
        return _ownerless_run_readable()
    return owner == active_pid


def _ownerless_run_readable() -> bool:
    """Shared-instance blast-radius rule for ownerless legacy runs (ADR-0014).

    "Runs with no owner stamped stay readable" was a single-org-box design
    choice; on a shared multi-tenant instance the same rule would mean
    "readable by any signed-in stranger". So: the env-gated operator and
    legacy *anonymous* sessions (single-instance / pilot mode, where the
    whole box is one trust domain) keep today's behaviour, while a
    signed-in regular account — an actor that exists only in the shared-
    instance world — is refused. Outside a request context (direct unit
    calls) this stays permissive, preserving the original contract.
    """
    try:
        from flask import has_request_context

        if not has_request_context():
            return True
        if _auth.is_dev_operator():
            return True
        return _auth.current_user_email() is None
    except Exception:
        return True


def _can_access_pack(rec: Optional[dict], active_pid: Optional[str]) -> bool:
    """Tenant isolation guard for stub draft packs.

    Mirrors the run guard: a pack with no owner stamped is legacy and
    accessible; otherwise only the owning org's session may read or
    mutate it. ``rec`` is the dict returned by ``stub_pack_store.load_pack``;
    callers pass ``None`` for "pack not found", which keeps the 404
    branch indistinguishable from a foreign-org probe.

    See ``_can_access_run`` for the ``active_pid is None`` sandbox rule.
    """
    if active_pid is None:
        return True
    if not rec:
        return True
    owner = (rec.get("profile_id") or "").strip()
    if not owner:
        return True
    return owner == active_pid


def _run_state(run_id: str) -> str:
    """Return one of ``unknown`` | ``in_progress`` | ``done``.

    "unknown" = no DB row and no JSON file. "in_progress" = DB row says
    queued/running OR an entry exists in the in-memory _active_runs dict.
    "done" = JSON file is on disk.

    Used by routes that depend on _load_run to render a friendly
    "still processing" page instead of a misleading 404 while the
    background worker is still running.
    """
    # JSON file present &rarr; run is fully persisted.
    if (RUNS_DIR / f"{run_id}.json").exists():
        return "done"
    # In-memory active dict &rarr; worker thread is alive in THIS process.
    # copy_value takes BoundedCache's own lock and returns a snapshot,
    # so we don't hold a lock across the downstream status check.
    active = _active_runs.copy_value(run_id)
    if active:
        status = (active.get("status") or "").lower()
        if status in ("queued", "running"):
            return "in_progress"
        if status == "error":
            return "done"  # error is "finished" &mdash; caller can read it from DB
    # Fall back to DB row (handles process restart between worker death
    # and persistence &mdash; rare, but possible).
    try:
        conn = _db()
        row = conn.execute("SELECT status FROM runs WHERE id = ?", (run_id,)).fetchone()
        conn.close()
    except Exception:
        return "unknown"
    if not row:
        return "unknown"
    status = (row["status"] or "").lower()
    if status in ("queued", "running"):
        return "in_progress"
    return "done"


_WF_STATUS_LABEL = {
    "queue": "In queue",
    "approved": "Approved",
    "rejected": "Rejected",
    "posted": "Posted",
    "edited": "Edited",
}


def _render_wf_actions(run_id: str, card_id: str, wf_status: str) -> str:
    """Render the per-card Approve / Re-queue action strip.

    Round-8: shared between /pack/<id>/grouped (where the audit found
    no approval primitive at all) and any other page that wants the
    same workflow control surface. The "Status" strap shows the
    current state and is updated optimistically by the global
    `[data-mh-wf]` click handler in _layout.

    Approve-only flow: a card is either in the queue or approved — there
    is no reject. Skipping a card simply leaves it in the queue. The
    approve button reads as an action still to take (outline) until the
    card is actually approved, then flips to a filled confirmation; the
    old always-green fill made every card look already approved.
    """
    status_key = (wf_status or "queue").lower()
    label = _WF_STATUS_LABEL.get(
        status_key, status_key.replace("_", " ").capitalize() or "In queue"
    )
    is_approved = status_key == "approved"

    # Visually de-emphasise the action that matches the current state
    # so the user sees "I'm already in this state".
    def _disabled_attrs(target: str) -> str:
        return (
            ' aria-pressed="true" style="opacity:0.55;cursor:default"'
            if status_key == target
            else ""
        )

    approve_cls = "btn mh-wf-approve is-on" if is_approved else "btn secondary mh-wf-approve"
    approve_label = "Approved ✓" if is_approved else "Approve"
    approve_pressed = ' aria-pressed="true"' if is_approved else ""
    _dl_link = ""
    if is_approved:
        _dl_url = url_for("api_card_download", run_id=run_id, card_id=card_id)
        _dl_link = (
            f'<a class="btn secondary" href="{_h(_dl_url)}"'
            f' style="font-size:12px;padding:4px 10px"'
            f' title="Download caption + visual as a .zip for manual posting">'
            f"&#x2B07; Download</a>"
        )
    return (
        f'<span class="strap" data-mh-wf-target="{_h(card_id)}" '
        f'data-mh-wf-state="{_h(status_key)}" style="padding:0">'
        f"<span data-mh-wf-label>{_h(label)}</span></span>"
        f'<button class="{approve_cls}" type="button" style="font-size:12px;padding:4px 10px"'
        f' data-mh-wf="approved" data-mh-run-id="{_h(run_id)}" data-mh-card-id="{_h(card_id)}"'
        f"{approve_pressed}"
        f' title="Mark this card approved — it moves into the content builder for captioning, graphics and scheduling.">{approve_label}</button>'
        f'<button class="btn secondary" type="button" style="font-size:12px;padding:4px 10px"'
        f' data-mh-wf="queue" data-mh-run-id="{_h(run_id)}" data-mh-card-id="{_h(card_id)}"'
        f"{_disabled_attrs('queue')}"
        f' title="Send back to the queue — undoes the approval.">Re-queue</button>'
        f"{_dl_link}"
    )


# UI 1.25 — Emoji reactions. A FIXED, server-controlled allowlist: these three
# are the only values that can ever be written to `card_reactions` or rendered
# into a reaction strip. Keeping the set closed means no user-supplied string
# reaches the DB or the HTML, so the feature carries no stored-XSS / data-bloat
# surface. The order here is the left-to-right render order of the buttons.
REACTION_EMOJI: tuple[str, ...] = ("👍", "❤️", "🔥")

# Row-growth brake: at most this many DISTINCT anonymous reactors per
# (run, card). reactor_id is client-minted (localStorage), so without a cap a
# scripted client could insert unbounded rows until run deletion. Far above
# any legitimate review-page audience.
REACTION_MAX_REACTORS_PER_CARD = 500


def _run_card_id_set(run_data: dict) -> set[str]:
    """Every card id this run's surfaces can emit reactions for.

    Ranked achievements contribute their ``swim_id`` (or the synthetic
    ``sp:type:event`` id the review page mints for aggregate rows) plus any
    ra-level ``id``; the legacy top-level ``cards`` list contributes
    ``swim_id``/``id``. Used to reject reactions on card ids that aren't
    part of the run at all.
    """
    out: set[str] = set()
    rr = (run_data or {}).get("recognition_report") or {}
    for ra in rr.get("ranked_achievements") or []:
        ach = ra.get("achievement") or {}
        sid = ach.get("swim_id")
        if sid:
            out.add(str(sid))
        else:
            out.add(f"sp:{ach.get('type', '')}:{ach.get('event', '')}")
        rid = ra.get("id")
        if rid:
            out.add(str(rid))
    for c in (run_data or {}).get("cards") or []:
        for k in ("swim_id", "id", "card_id"):
            v = c.get(k)
            if v:
                out.add(str(v))
    # The synthetic weekend-in-numbers card is built from the recognition
    # report at render time (recognition.weekend_in_numbers) — mirror its
    # id derivation so its reaction strip keeps working.
    if rr:
        out.add(f"weekend_in_numbers:{rr.get('meet_name', 'Meet')}")
    return out


def _reaction_counts_for_run(run_id: str) -> dict[str, dict[str, int]]:
    """Server-side reaction tally for a whole run: ``{card_id: {emoji: count}}``.

    One indexed query (the ``card_reactions`` PK covers ``WHERE run_id=?``), so a
    150-card review page tallies every reaction without a per-card round-trip.
    Best-effort: any DB error yields an empty map and the strips render at zero
    rather than 500-ing the page. Only allowlisted emoji are surfaced.
    """
    out: dict[str, dict[str, int]] = {}
    try:
        conn = _db()
        rows = conn.execute(
            "SELECT card_id, emoji, COUNT(*) AS n FROM card_reactions "
            "WHERE run_id=? GROUP BY card_id, emoji",
            (run_id,),
        ).fetchall()
        conn.close()
        for r in rows:
            if r["emoji"] in REACTION_EMOJI:
                out.setdefault(r["card_id"], {})[r["emoji"]] = r["n"]
    except Exception:
        pass
    return out


def _render_reactions(
    run_id: str, card_id: str, run_counts: dict[str, dict[str, int]] | None = None
) -> str:
    """Render the per-card emoji reaction strip (UI 1.25).

    The counts are tallied server-side and baked into the markup so the strip is
    correct on first paint and survives with JS disabled; the global reaction
    script in ``_layout`` then enhances it (toggle via fetch, no page reload, and
    a load-time highlight of *this* client's reactions). ``run_counts`` is the
    whole-run tally from :func:`_reaction_counts_for_run`, looked up per card so
    the page makes a single DB query rather than one per card. Every emoji comes
    from the fixed :data:`REACTION_EMOJI` allowlist — nothing user-supplied is
    rendered here.
    """
    counts = (run_counts or {}).get(card_id, {}) if run_counts else {}
    btns = []
    for emoji in REACTION_EMOJI:
        n = int(counts.get(emoji, 0) or 0)
        hidden = "" if n else " hidden"
        btns.append(
            f'<button type="button" class="mh-react-btn"'
            f' data-mh-react-emoji="{_h(emoji)}"'
            f' data-mh-react-run="{_h(run_id)}" data-mh-react-card="{_h(card_id)}"'
            f' aria-pressed="false" aria-label="React {_h(emoji)}" title="React {_h(emoji)}">'
            f'<span class="mh-react-emoji" aria-hidden="true">{emoji}</span>'
            f'<span class="mh-react-count" data-mh-react-count{hidden}>{n}</span>'
            f"</button>"
        )
    return (
        f'<div class="mh-reactions" data-mh-react-card="{_h(card_id)}"'
        f' role="group" aria-label="Quick reactions">' + "".join(btns) + "</div>"
    )


def _in_progress_page(run_id: str, return_url_endpoint: str = "review") -> str:
    """Return a friendly HTML page that auto-refreshes every 4 seconds."""
    try:
        retry_url = url_for(return_url_endpoint, run_id=run_id)
    except Exception:
        retry_url = ""
    status_url = url_for("api_status", run_id=run_id)
    return f"""
<div style="text-align:center;padding:64px 24px">
  <div class="mh-spinner" style="margin:0 auto 24px"></div>
  <h1 style="margin-bottom:10px">Still processing your run</h1>
  <p class="dim" style="max-width:480px;margin:0 auto 24px">
    The pipeline is reading the file, finding your athletes, and drafting
    captions. This usually takes 20&ndash;60 seconds. We&rsquo;ll auto-refresh
    when it&rsquo;s ready.
  </p>
  <a class="btn secondary" href="{retry_url or status_url}">Refresh now</a>
</div>
<script>
  setTimeout(function() {{ location.reload(); }}, 4000);
</script>
"""


def _delete_run(run_id: str) -> bool:
    p = RUNS_DIR / f"{run_id}.json"
    existed = p.exists()
    # Erasure cascade (UK GDPR Art. 17) — the stores OUTSIDE the run files:
    # per-run PB cache, caption memory, posting-log excerpts, motion cache.
    # Resolved before the JSON disappears (it carries the owning profile_id),
    # and never allowed to abort the file/DB deletion below.
    try:
        from mediahub.privacy import run_deletion_cascade  # noqa: PLC0415

        run_deletion_cascade(run_id, _run_owner_profile_id(run_id) or "")
    except Exception:  # noqa: BLE001
        log.warning("run deletion cascade failed for %s", run_id, exc_info=True)
    if existed:
        p.unlink()
    # Also drop any per-run sidecar directory (visuals, motion, briefs,
    # caption_history, etc.) that pipelines write under runs_v4/<run_id>/.
    # Leaving it behind defeats the user's intent when they hit "delete".
    side_dir = RUNS_DIR / run_id
    if side_dir.is_dir():
        try:
            import shutil  # noqa: PLC0415

            shutil.rmtree(side_dir, ignore_errors=True)
        except Exception:  # noqa: BLE001
            log.warning("could not remove run sidecar dir for %s", run_id)
    # Workflow approvals live in their own sidecar file, not the dir above.
    try:
        (RUNS_DIR / f"{run_id}__workflow.json").unlink(missing_ok=True)
    except Exception:  # noqa: BLE001
        pass
    # Derivative ("turn into") packs generated from this run.
    try:
        import shutil  # noqa: PLC0415

        shutil.rmtree(DATA_DIR / "turn_into_packs" / run_id, ignore_errors=True)
    except Exception:  # noqa: BLE001
        pass
    # The in-memory progress entry. Without this, deleted meets kept
    # surfacing in pickers and status pages until a process restart —
    # the "it didn't actually delete it from memory" complaint.
    try:
        with _active_lock:
            _active_runs.pop(run_id, None)
    except Exception:  # noqa: BLE001
        pass
    conn = _db()
    conn.execute("DELETE FROM runs WHERE id = ?", (run_id,))
    # UI 1.25 — cascade the run's emoji reactions so a deleted meet leaves no
    # orphan tally behind (and a recycled run id can never inherit stale counts).
    conn.execute("DELETE FROM card_reactions WHERE run_id = ?", (run_id,))
    conn.commit()
    conn.close()
    return existed


def _sweep_demo_staging_dirs(older_than_hours: int = 24) -> int:
    """Delete abandoned try-demo staging dirs under RUNS_DIR (PC.7).

    ``POST /try`` stages the upload (input.bin + demo_meta.json) at
    ``RUNS_DIR/<temp_id>/`` before the club picker; ``/try/start`` removes
    the dir when the run actually launches. A visitor who abandons the
    picker leaves the dir orphaned forever — it is never a registered run,
    so neither ``sweep_demo_runs`` (DB-driven) nor the retention purge
    (which scans ``runs_dir/*.json``) reaches it. Gate strictly on the
    ``demo_meta.json`` marker plus age so real run sidecar dirs are never
    touched. Returns the number of dirs removed.
    """
    import shutil  # noqa: PLC0415

    removed = 0
    cutoff = time.time() - older_than_hours * 3600
    try:
        candidates = list(RUNS_DIR.iterdir())
    except OSError:
        return 0
    for d in candidates:
        try:
            if not d.is_dir():
                continue
            marker = d / "demo_meta.json"
            if not marker.exists() or marker.stat().st_mtime >= cutoff:
                continue
            shutil.rmtree(d, ignore_errors=True)
            removed += 1
        except OSError:
            continue
    if removed:
        log.info("demo sweep: removed %d abandoned staging dir(s)", removed)
    return removed


def _run_owner_profile_id(run_id: str) -> Optional[str]:
    """Look up the owning profile_id for ``run_id`` from the DB.

    Returns the stored profile_id (possibly an empty string for legacy
    rows written before per-tenant tagging), or ``None`` when no such
    run exists.
    """
    try:
        conn = _db()
        row = conn.execute("SELECT profile_id FROM runs WHERE id = ?", (run_id,)).fetchone()
        conn.close()
    except Exception:  # noqa: BLE001
        return None
    if row is None:
        return None
    pid = row[0] if not hasattr(row, "keys") else row["profile_id"]
    return pid or ""


# ---------------------------------------------------------------------
# Run de-duplication — "have we processed this meet before?"
# ---------------------------------------------------------------------
# Two independent signals decide whether a new run repeats an existing one,
# scoped to the owning organisation:
#   * content_hash    — SHA-256 of the uploaded bytes. Catches an EXACT re-run
#                       of the same file/source, regardless of meet metadata.
#   * meet_fingerprint — org + normalised meet name + meet date (day precision).
#                       Catches the SAME meet processed through a DIFFERENT tool
#                       or file format, where the bytes differ but it's the same
#                       competition. Deliberately fuzzy on the name (punctuation
#                       and case are stripped) so "County Champs!" fingerprints
#                       the same as "county champs".
# Both are persisted on the runs row (see _start_run / _persist_run) so the
# upload step can WARN before a re-run and the listings can BADGE repeats. We
# never block — the human decides (MediaHub never silently guesses).


def _content_hash(file_bytes: bytes) -> str:
    """SHA-256 of an uploaded file's bytes; '' when it can't be computed."""
    try:
        return hashlib.sha256(file_bytes).hexdigest()
    except Exception:  # noqa: BLE001
        return ""


_MEET_NAME_NOISE = re.compile(r"[^a-z0-9]+")


def _normalize_meet_name(name: str) -> str:
    """Lower-case, strip punctuation, collapse whitespace — so trivially
    different spellings of the same meet name fingerprint identically."""
    s = _MEET_NAME_NOISE.sub(" ", (name or "").strip().lower())
    return " ".join(s.split())


def _meet_fingerprint(
    profile_id: Optional[str], meet_name: Optional[str], meet_date: Optional[str]
) -> str:
    """Stable identity for 'the same meet': org + normalised name + day.

    Returns '' when there is no usable meet name (a meet we can't name can't be
    fingerprinted — those runs simply never match on the fuzzy signal, though
    they can still match an exact re-run by content hash).
    """
    norm = _normalize_meet_name(meet_name or "")
    if not norm:
        return ""
    day = str(meet_date or "").strip()[:10]
    basis = f"{(profile_id or '').strip()}|{norm}|{day}"
    # SHA-256 (not SHA-1) — this is just a stable identity key, never a security
    # primitive, but SHA-256 keeps the static-analysis gate (bandit B324) clean.
    return hashlib.sha256(basis.encode("utf-8")).hexdigest()[:16]


def _find_duplicate_run(
    profile_id: Optional[str],
    content_hash: str,
    meet_fingerprint: str,
    *,
    exclude_run_id: Optional[str] = None,
) -> Optional[dict]:
    """The most recent FINISHED run in this org that repeats either signal,
    or None. Used by the upload step to warn before a re-run lands."""
    if not profile_id:
        return None
    clauses: list[str] = []
    params: list = []
    if content_hash:
        clauses.append("content_hash = ?")
        params.append(content_hash)
    if meet_fingerprint:
        clauses.append("meet_fingerprint = ?")
        params.append(meet_fingerprint)
    if not clauses:
        return None
    sql = (
        "SELECT id, meet_name, created_at, content_hash, meet_fingerprint, our_swims "
        "FROM runs WHERE profile_id = ? AND status = 'done' AND (" + " OR ".join(clauses) + ") "
    )
    args: list = [profile_id, *params]
    if exclude_run_id:
        sql += "AND id != ? "
        args.append(exclude_run_id)
    sql += "ORDER BY created_at DESC LIMIT 1"
    try:
        conn = _db()
        row = conn.execute(sql, args).fetchone()
        conn.close()
    except Exception:  # noqa: BLE001
        return None
    if not row:
        return None
    return {
        "run_id": row["id"],
        "meet_name": row["meet_name"] or "",
        "created_at": row["created_at"] or "",
        "our_swims": row["our_swims"] or 0,
        "exact": bool(content_hash and row["content_hash"] == content_hash),
    }


def _duplicate_map(rows) -> dict:
    """Map run_id -> {original_id, original_date, count} for every run that
    repeats a meet already seen in an EARLIER run within ``rows``.

    Two runs are 'the same meet' when they share a content hash OR a meet
    fingerprint; the relation is transitive (union-find), so a PDF uploaded
    once and later re-fetched from a link all land in one group. The OLDEST
    run in a group is the original and is never badged; every newer run points
    back to it. ``rows`` is the DB result set (sqlite3.Row); missing columns on
    legacy rows are tolerated and simply never match.
    """
    parent: dict = {}

    def find(x):
        parent.setdefault(x, x)
        root = x
        while parent[root] != root:
            root = parent[root]
        while parent[x] != root:
            parent[x], x = root, parent[x]
        return root

    def union(a, b):
        ra, rb = find(a), find(b)
        if ra != rb:
            parent[ra] = rb

    def _col(r, name):
        try:
            return (r[name] if name in r.keys() else "") or ""
        except Exception:  # noqa: BLE001
            return ""

    by_fp: dict = {}
    by_hash: dict = {}
    order: list = []
    rowmap: dict = {}
    for r in rows:
        rid = r["id"]
        order.append(rid)
        rowmap[rid] = r
        find(rid)
        fp = _col(r, "meet_fingerprint")
        ch = _col(r, "content_hash")
        if fp:
            if fp in by_fp:
                union(rid, by_fp[fp])
            else:
                by_fp[fp] = rid
        if ch:
            if ch in by_hash:
                union(rid, by_hash[ch])
            else:
                by_hash[ch] = rid

    groups: dict = {}
    for rid in order:
        groups.setdefault(find(rid), []).append(rid)

    dup: dict = {}
    for members in groups.values():
        if len(members) < 2:
            continue
        members_sorted = sorted(members, key=lambda i: rowmap[i]["created_at"] or "")
        oldest = members_sorted[0]
        for rid in members_sorted[1:]:
            dup[rid] = {
                "original_id": oldest,
                "original_date": (rowmap[oldest]["created_at"] or "")[:10],
                "count": len(members),
            }
    return dup


def _org_duplicate_map(profile_id: Optional[str], limit: int = 500) -> dict:
    """Duplicate map across ALL of an org's runs, independent of any view
    filter/limit — so a re-run is still badged when the original is hidden by a
    status filter or has scrolled past the displayed page. Fail-soft to {}."""
    if not profile_id:
        return {}
    try:
        conn = _db()
        rows = conn.execute(
            "SELECT id, created_at, content_hash, meet_fingerprint "
            "FROM runs WHERE profile_id = ? ORDER BY created_at DESC LIMIT ?",
            (profile_id, limit),
        ).fetchall()
        conn.close()
    except Exception:  # noqa: BLE001
        return {}
    return _duplicate_map(rows)


def _dup_badge_html(dup_entry: Optional[dict]) -> str:
    """A compact 'Re-run' chip linking back to the original run, or '' when this
    run isn't a repeat. Communicates that the same meet was processed before —
    used on Activity and My Season. Inline-styled (no dedicated .tag class)."""
    if not dup_entry:
        return ""
    original_id = dup_entry.get("original_id")
    when = (dup_entry.get("original_date") or "").strip()
    title = "Same meet already processed" + (f" on {when}" if when else "")
    title += " — open the original"
    style = (
        "display:inline-flex;align-items:center;margin-left:8px;padding:1px 8px;"
        "border-radius:999px;font-size:11px;font-weight:600;line-height:1.6;"
        "border:1px solid var(--warn);color:var(--warn);background:var(--warn-bg);"
        "text-decoration:none;vertical-align:middle;white-space:nowrap"
    )
    if original_id:
        href = url_for("review", run_id=original_id)
        return f'<a href="{href}" title="{_h(title)}" style="{style}">Re-run</a>'
    return f'<span title="{_h(title)}" style="{style}">Re-run</span>'


# Shared client JS for run-row deletion + bulk clear. Bound once (delegated),
# so it covers the per-run "Delete" forms (class ``mh-run-delete`` — removes the
# row in place via fetch) AND a "Clear all runs" form (class
# ``mh-clear-all-runs`` — confirms with the count, then reloads). Reused
# verbatim on Activity, My Season and the Settings activity table; no-JS falls
# back to the plain form POST (the route honours ``next`` / redirects).
_RUN_DELETE_JS = """
<script>
(function(){
  if (window.__mhRunDeleteBound) return; window.__mhRunDeleteBound = true;
  function esc(v){ return (window.CSS && CSS.escape) ? CSS.escape(v) : String(v).replace(/["\\\\]/g,'\\\\$&'); }
  document.addEventListener('submit', function(e){
    var form = e.target;
    if (!form || !form.classList) return;
    if (form.classList.contains('mh-run-delete')) {
      e.preventDefault();
      if (!window.confirm('Delete these results? This cannot be undone.')) return;
      var rid = form.getAttribute('data-run-id');
      var btn = form.querySelector('button');
      if (btn) btn.disabled = true;
      // Send the form body so the auto-injected csrf_token rides along (the
      // delete route is not CSRF-exempt); X-Requested-With asks for JSON back.
      fetch(form.action, {method:'POST', headers:{'X-Requested-With':'XMLHttpRequest'}, body:new FormData(form)})
        .then(function(r){ return r.json().catch(function(){ return {}; }); })
        .then(function(j){
          if (j && j.ok) {
            var row = document.querySelector('[data-run-row="'+esc(rid)+'"]');
            var err = document.querySelector('[data-run-err="'+esc(rid)+'"]');
            if (err && err.parentNode) err.parentNode.removeChild(err);
            if (row && row.parentNode) row.parentNode.removeChild(row);
            if (window.MH && MH.toast) MH.toast('Run deleted.', 'success');
          } else {
            if (btn) btn.disabled = false;
            if (window.MH && MH.toast) MH.toast('Could not delete — reload and try again.', 'error');
          }
        })
        .catch(function(){
          if (btn) btn.disabled = false;
          if (window.MH && MH.toast) MH.toast('Could not delete — reload and try again.', 'error');
        });
    } else if (form.classList.contains('mh-clear-all-runs')) {
      e.preventDefault();
      var n = form.getAttribute('data-count') || '';
      var msg = n
        ? ('Permanently delete all ' + n + ' runs for this organisation? This cannot be undone.')
        : 'Permanently delete every run for this organisation? This cannot be undone.';
      if (!window.confirm(msg)) return;
      var cbtn = form.querySelector('button');
      if (cbtn) cbtn.disabled = true;
      fetch(form.action, {method:'POST', headers:{'X-Requested-With':'XMLHttpRequest'}, body:new FormData(form)})
        .then(function(r){ return r.json().catch(function(){ return {}; }); })
        .then(function(j){
          if (j && j.ok) {
            if (window.MH && MH.toast) MH.toast((j.deleted || 0) + ' runs deleted.', 'success');
            window.location.reload();
          } else {
            if (cbtn) cbtn.disabled = false;
            if (window.MH && MH.toast) MH.toast('Could not delete — reload and try again.', 'error');
          }
        })
        .catch(function(){
          if (cbtn) cbtn.disabled = false;
          if (window.MH && MH.toast) MH.toast('Could not delete — reload and try again.', 'error');
        });
    }
  }, false);
})();
</script>"""


def _translatable_langs_js() -> str:
    """``window.MH_TR_LANGS`` — the static [code, label] list the review/pack
    caption toolbar offers as on-demand translation targets (1.24). Excludes
    bare English (the usual source — a no-op) but offers the two English
    regional variants plus every other registry language. Static (registry-
    derived), so it ships inside the shared caption JS rather than per page."""
    from mediahub.web.languages import single_language_options as _single_lang_opts

    langs = [[c, lbl] for (c, lbl) in _single_lang_opts() if c != "en"]
    langs += [
        ["en-GB", "English (UK spelling)"],
        ["en-US", "English (US spelling)"],
    ]
    return "<script>window.MH_TR_LANGS = " + json.dumps(langs) + ";</script>\n"


def _card_creative_js() -> str:
    """Shared client JS for the per-card creative toolbar: live caption
    tone tabs, create-graphic, motion render, and the 3-variant graphic
    picker. Lives on the Content builder page (post-approval). The host
    page must define `WF_API_BASE` and `window._API_BASE` before this
    block so caption edits and visual picks can persist."""
    return (
        _translatable_langs_js()
        + """
<script>
// V8: Live caption tone toggle + regenerate
// switchTone() kept for backwards compat (content pack, other pages).
function switchTone(btn) {
  var cardId = btn.dataset.card;
  var newTone = btn.dataset.tone;
  document.querySelectorAll('.tone-tab[data-card="' + cardId + '"]').forEach(function(tab) {
    var isActive = tab.dataset.tone === newTone;
    tab.classList.toggle('active', isActive);
    if (isActive) {
      tab.style.background = tab.classList.contains('tone-tab-ai') ? 'color-mix(in oklab, var(--lane) 15%, transparent)' : 'color-mix(in oklab, var(--lane) 15%, transparent)';
      tab.style.color = tab.classList.contains('tone-tab-ai') ? 'var(--lane)' : 'var(--accent)';
    } else {
      tab.style.background = 'transparent';
      tab.style.color = 'var(--ink-dim)';
    }
  });
  document.querySelectorAll('.tone-panel[data-card="' + cardId + '"]').forEach(function(panel) {
    panel.style.display = panel.dataset.tone === newTone ? '' : 'none';
  });
}

// V8: switchToneLive &mdash; fetches caption from API on click.
// AI tab: always fetches fresh. Warm/Hype/Precise tabs: cached for the session.
// "&#x21BA; Regenerate" always forces a fresh fetch via regenerateCaption().
var _captionCache = {};
var _AI_TONE_KEYS = {'ai': true};  // other tones are cached after first gen

function switchToneLive(btn, captionUrl, cardId) {
  var newTone = btn.dataset.tone;
  var isAiTone = !!_AI_TONE_KEYS[newTone];

  // Update tab styles
  document.querySelectorAll('.tone-tab[data-card="' + cardId + '"]').forEach(function(tab) {
    var isActive = tab.dataset.tone === newTone;
    tab.classList.toggle('active', isActive);
    if (isActive) {
      tab.style.background = tab.classList.contains('tone-tab-ai') ? 'color-mix(in oklab, var(--lane) 15%, transparent)' : 'color-mix(in oklab, var(--lane) 15%, transparent)';
      tab.style.color = tab.classList.contains('tone-tab-ai') ? 'var(--lane)' : 'var(--accent)';
      tab.style.fontWeight = '600';
    } else {
      tab.style.background = 'transparent';
      tab.style.color = 'var(--ink-dim)';
      tab.style.fontWeight = '400';
    }
  });

  // Show active panel, hide others
  document.querySelectorAll('.tone-panel[data-card="' + cardId + '"]').forEach(function(panel) {
    panel.style.display = panel.dataset.tone === newTone ? '' : 'none';
  });

  var panel = document.querySelector('.tone-panel[data-tone="' + newTone + '"][data-card="' + cardId + '"]');
  if (!panel) { return; }

  var cacheKey = cardId + '|' + newTone;

  // AI tab: always fetch fresh &mdash; never use cache.
  // Named tones (warm/hype/precise): use session cache after first generation.
  if (!isAiTone && _captionCache[cacheKey]) {
    _renderCaption(panel, _captionCache[cacheKey]);
    return;
  }

  // All panels start with a placeholder &mdash; fetch if placeholder still present
  // (or if AI tone, always fetch).
  var placeholder = panel.querySelector('.caption-placeholder');
  if (!isAiTone && !placeholder) {
    return;  // already generated; cache hit handled above
  }

  _fetchCaption(captionUrl, newTone, panel, cacheKey, isAiTone, cardId);
}

function _fetchCaption(captionUrl, tone, panel, cacheKey, isAi, cardId) {
  var captionDiv = panel.querySelector('.caption-text');
  var textarea = panel.querySelector('.caption-textarea');
  if (captionDiv) {
    captionDiv.innerHTML = '<span style="color:var(--ink-muted);font-style:italic">Generating&hellip;<span class="spin" style="display:inline-block;margin-left:6px;animation:spin 0.8s linear infinite">&#x27F3;</span></span>';
  }
  // The tone rides in the query string; the JSON content-type is what keeps
  // this same-origin write CSRF-exempt (mirrors every other fetch on the
  // page). Without it the server 403s with {"error":"csrf"} and the caption
  // silently renders blank. r.ok / r.status are threaded onto the parsed
  // body so the catch-all error branch below can never fall through to an
  // empty caption.
  fetch(captionUrl + '?tone=' + encodeURIComponent(tone),
        {method: 'POST', headers: {'Content-Type': 'application/json'}, body: '{}'})
    .then(function(r) { return r.json().then(function(j) { j.__ok = r.ok; j.__status = r.status; return j; }); })
    .then(function(j) {
      var text = j.caption || '';
      var ts = j.generated_at ? new Date(j.generated_at).toLocaleTimeString() : '';
      var fallbackNote = '';
      // Distinguish transient (rate-limit / network blip) from terminal
      // (no key configured). Transient errors must NOT flip the dot red
      // permanently — the AI itself is still set up correctly, the
      // request just needs a retry.
      var isTransient = (j.error === 'transient' || (j.live === true && !text));
      var isTerminal = (j.live === false && j.error !== 'transient');
      if (isTerminal) {
        if (captionDiv) {
          captionDiv.innerHTML = '<div style="padding:10px;border:1px dashed var(--border);border-radius:6px;background:rgba(255,174,59,0.06);color:var(--ink-muted)">'
            + '<div style="font-weight:600;color:var(--ink);margin-bottom:4px">&#x2726; AI captions are unavailable</div>'
            + '<div style="font-size:11px;line-height:1.5">' + (j.message || 'Contact your administrator to enable AI.') + '</div>'
            + '</div>';
        }
        document.querySelectorAll('.ai-status-dot').forEach(function(d){ d.style.background='#ff5d6c'; });
        return;
      }
      if (isTransient) {
        if (captionDiv) {
          captionDiv.innerHTML = '<div style="padding:10px;border:1px solid color-mix(in oklab, var(--lane) 20%, transparent);border-radius:6px;background:color-mix(in oklab, var(--lane) 4%, transparent)">'
            + '<div style="font-weight:600;color:var(--accent);margin-bottom:4px">&#x21BB; Briefly busy &mdash; try again</div>'
            + '<div style="font-size:11px;line-height:1.5;color:var(--ink-dim)">' + (j.message || 'Wait a few seconds and click regenerate again.') + '</div>'
            + '</div>';
        }
        // Keep the dot green — provider is reachable, just throttled.
        return;
      }
      if (j.fallback && j.fallback_voice) {
        fallbackNote = '<div style="margin-top:4px;font-size:10px;color:var(--warn);padding:4px 8px;background:rgba(245,158,11,0.08);border-radius:4px">&#x26A0; AI generation unavailable, using ' + j.fallback_voice + '</div>';
      }
      // Render the caption + a variant picker if we got multiple back.
      var variants = (j.variants && j.variants.length) ? j.variants : [text];
      var safeText = function(t){ return (t||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); };
      // Catch-all: anything the transient/terminal branches above did not
      // classify — a CSRF 403 ({"error":"csrf"}), an unexpected 4xx/5xx, or
      // an empty body with no variants — must surface a retry, never a blank
      // caption. This is the last line of defence before the render.
      if (j.__ok === false || j.error || (!text && !(j.variants && j.variants.length))) {
        if (captionDiv) {
          captionDiv.innerHTML = '<div style="padding:10px;border:1px solid var(--border);border-radius:6px;background:rgba(255,93,108,0.06)">'
            + '<div style="font-weight:600;color:var(--ink);margin-bottom:4px">&#x21BB; Couldn&rsquo;t generate a caption</div>'
            + '<div style="font-size:11px;line-height:1.5;color:var(--ink-dim)">' + safeText(j.message || 'Something went wrong. Pick a tone again to retry.') + '</div>'
            + '</div>';
        }
        return;
      }
      function _renderActive(idx, reveal) {
        var active = variants[idx] || text;
        if (captionDiv) {
          var pickerHtml = '';
          if (variants.length > 1) {
            var pills = variants.map(function(_, i) {
              var sel = (i === idx);
              return '<button type="button" class="cap-var-pill" data-idx="' + i + '" style="font-size:10px;padding:3px 9px;border-radius:999px;border:1px solid ' + (sel ? 'var(--accent)' : 'var(--border)') + ';background:' + (sel ? 'color-mix(in oklab, var(--lane) 14%, transparent)' : 'transparent') + ';color:' + (sel ? 'var(--accent)' : 'var(--ink-dim)') + ';cursor:pointer;font-family:inherit;margin-right:4px">v' + (i+1) + '</button>';
            }).join('');
            pickerHtml = '<div style="display:flex;gap:4px;align-items:center;margin-bottom:6px"><span style="font-size:10px;color:var(--ink-muted);text-transform:uppercase;letter-spacing:0.5px;margin-right:4px">Variants</span>' + pills + '</div>';
          }
          captionDiv.innerHTML = pickerHtml + '<span class="mh-cap-body" style="white-space:pre-wrap" dir="auto">' + safeText(active) + '</span>' + fallbackNote;
          captionDiv.querySelectorAll('.cap-var-pill').forEach(function(btn) {
            btn.addEventListener('click', function() { _renderActive(parseInt(btn.dataset.idx, 10) || 0); });
          });
          // UI2.7 — word-by-word "AI is writing" reveal, on the *read-only*
          // caption preview only and only on a fresh generation (reveal=true);
          // variant-pill swaps re-render plainly. The editable textarea below
          // is set with the plain value and never typed on.
          if (reveal && window.MH && typeof MH.typeOn === 'function') {
            var capBody = captionDiv.querySelector('.mh-cap-body');
            if (capBody) MH.typeOn(capBody);
          }
        }
        if (textarea) { textarea.value = active; }
      }
      _renderActive(0, true);
      // W.13 (generalised): bilingual workspaces get the side-by-side
      // translation (Cymraeg, Gaeilge, 中文, …) beside the English caption
      // so both are approved in one pass. Label + text direction come from
      // the server's language registry, so new languages need no JS change.
      if (captionDiv && j.caption_secondary) {
        var secBox = document.createElement('div');
        secBox.style.cssText = 'margin-top:8px;padding:8px 10px;border:1px solid var(--border);border-radius:6px;background:color-mix(in oklab, var(--lane) 3%, transparent)';
        secBox.innerHTML = '<div style="font-size:10px;color:var(--ink-muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px">' + safeText(j.secondary_language_label || 'Translation') + '</div>'
          + '<span style="white-space:pre-wrap" dir="' + (j.secondary_rtl ? 'rtl' : 'auto') + '">' + safeText(j.caption_secondary) + '</span>';
        captionDiv.appendChild(secBox);
      }
      // 1.24 localisation: on-demand "translate this caption" into any
      // supported language, shown as a bilingual pair and SAVED with the card
      // so one approval covers both. Only appears where the page provided the
      // language list (review). Reuses the secBox look.
      if (captionDiv && j.live && window.MH_TR_LANGS && window.MH_TR_LANGS.length) {
        var trWrap = document.createElement('div');
        trWrap.style.cssText = 'margin-top:8px;display:flex;gap:6px;align-items:center;flex-wrap:wrap';
        var trSel = document.createElement('select');
        trSel.className = 'tr-lang-select';
        trSel.style.cssText = 'font-size:11px;padding:4px 8px;background:transparent;border:1px solid var(--border);border-radius:6px;color:var(--ink)';
        var optsHtml = '<option value="">Translate to…</option>';
        window.MH_TR_LANGS.forEach(function(o){ optsHtml += '<option value="' + o[0] + '">' + safeText(o[1]) + '</option>'; });
        trSel.innerHTML = optsHtml;
        var trBtn = document.createElement('button');
        trBtn.type = 'button'; trBtn.className = 'btn secondary tr-go';
        trBtn.style.cssText = 'font-size:11px;padding:4px 10px';
        trBtn.textContent = 'Translate';
        var trOut = document.createElement('div'); trOut.className = 'tr-out';
        trWrap.appendChild(trSel); trWrap.appendChild(trBtn);
        captionDiv.appendChild(trWrap); captionDiv.appendChild(trOut);
        trBtn.addEventListener('click', function(){
          var lang = trSel.value; if (!lang) return;
          var capNow = (textarea && textarea.value) || variants[0] || text || '';
          if (!capNow.trim()) { return; }
          var runBase = captionUrl.split('/swim/')[0];
          var trUrl = runBase + '/card/' + encodeURIComponent(cardId) + '/translate';
          var bodyObj = { lang: lang, caption: capNow };
          var altEl = captionDiv.querySelector('.alt-text-input');
          if (altEl && altEl.value) { bodyObj.alt_text = altEl.value; }
          trBtn.disabled = true; trBtn.textContent = 'Translating…';
          fetch(trUrl, {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify(bodyObj)})
            .then(function(r){ return r.json().then(function(jj){ return {ok:r.ok, j:jj}; }); })
            .then(function(res){
              trBtn.disabled = false; trBtn.textContent = 'Translate';
              var jj = res.j || {};
              if (!res.ok || jj.error) {
                trOut.innerHTML = '<div style="font-size:10px;color:var(--warn);margin-top:4px">' + safeText(jj.message || 'Translation unavailable.') + '</div>';
                return;
              }
              var s = (jj.slots && jj.slots.caption) || '';
              var lbl = jj.language_label || lang;
              var warnHtml = (jj.warnings && jj.warnings.length) ? '<div style="font-size:10px;color:var(--warn);margin-top:4px">⚠ ' + safeText(jj.warnings.join('; ')) + '</div>' : '';
              trOut.innerHTML = '<div style="margin-top:8px;padding:8px 10px;border:1px solid var(--border);border-radius:6px;background:color-mix(in oklab, var(--lane) 3%, transparent)">'
                + '<div style="font-size:10px;color:var(--ink-muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px">' + safeText(lbl) + ' · saved with this card</div>'
                + '<span style="white-space:pre-wrap" dir="' + (jj.rtl ? 'rtl' : 'auto') + '">' + safeText(s) + '</span>' + warnHtml + '</div>';
            })
            .catch(function(){ trBtn.disabled = false; trBtn.textContent = 'Translate'; trOut.innerHTML = '<div style="font-size:10px;color:var(--warn);margin-top:4px">Translation failed — try again.</div>'; });
        });
      }
      // W.11: result-grounded alt text — editable, saved with the card so
      // every export/publish surface carries what the approver saw.
      if (captionDiv && typeof j.alt_text === 'string' && j.live) {
        var altWrap = document.createElement('div');
        altWrap.style.cssText = 'margin-top:8px;display:flex;gap:6px;align-items:center';
        altWrap.innerHTML = '<span style="font-size:10px;color:var(--ink-muted);text-transform:uppercase;letter-spacing:0.5px;white-space:nowrap" title="Read aloud by screen readers — describes the result on the image">Alt text</span>'
          + '<input type="text" class="alt-text-input" maxlength="200" value="' + safeText(j.alt_text).replace(/"/g,'&quot;') + '" style="flex:1;font-size:12px;padding:5px 8px;background:transparent;border:1px solid var(--border);border-radius:6px;color:var(--ink)"/>'
          + '<button type="button" class="btn secondary alt-text-save" style="font-size:11px;padding:4px 10px">Save</button>';
        captionDiv.appendChild(altWrap);
        var altInput = altWrap.querySelector('.alt-text-input');
        var altSave = altWrap.querySelector('.alt-text-save');
        altSave.addEventListener('click', function() {
          if (typeof WF_API_BASE === 'undefined') { altSave.textContent = 'n/a'; return; }
          fetch(WF_API_BASE + encodeURIComponent(cardId), {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({action: 'set_edits', edits: {alt_text: altInput.value}})
          }).then(function(r){ return r.json(); }).then(function() {
            altSave.textContent = 'Saved';
            setTimeout(function(){ altSave.textContent = 'Save'; }, 1500);
          }).catch(function(){ altSave.textContent = 'Retry'; });
        });
      }
      // Update timestamp
      var picker = panel.closest('.tone-picker');
      if (picker) {
        var tsEl = picker.querySelector('.caption-timestamp');
        if (tsEl && ts) tsEl.textContent = 'regenerated just now \u00b7 ' + ts;
      }
      // Cache named-tone results for this session (not the AI tab &mdash; always fresh)
      if (!isAi) { _captionCache[cacheKey] = {text: text, variants: variants}; }
    })
    .catch(function(err) {
      if (captionDiv) {
        captionDiv.innerHTML = '<span style="color:var(--ink-muted);font-style:italic">Error generating caption. Please try again.</span>';
      }
    });
}

function _renderCaption(panel, cached) {
  var captionDiv = panel.querySelector('.caption-text');
  var textarea = panel.querySelector('.caption-textarea');
  if (captionDiv && cached.text) {
    captionDiv.innerHTML = '<span style="white-space:pre-wrap">' + cached.text.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</span>';
  }
  if (textarea && cached.text) {
    textarea.value = cached.text;
  }
}

function regenerateCaption(btn, captionUrl, cardId) {
  // Find the active panel and force a fresh re-fetch (clears session cache).
  var activeToneTab = document.querySelector('.tone-tab.active[data-card="' + cardId + '"]');
  if (!activeToneTab) { return; }
  var tone = activeToneTab.dataset.tone;
  var cacheKey = cardId + '|' + tone;
  delete _captionCache[cacheKey];  // force fresh generation
  var panel = document.querySelector('.tone-panel[data-tone="' + tone + '"][data-card="' + cardId + '"]');
  if (!panel) { return; }
  var isAiTone = !!_AI_TONE_KEYS[tone];
  _fetchCaption(captionUrl, tone, panel, cacheKey, isAiTone, cardId);
}


function copyActiveTone(btn, cardId) {
  // Find the active tone panel
  var activePanel = document.querySelector('.tone-panel[data-card="' + cardId + '"]:not([style*="none"])');
  if (!activePanel) {
    activePanel = document.querySelector('.tone-panel[data-card="' + cardId + '"]');
  }
  if (!activePanel) { return; }
  // Get text from caption-textarea or caption-text
  var ta = activePanel.querySelector('.caption-textarea');
  var textEl = activePanel.querySelector('.caption-text');
  var text = (ta && ta.value) ? ta.value : (textEl ? textEl.textContent : '');
  // Also check old-style tone-text-ID elements
  if (!text) {
    var activeTone = activePanel.dataset.tone;
    var oldTa = document.getElementById('tone-text-' + cardId + '-' + activeTone);
    if (oldTa) text = oldTa.value;
  }
  if (!text) { return; }
  navigator.clipboard.writeText(text).then(function() {
    var orig = btn.textContent;
    btn.textContent = 'Copied!';
    setTimeout(function() { btn.textContent = orig; }, 1500);
  }).catch(function() {
    var tempTa = document.createElement('textarea');
    tempTa.value = text;
    document.body.appendChild(tempTa);
    tempTa.select();
    document.execCommand('copy');
    document.body.removeChild(tempTa);
    var orig = btn.textContent;
    btn.textContent = 'Copied!';
    setTimeout(function() { btn.textContent = orig; }, 1500);
  });
}

// Inline caption assist — revise the ACTIVE tone's caption in place. Never
// posts/approves; it only rewrites wording via /caption/assist and drops the
// result back into the editable textarea for the human to review.
function captionAssistToggle(btn, cardId) {
  var picker = document.getElementById('wf-' + cardId);
  if (!picker) return;
  var row = picker.querySelector('.assist-row[data-card="' + cardId + '"]');
  if (!row) return;
  row.style.display = (row.style.display === 'block') ? 'none' : 'block';
}
function _assistActivePanel(cardId) {
  var sel = '.tone-panel[data-card="' + cardId + '"]';
  return document.querySelector(sel + ':not([style*="none"])') || document.querySelector(sel);
}
function captionAssistRun(btn, cardId, transform) {
  var picker = document.getElementById('wf-' + cardId);
  if (!picker) return;
  var row = picker.querySelector('.assist-row[data-card="' + cardId + '"]');
  var statusEl = row ? row.querySelector('.assist-status') : null;
  var panel = _assistActivePanel(cardId);
  if (!panel) return;
  var ta = panel.querySelector('.caption-textarea');
  var textEl = panel.querySelector('.caption-text');
  var current = (ta && ta.value) ? ta.value : (textEl ? textEl.textContent.trim() : '');
  if (!current) { if (statusEl) statusEl.textContent = 'Generate a caption first, then assist it.'; return; }
  var tone = panel.dataset.tone || 'warm-club';
  var custom = '';
  if (transform === 'custom') {
    var input = row ? row.querySelector('.assist-custom') : null;
    custom = input ? input.value.trim() : '';
    if (!custom) { if (statusEl) statusEl.textContent = 'Type a change first.'; return; }
  }
  var captionUrl = picker.dataset.captionUrl;
  if (!captionUrl) return;
  if (statusEl) statusEl.textContent = 'Revising…';
  fetch(captionUrl + '/assist', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({current_caption: current, transform: transform, custom: custom, tone: tone})
  }).then(function(r){ return r.json().then(function(j){ return {s:r.status, j:j}; }); })
    .then(function(o){
      var j = o.j || {};
      if (j.error || !j.caption) {
        if (statusEl) statusEl.textContent = j.message || 'Could not revise the caption.';
        return;
      }
      if (textEl) textEl.textContent = j.caption;
      if (ta) ta.value = j.caption;
      if (statusEl) statusEl.textContent = 'Revised — review and edit as you like.';
    }).catch(function(){ if (statusEl) statusEl.textContent = 'Network error — try again.'; });
}

// V8: Lazy visual generation. Cached per (card, format) within session.
var _visualCache = {};
function createGraphic(btn, createUrl, cardId, fmt, assetId, noPhoto) {
  fmt = fmt || 'feed_portrait';
  assetId = assetId || '';
  var panel = document.querySelector('.visual-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  panel.style.display = '';
  var origLabel = btn.textContent;
  btn.disabled = true;
  btn.textContent = 'Generating\u2026';
  var cacheKey = cardId + '|' + fmt + '|' + assetId + '|' + (noPhoto ? '1' : '0');
  if (_visualCache[cacheKey]) {
    _renderVisualPanel(panel, _visualCache[cacheKey], cardId, createUrl);
    btn.disabled = false; btn.textContent = origLabel;
    return;
  }
  var prog = MH.renderProgress(panel, {label: 'Designing your graphic', sub: 'Usually 5\u201315 seconds', expectedMs: 9000, accent: 'lane'});
  var reqBody = {format: fmt};
  if (assetId) reqBody.asset_id = assetId;
  if (noPhoto) reqBody.no_photo = true;
  fetch(createUrl, {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify(reqBody)})
    .then(function(r) { return r.json().then(function(j){ return {ok: r.ok, body: j}; }); })
    .then(function(res) {
      if (!res.ok || res.body.error) {
        // Prefer user_message (clean operator copy, e.g. the "renderer
        // busy" 429) over the raw error code.
        prog.stop();
        btn.disabled = false; btn.textContent = origLabel;
        var emsg = (res.body && res.body.user_message) || ('Error: ' + ((res.body && res.body.error) || 'render failed'));
        panel.innerHTML = '<div style="padding:14px;color:var(--bad);font-size:13px">' + emsg + '</div>';
        return;
      }
      _visualCache[cacheKey] = res.body;
      prog.complete(function(){
        btn.disabled = false; btn.textContent = origLabel;
        _renderVisualPanel(panel, res.body, cardId, createUrl);
      });
    })
    .catch(function(err) {
      prog.stop();
      btn.disabled = false; btn.textContent = origLabel;
      panel.innerHTML = '<div style="padding:14px;color:var(--bad);font-size:13px">Network error: ' + err + '</div>';
    });
}

// Escape a JS expression so it can safely live inside an HTML onclick="..." attribute.
// JSON.stringify produces a string with literal double quotes; those would close the HTML
// attribute prematurely. We replace inner " with the &quot; entity (the browser decodes
// them back to " before passing to the JS engine).
function _attrEsc(jsExpr) {
  return '"' + jsExpr.replace(/&/g, '&amp;').replace(/"/g, '&quot;') + '"';
}

// Upload a photo for ONE card: file dialog → POST to the card's /photo
// endpoint (which links it to the athlete in the media library) → attach
// the new asset to this graphic by re-rendering with it selected.
function mhCardPhotoUpload(btn, photoUrl, createUrl, cardId, fmt, accept) {
  var inp = document.createElement('input');
  inp.type = 'file';
  inp.accept = accept || 'image/*';
  inp.style.display = 'none';
  inp.onchange = function() {
    if (!inp.files || !inp.files.length) return;
    var fd = new FormData();
    fd.append('photo', inp.files[0]);
    var orig = btn.textContent;
    btn.disabled = true;
    btn.textContent = 'Uploading…';
    fetch(photoUrl, {method: 'POST', body: fd})
      .then(function(r) { return r.json(); })
      .then(function(j) {
        btn.disabled = false; btn.textContent = orig;
        if (!j.ok || !j.asset) {
          if (window.MH && MH.toast) MH.toast('Upload failed: ' + (j.message || j.error || 'unknown'), 'error', 4000);
          return;
        }
        if (j.asset.kind === 'clip') {
          // M24 — a race clip: linked to this card's athlete + meet, so the
          // motion render can back the card with real footage. The auto-
          // extracted best frame (M25, when available) becomes the still's
          // photo in the same breath.
          var hasFrame = j.asset.frame_asset && j.asset.frame_asset.id;
          if (window.MH && MH.toast) MH.toast('Race clip saved &amp; linked to this card' + (hasFrame ? ' — using its best frame as the photo' : ''), 'success', 3200);
          createGraphic(btn, createUrl, cardId, fmt, hasFrame ? j.asset.frame_asset.id : '', false);
          return;
        }
        if (window.MH && MH.toast) MH.toast('Photo saved to your library — rendering with it now', 'success', 2500);
        createGraphic(btn, createUrl, cardId, fmt, j.asset.id, false);
      })
      .catch(function(e) {
        btn.disabled = false; btn.textContent = orig;
        if (window.MH && MH.toast) MH.toast('Upload failed: ' + e, 'error', 4000);
      });
  };
  document.body.appendChild(inp);
  inp.click();
  setTimeout(function(){ try { document.body.removeChild(inp); } catch(e) {} }, 60000);
}

// PHOTOS-6 / M4 write-back: confirm a meet-scoped candidate photo. One
// click writes the athlete link back onto the library asset (so next meet
// the picker suggests it automatically) and then renders this graphic with
// the photo. The confirm is best-effort — a link hiccup never blocks the
// render the user asked for.
function mhConfirmCandidate(btn, confirmUrl, createUrl, cardId, fmt, assetId) {
  fetch(confirmUrl, {method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({asset_id: assetId})})
    .then(function(r) { return r.json(); })
    .catch(function() { return null; })
    .then(function(j) {
      if (j && j.ok && window.MH && MH.toast) {
        MH.toast('Photo linked to ' + (j.athlete || 'this athlete') + ' — remembered for future meets', 'success', 2500);
      }
      createGraphic(btn, createUrl, cardId, fmt, assetId, false);
    });
}

// M24 — detach a race clip from this card (the clip stays in the library;
// only the card link is removed). Re-renders so the chip row refreshes.
function mhClipUnlink(btn, unlinkUrl, assetId, createUrl, cardId, fmt) {
  btn.disabled = true;
  fetch(unlinkUrl, {method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({asset_id: assetId})})
    .then(function(r) { return r.json(); })
    .then(function(j) {
      if (window.MH && MH.toast) MH.toast(j.ok ? 'Race clip detached from this card' : ('Could not detach the clip: ' + (j.error || 'unknown')), j.ok ? 'success' : 'error', 2500);
      if (j.ok) { createGraphic(btn, createUrl, cardId, fmt, '', false); }
      else { btn.disabled = false; }
    })
    .catch(function() { btn.disabled = false; });
}

// Venue backdrops: CC-licensed public photos of the meet's pool/venue,
// searched server-side (venue_search), imported into the org's library with
// licence + attribution preserved, then attached to this graphic.
var _venueResults = {};
// Stock-thumb proxy serves cache-only (a miss 404s while it warms in the
// background); retry a few times with backoff so the warmed tile loads, then
// hide the broken preview. The &_r= buster forces a fresh request each try.
function mhThumbRetry(img) {
  var n = (parseInt(img.getAttribute('data-try') || '0', 10)) + 1;
  img.setAttribute('data-try', n);
  if (n <= 9) {
    var base = img.getAttribute('data-src') || img.src;
    setTimeout(function(){ img.src = base + (base.indexOf('?') < 0 ? '?' : '&') + '_r=' + n; }, Math.min(3500, 900 * n));
  } else {
    img.onerror = null; img.style.visibility = 'hidden';
  }
}
function mhVenueSearchOpen(btn, createUrl, cardId, fmt) {
  var slot = document.querySelector('.mh-venue-results[data-card="' + cardId + '"]');
  if (!slot) return;
  if (slot.dataset.open === '1') { slot.style.display = 'none'; slot.dataset.open = ''; return; }
  slot.dataset.open = '1'; slot.style.display = '';
  slot.innerHTML = '<span style="font-size:11px;color:var(--ink-muted)">Searching public venue photos&hellip;</span>';
  var base = createUrl.replace(/\/cards\/[^/]*\/create-graphic$/, '');
  fetch(base + '/venue-search')
    .then(function(r){ return r.json(); })
    .then(function(j) {
      var res = (j && j.results) || [];
      if (!res.length) {
        slot.innerHTML = '<span style="font-size:11px;color:var(--ink-muted)">No public venue photos found' + (j && j.query ? ' for “' + j.query + '”' : '') + '.</span>';
        return;
      }
      _venueResults[cardId] = res;
      var html = '<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-bottom:4px">Venue backdrops' + (j.query ? ' · ' + j.query : '') + ' · CC-licensed, attribution saved with the asset</div>';
      res.forEach(function(ph, i) {
        html += '<button type="button" title="' + ((ph.title || '') + (ph.licence ? ' · ' + ph.licence : '')).replace(/"/g, '&quot;') + '"' +
          ' onclick=' + _attrEsc('mhVenueImport(this, ' + JSON.stringify(createUrl) + ', ' + JSON.stringify(cardId) + ', ' + JSON.stringify(fmt) + ', ' + i + ')') +
          ' style="padding:0;border-radius:6px;cursor:pointer;border:2px solid var(--border);background:var(--bg);line-height:0;margin:0 4px 4px 0">' +
          '<img src="' + ph.thumb_url + '" data-src="' + ph.thumb_url + '" onerror="mhThumbRetry(this)" alt="" style="width:44px;height:44px;object-fit:cover;border-radius:4px;pointer-events:none"/></button>';
      });
      slot.innerHTML = html;
    })
    .catch(function() {
      slot.innerHTML = '<span style="font-size:11px;color:var(--bad)">Venue search failed.</span>';
    });
}
function mhVenueImport(btn, createUrl, cardId, fmt, idx) {
  var ph = (_venueResults[cardId] || [])[idx];
  if (!ph) return;
  var base = createUrl.replace(/\/cards\/[^/]*\/create-graphic$/, '');
  btn.disabled = true;
  fetch(base + '/venue-import', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify(ph)
  })
    .then(function(r){ return r.json(); })
    .then(function(j) {
      btn.disabled = false;
      if (!j.ok || !j.asset) {
        if (window.MH && MH.toast) MH.toast('Venue photo import failed: ' + (j.error || 'unknown'), 'error', 4000);
        return;
      }
      if (window.MH && MH.toast) MH.toast('Venue photo saved to your library — rendering with it now', 'success', 2500);
      createGraphic(btn, createUrl, cardId, fmt, j.asset.id, false);
    })
    .catch(function(e) {
      btn.disabled = false;
      if (window.MH && MH.toast) MH.toast('Venue photo import failed: ' + e, 'error', 4000);
    });
}

function _renderVisualPanel(panel, data, cardId, createUrl) {
  var visuals = data.visuals || [];
  if (!visuals.length) {
    panel.innerHTML = '<div style="padding:14px;color:var(--ink-muted);font-size:13px">No visuals generated. ' + ((data.errors && data.errors.length) ? 'Errors: ' + window.safeText(data.errors.join('; ')) : '') + '</div>';
    return;
  }
  var v = visuals[0];
  // Use absolute path that respects the deployed /port/5000 prefix; the backend prepends location.pathname's base via window._API_BASE.
  var apiBase = (window._API_BASE || '');
  var cur = v.format_name || 'feed_portrait';
  var chosen = data.chosen_asset_id || '';
  var noP = !!data.no_photo;
  var imgUrl = apiBase + '/api/visual/' + encodeURIComponent(v.id) + '/png/' + encodeURIComponent(cur);
  var why = (data.brief && data.brief.why_this_design) || v.why_this_design || '';
  var layout = v.layout_template || (data.brief && data.brief.layout_template) || '';
  var formats = ['feed_portrait', 'feed_square', 'story_vertical'];
  var formatLabels = {'feed_portrait':'Portrait', 'feed_square':'Square', 'story_vertical':'Story'};
  var tabsHtml = formats.map(function(f) {
    var active = (f === cur);
    return '<button class="vfmt-tab" data-fmt="' + f + '" onclick=' + _attrEsc('createGraphic(this, ' + JSON.stringify(createUrl) + ', ' + JSON.stringify(cardId) + ', ' + JSON.stringify(f) + ', ' + JSON.stringify(chosen) + ', ' + (noP ? 'true' : 'false') + ')') + ' style="font-size:11px;padding:3px 10px;border-radius:999px;border:1px solid var(--border);cursor:pointer;background:' + (active ? 'color-mix(in oklab, var(--lane) 15%, transparent)' : 'transparent') + ';color:' + (active ? 'var(--lane)' : 'var(--ink-dim)') + ';font-family:inherit;margin-right:4px">' + formatLabels[f] + '</button>';
  }).join('');
  // Per-graphic photo picker — the user decides which photo lands on THIS
  // graphic. Library photos remembered for this card's athlete (linked at
  // an earlier upload, possibly a previous meet) are flagged ★ and sorted
  // first by the server. The "+ Add photo of <name>" button uploads a new
  // photo, links it to the athlete in the media library, and attaches it
  // to this graphic in one step.
  var photos = data.available_photos || [];
  var athlete = data.card_athlete || '';
  var photoUrl = createUrl.replace(/\/create-graphic$/, '/photo');
  var confirmUrl = createUrl.replace(/\/create-graphic$/, '/photo-confirm');
  // PHOTOS-6 handoff: the evaluator's meet-scoped candidates ({asset_id,
  // score, reason_summary}) pre-sort the picker — photos uploaded for THIS
  // meet come first, best match first — and picking one confirms the
  // athlete link back onto the asset (the M4 write-back seam), so next
  // meet the right face is automatic.
  var evalR = data.evaluation || {};
  var cands = evalR.candidates || [];
  var candRank = {}, candReason = {};
  cands.forEach(function(c, i) {
    if (c && c.asset_id) { candRank[c.asset_id] = i + 1; candReason[c.asset_id] = c.reason_summary || ''; }
  });
  if (cands.length) {
    photos = photos.slice().sort(function(a, b) {
      var ra = candRank[a.id] || 999, rb = candRank[b.id] || 999;
      if (ra !== rb) return ra - rb;
      return (a.suggested === b.suggested) ? 0 : (a.suggested ? -1 : 1);
    });
  }
  var pickNote = '';
  if (cands.length && evalR.recommended_action && evalR.recommended_action.indexOf('Pick from') === 0) {
    pickNote = '<div style="font-size:12px;color:var(--lane);margin-bottom:4px">&#x1F4F7; ' +
      window.safeText(evalR.recommended_action) + ' Picking one links it to this swimmer for future meets.</div>';
  }
  function _pchip(label, active, oc) {
    return '<button type="button" onclick=' + _attrEsc(oc) + ' style="font-size:11px;padding:3px 9px;border-radius:6px;cursor:pointer;border:1px solid ' + (active ? 'var(--lane)' : 'var(--border)') + ';background:' + (active ? 'color-mix(in oklab, var(--lane) 12%, transparent)' : 'transparent') + ';color:var(--ink-dim);font-family:inherit;margin:0 4px 4px 0">' + label + '</button>';
  }
  var autoOc = 'createGraphic(this, ' + JSON.stringify(createUrl) + ', ' + JSON.stringify(cardId) + ', ' + JSON.stringify(cur) + ', "", false)';
  var noneOc = 'createGraphic(this, ' + JSON.stringify(createUrl) + ', ' + JSON.stringify(cardId) + ', ' + JSON.stringify(cur) + ', "", true)';
  var thumbs = photos.map(function(ph) {
    var on = (ph.id === chosen);
    var isCand = !!candRank[ph.id];
    // A meet-scoped candidate click confirms the athlete link (write-back)
    // before rendering; every other photo renders directly as before.
    var oc = isCand
      ? 'mhConfirmCandidate(this, ' + JSON.stringify(confirmUrl) + ', ' + JSON.stringify(createUrl) + ', ' + JSON.stringify(cardId) + ', ' + JSON.stringify(cur) + ', ' + JSON.stringify(ph.id) + ')'
      : 'createGraphic(this, ' + JSON.stringify(createUrl) + ', ' + JSON.stringify(cardId) + ', ' + JSON.stringify(cur) + ', ' + JSON.stringify(ph.id) + ', false)';
    var ttl = isCand
      ? ('Uploaded for this meet' + (candReason[ph.id] ? ' — ' + candReason[ph.id] : '') + '. Click to use & remember for ' + (athlete || 'this athlete'))
      : (ph.suggested ? 'Remembered for ' + (ph.label || 'this athlete') + ' — click to use' : (ph.label || ''));
    var star = ph.suggested ? '<span style="position:absolute;top:-5px;right:-5px;font-size:11px;line-height:1;pointer-events:none">&#x2B50;</span>'
      : (isCand ? '<span style="position:absolute;top:-5px;right:-5px;font-size:11px;line-height:1;pointer-events:none">&#x1F4F7;</span>' : '');
    return '<span style="position:relative;display:inline-block;margin:0 4px 4px 0">' +
      '<button type="button" title="' + ttl.replace(/"/g, '&quot;') + '" onclick=' + _attrEsc(oc) + ' style="padding:0;border-radius:6px;cursor:pointer;border:2px solid ' + (on ? 'var(--lane)' : (isCand ? 'var(--lane)' : (ph.suggested ? 'var(--medal)' : 'var(--border)'))) + ';background:var(--bg);line-height:0"><img src="' + ph.url + '" alt="" style="width:44px;height:44px;object-fit:cover;border-radius:4px;pointer-events:none"/></button>' + star + '</span>';
  }).join('');
  var firstName = athlete ? athlete.split(' ')[0] : '';
  var upOc = 'mhCardPhotoUpload(this, ' + JSON.stringify(photoUrl) + ', ' + JSON.stringify(createUrl) + ', ' + JSON.stringify(cardId) + ', ' + JSON.stringify(cur) + ')';
  var uploadBtn = '<button type="button" onclick=' + _attrEsc(upOc) + ' style="font-size:11px;padding:3px 9px;border-radius:6px;cursor:pointer;border:1px dashed var(--lane);background:transparent;color:var(--lane);font-family:inherit;margin:0 4px 4px 0">+ Add photo' + (firstName ? ' of ' + firstName : '') + '</button>';
  // M24 — the card's race clips: the footage that can back this card's
  // motion render (M23). Chip per linked clip (filename + duration +
  // permission state) with a detach affordance, plus an add/replace upload.
  var clips = data.race_clips || [];
  var clipUnlinkUrl = createUrl.replace(/\/create-graphic$/, '/clip-unlink');
  var clipChips = clips.map(function(c) {
    var dur = c.duration_ms ? (' · ' + Math.round(c.duration_ms / 1000) + 's') : '';
    var perm = c.usable ? '' : ' <span title="Blocked: ' + window.safeText((c.permission_status || '').replace(/_/g, ' ')) + '">&#9888;</span>';
    var rmOc = 'mhClipUnlink(this, ' + JSON.stringify(clipUnlinkUrl) + ', ' + JSON.stringify(c.id) + ', ' + JSON.stringify(createUrl) + ', ' + JSON.stringify(cardId) + ', ' + JSON.stringify(cur) + ')';
    return '<span style="display:inline-flex;align-items:center;gap:5px;font-size:11px;padding:3px 9px;border-radius:6px;border:1px solid ' + (c.usable ? 'var(--border)' : 'var(--bad)') + ';color:var(--ink-dim);margin:0 4px 4px 0">&#x1F3AC; ' +
      window.safeText(c.filename) + dur + perm +
      '<button type="button" title="Detach this clip from the card" onclick=' + _attrEsc(rmOc) + ' style="border:0;background:transparent;color:var(--ink-muted);cursor:pointer;padding:0;font-size:12px;line-height:1">&#10005;</button></span>';
  }).join('');
  var clipUpOc = 'mhCardPhotoUpload(this, ' + JSON.stringify(photoUrl) + ', ' + JSON.stringify(createUrl) + ', ' + JSON.stringify(cardId) + ', ' + JSON.stringify(cur) + ', "video/*")';
  var clipBtn = '<button type="button" onclick=' + _attrEsc(clipUpOc) + ' style="font-size:11px;padding:3px 9px;border-radius:6px;cursor:pointer;border:1px dashed var(--border);background:transparent;color:var(--ink-dim);font-family:inherit;margin:0 4px 4px 0">' + (clips.length ? '&#x21BA; Replace race clip' : '+ Add race clip' + (firstName ? ' of ' + firstName : '')) + '</button>';
  var clipRow =
    '<div style="margin:2px 0 4px">' +
      '<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-bottom:4px">Race clip &middot; backs the motion video</div>' +
      clipChips + clipBtn +
    '</div>';
  var venueOc = 'mhVenueSearchOpen(this, ' + JSON.stringify(createUrl) + ', ' + JSON.stringify(cardId) + ', ' + JSON.stringify(cur) + ')';
  var venueBtn = '<button type="button" onclick=' + _attrEsc(venueOc) + ' style="font-size:11px;padding:3px 9px;border-radius:6px;cursor:pointer;border:1px dashed var(--border);background:transparent;color:var(--ink-dim);font-family:inherit;margin:0 4px 4px 0">Venue backdrop&hellip;</button>';
  // Roadmap 1.2 — when a real library photo is on this graphic, deep-link it
  // into the image studio (fill/erase/expand/upscale/restyle) in a new tab. The
  // URL is server-built with url_for; absent when no photo (Auto/No photo) is set.
  var studioUrl = data.studio_url || '';
  var studioBtn = (chosen && studioUrl) ? '<a href="' + studioUrl + '" target="_blank" rel="noopener" title="Fill, erase, expand, upscale or restyle this photo with AI" style="font-size:11px;padding:3px 9px;border-radius:6px;cursor:pointer;border:1px dashed var(--lane);background:transparent;color:var(--lane);font-family:inherit;margin:0 4px 4px 0;text-decoration:none;display:inline-block">✦ Edit photo</a>' : '';
  var pickerHtml =
    '<div style="margin-bottom:8px">' +
      '<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-bottom:4px">Photo &middot; pick which goes on this graphic</div>' +
      pickNote +
      _pchip('Auto', (!chosen && !noP), autoOc) + _pchip('No photo', noP, noneOc) + thumbs + uploadBtn + studioBtn + venueBtn +
      '<div class="mh-venue-results" data-card="' + cardId.replace(/"/g, '&quot;') + '" style="display:none;margin-top:6px"></div>' +
      clipRow +
    '</div>';
  panel.innerHTML =
    '<div style="display:flex;gap:14px;align-items:flex-start;flex-wrap:wrap">' +
      '<div style="flex:0 0 min(220px,100%);max-width:240px">' +
        '<img src="' + imgUrl + '" alt="Generated graphic" style="width:100%;border-radius:6px;border:1px solid var(--border);background:var(--bg)" />' +
      '</div>' +
      '<div style="flex:1;min-width:min(200px,100%)">' +
        '<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-bottom:4px">Generated visual &middot; ' + window.safeText(layout || 'auto') + '</div>' +
        // why_this_design is LLM output that can echo user-provided club/meet
        // strings — escape before it touches innerHTML.
        (why ? '<div style="font-size:12px;color:var(--ink);margin-bottom:8px;line-height:1.4">' + window.safeText(why) + '</div>' : '') +
        '<div style="margin-bottom:8px">' + tabsHtml + '</div>' +
        pickerHtml +
        '<div style="display:flex;gap:6px;flex-wrap:wrap">' +
          '<a class="btn secondary" href="' + imgUrl + '" download style="font-size:11px;padding:4px 10px">Download PNG</a>' +
          '<button class="btn secondary" style="font-size:11px;padding:4px 10px" onclick=' + _attrEsc('regenerateGraphic(this, ' + JSON.stringify(createUrl) + ', ' + JSON.stringify(cardId) + ', ' + JSON.stringify(chosen) + ', ' + (noP ? 'true' : 'false') + ')') + '>&#x21BA; Regenerate (3 variants)</button>' +
          '<button class="btn secondary" style="font-size:11px;padding:4px 10px" onclick=' + _attrEsc('addGraphicToPack(this, ' + JSON.stringify(v.id) + ')') + '>+ Add to pack</button>' +
        '</div>' +
      '</div>' +
    '</div>';
}

// Motion-graphic generation: async job + poll, cached server-side. fmt picks
// the output cut (story 9:16 default, portrait 4:5, square 1:1, landscape
// 16:9) \u2014 same card facts, same brand, re-laid-out per platform.
var _motionCache = {};
var _MOTION_FMT_DIMS = {story: '1080&times;1920', portrait: '1080&times;1350', square: '1080&times;1080', landscape: '1920&times;1080'};
function _motionFmtChips(motionUrl, cardId, active) {
  var out = '';
  ['story', 'portrait', 'square', 'landscape'].forEach(function(f) {
    var label = f.charAt(0).toUpperCase() + f.slice(1);
    if (f === active) {
      out += '<span class="btn secondary" style="font-size:11px;padding:4px 10px;opacity:0.55;pointer-events:none">' + label + ' &#x2713;</span>';
    } else {
      out += '<button class="btn secondary" style="font-size:11px;padding:4px 10px" onclick=' +
        _attrEsc('generateMotion(this, ' + JSON.stringify(motionUrl) + ', ' + JSON.stringify(cardId) + ', ' + JSON.stringify(f) + ')') +
        '>' + label + '</button>';
    }
  });
  return out;
}
// M32 (UX-4): per-card motion now uses the same async job + poll pattern the
// reel adopted — a cold Remotion render (30-90s) on a held connection gets
// killed by front-line proxies as a bogus "Network error". The button kicks
// a background job, polls, then streams the finished MP4 from the motion-file
// route (a real URL that survives navigation, with a ?poster=1 sidecar).
function generateMotion(btn, motionUrl, cardId, fmt) {
  fmt = fmt || 'story';
  var panel = document.querySelector('.motion-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  panel.style.display = '';
  var origLabel = btn.textContent;
  btn.disabled = true;
  btn.textContent = 'Rendering motion…';
  var prog = MH.renderProgress(panel, {label: 'Rendering ' + fmt + ' motion', sub: 'First render can take up to 90 seconds — repeats are instant', expectedMs: 45000, accent: 'medal'});
  var fail = function(msg) {
    prog.stop();
    btn.disabled = false; btn.textContent = origLabel;
    // msg can be a raw str(e) detail (meet names, node stderr) — escape
    // before it touches innerHTML.
    panel.innerHTML = '<div style="padding:14px;color:var(--bad);font-size:13px">' + window.safeText(msg) + '</div>';
  };
  var jobUrl = motionUrl + '-job' + (fmt !== 'story' ? '?format=' + encodeURIComponent(fmt) : '');
  // JSON content-type: the CSRF layer exempts application/json fetches
  // (a cross-site page can't send them without a CORS preflight).
  fetch(jobUrl, {method:'POST', headers:{'Content-Type':'application/json'}, body:'{}'})
    .then(function(r) { return r.json().then(function(j){ return {status: r.status, body: j}; }); })
    .then(function(res) {
      if (res.status !== 202 || !res.body || !res.body.poll_url) {
        fail((res.body && (res.body.user_message || res.body.detail || res.body.error)) || 'could not start the render');
        return;
      }
      var tries = 0;
      var poll = function() {
        tries++;
        if (tries > 80) { fail('timed out waiting for the render — try again'); return; }
        fetch(res.body.poll_url)
          .then(function(r){ return r.json(); })
          .then(function(j) {
            if (j.status === 'done' && j.video_url) {
              prog.complete(function(){
                btn.disabled = false; btn.textContent = origLabel;
                _motionCache[cardId + ':' + fmt] = j.video_url;
                mhRenderMotion(panel, motionUrl, cardId, fmt, j.video_url);
              });
              return;
            }
            if (j.status === 'error' || (j.error && j.status !== 'running')) {
              fail(j.user_message || j.error || 'render failed'); return;
            }
            setTimeout(poll, 3000);
          })
          .catch(function() { setTimeout(poll, 3000); });
      };
      setTimeout(poll, 3000);
    })
    .catch(function(err) { fail('Network error: ' + err); });
}

// The finished per-card motion panel — used by generateMotion's success path
// and the on-load "Rendered videos" restore. videoUrl is the persistent
// motion-file route; its ?poster=1 sidecar becomes the <video> poster.
function mhRenderMotion(panel, motionUrl, cardId, fmt, videoUrl) {
  var poster = videoUrl + (videoUrl.indexOf('?') === -1 ? '?' : '&') + 'poster=1';
  var vidCol = fmt === 'landscape' ? 'flex:0 0 min(300px,100%);max-width:320px' : 'flex:0 0 min(200px,100%);max-width:220px';
  panel.innerHTML =
    '<div style="display:flex;gap:14px;align-items:flex-start;flex-wrap:wrap">' +
      '<div style="' + vidCol + '">' +
        '<video class="mh-motion-video" src="' + videoUrl + '" poster="' + poster + '" controls playsinline preload="metadata" style="width:100%;border-radius:6px;border:1px solid var(--border);background:#000"></video>' +
      '</div>' +
      '<div style="flex:1;min-width:min(200px,100%)">' +
        '<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-bottom:4px">Motion &middot; ' + (_MOTION_FMT_DIMS[fmt] || '') + ' &middot; 6s</div>' +
        '<div style="font-size:12px;color:var(--ink);margin-bottom:8px;line-height:1.4">Branded MP4. Same archetype, colours, and seed as the static card &mdash; including your Inspector accent and photo on/off choices. An Inspector crop applies to stills only for now.</div>' +
        '<div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:6px">' + _motionFmtChips(motionUrl, cardId, fmt) + '</div>' +
        '<div style="display:flex;gap:6px;flex-wrap:wrap">' +
          '<a class="btn secondary" href="' + videoUrl + '" download="motion-' + cardId + '-' + fmt + '.mp4" style="font-size:11px;padding:4px 10px">Download MP4</a>' +
        '</div>' +
        '<div class="mh-motion-why" style="font-size:11px;color:var(--ink-muted);margin-top:8px"></div>' +
      '</div>' +
    '</div>' +
    '<div class="mh-reel-comments" style="margin-top:12px"></div>';
  _loadMotionWhy(panel, motionUrl, fmt);
  // UI 1.8 - pin timestamp comments to this card's motion clip too. The
  // run-level comments endpoint sits at the path before '/card/'.
  var _cmRoot = motionUrl.split('/card/')[0];
  var _cmMount = panel.querySelector('.mh-reel-comments');
  if (_cmMount && typeof mhReelComments === 'function') {
    mhReelComments({mount: _cmMount, video: panel.querySelector('video.mh-motion-video'), baseUrl: _cmRoot + '/reel/comments', target: 'card:' + cardId});
  }
}

// "Why this motion design" \u2014 the render's explainability sidecar, fetched
// after the MP4 lands. Absence is fine (legacy renders predate manifests).
function _loadMotionWhy(panel, motionUrl, fmt) {
  var slot = panel.querySelector('.mh-motion-why');
  if (!slot) return;
  var mUrl = motionUrl + '/manifest' + (fmt !== 'story' ? '?format=' + encodeURIComponent(fmt) : '');
  fetch(mUrl).then(function(r){ return r.ok ? r.json() : null; }).then(function(m) {
    if (!m || !m.card) return;
    var bits = [];
    if (m.card.archetype) bits.push('archetype <b>' + m.card.archetype + '</b>');
    if (m.card.motion_intent) bits.push('motion <b>' + m.card.motion_intent + '</b>');
    if (m.card.mood) bits.push('mood <b>' + m.card.mood + '</b>');
    bits.push(m.card.colour_source === 'still-parity-roles' ? 'colours mirror the approved still' : 'colours from seed ' + (m.card.variation_seed || ''));
    slot.innerHTML = 'Why this design: ' + bits.join(' &middot; ') + mhEngineNoteHtml(m);
  }).catch(function(){});
}

// M22 handoff — honest engine disclosure. The manifest names the engine that
// produced this video; the reduced-motion FFmpeg fallback writes plain-language
// capability notes (no text choreography / count-up, static cover chips) that
// the user deserves to see instead of silently wondering why the video looks
// simpler. Manifest fields are engine-written but escaped anyway.
function mhEngineNoteHtml(m) {
  if (!m || m.engine !== 'ffmpeg') return '';
  var notes = m.notes || {};
  var line = notes.engine_note || 'Rendered by the reduced-motion FFmpeg engine.';
  var extra = [];
  if (notes.captions === 'unsupported-on-engine') extra.push('burned captions are unavailable on this engine');
  if (notes.stat_chips === 'static-cover') extra.push('cover stats are static (no count-up)');
  return '<div style="margin-top:4px;color:var(--ink-muted)">' + window.safeText(line) +
    (extra.length ? ' (' + window.safeText(extra.join('; ')) + ')' : '') + '</div>';
}

// Voiceover (opt-in, MEDIAHUB_VOICEOVER=1): speak the human-approved caption.
// The route is the audio approval gate — a 409 means "approve first", a 429
// means the render slot is busy, a 503 means the speech backend is off/missing.
// All three surface their honest user_message inline; nothing is fabricated.
function voiceoverToggle(btn, voUrl, cardId) {
  var panel = document.querySelector('.voiceover-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  if (panel.dataset.loaded) {
    panel.style.display = (panel.style.display === 'none') ? '' : 'none';
    return;
  }
  panel.style.display = '';
  var origLabel = btn.textContent;
  btn.disabled = true;
  btn.textContent = 'Preparing voiceover…';
  panel.innerHTML = '<div style="padding:10px;font-size:12px;color:var(--ink-muted)">Synthesising the approved caption… the first run can take a few seconds.</div>';
  // JSON content-type keeps this fetch inside the CSRF layer's JSON
  // exemption (a bare POST is rejected outside test mode).
  fetch(voUrl + '?format=json', {method:'POST', headers:{'Content-Type':'application/json'}, body:'{}'})
    .then(function(r){ return r.json().then(function(j){ return {status: r.status, body: j}; }); })
    .then(function(res){
      btn.disabled = false; btn.textContent = origLabel;
      var j = res.body || {};
      if (res.status !== 200 || !j.ok) {
        var msg = j.user_message || j.detail || j.error || 'Voiceover failed — try again.';
        panel.innerHTML = '<div style="padding:10px;font-size:12px;color:var(--bad)">' + msg + '</div>';
        return;
      }
      panel.dataset.loaded = '1';
      var esc = function(s){ return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;'); };
      var srtLink = j.has_subtitles
        ? '<a class="btn secondary" style="font-size:11px;padding:4px 10px" href="' + voUrl + '?format=srt" download>Download subtitles (.srt)</a>'
        : '';
      panel.innerHTML =
        '<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-bottom:6px">Voiceover &middot; ' + esc(j.voice) + ' &middot; ' + Math.round((j.duration_ms || 0) / 1000) + 's &middot; speaks the approved caption, verbatim</div>' +
        '<audio controls preload="none" src="' + voUrl + '" style="width:100%;margin-bottom:8px"></audio>' +
        (j.transcript ? '<div style="font-size:12px;color:var(--ink-dim);white-space:pre-wrap;margin-bottom:8px">' + esc(j.transcript) + '</div>' : '') +
        '<div style="display:flex;gap:6px;flex-wrap:wrap">' +
          '<a class="btn secondary" style="font-size:11px;padding:4px 10px" href="' + voUrl + '" download>Download MP3</a>' + srtLink +
        '</div>';
    })
    .catch(function(err){
      btn.disabled = false; btn.textContent = origLabel;
      panel.innerHTML = '<div style="padding:10px;font-size:12px;color:var(--bad)">Network error: ' + err + '</div>';
    });
}

// Meet-reel generation: async job + poll. A cold render takes 30-90s \u2014
// far past what front-line proxies tolerate on a held connection \u2014 so the
// button kicks off a background job and polls until the MP4 is ready.
// fmt picks the output cut (story 9:16 default, portrait 4:5, square 1:1,
// landscape 16:9).
function _reelFmtChips(reelUrl, active) {
  var out = '';
  ['story', 'portrait', 'square', 'landscape'].forEach(function(f) {
    var label = f.charAt(0).toUpperCase() + f.slice(1);
    if (f === active) {
      out += '<span class="btn secondary" style="font-size:12px;padding:4px 12px;opacity:0.55;pointer-events:none">' + label + ' &#x2713;</span>';
    } else {
      out += '<button class="btn secondary" style="font-size:12px;padding:4px 12px" onclick=' +
        _attrEsc('generateReel(this, ' + JSON.stringify(reelUrl) + ', ' + JSON.stringify(f) + ')') +
        '>' + label + '</button>';
    }
  });
  return out;
}
function generateReel(btn, reelUrl, fmt) {
  fmt = fmt || 'story';
  var panel = document.getElementById('reel-panel');
  if (!panel) return;
  panel.style.display = '';
  var origLabel = btn.textContent;
  btn.disabled = true;
  btn.textContent = 'Rendering reel\u2026';
  var prog = MH.renderProgress(panel, {label: 'Producing your ' + fmt + ' reel', sub: 'Top ranked moments \u2014 up to 90 seconds the first time', expectedMs: 60000, accent: 'medal'});
  var fail = function(msg) {
    prog.stop();
    btn.disabled = false; btn.textContent = origLabel;
    // msg can fall back to a raw str(e) detail (meet names, node stderr) —
    // escape before it touches innerHTML.
    panel.innerHTML = '<div style="padding:14px;color:var(--bad);font-size:13px">Reel render error: ' + window.safeText(msg) + '</div>';
  };
  var success = function(videoUrl) {
    prog.complete(function(){
      btn.disabled = false; btn.textContent = origLabel;
      mhRenderReel(panel, reelUrl, fmt, videoUrl);
    });
  };
  // M31: the reel composer's picks (cards / rhythm / mix) ride the job
  // request. An untouched composer contributes NOTHING, so the default
  // request — and therefore the default top-3 reel — stays byte-identical.
  var _q = [];
  if (fmt !== 'story') _q.push('format=' + encodeURIComponent(fmt));
  var _extra = (typeof mhReelComposerQuery === 'function') ? mhReelComposerQuery() : '';
  if (_extra) _q.push(_extra);
  fetch(reelUrl + '-job' + (_q.length ? '?' + _q.join('&') : ''), {method:'POST', headers:{'Content-Type':'application/json'}, body:'{}'})
    .then(function(r) { return r.json().then(function(j){ return {status: r.status, body: j}; }); })
    .then(function(res) {
      if (res.status !== 202 || !res.body || !res.body.poll_url) {
        fail((res.body && (res.body.user_message || res.body.detail || res.body.error)) || 'could not start the render');
        return;
      }
      var tries = 0;
      var poll = function() {
        tries++;
        if (tries > 80) { fail('timed out waiting for the render \u2014 try again'); return; }
        fetch(res.body.poll_url)
          .then(function(r){ return r.json(); })
          .then(function(j) {
            if (j.status === 'done' && j.video_url) { success(j.video_url); return; }
            if (j.status === 'error' || (j.error && j.status !== 'running')) {
              fail(j.user_message || j.error || 'render failed'); return;
            }
            setTimeout(poll, 3000);
          })
          .catch(function() { setTimeout(poll, 3000); });
      };
      setTimeout(poll, 3000);
    })
    .catch(function(err) { fail('Network error: ' + err); });
}

// R1.15 - render every reel cut (story/portrait/square/landscape) in one
// background pass, then offer a download per produced cut. Reuses any cut
// already cached, so running this after a single-format render only renders
// the cuts still missing. Polls the same job-status route as generateReel.
function generateReelBatch(btn, reelUrl) {
  var panel = document.getElementById('reel-panel');
  if (!panel) return;
  panel.style.display = '';
  var origLabel = btn.textContent;
  btn.disabled = true;
  btn.textContent = 'Rendering all formats…';
  var prog = MH.renderProgress(panel, {label: 'Producing every reel format', sub: 'Story, portrait, square & landscape — up to a few minutes the first time', expectedMs: 150000, accent: 'medal'});
  var fail = function(msg) {
    prog.stop();
    btn.disabled = false; btn.textContent = origLabel;
    panel.innerHTML = '<div style="padding:14px;color:var(--bad);font-size:13px">Reel render error: ' + window.safeText(msg) + '</div>';
  };
  var success = function(videoUrls, failed) {
    prog.complete(function(){
      btn.disabled = false; btn.textContent = origLabel;
      mhRenderReelBatch(panel, reelUrl, videoUrls, failed);
    });
  };
  // M31: the composer's picks apply to the all-formats batch too.
  var _extraB = (typeof mhReelComposerQuery === 'function') ? mhReelComposerQuery() : '';
  fetch(reelUrl + '-batch' + (_extraB ? '?' + _extraB : ''), {method:'POST', headers:{'Content-Type':'application/json'}, body:'{}'})
    .then(function(r) { return r.json().then(function(j){ return {status: r.status, body: j}; }); })
    .then(function(res) {
      if (res.status !== 202 || !res.body || !res.body.poll_url) {
        fail((res.body && (res.body.user_message || res.body.detail || res.body.error)) || 'could not start the render');
        return;
      }
      var tries = 0;
      var poll = function() {
        tries++;
        if (tries > 120) { fail('timed out waiting for the render — try again'); return; }
        fetch(res.body.poll_url)
          .then(function(r){ return r.json(); })
          .then(function(j) {
            if (j.status === 'done' && j.video_urls && Object.keys(j.video_urls).length) { success(j.video_urls, j.formats_failed || {}); return; }
            if (j.status === 'error' || (j.error && j.status !== 'running')) {
              fail(j.user_message || j.error || 'render failed'); return;
            }
            setTimeout(poll, 3000);
          })
          .catch(function() { setTimeout(poll, 3000); });
      };
      setTimeout(poll, 3000);
    })
    .catch(function(err) { fail('Network error: ' + err); });
}

// R1.15 - the finished multi-format panel: the story cut (or first produced)
// as the scrubbable preview plus a labelled download for every cut, and an
// honest note for any cut the active engine couldn't produce.
function mhRenderReelBatch(panel, reelUrl, videoUrls, failed) {
  var order = ['story', 'portrait', 'square', 'landscape'];
  var primary = videoUrls.story || '';
  if (!primary) { for (var i = 0; i < order.length; i++) { if (videoUrls[order[i]]) { primary = videoUrls[order[i]]; break; } } }
  var dl = '';
  order.forEach(function(f) {
    if (videoUrls[f]) {
      dl += '<a class="btn secondary" href="' + videoUrls[f] + '" download="meet-reel-' + f + '.mp4" style="font-size:12px;padding:4px 12px">' +
        f.charAt(0).toUpperCase() + f.slice(1) + ' &middot; ' + (_MOTION_FMT_DIMS[f] || '') + '</a>';
    }
  });
  var failNote = '';
  var failedKeys = failed ? Object.keys(failed) : [];
  if (failedKeys.length) {
    // Show the API's honest per-cut reason (since R1.16 the ffmpeg engine
    // renders all four cuts, so a remaining entry is a genuine render failure,
    // not an engine gap). Escape each reason — they can carry node stderr /
    // markup — instead of the old misleading "switch engine" advice.
    var rows = failedKeys.map(function(f){
      var fmt = f.charAt(0).toUpperCase() + f.slice(1);
      var reason = (failed[f] == null ? '' : String(failed[f])) || 'render failed';
      return '<div style="margin-top:2px">' + window.safeText(fmt) + ' — ' + window.safeText(reason) + '</div>';
    }).join('');
    failNote = '<div style="font-size:12px;color:var(--ink-muted);margin-top:8px">These cuts failed to render:' + rows + '</div>';
  }
  panel.innerHTML =
    '<div style="display:flex;gap:16px;align-items:flex-start;flex-wrap:wrap">' +
      '<div style="flex:0 0 min(240px,100%);max-width:260px">' +
        (primary ? '<video class="mh-reel-video" src="' + primary + '" controls playsinline preload="metadata" style="width:100%;border-radius:6px;border:1px solid var(--border);background:var(--bg)"></video>' : '') +
      '</div>' +
      '<div style="flex:1;min-width:min(240px,100%)">' +
        '<div style="font-size:11px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-bottom:4px">Meet reel &middot; every format</div>' +
        '<div style="font-size:13px;color:var(--ink);margin-bottom:10px;line-height:1.4">All cuts rendered in one pass from the same ranked moments — download the size each channel wants.</div>' +
        '<div style="display:flex;gap:6px;flex-wrap:wrap">' + dl + '</div>' +
        failNote +
      '</div>' +
    '</div>' +
    '<div class="mh-reel-comments" style="margin-top:14px"></div>';
  var mount = panel.querySelector('.mh-reel-comments');
  if (mount) mhReelComments({mount: mount, video: panel.querySelector('video.mh-reel-video'), baseUrl: reelUrl + '/comments', target: 'reel'});
}

// UI 1.8 - render the finished reel panel (video + format chips + download)
// plus the Frame.io-style timestamp comment surface beneath it. Used by both
// generateReel's success path and the on-load restore of a cached reel.
function mhRenderReel(panel, reelUrl, fmt, videoUrl) {
  var vidCol = fmt === 'landscape' ? 'flex:0 0 min(340px,100%);max-width:360px' : 'flex:0 0 min(240px,100%);max-width:260px';
  // M32: the reel-file route serves a poster-frame sidecar via ?poster=1.
  var poster = videoUrl + (videoUrl.indexOf('?') === -1 ? '?' : '&') + 'poster=1';
  panel.innerHTML =
    '<div style="display:flex;gap:16px;align-items:flex-start;flex-wrap:wrap">' +
      '<div style="' + vidCol + '">' +
        '<video class="mh-reel-video" src="' + videoUrl + '" poster="' + poster + '" controls playsinline preload="metadata" style="width:100%;border-radius:6px;border:1px solid var(--border);background:#000"></video>' +
      '</div>' +
      '<div style="flex:1;min-width:min(240px,100%)">' +
        '<div style="font-size:11px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-bottom:4px">Meet reel &middot; ' + (_MOTION_FMT_DIMS[fmt] || '') + '</div>' +
        '<div style="font-size:13px;color:var(--ink);margin-bottom:10px;line-height:1.4">Your picked moments stitched into a branded reel &mdash; honest cover stats, archetype-matched beats, and a club outro. Scrub to a moment and pin a comment for your team.</div>' +
        '<div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:6px">' + _reelFmtChips(reelUrl, fmt) + '</div>' +
        '<div style="display:flex;gap:6px;flex-wrap:wrap">' +
          '<a class="btn secondary" href="' + videoUrl + '" download="meet-reel-' + fmt + '.mp4" style="font-size:12px;padding:4px 12px">Download MP4</a>' +
          '<button class="btn secondary" style="font-size:12px;padding:4px 12px" onclick=' + _attrEsc('generateReelBatch(this, ' + JSON.stringify(reelUrl) + ')') + '>Render all formats</button>' +
        '</div>' +
        '<div class="mh-reel-why" style="font-size:11px;color:var(--ink-muted);margin-top:8px"></div>' +
      '</div>' +
    '</div>' +
    '<div class="mh-reel-comments" style="margin-top:14px"></div>';
  // M22 handoff — the reel's explainability manifest names the engine; the
  // reduced-motion FFmpeg fallback's honest capability note is surfaced.
  var whySlot = panel.querySelector('.mh-reel-why');
  if (whySlot) {
    var mUrl = videoUrl.replace('reel-file', 'reel-manifest').replace(/([?&])poster=1(&|$)/, '$1');
    fetch(mUrl).then(function(r){ return r.ok ? r.json() : null; }).then(function(m) {
      if (!m) return;
      var note = mhEngineNoteHtml(m);
      if (note) whySlot.innerHTML = note;
    }).catch(function(){});
  }
  var mount = panel.querySelector('.mh-reel-comments');
  if (mount) mhReelComments({mount: mount, video: panel.querySelector('video.mh-reel-video'), baseUrl: reelUrl + '/comments', target: 'reel'});
}

// ---------------------------------------------------------------------------
// M31 (UX-3) — reel composer. Reads the composer card's state (picked
// moments, rhythm preset, audio mix) into query params for the reel job
// routes. The three rhythm presets map onto the R1.12 rhythm request shape:
//   Steady   — the default skeleton (no params at all);
//   Punchy   — the top pick earns a heavier beat weight (1.5x);
//   Showcase — longer cover + outro bookends (3.5s each).
// An untouched composer (top-3 picked, Steady, default mix) returns '' so
// the default request — and the default top-3 reel — stays byte-identical.
// ---------------------------------------------------------------------------
// Mirrors visual/motion.py reel maths: REEL_COVER_SEC=2, REEL_PER_CARD_SEC=4,
// REEL_OUTRO_SEC=2.5, totals clamped to [3, 60]. 3 cards ≈ 16.5s.
var MH_REEL_MATHS = {cover: 2.0, perCard: 4.0, outro: 2.5, totalMin: 3.0, totalMax: 60.0,
                     showcaseCover: 3.5, showcaseOutro: 3.5, punchyTopWeight: 1.5};
function mhReelComposerState() {
  var comp = document.getElementById('mh-reel-composer');
  if (!comp) return null;
  var picks = Array.prototype.slice.call(comp.querySelectorAll('.mh-reel-pick:checked')).map(function(c){ return c.value; });
  var defaults = (comp.getAttribute('data-default-cards') || '').split(',').filter(Boolean);
  var rhythmSel = document.getElementById('mh-reel-rhythm');
  var mixSel = document.getElementById('mh-reel-mix');
  return {
    comp: comp,
    picks: picks,
    defaults: defaults,
    rhythm: rhythmSel ? rhythmSel.value : 'steady',
    mix: mixSel ? mixSel.value : ''
  };
}
function mhReelComposerQuery() {
  var st = mhReelComposerState();
  if (!st) return '';
  var params = [];
  var isDefaultSel = st.picks.length === st.defaults.length &&
    st.picks.every(function(v, i) { return v === st.defaults[i]; });
  if (st.picks.length && !isDefaultSel) {
    params.push('cards=' + encodeURIComponent(st.picks.join(',')));
  }
  if (st.rhythm === 'punchy' && st.picks.length) {
    var w = [String(MH_REEL_MATHS.punchyTopWeight)];
    for (var i = 1; i < Math.min(st.picks.length, 5); i++) w.push('1');
    params.push('weights=' + encodeURIComponent(w.join(',')));
  } else if (st.rhythm === 'showcase') {
    params.push('cover=' + MH_REEL_MATHS.showcaseCover);
    params.push('outro=' + MH_REEL_MATHS.showcaseOutro);
  }
  if (st.mix) params.push('mix=' + encodeURIComponent(st.mix));
  return params.join('&');
}
// Keep the readout + max-5 rule live as the user ticks moments.
function mhReelComposerSync() {
  var st = mhReelComposerState();
  if (!st) return;
  var boxes = Array.prototype.slice.call(st.comp.querySelectorAll('.mh-reel-pick'));
  var n = st.picks.length;
  boxes.forEach(function(b) {
    b.disabled = (!b.checked && n >= 5);
    var row = b.closest('label');
    if (row) row.style.opacity = b.disabled ? '0.45' : '';
  });
  var cover = MH_REEL_MATHS.cover, outro = MH_REEL_MATHS.outro;
  var weightSum = Math.min(n, 5);
  if (st.rhythm === 'punchy' && n > 0) weightSum = MH_REEL_MATHS.punchyTopWeight + (Math.min(n, 5) - 1);
  if (st.rhythm === 'showcase') { cover = MH_REEL_MATHS.showcaseCover; outro = MH_REEL_MATHS.showcaseOutro; }
  var total = cover + MH_REEL_MATHS.perCard * weightSum + outro;
  total = Math.max(MH_REEL_MATHS.totalMin, Math.min(MH_REEL_MATHS.totalMax, total));
  var out = document.getElementById('mh-reel-duration');
  if (out) {
    out.textContent = n
      ? (n + (n === 1 ? ' moment' : ' moments') + ' ≈ ' + (Math.round(total * 10) / 10) + 's')
      : 'Pick at least one moment';
  }
  st.comp.querySelectorAll('.mh-reel-go').forEach(function(btn) { btn.disabled = (n === 0); });
}

// UI 1.8 - the comments persist even when the cached MP4 is gone (a fresh
// container, an evicted cache). Show the saved notes with a regenerate hint
// rather than a broken <video>.
function mhRenderReelCommentsOnly(panel, reelUrl, n) {
  panel.innerHTML =
    '<div style="font-size:13px;color:var(--ink);margin-bottom:8px;line-height:1.4">' +
      'You have <b>' + n + '</b> saved review ' + (n === 1 ? 'comment' : 'comments') + ' on this reel. ' +
      'Generate the reel above to see ' + (n === 1 ? 'it' : 'them') + ' pinned on the timeline.' +
    '</div>' +
    '<div class="mh-reel-comments"></div>';
  var mount = panel.querySelector('.mh-reel-comments');
  if (mount) mhReelComments({mount: mount, video: null, baseUrl: reelUrl + '/comments', target: 'reel'});
}

// UI 1.8 - timestamp-anchored review comments (Frame.io-style). Builds a
// scrubber track with a pin per comment, a "comment at <time>" composer that
// captures the current playhead, and a list with seek/resolve/delete. All
// user text goes in via textContent (never innerHTML) so a caption-style XSS
// can't ride a comment body; every write is a JSON POST (CSRF-exempt).
function mhReelComments(opts) {
  var mount = opts.mount, video = opts.video, baseUrl = opts.baseUrl, target = opts.target || 'reel';
  if (!mount) return;
  var state = { comments: [] };

  function fmtTime(ms) {
    var s = Math.max(0, Math.floor((ms || 0) / 1000));
    var m = Math.floor(s / 60), r = s % 60;
    return m + ':' + (r < 10 ? '0' : '') + r;
  }
  function curMs() { return (video && isFinite(video.currentTime)) ? Math.round(video.currentTime * 1000) : 0; }
  function timeline() {
    if (video && isFinite(video.duration) && video.duration > 0) return video.duration * 1000;
    var mx = 0; state.comments.forEach(function(c){ if (c.t_ms > mx) mx = c.t_ms; });
    return Math.max(mx * 1.08, 1000);
  }
  function jget(url) { return fetch(url, {headers:{'Accept':'application/json'}}).then(function(r){ return r.json(); }); }
  function jpost(url, body) {
    return fetch(url, {method:'POST', headers:{'Content-Type':'application/json','Accept':'application/json'}, body: JSON.stringify(body || {})})
      .then(function(r){ return r.json().then(function(j){ return {status:r.status, body:j}; }, function(){ return {status:r.status, body:null}; }); });
  }
  function showErr(m) { errEl.textContent = m; errEl.style.display = ''; setTimeout(function(){ errEl.style.display = 'none'; }, 4000); }

  mount.innerHTML =
    '<div style="display:flex;align-items:center;justify-content:space-between;gap:8px;margin-bottom:6px">' +
      '<div style="font-size:11px;text-transform:uppercase;letter-spacing:0.5px;color:var(--ink-muted)">Review comments <span class="mh-rc-count"></span></div>' +
      '<div style="font-size:11px;color:var(--ink-muted)">Pin feedback to a moment</div>' +
    '</div>' +
    '<div class="mh-rc-track" title="Click to seek" style="position:relative;height:26px;border-radius:6px;background:var(--panel);border:1px solid var(--border);margin-bottom:8px;cursor:pointer;overflow:hidden">' +
      '<div class="mh-rc-played" style="position:absolute;top:0;left:0;bottom:0;width:0;background:rgba(244,213,141,0.16);pointer-events:none"></div>' +
      '<div class="mh-rc-playhead" style="position:absolute;top:0;bottom:0;left:0;width:2px;background:var(--accent);pointer-events:none"></div>' +
    '</div>' +
    '<form class="mh-rc-form" style="display:flex;gap:6px;flex-wrap:wrap;align-items:center;margin-bottom:10px">' +
      '<span class="mh-rc-at" title="Pinned at this moment" style="font-variant-numeric:tabular-nums;font-size:12px;background:var(--accent);color:var(--medal-ink);border-radius:4px;padding:3px 8px;font-weight:700">0:00</span>' +
      '<input class="mh-rc-body" type="text" maxlength="2000" placeholder="Add a comment at this moment…" style="flex:1;min-width:160px;font-size:13px;padding:6px 10px;border-radius:6px;border:1px solid var(--border);background:var(--bg);color:var(--ink)" />' +
      '<input class="mh-rc-author" type="text" maxlength="120" placeholder="Your name" style="width:118px;font-size:12px;padding:6px 8px;border-radius:6px;border:1px solid var(--border);background:var(--bg);color:var(--ink)" />' +
      '<button type="submit" class="btn mh-rc-submit" style="font-size:12px;padding:6px 12px">Pin comment</button>' +
    '</form>' +
    '<div class="mh-rc-list" style="display:flex;flex-direction:column;gap:6px"></div>' +
    '<div class="mh-rc-err" style="display:none;color:var(--bad);font-size:12px;margin-top:6px"></div>';

  var track = mount.querySelector('.mh-rc-track');
  var played = mount.querySelector('.mh-rc-played');
  var playhead = mount.querySelector('.mh-rc-playhead');
  var atChip = mount.querySelector('.mh-rc-at');
  var form = mount.querySelector('.mh-rc-form');
  var bodyIn = mount.querySelector('.mh-rc-body');
  var authorIn = mount.querySelector('.mh-rc-author');
  var list = mount.querySelector('.mh-rc-list');
  var countEl = mount.querySelector('.mh-rc-count');
  var errEl = mount.querySelector('.mh-rc-err');

  try { authorIn.value = localStorage.getItem('mh_reviewer_name') || ''; } catch(e) {}
  var typing = false;
  bodyIn.addEventListener('focus', function(){ typing = true; });
  bodyIn.addEventListener('blur', function(){ typing = false; });

  function seekTo(ms) {
    if (video && isFinite(video.duration)) { try { video.currentTime = Math.min(video.duration, ms / 1000); video.pause(); } catch(e) {} }
  }
  function highlight(id) {
    var row = list.querySelector('.mh-rc-row[data-id="' + id + '"]');
    if (!row) return;
    row.style.outline = '2px solid var(--accent)';
    row.scrollIntoView({block:'nearest', behavior:'smooth'});
    setTimeout(function(){ row.style.outline = ''; }, 1500);
  }

  function renderMarkers() {
    Array.prototype.slice.call(track.querySelectorAll('.mh-rc-pin')).forEach(function(p){ p.remove(); });
    var tl = timeline();
    state.comments.forEach(function(c) {
      var pin = document.createElement('button');
      pin.type = 'button';
      pin.className = 'mh-rc-pin';
      pin.title = fmtTime(c.t_ms) + ' — ' + c.body;
      var pct = Math.max(0, Math.min(100, (c.t_ms / tl) * 100));
      pin.style.cssText = 'position:absolute;top:3px;bottom:3px;width:3px;border:0;padding:0;border-radius:2px;cursor:pointer;transform:translateX(-1px);left:' + pct + '%;background:' + (c.resolved ? 'var(--ink-muted)' : 'var(--medal)');
      pin.addEventListener('click', function(ev){ ev.stopPropagation(); seekTo(c.t_ms); highlight(c.id); });
      track.appendChild(pin);
    });
  }

  function renderList() {
    list.textContent = '';
    countEl.textContent = '· ' + state.comments.length;
    if (!state.comments.length) {
      var empty = document.createElement('div');
      empty.style.cssText = 'font-size:12px;color:var(--ink-muted);padding:6px 0';
      empty.textContent = 'No comments yet — scrub to a moment and pin the first note.';
      list.appendChild(empty);
      return;
    }
    state.comments.forEach(function(c) {
      var row = document.createElement('div');
      row.className = 'mh-rc-row';
      row.setAttribute('data-id', c.id);
      row.style.cssText = 'display:flex;gap:8px;align-items:flex-start;padding:6px 8px;border-radius:6px;border:1px solid var(--border);background:var(--panel)' + (c.resolved ? ';opacity:0.55' : '');

      var tbtn = document.createElement('button');
      tbtn.type = 'button';
      tbtn.textContent = fmtTime(c.t_ms);
      tbtn.title = 'Jump to this moment';
      tbtn.style.cssText = 'flex:0 0 auto;font-variant-numeric:tabular-nums;font-size:11px;font-weight:700;background:var(--medal);color:var(--medal-ink);border:0;border-radius:4px;padding:3px 7px;cursor:pointer';
      tbtn.addEventListener('click', function(){ seekTo(c.t_ms); });

      var mid = document.createElement('div');
      mid.style.cssText = 'flex:1;min-width:0';
      var bodyD = document.createElement('div');
      bodyD.style.cssText = 'font-size:13px;color:var(--ink);line-height:1.35;word-break:break-word' + (c.resolved ? ';text-decoration:line-through' : '');
      bodyD.textContent = c.body;
      var meta = document.createElement('div');
      meta.style.cssText = 'font-size:11px;color:var(--ink-muted);margin-top:2px';
      meta.textContent = c.author || 'Reviewer';
      mid.appendChild(bodyD); mid.appendChild(meta);

      var actions = document.createElement('div');
      actions.style.cssText = 'flex:0 0 auto;display:flex;gap:4px';
      var resBtn = document.createElement('button');
      resBtn.type = 'button';
      resBtn.className = 'btn secondary';
      resBtn.textContent = c.resolved ? 'Reopen' : 'Resolve';
      resBtn.style.cssText = 'font-size:11px;padding:3px 8px';
      resBtn.addEventListener('click', function(){ mutate(c.id, {action: c.resolved ? 'reopen' : 'resolve'}); });
      var delBtn = document.createElement('button');
      delBtn.type = 'button';
      delBtn.className = 'btn secondary';
      delBtn.textContent = 'Delete';
      delBtn.style.cssText = 'font-size:11px;padding:3px 8px';
      delBtn.addEventListener('click', function(){ if (window.confirm('Delete this comment?')) mutate(c.id, {action:'delete'}); });
      actions.appendChild(resBtn); actions.appendChild(delBtn);

      row.appendChild(tbtn); row.appendChild(mid); row.appendChild(actions);
      list.appendChild(row);
    });
  }

  function refresh() {
    jget(baseUrl + '?target=' + encodeURIComponent(target)).then(function(j) {
      state.comments = (j && j.comments) || [];
      renderMarkers(); renderList(); syncHead();
    }).catch(function(){});
  }
  function mutate(id, body) {
    jpost(baseUrl + '/' + encodeURIComponent(id), body).then(function(res) {
      if (res.status >= 200 && res.status < 300) refresh();
      else showErr((res.body && (res.body.detail || res.body.error)) || 'could not update comment');
    }).catch(function(err){ showErr('Network error: ' + err); });
  }

  form.addEventListener('submit', function(ev) {
    ev.preventDefault();
    var text = (bodyIn.value || '').trim();
    if (!text) { bodyIn.focus(); return; }
    var author = (authorIn.value || '').trim();
    try { if (author) localStorage.setItem('mh_reviewer_name', author); } catch(e) {}
    jpost(baseUrl, {target: target, t_ms: curMs(), body: text, author: author}).then(function(res) {
      if (res.status >= 200 && res.status < 300) { bodyIn.value = ''; refresh(); }
      else showErr((res.body && (res.body.detail || res.body.error)) || 'could not add comment');
    }).catch(function(err){ showErr('Network error: ' + err); });
  });

  track.addEventListener('click', function(ev) {
    var rect = track.getBoundingClientRect();
    if (!rect.width) return;
    seekTo(timeline() * Math.max(0, Math.min(1, (ev.clientX - rect.left) / rect.width)));
  });

  function syncHead() {
    var tl = timeline();
    var ms = curMs();
    var pct = tl > 0 ? Math.max(0, Math.min(100, (ms / tl) * 100)) : 0;
    playhead.style.left = pct + '%';
    played.style.width = pct + '%';
    if (!typing) atChip.textContent = fmtTime(ms);
  }
  if (video) {
    video.addEventListener('loadedmetadata', function(){ renderMarkers(); syncHead(); });
    video.addEventListener('timeupdate', syncHead);
    video.addEventListener('seeked', syncHead);
  }
  refresh();
}

function regenerateGraphic(btn, createUrl, cardId, assetId, noPhoto) {
  // V10: kick off a background variants job and poll for results. The old
  // synchronous request held the connection for every render (60-120s)
  // while promising "10-30 seconds" — long enough to look broken and to
  // flirt with proxy timeouts.
  var panel = document.querySelector('.visual-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  panel.style.display = '';
  var variantsUrl = createUrl.replace(/\\/create-graphic$/, '/regenerate-variants');
  // Carry the user's photo choice so the 3 variants keep that photo.
  var regenBody = {};
  if (assetId) regenBody.asset_id = assetId;
  if (noPhoto) regenBody.no_photo = true;
  var origLabel = btn.textContent;
  btn.disabled = true;
  btn.textContent = 'Generating 3 options\u2026';
  var prog = MH.renderProgress(panel, {label: 'Designing 3 options', sub: 'Renders run one at a time \u2014 usually 1\u20132 minutes', expectedMs: 90000, accent: 'lane'});
  function _vFail(msg) {
    prog.stop();
    btn.disabled = false; btn.textContent = origLabel;
    panel.innerHTML = '<div style="padding:14px;color:var(--bad);font-size:13px">' + window.safeText(msg) + '</div>';
  }
  fetch(variantsUrl, {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify(regenBody)})
    .then(function(r){ return r.json().then(function(j){ return {ok:r.ok, body:j}; }); })
    .then(function(res){
      if (!res.ok || !res.body || res.body.error || !res.body.job_id) {
        _vFail('Error: ' + ((res.body && (res.body.user_message || res.body.error)) || 'variants failed'));
        return;
      }
      var pollUrl = (window._API_BASE || '') + '/api/variant-jobs/' + encodeURIComponent(res.body.job_id);
      var started = Date.now();
      var timer = setInterval(function(){
        if (Date.now() - started > 6 * 60 * 1000) {
          clearInterval(timer);
          _vFail('Timed out waiting for variants. The renderer may be busy - try again in a minute.');
          return;
        }
        fetch(pollUrl, {cache:'no-store'})
          .then(function(r){ return r.json().then(function(j){ return {ok:r.ok, body:j}; }); })
          .then(function(st){
            if (!st.ok || !st.body || st.body.error) {
              clearInterval(timer);
              _vFail('Error: ' + ((st.body && st.body.error) || 'job lost'));
              return;
            }
            if (st.body.status === 'running') {
              var total = st.body.total || 3;
              var done = st.body.done || 0;
              var current = Math.min(done + 1, total);
              prog.setPhase('Designing option ' + current + ' of ' + total, done + ' of ' + total + ' finished');
              prog.setProgress(Math.round((done / total) * 100));
              return;
            }
            clearInterval(timer);
            var variants = (st.body.variants || []).filter(function(v){ return v.visual; });
            if (!variants.length) {
              _vFail('Error: ' + (st.body.error || 'no variants produced'));
              return;
            }
            prog.complete(function(){
              btn.disabled = false; btn.textContent = origLabel;
              _renderVariantPicker(panel, variants, cardId, createUrl);
            });
          })
          .catch(function(){ /* transient poll error - keep polling */ });
      }, 2500);
    })
    .catch(function(err){ _vFail('Network error: ' + err); });
}

function _renderVariantPicker(panel, variants, cardId, createUrl) {
  if (!variants.length) {
    panel.innerHTML = '<div style="padding:14px;color:var(--ink-muted);font-size:13px">No variants returned.</div>';
    return;
  }
  var apiBase = (window._API_BASE || '');
  var tilesHtml = variants.map(function(vt) {
    var v = vt.visual;
    if (!v) {
      return '<div style="flex:1;min-width:min(160px,100%);padding:14px;border:1px dashed var(--border);border-radius:8px;text-align:center;color:var(--bad);font-size:12px">Variant ' + vt.seed + ' failed: ' + window.safeText((vt.errors||[]).join("; ") || 'unknown') + '</div>';
    }
    var imgUrl = apiBase + '/api/visual/' + encodeURIComponent(v.id) + '/png/' + encodeURIComponent(v.format_name || 'feed_portrait');
    var label = (vt.brief && vt.brief.layout_template) || v.layout_template || ('Variant ' + vt.seed);
    var hook = (vt.brief && vt.brief.primary_hook) || '';
    return (
      '<div class="variant-tile" style="flex:1;min-width:min(160px,100%);background:color-mix(in oklab, var(--lane) 4%, transparent);border:1px solid var(--border);border-radius:8px;padding:8px">' +
        '<img src="' + imgUrl + '" alt="Variant ' + vt.seed + '" style="width:100%;border-radius:6px;background:#0a0a0a;display:block" />' +
        '<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-top:6px">Option ' + vt.seed + ' &middot; ' + window.safeText(label) + '</div>' +
        (hook ? '<div style="font-size:11px;color:var(--ink);margin-top:2px">' + window.safeText(hook) + '</div>' : '') +
        '<button class="btn" data-pick-vid="' + v.id + '" data-pick-seed="' + vt.seed + '" data-pick-fmt="' + (v.format_name || 'feed_portrait') + '" style="margin-top:6px;width:100%;font-size:11px;padding:5px 0" onclick=' + _attrEsc('pickVariant(this, ' + JSON.stringify(cardId) + ', ' + JSON.stringify(createUrl) + ')') + '>Pick this one</button>' +
      '</div>'
    );
  }).join('');
  panel.innerHTML =
    '<div style="font-size:11px;color:var(--ink-muted);margin-bottom:8px;text-transform:uppercase;letter-spacing:0.5px">Choose a variant</div>' +
    '<div style="display:flex;gap:10px;flex-wrap:wrap">' + tilesHtml + '</div>';
}

function pickVariant(btn, cardId, createUrl) {
  var vid = btn.dataset.pickVid;
  var seed = btn.dataset.pickSeed;
  var fmt = btn.dataset.pickFmt || 'feed_portrait';
  var apiBase = (window._API_BASE || '');
  var imgUrl = apiBase + '/api/visual/' + encodeURIComponent(vid) + '/png/' + encodeURIComponent(fmt);
  // Persist the choice in workflow sidecar
  var url = WF_API_BASE + encodeURIComponent(cardId);
  fetch(url, {method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify({action:'set_edits', edits:{picked_visual_id: vid, picked_variation_seed: seed}})}).catch(function(){});
  // Promote to primary view
  var panel = document.querySelector('.visual-panel[data-card="' + cardId + '"]');
  var fakeData = {
    visuals: [{id: vid, format_name: fmt, layout_template: btn.parentElement.querySelector('div').textContent || ''}],
    brief: {},
  };
  _renderVisualPanel(panel, fakeData, cardId, createUrl);
}

function addGraphicToPack(btn, visualId) {
  // Visuals are already persisted on render; this just confirms inclusion.
  btn.textContent = '\u2713 Added to pack';
  btn.disabled = true;
  setTimeout(function() { btn.textContent = '+ Add to pack'; btn.disabled = false; }, 2000);
}

// Poll LLM status on page load and every 30s afterwards. Self-healing:
// if a previous transient 429 painted the dot red, the next poll
// re-greens it once the rate-limit window has elapsed. Without this
// the user had to reload the page to recover from any blip.
(function pollLlmStatus(){
  function _tick() {
    try {
      var url = (window._API_BASE || '') + '/api/settings/llm-status';
      fetch(url, {cache:'no-store'})
        .then(function(r){ return r.json(); })
        .then(function(j){
          var dots = document.querySelectorAll('.ai-status-dot');
          var color = j.live ? '#2cc97f' : '#ff5d6c';
          var providerLabel = j.provider_label || 'AI key';
          var title = j.live
            ? ('Live AI enabled &mdash; provider: ' + providerLabel)
            : 'Live AI DISABLED &mdash; contact your administrator to enable AI captions.';
          dots.forEach(function(d){
            d.style.background = color;
            var btn = d.closest('button');
            if (btn) btn.title = title;
          });
        })
        .catch(function(){});
    } catch(e){}
  }
  _tick();
  setInterval(_tick, 30000);
})();

// ---- P6.1 — format catalogue picker + reformat ("turn this into that") ----
// Re-target an approved card design to any catalogue size/format. The server
// re-lays-out the approved brief for the new aspect (director + deterministic
// floor) and returns a PNG; we show it inline with a download link.
var _formatCatalogCache = null;
function reformatToggle(btn, cardId) {
  var panel = document.querySelector('.reformat-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  // First click: inline style is "none"; data-open tracks the toggle state.
  var showing = panel.getAttribute('data-open') === '1';
  if (showing) { panel.style.display = 'none'; panel.setAttribute('data-open', '0'); return; }
  panel.style.display = ''; panel.setAttribute('data-open', '1');
  if (panel.dataset.built === '1') return;
  panel.innerHTML = '<div style="font-size:12px;color:var(--ink-muted)">Loading formats…</div>';
  var build = function(cat) { _formatCatalogCache = cat; panel.dataset.built = '1'; _renderReformatPicker(panel, cardId, cat); };
  if (_formatCatalogCache) { build(_formatCatalogCache); return; }
  fetch(panel.dataset.formatsUrl).then(function(r){ return r.json(); }).then(build).catch(function(e){
    panel.innerHTML = '<div style="font-size:12px;color:var(--bad)">Could not load formats: ' + e + '</div>';
  });
}

function _renderReformatPicker(panel, cardId, cat) {
  var html = '<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-bottom:6px">Reformat this design</div>';
  (cat.groups || []).forEach(function(g){
    html += '<div style="margin:6px 0 3px;font-size:11px;font-weight:600;color:var(--ink-dim)">' + g.label + '</div><div style="display:flex;gap:5px;flex-wrap:wrap">';
    (g.formats || []).forEach(function(f){
      var ttl = f.title + ' · ' + f.width + '×' + f.height + (f.requires_post_types && f.requires_post_types.length ? ' (needs result data)' : '');
      html += '<button class="btn secondary" style="font-size:10px;padding:3px 8px" title="' + ttl + '" onclick=' + _attrEsc('reformatCard(this, ' + JSON.stringify(cardId) + ', ' + JSON.stringify(f.slug) + ')') + '>' + f.title + '</button>';
    });
    html += '</div>';
  });
  html += '<div style="margin-top:8px;display:flex;gap:5px;flex-wrap:wrap;align-items:center">' +
    '<input class="rf-w" type="number" min="200" max="10000" placeholder="W" aria-label="Custom width" style="width:62px;font-size:11px;padding:3px 6px;border:1px solid var(--border);border-radius:6px;background:rgba(255,255,255,0.04);color:inherit" />' +
    '<span style="color:var(--ink-muted)">×</span>' +
    '<input class="rf-h" type="number" min="200" max="10000" placeholder="H" aria-label="Custom height" style="width:62px;font-size:11px;padding:3px 6px;border:1px solid var(--border);border-radius:6px;background:rgba(255,255,255,0.04);color:inherit" />' +
    '<select class="rf-unit" aria-label="Unit" style="font-size:11px;padding:3px 6px;border:1px solid var(--border);border-radius:6px;background:rgba(255,255,255,0.04);color:inherit"><option value="px">px</option><option value="mm">mm</option><option value="cm">cm</option><option value="in">in</option></select>' +
    '<button class="btn secondary" style="font-size:10px;padding:3px 8px" onclick=' + _attrEsc('reformatCustom(this, ' + JSON.stringify(cardId) + ')') + '>Custom size</button>' +
    '<label style="font-size:11px;color:var(--ink-dim);display:inline-flex;align-items:center;gap:4px;margin-left:6px" title="Let the AI art director pick the best layout for the new shape"><input class="rf-ai" type="checkbox" /> AI re-layout</label>' +
    '</div>';
  html += '<div class="rf-result" style="margin-top:10px"></div>';
  panel.innerHTML = html;
}

function reformatCard(btn, cardId, slug) {
  var panel = document.querySelector('.reformat-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  var aiEl = panel.querySelector('.rf-ai');
  var url = panel.dataset.reformatUrl + '?format=' + encodeURIComponent(slug) + ((aiEl && aiEl.checked) ? '&ai=1' : '');
  _runReformat(panel, btn, url, slug.replace(/_/g, ' '));
}

function reformatCustom(btn, cardId) {
  var panel = document.querySelector('.reformat-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  var w = panel.querySelector('.rf-w').value, h = panel.querySelector('.rf-h').value;
  var unit = panel.querySelector('.rf-unit').value;
  if (!w || !h) { if (window.MH && MH.toast) MH.toast('Enter a width and height', 'error', 2500); return; }
  var aiEl = panel.querySelector('.rf-ai');
  var url = panel.dataset.reformatUrl + '?w=' + encodeURIComponent(w) + '&h=' + encodeURIComponent(h) + '&unit=' + encodeURIComponent(unit) + ((aiEl && aiEl.checked) ? '&ai=1' : '');
  _runReformat(panel, btn, url, 'custom ' + w + '×' + h + unit);
}

function _runReformat(panel, btn, url, label) {
  var result = panel.querySelector('.rf-result');
  var orig = btn.textContent;
  btn.disabled = true; btn.textContent = '…';
  if (result) result.innerHTML = '<div style="font-size:12px;color:var(--ink-muted)">Reformatting to ' + label + '… (5–20s)</div>';
  fetch(url, {method:'POST', headers:{'Content-Type':'application/json'}, body:'{}'})
    .then(function(r){
      var ct = r.headers.get('Content-Type') || '';
      if (r.ok && ct.indexOf('image') === 0) { return r.blob().then(function(b){ return {img: URL.createObjectURL(b)}; }); }
      return r.json().then(function(j){ return {err: (j && j.user_message) || (j && j.error) || 'Reformat failed'}; });
    })
    .then(function(res){
      btn.disabled = false; btn.textContent = orig;
      if (res.err) { if (result) result.innerHTML = '<div style="font-size:12px;color:var(--bad)">' + res.err + '</div>'; return; }
      if (result) result.innerHTML =
        '<div style="font-size:11px;color:var(--ink-muted);margin-bottom:4px">' + label + '</div>' +
        '<img src="' + res.img + '" alt="Reformatted design" style="max-width:100%;border-radius:6px;border:1px solid var(--border)" />' +
        '<div style="margin-top:6px"><a class="btn secondary" style="font-size:11px;padding:3px 10px" href="' + res.img + '" download="reformat.png">Download .png</a></div>';
    })
    .catch(function(e){
      btn.disabled = false; btn.textContent = orig;
      if (result) result.innerHTML = '<div style="font-size:12px;color:var(--bad)">Network error: ' + e + '</div>';
    });
}

// ---- P6.2 — conversational copilot (chat → validated spec-patch edits) ----
// Plain-words editing of an approved design: the server runs a bounded tool
// loop, applies only validated, on-brand, legible edits, and persists a new
// brief version; we show what changed and offer a live preview.
function copilotToggle(btn, cardId) {
  var panel = document.querySelector('.copilot-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  if (panel.getAttribute('data-open') === '1') { panel.style.display='none'; panel.setAttribute('data-open','0'); return; }
  panel.style.display=''; panel.setAttribute('data-open','1');
  if (panel.dataset.built === '1') return;
  panel.dataset.built = '1'; panel.dataset.session = '';
  panel.innerHTML =
    '<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-bottom:6px">Copilot &mdash; edit by conversation</div>' +
    '<div class="cp-suggest" style="display:flex;gap:5px;flex-wrap:wrap;margin-bottom:8px"></div>' +
    '<div class="cp-log" style="max-height:240px;overflow:auto;margin-bottom:8px"></div>' +
    '<div style="display:flex;gap:5px;align-items:center">' +
      '<input class="cp-input" type="text" placeholder="e.g. make the headline punchier, more navy" aria-label="Message the copilot" style="flex:1;font-size:12px;padding:5px 8px;border:1px solid var(--border);border-radius:6px;background:rgba(255,255,255,0.04);color:inherit;font-family:inherit" />' +
      '<button class="btn secondary cp-mic" style="font-size:12px;padding:5px 9px" title="Speak (your browser transcribes on-device)" onclick=' + _attrEsc('copilotMic(this, ' + JSON.stringify(cardId) + ')') + '>&#127908;</button>' +
      '<button class="btn cp-send" style="font-size:12px;padding:5px 12px;background:var(--lane);color:var(--lane-ink);border:none" onclick=' + _attrEsc('copilotSend(this, ' + JSON.stringify(cardId) + ')') + '>Send</button>' +
    '</div>' +
    '<div class="cp-status" style="font-size:11px;color:var(--ink-muted);margin-top:6px"></div>';
  fetch(panel.dataset.suggestUrl).then(function(r){return r.json();}).then(function(j){
    var box = panel.querySelector('.cp-suggest');
    (j.suggestions||[]).forEach(function(s){
      var b=document.createElement('button'); b.className='btn secondary'; b.style.cssText='font-size:10px;padding:2px 8px';
      b.textContent=s; b.onclick=function(){ panel.querySelector('.cp-input').value=s; panel.querySelector('.cp-input').focus(); };
      box.appendChild(b);
    });
  }).catch(function(){});
  panel.querySelector('.cp-input').addEventListener('keydown', function(e){ if(e.key==='Enter'){ copilotSend(panel.querySelector('.cp-send'), cardId); }});
}

/* One shared HTML escaper. Copilot replies, model-derived rejection reasons,
   comments and edit diffs are all server/LLM-echoed, so they must be escaped
   before touching innerHTML — a prompt-injection-to-XSS guard on the review
   surface. Previously `safeText` was only a local var in the caption closure
   and never global, so the `window.safeText?...` guards silently took the raw
   branch. Defined once here so every call below can be unconditional. */
window.safeText = window.safeText || function(t){ return String(t==null?'':t).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); };

function _cpAppend(panel, role, text) {
  var log = panel.querySelector('.cp-log');
  var who = role==='user' ? 'You' : 'Copilot';
  var col = role==='user' ? 'var(--ink)' : 'var(--lane)';
  var div = document.createElement('div'); div.style.cssText='margin-bottom:6px;font-size:12px';
  div.innerHTML = '<span style="color:'+col+';font-weight:600">'+who+':</span> ' + window.safeText(text);
  log.appendChild(div); log.scrollTop = log.scrollHeight;
  return div;
}

function copilotSend(btn, cardId) {
  var panel = document.querySelector('.copilot-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  var input = panel.querySelector('.cp-input');
  var msg = (input.value||'').trim();
  if (!msg) return;
  var status = panel.querySelector('.cp-status');
  _cpAppend(panel, 'user', msg);
  input.value=''; btn.disabled=true; status.textContent='Thinking…';
  var body = {message: msg};
  if (panel.dataset.session) body.session_id = panel.dataset.session;
  fetch(panel.dataset.assistantUrl, {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify(body)})
    .then(function(r){ return r.json().then(function(j){ return {ok:r.ok, j:j}; }); })
    .then(function(res){
      btn.disabled=false; status.textContent='';
      var j = res.j||{};
      if (!res.ok || j.error) { _cpAppend(panel, 'assistant', j.user_message || j.error || 'Something went wrong'); return; }
      if (j.session_id) panel.dataset.session = j.session_id;
      var d = _cpAppend(panel, 'assistant', j.reply || '(no reply)');
      var extra='';
      if (j.applied && j.applied.length) extra += '<div style="font-size:11px;color:var(--good);margin-top:2px">&#10003; ' + j.applied.length + ' change(s) applied</div>';
      if (j.rejected && j.rejected.length) {
        var reasons = j.rejected.map(function(x){return (x[1]||'');}).join('; ');
        extra += '<div style="font-size:11px;color:var(--bad);margin-top:2px">Skipped: ' + window.safeText(reasons) + '</div>';
      }
      if (j.changed && j.reformat_url && j.format) {
        var purl = j.reformat_url + '?format=' + encodeURIComponent(j.format);
        extra += '<div style="margin-top:4px"><button class="btn secondary" style="font-size:11px;padding:2px 9px" onclick=' + _attrEsc('copilotPreview(this, ' + JSON.stringify(purl) + ')') + '>Preview the edit</button></div>';
      }
      extra += '<div style="margin-top:4px"><button class="btn secondary" style="font-size:10px;padding:2px 8px" onclick="copilotRemember(this)" title="Save a standing preference the copilot will always respect">Remember a preference&hellip;</button></div>';
      d.innerHTML += extra;
      panel.querySelector('.cp-log').scrollTop = panel.querySelector('.cp-log').scrollHeight;
    })
    .catch(function(e){ btn.disabled=false; status.textContent=''; _cpAppend(panel,'assistant','Network error: '+e); });
}

function copilotPreview(btn, url) {
  var orig = btn.textContent; btn.disabled=true; btn.textContent='Rendering…';
  fetch(url, {method:'POST', headers:{'Content-Type':'application/json'}, body:'{}'})
    .then(function(r){ var ct=r.headers.get('Content-Type')||''; if (r.ok && ct.indexOf('image')===0) return r.blob().then(function(b){return {img:URL.createObjectURL(b)};}); return r.json().then(function(j){return {err:(j&&j.user_message)||'preview failed'};}); })
    .then(function(res){ btn.disabled=false; btn.textContent=orig;
      var holder=document.createElement('div'); holder.style.marginTop='6px';
      if (res.err) holder.innerHTML='<div style="font-size:11px;color:var(--bad)">'+window.safeText(res.err)+'</div>';
      else holder.innerHTML='<img src="'+res.img+'" alt="Edited design" style="max-width:100%;border-radius:6px;border:1px solid var(--border)" />';
      btn.parentNode.appendChild(holder);
    })
    .catch(function(e){ btn.disabled=false; btn.textContent=orig; });
}

function copilotRemember(btn) {
  var panel = btn.closest('.copilot-panel');
  var url = panel && panel.dataset.memoryUrl;
  if (!url) return;
  var txt = prompt('Save a standing preference the copilot will always respect (e.g. "never show times for 8-and-unders"):');
  if (!txt) return;
  fetch(url, {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({text: txt})})
    .then(function(r){return r.json();})
    .then(function(j){ if (window.MH && MH.toast) MH.toast(j.ok ? 'Saved — the copilot will remember that.' : (j.user_message||'Could not save'), j.ok?'success':'error', 3000); })
    .catch(function(){});
}

function copilotMic(btn, cardId) {
  var SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  var panel = document.querySelector('.copilot-panel[data-card="' + cardId + '"]');
  if (!SR) { if (window.MH && MH.toast) MH.toast('Voice input needs a browser with speech recognition — or just type.', 'info', 3500); return; }
  var rec = new SR(); rec.lang='en-GB'; rec.interimResults=false; rec.maxAlternatives=1;
  var orig = btn.textContent; btn.textContent='●'; btn.disabled=true;
  rec.onresult=function(e){ var t=(e.results[0][0]||{}).transcript||''; panel.querySelector('.cp-input').value=t; };
  rec.onend=function(){ btn.textContent=orig; btn.disabled=false; };
  rec.onerror=function(){ btn.textContent=orig; btn.disabled=false; };
  try { rec.start(); } catch(e) { btn.textContent=orig; btn.disabled=false; }
}

/* ---- Comments, @mentions & tasks (roadmap 1.18) ---- */
function _cmTxt(s){ return window.safeText(s); }
function _cmShortName(email){ if(!email) return 'Someone'; var i=email.indexOf('@'); return i>0?email.slice(0,i):email; }
function _cmAgo(ts){ try{ var d=Math.max(0,(Date.now()/1000)-ts); if(d<60)return'just now'; if(d<3600)return Math.floor(d/60)+'m ago'; if(d<86400)return Math.floor(d/3600)+'h ago'; return Math.floor(d/86400)+'d ago'; }catch(e){ return ''; } }

function commentsToggle(btn, cardId) {
  var panel = document.querySelector('.comments-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  if (panel.getAttribute('data-open') === '1') { panel.style.display='none'; panel.setAttribute('data-open','0'); return; }
  panel.style.display=''; panel.setAttribute('data-open','1');
  if (panel.dataset.built === '1') { commentsLoad(cardId); return; }
  panel.dataset.built = '1';
  panel.innerHTML =
    '<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-bottom:6px">Comments &amp; tasks &mdash; @mention a teammate; a task must be resolved before approval</div>' +
    '<div class="cm-list" style="max-height:280px;overflow:auto;margin-bottom:8px"></div>' +
    '<div style="display:flex;gap:5px;align-items:flex-start;flex-wrap:wrap">' +
      '<textarea class="cm-input" rows="2" placeholder="Add a comment&hellip; use @name to mention" aria-label="Add a comment" style="flex:1;min-width:180px;font-size:12px;padding:5px 8px;border:1px solid var(--border);border-radius:6px;background:rgba(255,255,255,0.04);color:inherit;font-family:inherit"></textarea>' +
    '</div>' +
    '<div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;margin-top:6px">' +
      '<label style="font-size:11px;color:var(--ink-muted)"><input type="checkbox" class="cm-is-task"/> as task</label>' +
      '<input class="cm-assignee" type="text" placeholder="assignee email (optional)" aria-label="Task assignee" style="display:none;font-size:11px;padding:4px 8px;border:1px solid var(--border);border-radius:6px;background:rgba(255,255,255,0.04);color:inherit;font-family:inherit;min-width:160px"/>' +
      '<span class="cm-reply-tag" style="display:none;font-size:11px;color:var(--lane)"></span>' +
      '<button class="btn cm-send" style="font-size:11px;padding:4px 12px;background:var(--lane);color:var(--lane-ink);border:none" onclick=' + _attrEsc('commentsSend(this, ' + JSON.stringify(cardId) + ')') + '>Post</button>' +
    '</div>' +
    '<div class="cm-status" style="font-size:11px;color:var(--ink-muted);margin-top:6px"></div>';
  panel.querySelector('.cm-is-task').addEventListener('change', function(){
    panel.querySelector('.cm-assignee').style.display = this.checked ? '' : 'none';
  });
  commentsLoad(cardId);
}

function commentsLoad(cardId) {
  var panel = document.querySelector('.comments-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  var realCard = panel.dataset.realCard || '';
  var url = panel.dataset.commentsUrl + '?card_id=' + encodeURIComponent(realCard);
  fetch(url).then(function(r){return r.json();}).then(function(j){
    if (!j.ok) return;
    panel.dataset.me = j.me || '';
    commentsRender(panel, cardId, j.comments||[]);
    var badge = document.querySelector('.comments-count[data-card="' + cardId + '"]');
    if (badge) { var n=(j.comments||[]).length; var t=j.open_tasks||0; badge.textContent = n? (' '+n+(t?(' · '+t+'☑'):'')) : ''; }
  }).catch(function(){});
}

function commentsRender(panel, cardId, comments) {
  var list = panel.querySelector('.cm-list');
  list.textContent='';
  if (!comments.length) { var e=document.createElement('div'); e.style.cssText='font-size:12px;color:var(--ink-muted)'; e.textContent='No comments yet.'; list.appendChild(e); return; }
  var me = panel.dataset.me || '';
  // group replies under roots by thread_id
  var roots = comments.filter(function(c){ return !c.parent_id; });
  var repliesByThread = {};
  comments.forEach(function(c){ if (c.parent_id){ (repliesByThread[c.thread_id]=repliesByThread[c.thread_id]||[]).push(c); } });
  roots.forEach(function(c){
    list.appendChild(commentsRow(panel, cardId, c, me, false));
    (repliesByThread[c.thread_id]||[]).forEach(function(r){ list.appendChild(commentsRow(panel, cardId, r, me, true)); });
  });
}

function commentsRow(panel, cardId, c, me, isReply) {
  var row = document.createElement('div');
  row.style.cssText = 'margin-bottom:8px;padding:7px 9px;border:1px solid var(--border);border-radius:6px;background:rgba(255,255,255,0.02)' + (isReply?';margin-left:18px':'') + (c.resolved?';opacity:0.6':'');
  var isTask = c.kind === 'task';
  var head = document.createElement('div');
  head.style.cssText='font-size:11px;color:var(--ink-muted);margin-bottom:3px;display:flex;gap:6px;align-items:center;flex-wrap:wrap';
  var tag = isTask ? ('<span style="color:var(--medal);font-weight:600">☑ TASK'+(c.assignee_email?(' → '+_cmTxt(_cmShortName(c.assignee_email))):'')+(c.resolved?' · done':'')+'</span> ') : '';
  head.innerHTML = tag + '<strong style="color:var(--ink)">' + _cmTxt(_cmShortName(c.author_email)) + '</strong> <span>' + _cmAgo(c.created_at) + '</span>';
  row.appendChild(head);
  var body = document.createElement('div'); body.style.cssText='font-size:12px;color:var(--ink);white-space:pre-wrap'; body.textContent = c.body; row.appendChild(body);
  // reactions
  var rx = document.createElement('div'); rx.style.cssText='margin-top:5px;display:flex;gap:5px;flex-wrap:wrap;align-items:center';
  var reactions = c.reactions||{};
  Object.keys(reactions).forEach(function(em){
    var b=document.createElement('button'); b.className='btn secondary'; b.style.cssText='font-size:11px;padding:1px 7px';
    b.textContent = em + ' ' + reactions[em].length;
    b.onclick=function(){ commentsReact(cardId, c.id, em); };
    rx.appendChild(b);
  });
  ['👍','✅','🎉'].forEach(function(em){
    var b=document.createElement('button'); b.className='btn secondary'; b.style.cssText='font-size:11px;padding:1px 6px;opacity:0.7';
    b.textContent=em; b.title='React'; b.onclick=function(){ commentsReact(cardId, c.id, em); };
    rx.appendChild(b);
  });
  row.appendChild(rx);
  // actions
  var act = document.createElement('div'); act.style.cssText='margin-top:5px;display:flex;gap:8px;flex-wrap:wrap';
  if (!isReply) {
    var reply=document.createElement('a'); reply.href='#'; reply.style.cssText='font-size:11px;color:var(--lane)'; reply.textContent='Reply';
    reply.onclick=function(ev){ ev.preventDefault(); commentsSetReply(cardId, c.id, _cmShortName(c.author_email)); }; act.appendChild(reply);
  }
  if (isTask) {
    var done=document.createElement('a'); done.href='#'; done.style.cssText='font-size:11px;color:var(--medal)';
    done.textContent = c.resolved ? 'Reopen task' : 'Mark done';
    done.onclick=function(ev){ ev.preventDefault(); commentsMutate(cardId, c.id, c.resolved?'reopen':'complete'); }; act.appendChild(done);
  } else if (!isReply) {
    var res=document.createElement('a'); res.href='#'; res.style.cssText='font-size:11px;color:var(--ink-muted)';
    res.textContent = c.resolved ? 'Reopen' : 'Resolve';
    res.onclick=function(ev){ ev.preventDefault(); commentsMutate(cardId, c.id, c.resolved?'reopen':'resolve'); }; act.appendChild(res);
  }
  if ((c.author_email||'') === (me||'') || !me) {
    var del=document.createElement('a'); del.href='#'; del.style.cssText='font-size:11px;color:var(--bad)'; del.textContent='Delete';
    del.onclick=function(ev){ ev.preventDefault(); if(confirm('Delete this comment?')) commentsMutate(cardId, c.id, 'delete'); }; act.appendChild(del);
  }
  row.appendChild(act);
  return row;
}

function commentsSetReply(cardId, parentId, who) {
  var panel = document.querySelector('.comments-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  panel.dataset.replyTo = parentId;
  var tag = panel.querySelector('.cm-reply-tag');
  tag.style.display=''; tag.textContent='Replying to ' + who + ' ✕';
  tag.style.cursor='pointer'; tag.onclick=function(){ panel.dataset.replyTo=''; tag.style.display='none'; };
  panel.querySelector('.cm-input').focus();
}

function commentsSend(btn, cardId) {
  var panel = document.querySelector('.comments-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  var input = panel.querySelector('.cm-input');
  var body = (input.value||'').trim();
  if (!body) return;
  var status = panel.querySelector('.cm-status');
  var isTask = panel.querySelector('.cm-is-task').checked;
  var payload = { card_id: panel.dataset.realCard || '', body: body, kind: isTask?'task':'comment' };
  if (isTask) payload.assignee = (panel.querySelector('.cm-assignee').value||'').trim();
  if (panel.dataset.replyTo) payload.parent_id = panel.dataset.replyTo;
  btn.disabled=true; status.textContent='Posting…';
  fetch(panel.dataset.commentsUrl, {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify(payload)})
    .then(function(r){ return r.json().then(function(j){ return {ok:r.ok, j:j}; }); })
    .then(function(res){
      btn.disabled=false;
      if (!res.ok || res.j.error) { status.textContent = res.j.reason || res.j.detail || res.j.error || 'Could not post'; return; }
      status.textContent=''; input.value=''; panel.querySelector('.cm-is-task').checked=false;
      panel.querySelector('.cm-assignee').style.display='none'; panel.querySelector('.cm-assignee').value='';
      panel.dataset.replyTo=''; var tg=panel.querySelector('.cm-reply-tag'); if(tg) tg.style.display='none';
      commentsLoad(cardId);
    }).catch(function(){ btn.disabled=false; status.textContent='Network error'; });
}

function commentsMutate(cardId, commentId, action) {
  var panel = document.querySelector('.comments-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  fetch(panel.dataset.commentsUrl + '/' + encodeURIComponent(commentId), {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({action: action})})
    .then(function(r){return r.json();}).then(function(){ commentsLoad(cardId); }).catch(function(){});
}

function commentsReact(cardId, commentId, emoji) {
  var panel = document.querySelector('.comments-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  fetch(panel.dataset.commentsUrl + '/' + encodeURIComponent(commentId), {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({action:'react', emoji: emoji})})
    .then(function(r){return r.json();}).then(function(){ commentsLoad(cardId); }).catch(function(){});
}

/* ---- Version history: diff + restore (roadmap 1.18) ---- */
function historyToggle(btn, cardId) {
  var panel = document.querySelector('.history-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  if (panel.getAttribute('data-open') === '1') { panel.style.display='none'; panel.setAttribute('data-open','0'); return; }
  panel.style.display=''; panel.setAttribute('data-open','1');
  panel.innerHTML = '<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-bottom:6px">Version history</div><div class="hist-list" style="font-size:12px;color:var(--ink-muted)">Loading&hellip;</div><div class="hist-diff" style="margin-top:8px"></div>';
  historyLoad(cardId);
}

function historyLoad(cardId) {
  var panel = document.querySelector('.history-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  fetch(panel.dataset.revisionsUrl).then(function(r){return r.json();}).then(function(j){
    var list = panel.querySelector('.hist-list'); list.textContent='';
    if (!j.ok || !(j.revisions||[]).length) { list.textContent='No saved versions yet — edit the design to start a history.'; return; }
    var revs = j.revisions;
    revs.forEach(function(rev, i){
      var row=document.createElement('div'); row.style.cssText='display:flex;gap:8px;align-items:center;padding:5px 0;border-bottom:1px solid var(--border);flex-wrap:wrap';
      var num=document.createElement('span'); num.style.cssText='font-size:11px;color:var(--ink-muted);min-width:24px'; num.textContent='v'+(i+1);
      var lab=document.createElement('span'); lab.style.cssText='flex:1;font-size:12px;color:var(--ink)'; lab.textContent = rev.label + (rev.is_current?'  (current)':'');
      row.appendChild(num); row.appendChild(lab);
      if (i>0) { var d=document.createElement('a'); d.href='#'; d.style.cssText='font-size:11px;color:var(--lane)'; d.textContent='Diff vs previous';
        d.onclick=function(ev){ ev.preventDefault(); historyDiff(cardId, revs[i-1].brief_id, rev.brief_id); }; row.appendChild(d); }
      if (!rev.is_current) { var rb=document.createElement('a'); rb.href='#'; rb.style.cssText='font-size:11px;color:var(--medal)'; rb.textContent='Restore';
        rb.onclick=function(ev){ ev.preventDefault(); historyRestore(cardId, rev.brief_id); }; row.appendChild(rb); }
      list.appendChild(row);
    });
  }).catch(function(){});
}

function historyDiff(cardId, a, b) {
  var panel = document.querySelector('.history-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  var base = panel.dataset.revisionsUrl + '/diff?a=' + encodeURIComponent(a) + '&b=' + encodeURIComponent(b);
  fetch(base).then(function(r){return r.json();}).then(function(j){
    var box = panel.querySelector('.hist-diff'); box.textContent='';
    if (!j.ok) return;
    if (!(j.diff||[]).length) { box.textContent='No design fields differ between these versions.'; box.style.cssText='font-size:12px;color:var(--ink-muted)'; return; }
    var t=document.createElement('div'); t.style.cssText='font-size:11px';
    j.diff.forEach(function(d){
      var r=document.createElement('div'); r.style.cssText='margin-bottom:4px';
      r.innerHTML = '<strong style="color:var(--ink)">'+_cmTxt(d.field)+'</strong>: <span style="color:var(--ink-muted);text-decoration:line-through">'+_cmTxt(d.before||'—')+'</span> &rarr; <span style="color:var(--lane)">'+_cmTxt(d.after||'—')+'</span>';
      t.appendChild(r);
    });
    box.appendChild(t);
  }).catch(function(){});
}

function historyRestore(cardId, briefId) {
  if (!confirm('Restore this version? It becomes the current design (earlier versions are kept).')) return;
  var panel = document.querySelector('.history-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  fetch(panel.dataset.revisionsUrl + '/restore', {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({brief_id: briefId})})
    .then(function(r){return r.json();}).then(function(j){
      if (j.ok) { if (window.MH && MH.toast) MH.toast('Version restored — regenerate the graphic to see it.', 'success', 3500); historyLoad(cardId); }
      else if (window.MH && MH.toast) MH.toast(j.reason || 'Could not restore', 'error', 3000);
    }).catch(function(){});
}

/* ---- Element locks (roadmap 1.18) ---- */
function locksToggle(btn, cardId) {
  var panel = document.querySelector('.locks-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  if (panel.getAttribute('data-open') === '1') { panel.style.display='none'; panel.setAttribute('data-open','0'); return; }
  panel.style.display=''; panel.setAttribute('data-open','1');
  panel.innerHTML = '<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-bottom:6px">Locked elements &mdash; a locked element cannot be changed by an edit or the copilot</div><div class="locks-list" style="display:flex;gap:6px;flex-wrap:wrap">Loading&hellip;</div>';
  locksLoad(cardId);
}

function locksLoad(cardId) {
  var panel = document.querySelector('.locks-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  fetch(panel.dataset.locksUrl).then(function(r){return r.json();}).then(function(j){
    var list = panel.querySelector('.locks-list'); list.textContent='';
    if (!j.ok) return;
    var locked = {}; (j.locked||[]).forEach(function(e){ locked[e]=1; });
    (j.lockable||[]).forEach(function(el){
      var on = !!locked[el];
      var b=document.createElement('button'); b.className='btn ' + (on?'':'secondary');
      b.style.cssText='font-size:11px;padding:3px 9px' + (on?';background:var(--medal);color:var(--medal-ink);border:none':'');
      b.textContent = (on?'🔒 ':'🔓 ') + el;
      b.onclick=function(){ locksSet(cardId, el, !on); };
      list.appendChild(b);
    });
  }).catch(function(){});
}

function locksSet(cardId, element, locked) {
  var panel = document.querySelector('.locks-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  fetch(panel.dataset.locksUrl, {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({element: element, locked: locked})})
    .then(function(r){return r.json().then(function(j){return {ok:r.ok,j:j};});}).then(function(res){
      if (!res.ok) { if (window.MH && MH.toast) MH.toast(res.j.reason || 'Could not change lock', 'error', 3000); return; }
      locksLoad(cardId);
    }).catch(function(){});
}

/* ---- Share for review: expiring external links (roadmap 1.18) ---- */
function shareToggle(btn, cardId) {
  var panel = document.querySelector('.share-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  if (panel.getAttribute('data-open') === '1') { panel.style.display='none'; panel.setAttribute('data-open','0'); return; }
  panel.style.display=''; panel.setAttribute('data-open','1');
  if (panel.dataset.built !== '1') {
    panel.dataset.built = '1';
    panel.innerHTML =
      '<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);letter-spacing:0.5px;margin-bottom:6px">Share this card for review (no account needed)</div>' +
      '<div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;margin-bottom:8px">' +
        '<select class="sh-perm" style="font-size:12px;padding:4px 8px;border:1px solid var(--border);border-radius:6px;background:rgba(255,255,255,0.04);color:inherit"><option value="view">View only</option><option value="comment">Can comment</option></select>' +
        '<label style="font-size:11px;color:var(--ink-muted)">expires in <input class="sh-ttl" type="number" min="1" max="90" value="7" style="width:56px;padding:4px 6px;border:1px solid var(--border);border-radius:6px;background:rgba(255,255,255,0.04);color:inherit"/> days</label>' +
        '<button class="btn sh-create" style="font-size:11px;padding:4px 12px;background:var(--lane);color:var(--lane-ink);border:none" onclick=' + _attrEsc('shareCreate(this, ' + JSON.stringify(cardId) + ')') + '>Create link</button>' +
      '</div>' +
      '<div class="sh-list" style="font-size:12px"></div>' +
      '<div class="sh-status" style="font-size:11px;color:var(--ink-muted);margin-top:6px"></div>';
  }
  shareLoad(cardId);
}

function shareLoad(cardId) {
  var panel = document.querySelector('.share-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  var realCard = panel.dataset.realCard || '';
  fetch(panel.dataset.sharesUrl).then(function(r){return r.json().then(function(j){return {ok:r.ok,j:j};});}).then(function(res){
    var list = panel.querySelector('.sh-list'); list.textContent='';
    if (!res.ok) { list.textContent = res.j.reason || 'Only an owner can manage share links.'; return; }
    var mine = (res.j.shares||[]).filter(function(s){ return s.card_id === realCard; });
    if (!mine.length) { list.textContent = 'No active links for this card.'; return; }
    mine.forEach(function(s){
      var row=document.createElement('div'); row.style.cssText='display:flex;gap:8px;align-items:center;padding:5px 0;border-top:1px solid var(--border);flex-wrap:wrap';
      var inp=document.createElement('input'); inp.type='text'; inp.readOnly=true; inp.value=s.url;
      inp.style.cssText='flex:1;min-width:160px;font-size:11px;padding:4px 6px;border:1px solid var(--border);border-radius:6px;background:rgba(255,255,255,0.04);color:inherit';
      inp.onclick=function(){ inp.select(); };
      var tag=document.createElement('span'); tag.style.cssText='font-size:11px;color:var(--ink-muted)'; tag.textContent = (s.perm==='comment'?'can comment':'view only');
      var rev=document.createElement('a'); rev.href='#'; rev.style.cssText='font-size:11px;color:var(--bad)'; rev.textContent='Revoke';
      rev.onclick=function(ev){ ev.preventDefault(); shareRevoke(cardId, s.token); };
      row.appendChild(inp); row.appendChild(tag); row.appendChild(rev); list.appendChild(row);
    });
  }).catch(function(){});
}

function shareCreate(btn, cardId) {
  var panel = document.querySelector('.share-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  var perm = panel.querySelector('.sh-perm').value;
  var ttl = parseInt(panel.querySelector('.sh-ttl').value, 10) || 7;
  var status = panel.querySelector('.sh-status');
  btn.disabled=true; status.textContent='Creating…';
  fetch(panel.dataset.sharesUrl, {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({card_id: panel.dataset.realCard||'', perm: perm, ttl_days: ttl})})
    .then(function(r){return r.json().then(function(j){return {ok:r.ok,j:j};});}).then(function(res){
      btn.disabled=false;
      if (!res.ok) { status.textContent = res.j.reason || res.j.detail || 'Could not create link'; return; }
      status.textContent=''; shareLoad(cardId);
    }).catch(function(){ btn.disabled=false; status.textContent='Network error'; });
}

function shareRevoke(cardId, token) {
  if (!confirm('Revoke this link? Anyone holding it loses access immediately.')) return;
  var panel = document.querySelector('.share-panel[data-card="' + cardId + '"]');
  if (!panel) return;
  fetch(panel.dataset.sharesUrl + '/' + encodeURIComponent(token) + '/revoke', {method:'POST', headers:{'Content-Type':'application/json'}, body:'{}'})
    .then(function(r){return r.json();}).then(function(){ shareLoad(cardId); }).catch(function(){});
}
</script>
"""
    )


def _schedule_button_html(run_id: str, card_id_raw, el_id: str) -> str:
    """Render the per-card "Schedule" affordance as a disabled "Coming soon"
    chip. Auto scheduling content straight onto a social page has been
    withdrawn; approved cards are still fully exportable/downloadable for
    manual posting. The chip keeps the toolbar's shape so the feature can be
    reintroduced later without a layout change.
    """
    if not card_id_raw:
        return ""
    return (
        '<span class="btn secondary" aria-disabled="true" '
        'style="font-size:11px;padding:4px 10px;opacity:0.6;cursor:default" '
        'title="Auto scheduling to social is coming soon">Schedule &middot; Coming soon</span>'
    )


def _render_stored_translations(card: dict) -> str:
    """Server-side render of a card's SAVED translations (1.24 bilingual pairs).

    The on-demand "Translate to…" control shows a variant only in the seconds
    after the user clicks it; the variant is persisted on the card's workflow
    state, but without this it would never reappear. This renders every saved
    variant from ``card["workflow"]["translations"]`` so the bilingual approval
    pair survives a page refresh — server-side and ``_h``-escaped (the persisted
    text came from a provider, so it is treated as untrusted and never injected
    raw). Empty string when the card has no saved translations (byte-identical
    to before for the common case)."""
    wf = card.get("workflow") if isinstance(card, dict) else None
    translations = (wf or {}).get("translations") if isinstance(wf, dict) else None
    if not isinstance(translations, dict) or not translations:
        return ""
    rows: list[str] = []
    for _lang, variant in translations.items():
        if not isinstance(variant, dict):
            continue
        caption = str((variant.get("slots") or {}).get("caption") or "").strip()
        if not caption:
            continue
        label = str(variant.get("language_label") or _lang or "Translation")
        direction = "rtl" if variant.get("rtl") else "auto"
        rows.append(
            '<div style="margin-top:6px;padding:8px 10px;border:1px solid var(--border);'
            'border-radius:6px;background:color-mix(in oklab, var(--lane) 3%, transparent)">'
            '<div style="font-size:10px;color:var(--ink-muted);text-transform:uppercase;'
            f'letter-spacing:0.5px;margin-bottom:4px">{_h(label)} &middot; saved with this card</div>'
            f'<span style="white-space:pre-wrap" dir="{direction}">{_h(caption)}</span>'
            "</div>"
        )
    if not rows:
        return ""
    return (
        '<div class="mh-stored-translations" style="margin-top:8px">'
        '<div style="font-size:11px;color:var(--ink-dim)">Saved translations</div>'
        + "".join(rows)
        + "</div>"
    )


# Fixed slug order for the review-screen assist buttons. `fuller`/`calmer`
# remain opt-in presets with no button; labels come from
# caption_assist.PRESET_LABELS so a label change propagates to every row.
_ASSIST_BUTTON_ORDER = ("shorter", "punchier", "add_time", "tidy", "summarise", "expand", "rewrite")
_ASSIST_BUTTON_TITLES = {
    "summarise": "One tight sentence",
    "expand": "Add one on-brand detail",
    "rewrite": "Fresh angle, same facts",
}


def _caption_assist_buttons(card_uuid: str) -> str:
    """Build the review-screen Assist button row from caption_assist.PRESET_LABELS."""
    from mediahub.web.caption_assist import PRESET_LABELS

    out = []
    for slug in _ASSIST_BUTTON_ORDER:
        label = _h(PRESET_LABELS.get(slug, slug))
        title = _ASSIST_BUTTON_TITLES.get(slug)
        title_attr = f' title="{_h(title)}"' if title else ""
        out.append(
            f'<button class="btn secondary" style="font-size:11px;padding:3px 9px" '
            f"onclick=\"captionAssistRun(this, '{card_uuid}', '{slug}')\"{title_attr}>{label}</button>"
        )
    return "".join(out)


# M35 (UX-6) — styling + behaviour for the per-card "More" overflow popover.
# Emitted once per host page (the Content builder). Pure details/summary +
# a click-outside closer: no new JS framework, dark-first via the existing
# --panel/--border vars.
_CARD_TOOLBAR_CSS = """
.mh-card-more { position: relative; display: inline-block; }
.mh-card-more > summary { list-style: none; cursor: pointer; user-select: none; display: inline-flex; align-items: center; gap: 4px; }
.mh-card-more > summary::-webkit-details-marker { display: none; }
.mh-card-more[open] > summary { border-color: var(--lane); color: var(--lane); }
.mh-card-more-menu { position: absolute; right: 0; top: calc(100% + 6px); z-index: 60;
  min-width: 190px; display: flex; flex-direction: column; gap: 4px; padding: 8px;
  background: var(--panel); border: 1px solid var(--border); border-radius: 10px;
  box-shadow: 0 12px 32px rgba(0,0,0,0.4); }
.mh-card-more-menu .btn { width: 100%; text-align: left; justify-content: flex-start; }
"""

_CARD_TOOLBAR_JS = """
<script>
// M35 — close an open per-card "More" popover on outside click or Escape,
// and after choosing an action inside it (the chosen panel opens below).
document.addEventListener('click', function(e){
  document.querySelectorAll('details.mh-card-more[open]').forEach(function(d){
    if (!d.contains(e.target)) { d.open = false; return; }
    if (e.target.closest('.mh-card-more-menu button, .mh-card-more-menu a')) {
      setTimeout(function(){ d.open = false; }, 0);
    }
  });
});
document.addEventListener('keydown', function(e){
  if (e.key === 'Escape') {
    document.querySelectorAll('details.mh-card-more[open]').forEach(function(d){ d.open = false; });
  }
});
</script>
"""


def _render_card_creative_toolbar(
    run_id: str,
    card_id_raw: str,
    *,
    initial_visual_html: str = "",
    initial_motion_html: str = "",
) -> str:
    """Per-card creative toolbar for the Content builder (post-approval).

    M35 (UX-6) layout: the two actions a volunteer actually needs — Create
    graphic and Generate motion — stay primary-styled and inline with Copy
    caption; the collaboration/power features (Reformat, Copilot, Comments,
    History, Locks, Share, Schedule, Voiceover) live in one "More" overflow
    (a ``<details>`` popover, no new JS framework), and the caption actions
    (Regenerate, Assist) dock under the caption tone panel where the caption
    lives. Same handlers, same panels — only the trigger layout changed.

    ``initial_visual_html`` / ``initial_motion_html`` (M30/M32): server-
    rendered content for the visual / motion panels so a page load shows the
    run's already-rendered PNGs and MP4s without a re-render; empty keeps the
    legacy hidden-empty panels. Pairs with `_card_creative_js()` on the host
    page. `card_id_raw` is the swim_id."""
    card_uuid = str(card_id_raw).replace(":", "_").replace(",", "_")
    _caption_url = url_for("api_live_caption", run_id=run_id, swim_id=card_id_raw)
    _create_graphic_url = url_for("api_create_graphic", run_id=run_id, card_id=card_id_raw)
    _motion_url = url_for("api_card_motion", run_id=run_id, card_id=card_id_raw)
    _reformat_url = url_for("api_card_reformat", run_id=run_id, card_id=card_id_raw)
    _formats_url = url_for("api_formats")
    _assistant_url = url_for("api_card_assistant", run_id=run_id, card_id=card_id_raw)
    _assistant_suggest_url = url_for(
        "api_assistant_suggestions", run_id=run_id, card_id=card_id_raw
    )
    _assistant_memory_url = url_for("api_assistant_memory")
    _comments_url = url_for("api_collab_comments", run_id=run_id)
    _revisions_url = url_for("api_card_revisions", run_id=run_id, card_id=card_id_raw)
    _locks_url = url_for("api_card_locks", run_id=run_id, card_id=card_id_raw)
    _shares_url = url_for("api_run_shares", run_id=run_id)

    _STD_TONES = [
        (
            "ai",
            "✦ AI",
            True,
            "tone-tab-ai",
            "color-mix(in oklab, var(--lane) 15%, transparent)",
            "var(--lane)",
            "Live AI caption. Generates fresh each time.",
        ),
        (
            "warm-club",
            "Warm",
            False,
            "",
            "color-mix(in oklab, var(--lane) 15%, transparent)",
            "var(--accent)",
            "Warm & community — friendly, first-name, inclusive.",
        ),
        (
            "hype",
            "Hype",
            False,
            "",
            "color-mix(in oklab, var(--lane) 15%, transparent)",
            "var(--accent)",
            "Energetic & hype — race-day language, high energy.",
        ),
        (
            "data-led",
            "Precise",
            False,
            "",
            "color-mix(in oklab, var(--lane) 15%, transparent)",
            "var(--accent)",
            "Data-led — numbers first, sponsor-friendly, no fluff.",
        ),
    ]
    tabs_html = ""
    panels_html = ""
    for t_key, t_label, is_active, extra_cls, active_bg, active_fg, title in _STD_TONES:
        init_bg = active_bg if is_active else "transparent"
        init_fg = active_fg if is_active else "var(--ink-dim)"
        active_attr = "active" if is_active else ""
        display = "" if is_active else "display:none"
        status_dot = (
            '<span class="ai-status-dot" style="display:inline-block;width:7px;height:7px;'
            'border-radius:50%;background:#ffae3b" aria-hidden="true"></span>'
            if t_key == "ai"
            else ""
        )
        tabs_html += (
            f'<button class="tone-tab {extra_cls} {active_attr}" '
            f'data-card="{card_uuid}" data-tone="{t_key}" '
            f'onclick="switchToneLive(this, {repr(_caption_url)}, {repr(card_uuid)})" '
            f'title="{_h(title)}" '
            f'style="font-size:11px;padding:3px 10px;border-radius:999px;border:1px solid var(--border);'
            f"cursor:pointer;background:{init_bg};color:{init_fg};"
            f"font-family:inherit;margin-right:4px;font-weight:{'600' if is_active else '400'};"
            f'display:inline-flex;align-items:center;gap:5px">'
            f"{status_dot}{_h(t_label)}</button>"
        )
        panels_html += (
            f'<div class="tone-panel" data-tone="{t_key}" data-card="{card_uuid}" style="{display}">'
            f'<div class="caption-text" style="font-size:12px;color:var(--ink);white-space:pre-wrap">'
            f'<span class="caption-placeholder" style="color:var(--ink-muted);font-style:italic">'
            f"Click to generate&hellip;</span></div>"
            f'<textarea class="caption-textarea" dir="auto" style="display:none"></textarea>'
            f"</div>"
        )

    _wf_card_el_id = f"wf-{card_uuid}"
    schedule_btn = _schedule_button_html(run_id, card_id_raw, _wf_card_el_id)

    # Voiceover (roadmap: audio & voiceover) — only rendered when the operator
    # opted in (MEDIAHUB_VOICEOVER=1 + importable backend). The route itself
    # re-checks approval and availability; this is just the reachable control.
    _voiceover_btn = ""
    _voiceover_panel = ""
    if _voiceover_enabled():
        _voiceover_url = url_for("api_card_voiceover", run_id=run_id, card_id=card_id_raw)
        _voiceover_btn = (
            f'<button class="btn secondary" style="font-size:11px;padding:4px 10px" '
            f"onclick=\"voiceoverToggle(this, {repr(_voiceover_url)}, '{card_uuid}')\" "
            f'title="Hear the approved caption read aloud &mdash; MP3 + subtitles for a muted-autoplay post. Speaks only the human-approved text, verbatim.">'
            f"&#x1F50A; Voiceover</button>"
        )
        _voiceover_panel = (
            f'<div class="voiceover-panel" data-card="{card_uuid}" '
            f'data-voiceover-url="{_h(_voiceover_url)}" '
            f'style="display:none;margin-top:10px;padding:12px;background:rgba(244,213,141,0.04);'
            f'border:1px solid var(--border);border-radius:8px"></div>'
        )

    # M35: the overflow menu — collaboration/power features behind one trigger.
    # The unresolved-comments badge (.comments-count) rides the More trigger so
    # a pending task stays visible without thirteen equal-weight buttons.
    _more_menu = (
        f'<details class="mh-card-more" data-card="{card_uuid}">'
        f'<summary class="btn secondary" style="font-size:11px;padding:4px 10px">'
        f'More &#x25BE;<span class="comments-count" data-card="{card_uuid}"></span></summary>'
        f'<div class="mh-card-more-menu">'
        f'<button class="btn secondary" style="font-size:11px;padding:4px 10px" onclick="reformatToggle(this, \'{card_uuid}\')" title="Re-target this approved design to another size or format — story, square, poster, certificate, YouTube thumbnail…">&#x21C4; Reformat&hellip;</button>'
        f'<button class="btn secondary" style="font-size:11px;padding:4px 10px" onclick="copilotToggle(this, \'{card_uuid}\')" title="Ask the copilot to edit this design in plain words — &lsquo;make the headline punchier, more navy&rsquo;. It proposes safe, on-brand changes; you approve.">&#10024; Copilot&hellip;</button>'
        f'<button class="btn secondary" style="font-size:11px;padding:4px 10px" onclick="commentsToggle(this, \'{card_uuid}\')" title="Comments, @mentions and tasks. A task must be resolved before this card can be approved.">&#x1F4AC; Comments</button>'
        f'<button class="btn secondary" style="font-size:11px;padding:4px 10px" onclick="historyToggle(this, \'{card_uuid}\')" title="Version history — see every design version of this card, compare them, and roll back.">&#x21BA; History</button>'
        f'<button class="btn secondary" style="font-size:11px;padding:4px 10px" onclick="locksToggle(this, \'{card_uuid}\')" title="Lock elements (e.g. the sponsor strip) so a later edit — even the copilot — can\'t change them.">&#x1F512; Locks</button>'
        f'<button class="btn secondary" style="font-size:11px;padding:4px 10px" onclick="shareToggle(this, \'{card_uuid}\')" title="Create an expiring link so someone outside the club (e.g. a parent) can view — or comment on — this card without an account.">&#x1F517; Share</button>'
        f"{schedule_btn}"
        f"{_voiceover_btn}"
        f"</div></details>"
    )
    _visual_display = "" if initial_visual_html else "display:none;"
    _motion_display = "" if initial_motion_html else "display:none;"
    return (
        f'<div class="tone-picker" id="wf-{card_uuid}" data-caption-url="{_h(_caption_url)}" data-card="{card_uuid}" style="margin-top:10px;padding:12px;background:color-mix(in oklab, var(--lane) 4%, transparent);border:1px solid var(--border);border-radius:8px">'
        f'<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);margin-bottom:6px;letter-spacing:0.5px">Caption tone</div>'
        f'<div style="margin-bottom:8px">{tabs_html}</div>'
        f'<div class="tone-panels" data-card="{card_uuid}">{panels_html}</div>'
        # M35: caption actions dock under the tone panel, next to the caption
        # they act on.
        f'<div class="mh-caption-actions" style="margin-top:6px;display:flex;gap:6px;flex-wrap:wrap;align-items:center">'
        f'<button class="btn secondary" style="font-size:11px;padding:4px 10px" onclick="regenerateCaption(this, {repr(_caption_url)}, \'{card_uuid}\')">&#x21BA; Regenerate caption</button>'
        f'<button class="btn secondary" style="font-size:11px;padding:4px 10px" onclick="captionAssistToggle(this, \'{card_uuid}\')">&#10024; Assist&hellip;</button>'
        f"</div>"
        # M35: the primary action row — the two things that matter, then Copy,
        # then everything else behind More.
        f'<div class="mh-card-actions" style="margin-top:8px;display:flex;gap:6px;flex-wrap:wrap;align-items:center">'
        f'<button class="btn" style="font-size:11px;padding:4px 10px;background:var(--lane);color:var(--lane-ink);border:none" onclick="createGraphic(this, {repr(_create_graphic_url)}, \'{card_uuid}\')">&#x2726; Create graphic</button>'
        f'<button class="btn" style="font-size:11px;padding:4px 10px;background:var(--medal);color:var(--medal-ink);border:none" onclick="generateMotion(this, {repr(_motion_url)}, \'{card_uuid}\')">&#x25B6; Generate motion</button>'
        f'<button class="btn secondary" style="font-size:11px;padding:4px 10px" onclick="copyActiveTone(this, \'{card_uuid}\')">Copy caption</button>'
        f"{_more_menu}"
        f'<span class="caption-timestamp" style="font-size:10px;color:var(--ink-muted)"></span>'
        f"</div>"
        f'<div class="assist-row" data-card="{card_uuid}" style="display:none;margin-top:8px;padding:8px 10px;background:rgba(255,255,255,0.02);border:1px dashed var(--border);border-radius:6px">'
        f'<div style="font-size:10px;text-transform:uppercase;color:var(--ink-muted);margin-bottom:6px;letter-spacing:0.5px">Assist &mdash; revise the current caption (AI suggests; you approve)</div>'
        f'<div style="display:flex;gap:5px;flex-wrap:wrap;align-items:center">'
        f"{_caption_assist_buttons(card_uuid)}"
        f'<input class="assist-custom" type="text" maxlength="140" placeholder="or type a change&hellip;" aria-label="Custom caption change instruction" style="flex:1;min-width:140px;font-size:12px;padding:4px 8px;border:1px solid var(--border);border-radius:6px;background:rgba(255,255,255,0.04);color:inherit;font-family:inherit" />'
        f'<button class="btn" style="font-size:11px;padding:3px 10px;background:var(--lane);color:var(--lane-ink);border:none" onclick="captionAssistRun(this, \'{card_uuid}\', \'custom\')">Apply</button>'
        f"</div>"
        f'<div class="assist-status" style="font-size:11px;color:var(--ink-muted);margin-top:6px"></div>'
        f"</div>"
        f'<div class="visual-panel" data-card="{card_uuid}" data-create-url="{_h(_create_graphic_url)}" style="{_visual_display}margin-top:10px;padding:12px;background:color-mix(in oklab, var(--lane) 4%, transparent);border:1px solid var(--border);border-radius:8px">{initial_visual_html}</div>'
        f'<div class="motion-panel" data-card="{card_uuid}" data-motion-url="{_h(_motion_url)}" style="{_motion_display}margin-top:10px;padding:12px;background:rgba(244,213,141,0.04);border:1px solid var(--border);border-radius:8px">{initial_motion_html}</div>'
        f"{_voiceover_panel}"
        f'<div class="reformat-panel" data-card="{card_uuid}" data-reformat-url="{_h(_reformat_url)}" data-formats-url="{_h(_formats_url)}" style="display:none;margin-top:10px;padding:12px;background:color-mix(in oklab, var(--lane) 4%, transparent);border:1px solid var(--border);border-radius:8px"></div>'
        f'<div class="copilot-panel" data-card="{card_uuid}" data-assistant-url="{_h(_assistant_url)}" data-suggest-url="{_h(_assistant_suggest_url)}" data-memory-url="{_h(_assistant_memory_url)}" style="display:none;margin-top:10px;padding:12px;background:color-mix(in oklab, var(--lane) 5%, transparent);border:1px solid var(--border);border-radius:8px"></div>'
        f'<div class="comments-panel" data-card="{card_uuid}" data-real-card="{_h(card_id_raw)}" data-comments-url="{_h(_comments_url)}" style="display:none;margin-top:10px;padding:12px;background:color-mix(in oklab, var(--lane) 4%, transparent);border:1px solid var(--border);border-radius:8px"></div>'
        f'<div class="history-panel" data-card="{card_uuid}" data-revisions-url="{_h(_revisions_url)}" style="display:none;margin-top:10px;padding:12px;background:rgba(244,213,141,0.04);border:1px solid var(--border);border-radius:8px"></div>'
        f'<div class="locks-panel" data-card="{card_uuid}" data-locks-url="{_h(_locks_url)}" style="display:none;margin-top:10px;padding:12px;background:color-mix(in oklab, var(--lane) 4%, transparent);border:1px solid var(--border);border-radius:8px"></div>'
        f'<div class="share-panel" data-card="{card_uuid}" data-real-card="{_h(card_id_raw)}" data-shares-url="{_h(_shares_url)}" style="display:none;margin-top:10px;padding:12px;background:rgba(244,213,141,0.04);border:1px solid var(--border);border-radius:8px"></div>'
        f"</div>"
    )


# ---------------------------------------------------------------------------
# UI 1.18 — Inspector / properties panel (Sketch-inspired)
# ---------------------------------------------------------------------------
#
# A lightweight slide-in drawer (ONE shared instance per page) for tweaking a
# generated card *before* approval: edit the caption, swap the brand-palette
# accent, toggle elements (photo / sponsor strip), and adjust the crop. Every
# control posts back to EXISTING routes — create-graphic for the live re-render,
# live-caption for AI drafts, and the workflow set_edits route for persistence
# (the same edited_captions bag, under dotted ``insp.*`` keys). No new store.

# 3×3 manual-crop grid → CSS object-position. Mirrors saliency's vocabulary so
# the override reads the same as the automatic focus it replaces.
_INSPECTOR_CROP_CELLS = [
    ("left top", "Top-left"),
    ("center top", "Top"),
    ("right top", "Top-right"),
    ("left center", "Left"),
    ("center center", "Centre"),
    ("right center", "Right"),
    ("left bottom", "Bottom-left"),
    ("center bottom", "Bottom"),
    ("right bottom", "Bottom-right"),
]


def _render_inspector_panel(swatches: list[dict]) -> str:
    """Static markup for the shared inspector drawer + its scrim.

    ``swatches`` are the brand-locked accent options (``[{role, hex}]``) resolved
    once per page — rendered server-side so the palette shows instantly without a
    render round-trip. The drawer starts hidden; ``_inspector_js`` wires it up.
    """
    swatch_btns = (
        '<button type="button" class="mh-insp-swatch is-auto" data-accent="" '
        'aria-pressed="true" title="Automatic — the design director\'s pick">'
        "Auto</button>"
    )
    for sw in swatches or []:
        hexv = _h(sw.get("hex", ""))
        role = _h(sw.get("role", ""))
        swatch_btns += (
            f'<button type="button" class="mh-insp-swatch" data-accent="{hexv}" '
            f'aria-pressed="false" title="Brand {role} — {hexv}" '
            f'style="--sw:{hexv}"><span class="mh-insp-swatch-dot"></span>'
            f"{role}</button>"
        )

    crop_btns = (
        '<button type="button" class="mh-insp-crop is-auto" data-focus="" '
        'aria-pressed="true" title="Automatic crop (saliency focus)">Auto</button>'
    )
    for value, label in _INSPECTOR_CROP_CELLS:
        crop_btns += (
            f'<button type="button" class="mh-insp-crop" data-focus="{_h(value)}" '
            f'aria-pressed="false" title="{_h(label)}" aria-label="Crop: {_h(label)}">'
            "</button>"
        )

    return f"""
<div class="mh-inspector-scrim" id="mh-inspector-scrim" hidden></div>
<aside class="mh-inspector" id="mh-inspector" role="dialog" aria-modal="true"
       aria-labelledby="mh-insp-title" aria-hidden="true" hidden>
  <header class="mh-insp-head">
    <div>
      <div class="mh-insp-kicker">Inspector</div>
      <h3 class="mh-insp-title" id="mh-insp-title">Card</h3>
    </div>
    <button type="button" class="mh-insp-close" id="mh-insp-close"
            aria-label="Close inspector">&times;</button>
  </header>
  <div class="mh-insp-body">
    <div class="mh-insp-preview" id="mh-insp-preview" aria-live="polite">
      <div class="mh-insp-preview-empty">Apply changes to render a preview.</div>
    </div>

    <section class="mh-insp-group">
      <div class="mh-insp-group-label">Caption</div>
      <textarea id="mh-insp-caption" class="mh-insp-caption" rows="3" dir="auto"
                maxlength="600" aria-label="Card caption"
                placeholder="Write a caption, or generate one with AI&hellip;"></textarea>
      <div class="mh-insp-row">
        <button type="button" class="btn secondary" id="mh-insp-caption-ai"
                style="font-size:11px;padding:4px 10px">&#10024; Generate with AI</button>
        <button type="button" class="btn secondary" id="mh-insp-caption-save"
                style="font-size:11px;padding:4px 10px">Save caption</button>
        <span class="mh-insp-mini" id="mh-insp-caption-status"></span>
      </div>
    </section>

    <section class="mh-insp-group">
      <div class="mh-insp-group-label">Brand palette</div>
      <div class="mh-insp-swatches" id="mh-insp-swatches">{swatch_btns}</div>
      <div class="mh-insp-mini">Only this club&rsquo;s brand colours &mdash; legibility is checked on render.</div>
    </section>

    <section class="mh-insp-group">
      <div class="mh-insp-group-label">Elements</div>
      <label class="mh-insp-toggle"><input type="checkbox" id="mh-insp-photo" checked>
        <span>Show athlete photo</span></label>
      <label class="mh-insp-toggle"><input type="checkbox" id="mh-insp-sponsor" checked>
        <span>Show sponsor strip</span></label>
    </section>

    <section class="mh-insp-group">
      <div class="mh-insp-group-label">Crop &amp; focus</div>
      <div class="mh-insp-cropgrid" id="mh-insp-cropgrid">{crop_btns}</div>
    </section>
  </div>
  <footer class="mh-insp-foot">
    <span class="mh-insp-status" id="mh-insp-status" aria-live="polite"></span>
    <button type="button" class="btn secondary" id="mh-insp-reset"
            style="font-size:12px;padding:6px 12px">Reset</button>
    <button type="button" class="btn" id="mh-insp-apply"
            style="font-size:12px;padding:6px 14px;background:var(--lane);color:var(--lane-ink);border:none">
      Apply changes</button>
  </footer>
</aside>
"""


def _inspector_js() -> str:
    """Behaviour for the shared inspector drawer (UI 1.18).

    Plain JS (no f-string) so the many braces stay literal. Relies on globals
    already present on every page via ``_layout``: ``window._API_BASE`` (the
    workflow POST base) and ``window.MH`` (toast). Reads each card's context +
    persisted state from the clicked ``[data-mh-inspect]`` button's data-*.
    """
    return """
<script>
(function(){
  var drawer = document.getElementById('mh-inspector');
  var scrim  = document.getElementById('mh-inspector-scrim');
  if (!drawer || !scrim) return;
  var ctx = null;            // current card context
  var pending = {};          // unsaved overrides: accent / photo_pos / hide_sponsor / no_photo
  var lastFocus = null;      // for focus restoration on close

  var $ = function(id){ return document.getElementById(id); };
  var apiBase = function(){ return window._API_BASE || ''; };
  function toast(msg, kind){ if (window.MH && MH.toast) MH.toast(msg, kind || 'info', 3000); }
  function status(msg){ var s = $('mh-insp-status'); if (s) s.textContent = msg || ''; }

  function setPressed(group, attr, value){
    var btns = drawer.querySelectorAll(group);
    btns.forEach(function(b){
      var on = (b.getAttribute(attr) || '') === (value || '');
      b.setAttribute('aria-pressed', on ? 'true' : 'false');
      b.classList.toggle('is-active', on);
    });
  }

  function syncControls(){
    // Reflect `pending` into the controls.
    setPressed('.mh-insp-swatch', 'data-accent', pending.accent || '');
    setPressed('.mh-insp-crop', 'data-focus', pending.photo_pos || '');
    var photo = $('mh-insp-photo'); if (photo) photo.checked = !pending.no_photo;
    var spon = $('mh-insp-sponsor'); if (spon) spon.checked = !pending.hide_sponsor;
  }

  function markDirty(){ status('Unsaved — Apply changes to render & save.'); }

  function openInspector(btn){
    ctx = {
      runId: btn.getAttribute('data-run-id'),
      cardId: btn.getAttribute('data-card-id'),
      graphicUrl: btn.getAttribute('data-graphic-url'),
      captionUrl: btn.getAttribute('data-caption-url'),
      title: btn.getAttribute('data-card-title') || 'Card'
    };
    // Seed pending state from the card's persisted inspector data-* attributes.
    pending = {};
    var a = btn.getAttribute('data-insp-accent'); if (a) pending.accent = a;
    var f = btn.getAttribute('data-insp-focus'); if (f) pending.photo_pos = f;
    if (btn.getAttribute('data-insp-hide-sponsor') === '1') pending.hide_sponsor = true;
    if (btn.getAttribute('data-insp-no-photo') === '1') pending.no_photo = true;
    // textContent, NOT innerHTML: getAttribute decodes the server-side HTML
    // escaping, so innerHTML would re-parse a hostile card title as markup.
    var titleEl = $('mh-insp-title'); if (titleEl) titleEl.textContent = ctx.title;
    var capEl = $('mh-insp-caption');
    if (capEl) capEl.value = btn.getAttribute('data-insp-caption') || '';
    var capStatus = $('mh-insp-caption-status'); if (capStatus) capStatus.textContent = '';
    // M29: seed the preview with the card's current design (the same cached
    // thumbnail the review row shows) so tweaks start from what exists. The
    // placeholder only appears when no thumbnail is available yet.
    var prev = $('mh-insp-preview');
    if (prev) {
      var thumbUrl = btn.getAttribute('data-thumb-url') || '';
      if (thumbUrl) {
        prev.innerHTML = '<div class="mh-insp-preview-empty mh-insp-loading">Loading current design&hellip;</div>';
        var seed = new Image();
        seed.alt = 'Current design for this card';
        seed.className = 'mh-insp-preview-img';
        seed.onload = function() { prev.innerHTML = ''; prev.appendChild(seed); };
        seed.onerror = function() { prev.innerHTML = '<div class="mh-insp-preview-empty">Apply changes to render a preview.</div>'; };
        seed.src = thumbUrl;
      } else {
        prev.innerHTML = '<div class="mh-insp-preview-empty">Apply changes to render a preview.</div>';
      }
    }
    syncControls();
    status('');
    lastFocus = btn;
    drawer.hidden = false; scrim.hidden = false;
    // rAF so the transition runs from the hidden state.
    requestAnimationFrame(function(){
      drawer.classList.add('is-open'); scrim.classList.add('is-open');
      drawer.setAttribute('aria-hidden', 'false');
    });
    var close = $('mh-insp-close'); if (close) close.focus();
  }

  function closeInspector(){
    drawer.classList.remove('is-open'); scrim.classList.remove('is-open');
    drawer.setAttribute('aria-hidden', 'true');
    var done = function(){ drawer.hidden = true; scrim.hidden = true; };
    if (matchMedia('(prefers-reduced-motion: reduce)').matches) { done(); }
    else { setTimeout(done, 220); }
    if (lastFocus && lastFocus.focus) lastFocus.focus();
    ctx = null;
  }

  // --- Build the override payload for create-graphic from `pending`. ---
  function overrideBody(){
    var body = {};
    body.accent = pending.accent || '';
    body.focus = pending.photo_pos || '';
    body.hide_sponsor = !!pending.hide_sponsor;
    body.no_photo = !!pending.no_photo;
    return body;
  }

  // --- Persist current overrides via the existing workflow set_edits route. ---
  function persistEdits(extra){
    if (!ctx) return Promise.resolve();
    var edits = {
      'insp.accent': pending.accent || '',
      'insp.focus': pending.photo_pos || '',
      'insp.hideSponsor': pending.hide_sponsor ? '1' : '',
      'insp.noPhoto': pending.no_photo ? '1' : ''
    };
    if (extra) { for (var k in extra) { if (extra.hasOwnProperty(k)) edits[k] = extra[k]; } }
    var url = apiBase() + '/api/workflow/' + encodeURIComponent(ctx.runId) +
              '/' + encodeURIComponent(ctx.cardId);
    return fetch(url, {
      method: 'POST', headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({action: 'set_edits', edits: edits})
    }).then(function(r){ return r.json().then(function(j){ return {ok: r.ok, body: j}; }); });
  }

  function renderPreview(){
    if (!ctx) return;
    var prev = $('mh-insp-preview');
    if (prev) prev.innerHTML = '<div class="mh-insp-preview-empty mh-insp-loading">Rendering preview&hellip;</div>';
    status('Rendering &amp; saving&hellip;');
    var applyBtn = $('mh-insp-apply'); if (applyBtn) applyBtn.disabled = true;
    // Persist first (so the override sticks even if the user navigates away
    // mid-render), then render with the explicit overrides for an instant result.
    persistEdits().then(function(){
      return fetch(ctx.graphicUrl, {
        method: 'POST', headers: {'Content-Type': 'application/json'},
        body: JSON.stringify(overrideBody())
      });
    }).then(function(r){ return r.json().then(function(j){ return {ok: r.ok, body: j}; }); })
      .then(function(o){
        if (applyBtn) applyBtn.disabled = false;
        if (!o.ok || !o.body || o.body.error) {
          var msg = (o.body && (o.body.error || o.body.message)) || 'render failed';
          status('Could not render: ' + msg);
          if (prev) prev.innerHTML = '<div class="mh-insp-preview-empty">Could not render this preview.</div>';
          toast('Inspector render failed: ' + msg, 'error');
          return;
        }
        var vis = (o.body.visuals || [])[0];
        var src = vis && (vis.png_url || vis.url || vis.file_url);
        if (!src && vis && vis.id) {
          src = apiBase() + '/api/visual/' + encodeURIComponent(vis.id) + '/png';
        }
        if (src && prev) {
          var img = new Image();
          img.alt = 'Preview of the edited card';
          img.className = 'mh-insp-preview-img';
          img.onload = function(){ prev.innerHTML = ''; prev.appendChild(img); };
          img.onerror = function(){ prev.innerHTML = '<div class="mh-insp-preview-empty">Preview rendered, but the image could not load.</div>'; };
          img.src = src + (src.indexOf('?') >= 0 ? '&' : '?') + 't=' + Date.now();
        } else if (prev) {
          prev.innerHTML = '<div class="mh-insp-preview-empty">Rendered, but no preview image was returned.</div>';
        }
        status('Saved.');
        // Mark the card edited in the pile so the review counts/badge update.
        markCardEdited();
      }).catch(function(e){
        if (applyBtn) applyBtn.disabled = false;
        status('Could not render.');
        toast('Inspector error: ' + (e && e.message || e), 'error');
      });
  }

  function markCardEdited(){
    if (!ctx) return;
    var esc = (window.CSS && CSS.escape) ? CSS.escape(ctx.cardId) : ctx.cardId;
    try {
      document.querySelectorAll('.ach-row [data-card-id="' + esc + '"][data-mh-inspect]').forEach(function(b){
        var row = b.closest('.ach-row');
        if (row && row.dataset.status === 'queue') { row.dataset.status = 'edited'; }
        // Update the button's persisted data-* so re-opening reflects the save.
        b.setAttribute('data-insp-accent', pending.accent || '');
        b.setAttribute('data-insp-focus', pending.photo_pos || '');
        b.setAttribute('data-insp-hide-sponsor', pending.hide_sponsor ? '1' : '');
        b.setAttribute('data-insp-no-photo', pending.no_photo ? '1' : '');
      });
      if (window.mhRecountReview) window.mhRecountReview();
    } catch (e) { /* non-fatal */ }
  }

  // --- Caption: AI draft (existing live-caption route) ---
  function generateCaption(){
    if (!ctx) return;
    var btn = $('mh-insp-caption-ai'); var cs = $('mh-insp-caption-status');
    if (btn) btn.disabled = true;
    if (cs) cs.textContent = 'Generating…';
    var url = ctx.captionUrl + (ctx.captionUrl.indexOf('?') >= 0 ? '&' : '?') + 'tone=ai';
    fetch(url, {method: 'POST', headers: {'Content-Type': 'application/json'}, body: '{}'})
      .then(function(r){ return r.json(); })
      .then(function(j){
        if (btn) btn.disabled = false;
        if (j && j.caption) {
          var ta = $('mh-insp-caption'); if (ta) ta.value = j.caption;
          if (cs) cs.textContent = j.live ? 'AI draft ready' : '';
        } else {
          if (cs) cs.textContent = (j && j.message) ? j.message : 'No caption returned';
        }
      }).catch(function(){ if (btn) btn.disabled = false; if (cs) cs.textContent = 'Generation failed'; });
  }

  function saveCaption(){
    if (!ctx) return;
    var ta = $('mh-insp-caption'); var cs = $('mh-insp-caption-status');
    var text = ta ? ta.value : '';
    // Persist under every standard tone's headline slot so the user's wording
    // is honoured at pack build regardless of which tone is exported.
    var extra = {
      'warm-club_headline': text, 'hype_headline': text, 'data-led_headline': text
    };
    if (cs) cs.textContent = 'Saving…';
    persistEdits(extra).then(function(o){
      if (cs) cs.textContent = (o && o.ok) ? 'Caption saved' : 'Save failed';
      if (o && o.ok) {
        var esc = (window.CSS && CSS.escape) ? CSS.escape(ctx.cardId) : ctx.cardId;
        document.querySelectorAll('[data-card-id="' + esc + '"][data-mh-inspect]').forEach(function(b){
          b.setAttribute('data-insp-caption', text);
        });
      }
    }).catch(function(){ if (cs) cs.textContent = 'Save failed'; });
  }

  // --- Wiring -------------------------------------------------------------
  document.addEventListener('click', function(e){
    var openBtn = e.target.closest('[data-mh-inspect]');
    if (openBtn) { e.preventDefault(); openInspector(openBtn); return; }
  });
  $('mh-insp-close').addEventListener('click', closeInspector);
  scrim.addEventListener('click', closeInspector);
  document.addEventListener('keydown', function(e){
    if (e.key === 'Escape' && drawer.classList.contains('is-open')) closeInspector();
  });

  drawer.querySelectorAll('.mh-insp-swatch').forEach(function(b){
    b.addEventListener('click', function(){
      var v = b.getAttribute('data-accent') || '';
      pending.accent = v; setPressed('.mh-insp-swatch', 'data-accent', v); markDirty();
    });
  });
  drawer.querySelectorAll('.mh-insp-crop').forEach(function(b){
    b.addEventListener('click', function(){
      var v = b.getAttribute('data-focus') || '';
      pending.photo_pos = v; setPressed('.mh-insp-crop', 'data-focus', v); markDirty();
    });
  });
  var photoEl = $('mh-insp-photo');
  if (photoEl) photoEl.addEventListener('change', function(){ pending.no_photo = !photoEl.checked; markDirty(); });
  var sponEl = $('mh-insp-sponsor');
  if (sponEl) sponEl.addEventListener('change', function(){ pending.hide_sponsor = !sponEl.checked; markDirty(); });

  $('mh-insp-apply').addEventListener('click', renderPreview);
  $('mh-insp-reset').addEventListener('click', function(){
    pending = {}; syncControls(); markDirty();
  });
  $('mh-insp-caption-ai').addEventListener('click', generateCaption);
  $('mh-insp-caption-save').addEventListener('click', saveCaption);
})();
</script>
"""


def _render_turn_into_card(run_id: str) -> str:
    """The 'Turn meet into a derivative pack' generator (recap, spotlights,
    thread, newsletter, sponsor thank-you, coach quote, next-meet preview).
    Lives on the Content builder page — it is content creation, so it sits
    after approval, never on the Review triage page."""
    try:
        from mediahub.turn_into import list_packs as _list_ti_packs

        _ti_packs = _list_ti_packs(run_id, base_dir=DATA_DIR / "turn_into_packs")
    except Exception:
        _ti_packs = []
    _turn_into_api = url_for("api_turn_into", run_id=run_id)

    _ti_prior_html = ""
    if _ti_packs:
        rows = []
        for p in _ti_packs[:5]:
            _pid = p.get("pack_id", "")
            _gen = p.get("generated_at", "")
            _n = p.get("n_artefacts", 0)
            _skipped = p.get("n_skipped", 0)
            try:
                _view = url_for("turn_into_pack_view", run_id=run_id, pack_id=_pid)
            except Exception:
                _view = "#"
            rows.append(
                f'<li style="font-size:12px;margin-bottom:4px">'
                f'<a href="{_view}">{_h(_gen)}</a> '
                f'<span class="muted">&mdash; {_n} artefacts'
                + (f", {_skipped} skipped" if _skipped else "")
                + "</span></li>"
            )
        _ti_prior_html = (
            '<div style="margin-top:14px">'
            '<div class="muted" style="font-size:12px;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px">'
            "Previously generated packs</div>"
            f'<ul style="margin:0;padding-left:20px">{"".join(rows)}</ul>'
            "</div>"
        )

    _ti_chips = "".join(
        f'<span style="display:inline-block;padding:3px 10px;margin:0 6px 6px 0;'
        f"border:1px solid var(--border);border-radius:999px;font-size:11.5px;"
        f'color:var(--ink-dim)">{label}</span>'
        for label in (
            "Meet recap",
            "Swimmer spotlights",
            "X / LinkedIn thread",
            "Parent newsletter",
            "Sponsor thank-you",
            "Coach quote (draft)",
            "Next-meet preview",
        )
    )
    return f"""
<div class="card" id="turn-into-card" style="border-left:3px solid var(--accent)">
  <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:16px;flex-wrap:wrap">
    <div style="flex:1;min-width:min(240px,100%)">
      <h2 style="margin-bottom:6px">Turn this meet into more</h2>
      <p class="dim" style="margin:0 0 10px 0;font-size:13px;max-width:540px">
        One click re-uses everything this meet already produced &mdash; the
        results, the approved cards, your brand voice &mdash; and drafts a
        full set of follow-on content. Everything lands on one page where
        you can edit each caption before using it:
      </p>
      <div>{_ti_chips}</div>
    </div>
    <div style="display:flex;gap:10px;align-items:flex-end;flex-wrap:wrap">
      <button id="ti-btn" class="btn mh-cta-motion" onclick="turnMeetIntoPack()" style="background:var(--lane);color:var(--lane-ink)">
        <span class="mh-btn-label">&#x2726; Generate the pack</span>
        <span class="mh-btn-spin" aria-hidden="true"></span>
        <span class="mh-btn-check" aria-hidden="true">&#x2713;</span>
      </button>
    </div>
  </div>
  <div id="ti-status" style="margin-top:10px;font-size:12px;color:var(--ink-muted);display:none"></div>
  {_ti_prior_html}
</div>
<script>
function turnMeetIntoPack() {{
  var btn = document.getElementById('ti-btn');
  var status = document.getElementById('ti-status');
  var secs = 0;
  // Re-entry guard: MH.btnState('loading') only sets pointer-events:none, which
  // blocks the mouse but NOT a keyboard re-activation (Enter/Space on the still-
  // focused button) — and if ui-kit.js failed to load there's no guard at all.
  // The disabled attribute stops both, so one click can't spawn a second
  // LLM-heavy pack job. Cleared again on failure so the user can retry.
  if (btn.disabled) return;
  btn.disabled = true;
  function setState(s) {{ if (window.MH && MH.btnState) MH.btnState(btn, s); }}
  // Stateful CTA: loading spins the primary action; data-mh-state="loading"
  // also blocks a second click (pointer-events:none).
  setState('loading');
  status.style.display = '';
  status.innerHTML = '<span style="display:inline-block;width:14px;height:14px;border:2px solid color-mix(in oklab, var(--lane) 30%, transparent);border-top-color:var(--lane);border-radius:50%;vertical-align:-2px;margin-right:8px;animation:spin 600ms linear infinite"></span>' +
    '<span id="ti-status-text">Drafting every artefact with live AI&hellip;</span>';
  var statusText = document.getElementById('ti-status-text');
  var ticker = setInterval(function() {{
    secs++;
    if (statusText) statusText.textContent = 'Drafting every artefact with live AI — ' + secs + 's. Usually under a minute.';
  }}, 1000);
  function _fail(msg) {{
    clearInterval(ticker);
    status.textContent = 'Failed: ' + msg;
    btn.disabled = false;
    setState('idle');
  }}
  function _done(packUrl) {{
    clearInterval(ticker);
    setState('success');
    status.textContent = 'Done — opening pack…';
    window.location.href = packUrl;
  }}
  function _poll(statusUrl) {{
    fetch(statusUrl).then(function(r) {{ return r.json(); }}).then(function(j) {{
      if (j.status === 'running') {{
        setTimeout(function() {{ _poll(statusUrl); }}, 2000);
      }} else if (j.status === 'done' && j.pack_url) {{
        _done(j.pack_url);
      }} else {{
        _fail(j.error || 'unknown error');
      }}
    }}).catch(function() {{ _fail('poll failed'); }});
  }}
  fetch({json.dumps(_turn_into_api)}, {{
    method: 'POST',
    headers: {{ 'Content-Type': 'application/json' }},
    body: JSON.stringify({{ async: true }}),
  }}).then(function(r) {{ return r.json(); }})
    .then(function(j) {{
      if (j && j.status_url) {{
        setTimeout(function() {{ _poll(j.status_url); }}, 2000);
      }} else if (j && j.pack_url) {{
        _done(j.pack_url);
      }} else {{
        _fail(j && j.message ? j.message : 'unknown error');
      }}
    }})
    .catch(function() {{
      _fail('Network error. Please retry.');
    }});
}}
</script>"""


# ---------------------------------------------------------------------
# U.4 — first-run sample-to-first-content-pack path
# ---------------------------------------------------------------------
#
# A freshly-onboarded org has its brand kit captured but no results file to
# hand, so it sees zero content until it sources a real meet export. The
# sample path closes that gap: one click runs the REAL pipeline on the
# bundled synthetic meet (the same Children's-Code-clean PDF the public /try
# demo uses — fictional swimmers, fictional clubs), stamped to the user's own
# org so captions and graphics come out in *their* brand. It lands on the
# real /review queue, so the very first thing a new user sees is the whole
# engine working end-to-end on data, not a marketing mock.
#
# The file is committed to the repo, so it ships on every deployment; the
# route still checks existence and surfaces an honest error if it is missing.
_SAMPLE_MEET_PDF = Path(__file__).resolve().parents[3] / "samples" / "demo-meet-results.pdf"
# The meet's namesake club — the one with the two golds and the strongest
# spread of cards — so the sample pack looks its best out of the box.
_SAMPLE_MEET_CLUB = "Riverbend SC"
_SAMPLE_MEET_FILENAME = "Sample meet — Riverbend Autumn Sprint Gala.pdf"


def _run_is_sample(run_id: str) -> bool:
    """True when this run was generated by the U.4 sample path.

    Detected via a tiny sidecar marker written next to the run's input,
    so the review page can explain that the swimmers are demo data while
    the branding is the user's own — and point them at uploading a real
    file when they're ready.
    """
    try:
        return (RUNS_DIR / run_id / "sample.json").exists()
    except Exception:
        return False


def _mark_run_sample(run_id: str) -> None:
    """Write the sample marker sidecar for a freshly-started sample run."""
    try:
        d = RUNS_DIR / run_id
        d.mkdir(parents=True, exist_ok=True)
        (d / "sample.json").write_text(
            json.dumps({"sample": True, "club": _SAMPLE_MEET_CLUB}),
            encoding="utf-8",
        )
    except Exception:
        log.warning("could not write sample marker for run %s", run_id, exc_info=True)


def _sample_pack_cta(
    *,
    heading: str = "No results file to hand?",
    sub: str = (
        "Generate a sample content pack from a demo meet and watch the whole "
        "engine run — detection, ranking, captions and cards — in your brand. "
        "It lands in your review queue like any real run; delete it whenever."
    ),
    button_label: str = "Generate a sample pack →",
    compact: bool = False,
) -> str:
    """Reusable 'try it on a sample meet' call-to-action.

    Renders a POST form to ``/onboarding/sample``; the app's CSRF
    auto-injection adds the hidden token, so callers don't have to. When
    the sample file isn't present on the deployment, returns an empty
    string so the surface simply omits the option rather than offering a
    button that 404s.
    """
    if not _SAMPLE_MEET_PDF.exists():
        return ""
    action = url_for("onboarding_sample")
    if compact:
        return (
            f'<form method="post" action="{action}" style="margin:0;display:inline">'
            f'<button type="submit" class="btn secondary">{_h(button_label)}</button>'
            "</form>"
        )
    return (
        '<div class="card mh-sample-cta" style="border:1px dashed var(--border);'
        "background:var(--surface);display:flex;gap:16px;align-items:center;"
        'flex-wrap:wrap;justify-content:space-between">'
        '<div style="flex:1;min-width:min(240px,100%)">'
        f'<h3 style="margin:0 0 6px;font-size:15px">{_h(heading)}</h3>'
        f'<p class="dim" style="margin:0;font-size:13px;line-height:1.5">{_h(sub)}</p>'
        "</div>"
        f'<form method="post" action="{action}" style="margin:0">'
        f'<button type="submit" class="btn">{_h(button_label)}</button>'
        "</form>"
        "</div>"
    )


# ---------------------------------------------------------------------
# Background pipeline worker
# ---------------------------------------------------------------------


def _start_run(
    file_bytes: bytes,
    file_name: str,
    profile_id: Optional[str],
    use_pb_cache: bool,
    fetch_pbs: bool,
    club_filter: Optional[str] = None,
    source_url: Optional[str] = None,
) -> str:
    run_id = uuid.uuid4().hex[:12]
    # When the input came from a pasted results link, record its origin as an
    # optional sidecar so the review page can show "Source: <host>" and offer a
    # re-fetch. Never mutates finished runs; just this new run's directory.
    if source_url:
        try:
            run_dir = RUNS_DIR / run_id
            run_dir.mkdir(parents=True, exist_ok=True)
            (run_dir / "source_url.txt").write_text(source_url, encoding="utf-8")
        except Exception:
            pass
    started_at = datetime.now(timezone.utc).isoformat()
    with _active_lock:
        _active_runs[run_id] = {
            "status": "queued",
            "log": ["Run queued"],
            "started_at": started_at,
            "file_name": file_name,
            # epoch seconds — advanced on every progress line. Lets the
            # status poller distinguish "still working" from "the worker
            # died mid-run" without waiting on a wall-clock guess.
            "heartbeat": time.time(),
        }
        # Evict completed older runs to keep the dict bounded.
        _maybe_evict_active_runs()
    # Fingerprint the input now (we have the bytes here) so a re-run of the same
    # file can be flagged. _persist_run carries this forward and adds the
    # meet-identity fingerprint once the canonical meet is known.
    content_hash = _content_hash(file_bytes)
    conn = _db()
    conn.execute(
        """INSERT INTO runs (id, created_at, status, file_name, profile_id,
                             progress_log, heartbeat_at, content_hash)
           VALUES (?,?,?,?,?,?,?,?)""",
        (
            run_id,
            started_at,
            "queued",
            file_name,
            profile_id or "",
            json.dumps(["Run queued"]),
            started_at,
            content_hash,
        ),
    )
    conn.commit()
    conn.close()

    # QA-015 — persist the launch input so a worker recycle / deploy / OOM that
    # kills the in-thread pipeline can RESUME this run (re-run from the same
    # input) instead of losing it. Best-effort: resume is simply unavailable if
    # this write fails, and the run otherwise behaves exactly as before.
    _store_run_input(
        run_id,
        file_bytes,
        file_name,
        profile_id,
        use_pb_cache,
        fetch_pbs,
        club_filter,
        source_url,
    )
    _spawn_run_thread(
        run_id=run_id,
        file_bytes=file_bytes,
        file_name=file_name,
        profile_id=profile_id,
        use_pb_cache=use_pb_cache,
        fetch_pbs=fetch_pbs,
        club_filter=club_filter,
    )
    return run_id


# ---------------------------------------------------------------------
# QA-015 — durable run worker + resume machinery
# ---------------------------------------------------------------------
# The pipeline runs in a daemon thread inside a gunicorn worker, so a
# `--max-requests` recycle, an overlapping deploy, or an OOM kills it mid-run —
# and the bigger the meet the longer it runs, so a recycle is far likelier to
# land while a 500+-swim run is in flight (which is why size correlates with the
# failure). Rather than lose the run, _start_run persists its launch input and
# these helpers RE-RUN it from there when it is found dead. The pipeline is
# deterministic and cache-backed, so a resume on a fresh worker re-walks the
# same steps (warm where cached) and converges; it is bounded by _RUN_MAX_RESUMES
# so a genuinely-broken input surfaces the honest "upload again" error instead of
# looping forever. The honest error is kept for the truly-unrecoverable case.


def _run_input_dir(run_id: str) -> Path:
    return RUNS_DIR / run_id


def _store_run_input(
    run_id: str,
    file_bytes: bytes,
    file_name: str,
    profile_id: Optional[str],
    use_pb_cache: bool,
    fetch_pbs: bool,
    club_filter: Optional[str],
    source_url: Optional[str],
) -> None:
    """Persist a run's launch inputs beside it so an interrupted run can be
    resumed. Best-effort; a failure here just means resume is unavailable."""
    try:
        d = _run_input_dir(run_id)
        d.mkdir(parents=True, exist_ok=True)
        (d / "input.bin").write_bytes(file_bytes)
        (d / "resume.json").write_text(
            json.dumps(
                {
                    "file_name": file_name,
                    "profile_id": profile_id,
                    "use_pb_cache": bool(use_pb_cache),
                    "fetch_pbs": bool(fetch_pbs),
                    "club_filter": club_filter,
                    "source_url": source_url,
                }
            ),
            encoding="utf-8",
        )
    except Exception:
        log.warning("QA-015: could not store resume input for run %s", run_id, exc_info=True)


def _load_run_input(run_id: str) -> Optional[tuple[bytes, dict]]:
    """The (file_bytes, launch-params) for a resumable run, or None."""
    try:
        d = _run_input_dir(run_id)
        meta = json.loads((d / "resume.json").read_text(encoding="utf-8"))
        data = (d / "input.bin").read_bytes()
        return data, meta
    except Exception:
        return None


def _resume_input_exists(run_id: str) -> bool:
    d = _run_input_dir(run_id)
    return (d / "input.bin").exists() and (d / "resume.json").exists()


def _cleanup_run_input(run_id: str) -> None:
    """Drop a finished run's stored launch input. Only ever called from the
    worker's own ``finally`` — i.e. the pipeline reached a clean terminal — so a
    killed worker never reaches here and its input stays put for resume."""
    try:
        d = _run_input_dir(run_id)
        for name in ("input.bin", "resume.json"):
            p = d / name
            if p.exists():
                p.unlink()
    except Exception:
        pass


def _execute_run(
    *,
    run_id: str,
    file_bytes: bytes,
    file_name: str,
    profile_id: Optional[str],
    use_pb_cache: bool,
    fetch_pbs: bool,
    club_filter: Optional[str],
) -> None:
    """Run the pipeline to completion and persist it. Shared by the initial
    launch (_start_run) and a resume (_resume_run); a resume differs only in
    that the in-memory log already carries a 'Resuming…' note."""
    with _active_lock:
        entry = _active_runs.get(run_id)
        if entry is not None:
            entry["status"] = "running"
            entry["heartbeat"] = time.time()
        # Persist whatever the entry was seeded with ("Run queued" for a fresh
        # run, the resume note for a resume) instead of clobbering it.
        start_log = list((entry or {}).get("log") or ["Run queued"])
    _persist_run_progress(run_id, "running", start_log)

    # Throttle DB writes: the in-memory log updates on every line, but
    # the DB only needs to be fresh to the second for cross-worker polls.
    _last_db = [0.0]

    def cb(msg: str):
        now = time.time()
        with _active_lock:
            entry = _active_runs.get(run_id)
            if entry is None:
                # Run was evicted from the bounded cache while in
                # flight — silently drop the progress line.
                return
            entry["heartbeat"] = now
            log_list = entry.setdefault("log", [])
            log_list.append(msg)
            # Cap each run's progress log so a buggy progress
            # callback can't grow the in-memory list to thousands
            # of entries × hundreds of bytes. Keep the first 5
            # entries (queue/start markers — useful for diagnosis)
            # and the most recent N-5 of the tail.
            if len(log_list) > _RUN_LOG_LIMIT:
                keep_tail = _RUN_LOG_LIMIT - 5
                entry["log"] = log_list[:5] + log_list[-keep_tail:]
            snapshot = list(entry["log"])
        # Stream to the DB outside the lock (SQLite write is slow-ish).
        if now - _last_db[0] >= _RUN_DB_HEARTBEAT_SECS:
            _last_db[0] = now
            _persist_run_progress(run_id, "running", snapshot)

    def _record_terminal(status: str, error: Optional[str] = None) -> None:
        """Stamp the in-memory entry with a terminal status. The
        entry may have been evicted from the bounded cache (a
        long-running pipeline outliving the LRU window), in
        which case the on-disk DB row remains the source of
        truth and the polling endpoint falls back to it."""
        with _active_lock:
            entry = _active_runs.get(run_id)
            if entry is None:
                return
            entry["status"] = status
            entry["heartbeat"] = time.time()
            if error is not None:
                entry["error"] = error

    # Liveness ticker: keep the heartbeat fresh for as long as THIS worker
    # thread is alive, independent of how often the pipeline emits a progress
    # line. Without it a long, progress-silent step — the heavy LLM
    # interpretation of a large fresh PDF, which can run past
    # _RUN_STALE_SECS without a single line — lets the heartbeat go stale and
    # the run is falsely declared dead mid-interpretation. If the worker is
    # recycled/killed this daemon thread dies with it, so a genuinely dead
    # run still goes stale exactly as before.
    _hb_stop = threading.Event()

    def _heartbeat_ticker():
        started = time.time()
        while not _hb_stop.wait(_RUN_HEARTBEAT_TICK_SECS):
            if time.time() - started > _RUN_MAX_LIVENESS_SECS:
                return  # safety cap: let a truly wedged run finally go stale
            if not _advance_run_heartbeat(run_id):
                return  # run finished or was evicted — stop ticking

    _hb_thread = threading.Thread(target=_heartbeat_ticker, name=f"hb-{run_id[:8]}", daemon=True)
    _hb_thread.start()

    # D-6: only a SUCCESSFUL run reclaims its stored launch input. A failed run
    # keeps input.bin + resume.json so the volunteer can re-run it from the saved
    # file (a killed worker never reaches the finally, so it stays resumable too).
    _ended_ok = False
    try:
        run = run_pipeline_v4(
            file_bytes=file_bytes,
            filename=file_name,
            profile_id=profile_id,
            use_pb_cache=use_pb_cache,
            fetch_pbs=fetch_pbs,
            progress_cb=cb,
            run_id=run_id,
            club_filter=club_filter,
        )
        _persist_run(run, file_name)
        _record_terminal(
            "error" if run.error else "done",
            run.error if run.error else None,
        )
        if not run.error:
            _ended_ok = True
            # "Pack ready for review" ping. Inert (no-op) unless an operator
            # configured a notification channel; runs in its own thread so it
            # never delays the run, and never raises.
            try:
                from mediahub.notify import notify_pack_ready

                notify_pack_ready(run_id)
            except Exception:
                pass
            # In-app notifications inbox (UI 1.14) — always-on, no-config:
            # record the "pack ready" milestone against the owning org so it
            # lands in the bell dropdown even with no push channel set up.
            try:
                from mediahub.notify import inbox as _inbox

                _inbox.record_pack_ready(profile_id, run_id, count=len(run.cards))
            except Exception:
                pass
            # Outbound webhook (1.21): notify subscribed integrations that a
            # run finished. Best-effort; never blocks or breaks the run.
            try:
                from mediahub import webhooks as _webhooks
                from mediahub.webhooks import events as _wh_events

                _webhooks.emit(
                    _wh_events.EVENT_RUN_FINISHED,
                    profile_id,
                    _wh_events.run_finished(profile_id, run_id, card_count=len(run.cards)),
                )
            except Exception:
                pass
        else:
            # The pipeline reported a terminal error (rather than raising) —
            # surface it in the inbox so the operator isn't left guessing.
            try:
                from mediahub.notify import inbox as _inbox

                _inbox.record_error(
                    profile_id,
                    "Run couldn't be processed",
                    str(run.error),
                    run_id=run_id,
                )
            except Exception:
                pass
    except Exception as e:
        import traceback

        traceback.print_exc()
        _record_terminal("error", str(e))
        conn = _db()
        conn.execute("UPDATE runs SET status='error', error=? WHERE id=?", (str(e), run_id))
        conn.commit()
        conn.close()
        try:
            from mediahub.notify import inbox as _inbox

            _inbox.record_error(
                profile_id,
                "Run couldn't be processed",
                str(e),
                run_id=run_id,
            )
        except Exception:
            pass
    finally:
        # Stop the liveness ticker the moment the pipeline returns (success
        # or error) so a finished run's heartbeat freezes and the entry can
        # settle into its terminal status.
        _hb_stop.set()
        # D-6: reclaim the stored launch input only on SUCCESS. A failed run
        # keeps it so it can be re-run from the saved file; a killed worker never
        # gets here, so an interrupted run keeps its input and stays resumable.
        if _ended_ok:
            _cleanup_run_input(run_id)


def _spawn_run_thread(
    *,
    run_id: str,
    file_bytes: bytes,
    file_name: str,
    profile_id: Optional[str],
    use_pb_cache: bool,
    fetch_pbs: bool,
    club_filter: Optional[str],
) -> None:
    threading.Thread(
        target=_execute_run,
        kwargs=dict(
            run_id=run_id,
            file_bytes=file_bytes,
            file_name=file_name,
            profile_id=profile_id,
            use_pb_cache=use_pb_cache,
            fetch_pbs=fetch_pbs,
            club_filter=club_filter,
        ),
        name=f"run-{run_id[:8]}",
        daemon=True,
    ).start()


def _mark_run_errored(run_id: str, message: str) -> None:
    """Stamp a still-non-terminal run as errored (DB + any in-memory entry).

    D-6: the stored launch input is deliberately KEPT (not reclaimed) so a
    failed run — including a resume-budget-exhausted / stale one — can still be
    re-run from the saved file. Input is only reclaimed on a successful run."""
    try:
        conn = _db()
        conn.execute(
            "UPDATE runs SET status='error', error=COALESCE(error, ?) "
            "WHERE id=? AND status IN ('queued','running')",
            (message, run_id),
        )
        conn.commit()
        conn.close()
    except Exception:
        pass
    with _active_lock:
        entry = _active_runs.get(run_id)
        if isinstance(entry, dict) and entry.get("status") in ("queued", "running", None):
            entry["status"] = "error"
            entry["error"] = entry.get("error") or message


def _claim_stale_run_for_resume(run_id: str, max_resumes: int) -> str:
    """Atomically claim a stale, resumable run for THIS worker to resume.

    Compare-and-swap on ``heartbeat_at`` so that when several workers spot the
    same dead run, exactly one wins (its UPDATE flips the heartbeat, the rest
    match zero rows). Returns ``'claimed'`` | ``'exhausted'`` | ``'skip'``
    (``skip`` = not stale / still alive / already handled elsewhere)."""
    conn = None
    try:
        conn = _db()
        row = conn.execute(
            "SELECT status, heartbeat_at, resume_count FROM runs WHERE id=?",
            (run_id,),
        ).fetchone()
        if row is None or row["status"] not in ("queued", "running"):
            conn.close()
            return "skip"
        age = _iso_age_secs(row["heartbeat_at"])
        if not (age is None or age > _RUN_STALE_SECS):
            conn.close()
            return "skip"  # fresh heartbeat — still alive, or just claimed
        if (row["resume_count"] or 0) >= max_resumes:
            conn.close()
            return "exhausted"
        now_iso = datetime.now(timezone.utc).isoformat()
        old_hb = row["heartbeat_at"]
        if old_hb is None:
            cur = conn.execute(
                "UPDATE runs SET status='running', heartbeat_at=?, "
                "resume_count=COALESCE(resume_count,0)+1 "
                "WHERE id=? AND status IN ('queued','running') AND heartbeat_at IS NULL",
                (now_iso, run_id),
            )
        else:
            cur = conn.execute(
                "UPDATE runs SET status='running', heartbeat_at=?, "
                "resume_count=COALESCE(resume_count,0)+1 "
                "WHERE id=? AND status IN ('queued','running') AND heartbeat_at=?",
                (now_iso, run_id, old_hb),
            )
        conn.commit()
        claimed = cur.rowcount == 1
        conn.close()
        return "claimed" if claimed else "skip"
    except Exception:
        try:
            if conn is not None:
                conn.close()
        except Exception:
            pass
        return "skip"


def _resume_run(run_id: str) -> None:
    """Re-launch an interrupted run from its stored input. The DB row has already
    been claimed (status → 'running', resume_count bumped) by the caller."""
    loaded = _load_run_input(run_id)
    if not loaded:
        _mark_run_errored(run_id, _RUN_STALE_ERROR)
        return
    data, meta = loaded
    note = (
        "Resuming after an interrupted run — the previous server worker was "
        "recycled mid-run. Picking up from your uploaded file…"
    )
    started_at = datetime.now(timezone.utc).isoformat()
    with _active_lock:
        _active_runs[run_id] = {
            "status": "running",
            "log": [note],
            "started_at": started_at,
            "file_name": meta.get("file_name") or "",
            "heartbeat": time.time(),
        }
        _maybe_evict_active_runs()
    _persist_run_progress(run_id, "running", [note])
    _spawn_run_thread(
        run_id=run_id,
        file_bytes=data,
        file_name=meta.get("file_name") or "upload.bin",
        profile_id=meta.get("profile_id"),
        use_pb_cache=bool(meta.get("use_pb_cache", True)),
        fetch_pbs=bool(meta.get("fetch_pbs", True)),
        club_filter=meta.get("club_filter"),
    )


def _maybe_resume_stale_run(run_id: str) -> bool:
    """Handle a run whose in-thread pipeline has gone stale (a dead worker).

    Returns True when the caller should report the run as ``running`` — it is
    being resumed, was claimed by another worker, or turned out to still be
    alive. Returns False when the run is genuinely unrecoverable (no stored
    input, or the resume budget is exhausted), in which case it has been stamped
    with the honest error for the caller to surface."""
    if not _resume_input_exists(run_id):
        _mark_run_errored(run_id, _RUN_STALE_ERROR)
        return False
    outcome = _claim_stale_run_for_resume(run_id, _RUN_MAX_RESUMES)
    if outcome == "claimed":
        try:
            _resume_run(run_id)
            return True
        except Exception:
            _mark_run_errored(run_id, _RUN_STALE_ERROR)
            return False
    if outcome == "exhausted":
        _mark_run_errored(run_id, _RUN_STALE_ERROR)
        return False
    # "skip" — claimed by another worker, or its heartbeat is fresh (alive). A
    # rare lost-race against a run that just finished/errored corrects itself on
    # the next poll, which reads the real terminal status from the DB.
    return True


# Startup sweep — defined here, after the resume machinery, so the import-time
# call can re-launch (or honestly fail) any run the previous process left
# interrupted.
_reconcile_interrupted_runs()


# ---------------------------------------------------------------------
# Results-from-a-link — background fetch job (Step 7)
# ---------------------------------------------------------------------
# Paste a results URL → a background thread reads the site (static →
# rendered → AI page-read), packages a mirror ZIP, and stages it exactly
# like an uploaded file so the URL path converges at /upload/configure.
# The file-upload path is untouched.

_url_jobs: dict[str, dict] = {}
_url_jobs_lock = threading.Lock()
_URL_JOBS_MAX = 32

# A fetch job whose heartbeat has been silent for this long is treated as stalled
# (a hung render, or a recycled worker that took the crawl thread with it) and
# reported as a terminal error so the page stops polling "Reading the site…"
# forever. Comfortably longer than the crawl's own page/render budgets (180/240s)
# so a healthy-but-slow crawl is never killed early.
_URL_JOB_STALL_S = 300.0

# Per-session rate limit on the fetch route — a headless browser crawl is a real
# cost, so cap how many a single session can kick off in a window.
_url_fetch_rate: dict[str, list[float]] = {}
_URL_FETCH_RATE_MAX = 6
_URL_FETCH_RATE_WINDOW_S = 300


def _url_fetch_rate_ok(key: str) -> bool:
    now = time.time()
    with _url_jobs_lock:
        hits = [t for t in _url_fetch_rate.get(key, []) if now - t < _URL_FETCH_RATE_WINDOW_S]
        if len(hits) >= _URL_FETCH_RATE_MAX:
            _url_fetch_rate[key] = hits
            return False
        hits.append(now)
        _url_fetch_rate[key] = hits
        if len(_url_fetch_rate) > 256:  # opportunistic cleanup
            for k in list(_url_fetch_rate)[:128]:
                _url_fetch_rate.pop(k, None)
        return True


def _results_url_enabled() -> bool:
    """Kill-switch: ``MEDIAHUB_RESULTS_FETCH_ENABLED=0`` hides the input and 404s
    the route. Default on."""
    return os.environ.get("MEDIAHUB_RESULTS_FETCH_ENABLED", "1").strip().lower() not in (
        "0",
        "false",
        "no",
        "off",
    )


def _url_jobs_dir() -> Path:
    """The shared-disk directory holding per-job status JSON.

    Lives under ``DATA_DIR`` (Render's persistent disk at ``/var/mediahub``) so
    every gunicorn worker reads the same job state — the crawl thread runs in
    one worker but the load-balanced status poll may land on another.
    """
    d = DATA_DIR / "url_jobs"
    d.mkdir(parents=True, exist_ok=True)
    return d


def _url_job_file_write(job_id: str, entry: dict) -> None:
    """Persist a job's state to shared disk (atomic replace; best-effort)."""
    try:
        path = _url_jobs_dir() / f"{job_id}.json"
        tmp = path.with_suffix(".json.tmp")
        tmp.write_text(json.dumps(entry), encoding="utf-8")
        tmp.replace(path)
    except Exception:
        pass


def _url_job_file_read(job_id: str) -> Optional[dict]:
    """Read a job's persisted state from shared disk, or ``None``."""
    try:
        path = _url_jobs_dir() / f"{job_id}.json"
        if path.is_file():
            return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        pass
    return None


def _url_jobs_files_prune() -> None:
    """Cap the on-disk job files, dropping finished jobs oldest-first.

    Mirrors the in-memory ``_URL_JOBS_MAX`` cleanup but works across workers:
    the files may have been written by any worker, so prune by directory listing
    rather than by this worker's in-memory view.
    """
    try:
        files = list(_url_jobs_dir().glob("*.json"))
        if len(files) <= _URL_JOBS_MAX:
            return
        now = time.time()
        # Files whose heartbeat is quiet well past the status route's stall
        # guard are dead — a worker crash/restart mid-crawl leaves a "running"
        # file forever, which the finished-only sweep below never reaps. Prune
        # them regardless of status so DATA_DIR/url_jobs can't grow unbounded.
        stale_ttl = _URL_JOB_STALL_S * 2
        finished: list[tuple[float, Path]] = []
        for f in files:
            try:
                data = json.loads(f.read_text(encoding="utf-8")) or {}
            except Exception:
                data = {}
            status = data.get("status")
            try:
                mtime = f.stat().st_mtime
            except OSError:
                continue
            beat = float(data.get("heartbeat") or 0.0) or mtime
            if status in ("done", "error"):
                finished.append((mtime, f))
            elif (now - beat) > stale_ttl:
                # A genuinely alive crawl heartbeats < stall_ttl; anything older
                # is wedged and safe to drop.
                f.unlink(missing_ok=True)
        finished.sort()
        remaining = len(list(_url_jobs_dir().glob("*.json")))
        for _, f in finished[: max(0, remaining - _URL_JOBS_MAX)]:
            f.unlink(missing_ok=True)
    except Exception:
        pass


def _url_job_set(job_id: str, **fields) -> None:
    with _url_jobs_lock:
        entry = _url_jobs.setdefault(job_id, {})
        entry.update(fields)
        entry["heartbeat"] = time.time()
        snapshot = dict(entry)
        if len(_url_jobs) > _URL_JOBS_MAX:
            finished = [j for j, e in _url_jobs.items() if e.get("status") in ("done", "error")]
            for j in finished[: max(0, len(_url_jobs) - _URL_JOBS_MAX)]:
                _url_jobs.pop(j, None)
    # Write-through to shared disk so any worker can serve the status poll.
    _url_job_file_write(job_id, snapshot)
    _url_jobs_files_prune()


def _url_job_get(job_id: str) -> Optional[dict]:
    with _url_jobs_lock:
        entry = _url_jobs.get(job_id)
        if entry:
            return dict(entry)
    # Not in this worker's memory — fall back to the shared-disk copy a sibling
    # worker may have written (the write-through cache only sees its own jobs).
    return _url_job_file_read(job_id)


def _run_source_url(run_id: str) -> Optional[str]:
    """The results-page URL a run was fetched from, or None for file uploads.

    Read from the optional ``source_url.txt`` sidecar ``_start_run`` writes. Lets
    the review page show provenance and offer a re-fetch as a fresh run.
    """
    try:
        path = RUNS_DIR / run_id / "source_url.txt"
        if path.is_file():
            val = path.read_text(encoding="utf-8").strip()
            return val or None
    except Exception:
        pass
    return None


def _run_provenance(run_id: str) -> Optional[dict]:
    """The mirror's ``_provenance.json`` for a results-from-a-link run, or None.

    Read from the run's persisted ``input.bin`` ZIP (the staged mirror, which
    the file-upload path never produces). Bounded via ``_zip_safety`` and fully
    defensive — never raises into the review page.
    """
    try:
        path = RUNS_DIR / run_id / "input.bin"
        if not path.is_file():
            return None
        import zipfile  # noqa: PLC0415

        from mediahub.interpreter._zip_safety import safe_infolist, safe_read_member  # noqa: PLC0415

        # Open the file directly (random access reads only the central directory
        # + the one member) rather than slurping the whole mirror ZIP — up to the
        # 50MB crawl cap — into RAM on every review-page render.
        with zipfile.ZipFile(path) as zf:
            info = {i.filename: i for i in safe_infolist(zf)}.get("_provenance.json")
            if info is None:
                return None
            raw = safe_read_member(zf, info)
        return json.loads(raw.decode("utf-8", "ignore"))
    except Exception:
        return None


def _run_ai_read_sources(run_id: str) -> list[dict]:
    """AI-read tables recorded for a run: ``[{source_url, model, tables,
    confidence}, …]``, or ``[]``. Lets the review page mark which results were
    read from the page by AI (Tier C) rather than parsed deterministically."""
    prov = _run_provenance(run_id)
    if not prov:
        return []
    return [e for e in (prov.get("ai_extractions") or []) if isinstance(e, dict)]


def _best_club_match(clubs: list[str], target: str) -> str:
    """The club whose name best matches ``target`` (the active org), or "".

    Combines substring containment, a significant-token subset/overlap test
    (so an abbreviation like "Otter SC" still matches "Otter Swimming Club"),
    and a difflib ratio — sport/vendor-agnostic, no abbreviation dictionaries.
    This is only a pre-selection default; the user still confirms. Returns ""
    when nothing clears a confidence floor, so a wrong club is never silently
    auto-picked.
    """
    import difflib  # noqa: PLC0415
    import re as _re  # noqa: PLC0415

    def _norm(s: str) -> str:
        return _re.sub(r"[^a-z0-9]+", " ", (s or "").lower()).strip()

    def _sig(norm: str) -> set[str]:
        toks = norm.split()
        big = [t for t in toks if len(t) >= 3]  # drop noise like "sc", "of"
        return set(big or toks)

    nt = _norm(target)
    if not nt or not clubs:
        return ""
    nt_sig = _sig(nt)
    best, best_score = "", 0.0
    for club in clubs:
        nc = _norm(club)
        if not nc:
            continue
        if nt == nc:
            return club
        score = difflib.SequenceMatcher(None, nt, nc).ratio()
        if nt in nc or nc in nt:
            score = max(score, 0.9)
        nc_sig = _sig(nc)
        if nt_sig and nc_sig:
            if nt_sig <= nc_sig or nc_sig <= nt_sig:
                score = max(score, 0.88)
            else:
                score = max(score, len(nt_sig & nc_sig) / len(nt_sig | nc_sig))
        if score > best_score:
            best, best_score = club, score
    return best if best_score >= 0.6 else ""


def _stage_results_zip(zip_bytes: bytes, source_url: str, profile_id: Optional[str]) -> str:
    """Write the mirror ZIP as a staged upload (mirrors ``upload()``) and return
    the temp run id for ``/upload/configure``. Adds ``source_url`` to the meta."""
    from urllib.parse import urlparse

    temp_run_id = uuid.uuid4().hex[:12]
    tmp_dir = RUNS_DIR / temp_run_id
    tmp_dir.mkdir(parents=True, exist_ok=True)
    (tmp_dir / "input.bin").write_bytes(zip_bytes)

    parsed = urlparse(source_url)
    host = (parsed.hostname or "site").replace(":", "_")
    path_slug = (parsed.path or "").strip("/").replace("/", "-")[:40] or "results"
    meta = {
        "filename": f"{host}-{path_slug}.zip",
        "profile_id": profile_id,
        "use_cache": True,
        "fetch_pbs": True,
        "display_name": "",
        "source_url": source_url,
    }
    # Same light-parse for clubs / meet name as the file-upload path.
    try:
        from mediahub.interpreter import interpret_document

        interpreted = interpret_document(zip_bytes, hint=None)
        clubs: list[str] = []
        seen: set[str] = set()
        for ev in interpreted.events:
            for sw in ev.swims:
                c = (sw.club or "").strip()
                if c and c.lower() not in seen:
                    seen.add(c.lower())
                    clubs.append(c)
        meta["clubs"] = sorted(clubs, key=str.lower)
        meta["meet_name"] = interpreted.meet_name or ""
        meta["meet_date"] = (interpreted.dates[0] if interpreted.dates else "") or ""
        meta["n_events"] = len(interpreted.events)
        meta["file_byte_size"] = len(zip_bytes)
    except Exception as exc:
        meta["clubs"] = []
        meta["parse_error"] = str(exc)
        meta["file_byte_size"] = len(zip_bytes)
    (tmp_dir / "upload_meta.json").write_text(json.dumps(meta, indent=2), encoding="utf-8")
    return temp_run_id


def _run_url_fetch_job(job_id: str, url: str, profile_id: Optional[str]) -> None:
    """Crawl → (AI-read) → package → stage. Updates the job's status dict so the
    upload page can poll tier-aware progress. Honest errors, never a 500."""
    _url_job_set(
        job_id, status="running", phase="fetching", progress="Reading the site…", percent=8
    )
    try:
        from mediahub.media_ai.llm import ClaudeUnavailableError
        from mediahub.results_fetch.ai_read import ai_read_candidates
        from mediahub.results_fetch.crawl import CrawlLimits, crawl_results_site
        from mediahub.results_fetch.package import package_mirror

        # Honest live percent for the fetching phase. A crawl has no fixed total
        # up front, so we blend two real signals: the fraction of the *discovered*
        # frontier already read (leads while the site is being mapped) and the
        # elapsed share of the crawl's own time budget (pulls the bar forward so a
        # deep site never feels stuck). The bar is held monotonic client-side. The
        # budget comes from the crawl's own canonical config (one source of truth).
        _fetch_t0 = time.monotonic()
        _timeout_budget = CrawlLimits.from_env().timeout_s or 180.0
        _FETCH_LO, _FETCH_HI = 8, 72

        def _on_progress(progress) -> None:
            pages = progress.pages_visited
            discovered = max(progress.discovered_total, pages)
            elapsed = time.monotonic() - _fetch_t0
            time_frac = min(1.0, elapsed / _timeout_budget)
            # Cap the time signal just under 1 so elapsed alone never reads "done".
            blended = max(progress.fraction, 0.85 * time_frac)
            percent = int(_FETCH_LO + blended * (_FETCH_HI - _FETCH_LO))
            kb = progress.total_bytes // 1024
            _url_job_set(
                job_id,
                phase="fetching",
                progress=(
                    f"Reading the site — page {pages} of ~{discovered} · "
                    f"{progress.kept} with results · {kb} KB"
                ),
                percent=max(_FETCH_LO, min(_FETCH_HI, percent)),
                # Structured counters so the UI renders live stat chips without
                # parsing the human text.
                pages=pages,
                discovered=discovered,
                kept=progress.kept,
                kb=kb,
            )

        crawl = crawl_results_site(url, progress_cb=_on_progress)
        _data_exts = (".pdf", ".csv", ".tsv", ".json", ".xlsx", ".xls", ".txt")
        _result_files = sum(1 for k in crawl.files if k.lower().endswith(_data_exts))
        summary = (
            f"Fetched {crawl.pages_visited} pages · {crawl.kept} kept "
            f"({_result_files} result file{'' if _result_files == 1 else 's'}) · "
            f"{crawl.total_bytes // 1024} KB"
        )
        if crawl.render_budget_hit:
            summary += " · render budget reached"
        _url_job_set(
            job_id,
            phase="reading",
            progress=summary,
            percent=75,
            pages=crawl.pages_visited,
            discovered=crawl.pages_visited,
            kept=crawl.kept,
            kb=crawl.total_bytes // 1024,
        )

        # "No results" = nothing the engine could keep. The entry landing page is
        # always recorded for provenance, so ``is_empty`` can be False even when
        # nothing useful was kept; gate on ``kept`` instead.
        no_results = crawl.kept == 0

        ai_extractions: list = []
        if crawl.ai_candidates:
            _url_job_set(
                job_id,
                phase="reading",
                progress=summary + f" · reading {len(crawl.ai_candidates)} page(s) with AI",
                percent=82,
            )
            try:

                def _ai_read_progress(i: int, total: int) -> None:
                    _url_job_set(
                        job_id,
                        phase="reading",
                        progress=summary + f" · AI-reading page {i} of {total}",
                        percent=82,
                    )

                ai_extractions = ai_read_candidates(
                    crawl.ai_candidates, progress_cb=_ai_read_progress
                )
            except ClaudeUnavailableError:
                if no_results:
                    _url_job_set(
                        job_id,
                        status="error",
                        error=(
                            "This site's results are only in images, and no AI vision "
                            "provider is configured to read them. Ask your administrator "
                            "to set a Gemini or Anthropic API key."
                        ),
                    )
                    return
                # Deterministic results exist — proceed without Tier C.

        if no_results and not ai_extractions:
            # Honest "why no results": surface what the crawl actually saw on the
            # entry page so a scope/discovery miss is diagnosable from the status
            # endpoint instead of silently staging an empty landing page.
            diag = (
                " · diagnostics: "
                f"entry tier={crawl.entry_tier or 'unknown'}, "
                f"final_url={crawl.entry_final_url or 'n/a'}, "
                f"links found={crawl.entry_links_found}, "
                f"in scope={crawl.entry_links_in_scope}"
            )
            _url_job_set(
                job_id,
                status="error",
                error=(
                    "No competition results were found on that page. It may be "
                    "login-walled, or the results live on a different URL." + diag
                ),
            )
            return

        _url_job_set(job_id, phase="packaging", progress=summary + " · packaging", percent=92)
        zip_bytes = package_mirror(crawl, ai_extractions)
        temp_run_id = _stage_results_zip(zip_bytes, url, profile_id)
        _url_job_set(job_id, status="done", run_id=temp_run_id, progress=summary, percent=100)
    except Exception as e:  # noqa: BLE001 — surface as an honest job error, not a 500
        import traceback

        traceback.print_exc()
        _url_job_set(job_id, status="error", error=str(e))


def _start_url_fetch_job(url: str, profile_id: Optional[str]) -> str:
    job_id = uuid.uuid4().hex[:12]
    _url_job_set(
        job_id, status="queued", phase="queued", progress="Queued", source_url=url, percent=3
    )
    t = threading.Thread(target=_run_url_fetch_job, args=(job_id, url, profile_id), daemon=True)
    t.start()
    return job_id


