BASE_CSS = """
/* PODIUM AFTER DARK
   - Big Shoulders Display: condensed sport display headlines
   - Fraunces (opsz): editorial serif for emphasis, drop-caps, italic accents
   - Hanken Grotesk: humanist body / UI (not Inter, not Roboto)
   - JetBrains Mono: scoreboard data, mono labels, slashed-zero
*/
/* Fonts are SELF-HOSTED (Council verdict 2026-05-31): _layout's <head> links
   the first-party static/theme/fonts.css (@font-face -> static/fonts/*.woff2)
   and preloads the two universal above-the-fold faces. No Google Fonts CDN —
   that fixes the intermittent Impact/Oswald fallback users saw and the EU/UK
   GDPR exposure of the CDN. The --font-body stack carries a metric-tuned
   'Hanken Grotesk Fallback' so the load swap produces no layout shift. */

:root {
  /* PHASE 1.6 STAGE A — every colour token below now resolves through the
     three-tier vocabulary defined in src/mediahub/web/theme_tokens.py
     (prepended ahead of BASE_CSS). Pixel-identical to the previous flat
     palette; the indirection is what lets Stage E re-skin the whole site
     from a single brand seed without touching component CSS. */

  /* Surfaces — pit-wall black to deep ink. Near-monochrome, no purple. */
  --bg:        var(--mh-surface);             /* #0A0B11 — pit-wall black */
  --bg-deep:   var(--mh-surface-deep);        /* #06070C */
  --surface:   var(--mh-surface-variant);     /* #14171F — card / panel base */
  --surface-2: var(--mh-surface-container);   /* #1A1E28 — raised */
  --surface-3: var(--mh-surface-container-high); /* #232838 — hover */
  --hairline:  var(--mh-outline-variant);     /* rgba(245,242,232,0.06) */
  --rule:      var(--mh-outline-rule);        /* rgba(245,242,232,0.10) */
  --chrome:    var(--mh-outline);             /* rgba(245,242,232,0.14) */

  /* Ink — paper-cream on dark for editorial warmth (not white-on-blue).
     --ink-muted raised from #7A7869 (4.41:1) to #9A988A (5.69:1 on bg)
     to clear WCAG AA for normal body text. The smallest text in the app
     (10.5px mono labels) lives at this token and was just below spec. */
  --ink:       var(--mh-on-surface);          /* #F5F2E8 — primary text */
  --ink-dim:   var(--mh-on-surface-variant);  /* #B6B2A6 — 9.27:1 safe */
  --ink-muted: var(--mh-on-surface-muted);    /* #9A988A — 5.69:1 AA */
  --ink-faint: var(--mh-on-surface-faint);    /* #62604F — large/decorative */

  /* SIGNATURE ACCENT — lane-marker yellow.
     The single chrome colour. Every CTA, focus ring, link, live state.
     No gradient, no fade — flat saturated hi-vis. */
  --lane:      var(--mh-primary);             /* #D4FF3A */
  --lane-h:    var(--mh-primary-hover);       /* #E6FF6B — hover lift */
  --lane-deep: var(--mh-primary-pressed);     /* #A8CC2E — pressed/underline */
  --lane-ink:  var(--mh-on-primary);          /* #0A0B11 — text on lane bg */
  /* The accent glow tracks --lane (← --mh-primary), so every glow/shadow that
     uses var(--lane-glow) follows the active club's brand colour just like the
     strokes do — change the club's colours and the whole site's accents recolour
     together. Falls back to the lane-yellow default when --lane is the default. */
  --lane-glow: color-mix(in oklab, var(--lane) 35%, transparent);

  /* SIGNATURE ACCENT 2 — medal gold.
     Reserved EXCLUSIVELY for athlete achievements (PB, medal, first-time,
     ranked, standout). NEVER chrome. NEVER UI. Earns its weight by scarcity. */
  --medal:        var(--mh-tertiary);                  /* #F4D58D */
  --medal-h:      var(--mh-prim-tertiary-200);         /* #FFE5A1 */
  --medal-deep:   var(--mh-prim-tertiary-600);         /* #C9A04B */
  --medal-ink:    var(--mh-on-tertiary);               /* #2B1F00 */
  --medal-glow:   rgba(244,213,141,0.30);
  --grad-medal:   linear-gradient(135deg, var(--mh-prim-tertiary-200) 0%, var(--mh-prim-tertiary-600) 100%);

  /* Tertiary — timing-screen blue. Rare. Used for INFO / NEUTRAL state only. */
  --info:      var(--mh-info);                /* #4DA3FF */
  --info-bg:   rgba(77,163,255,0.10);

  /* Semantic — desaturated, readable, no neon */
  --good:      var(--mh-success);             /* #5EE39A */
  --good-bg:   rgba(94,227,154,0.10);
  --warn:      var(--mh-warning);             /* #FFB454 */
  --warn-bg:   rgba(255,180,84,0.10);
  --bad:       var(--mh-error);               /* #FF6B6B */
  --bad-bg:    rgba(255,107,107,0.10);

  /* Legacy aliases so old class names keep working through the cascade.
     The new code should reference --mh-* (tier-2) directly. The middle
     layer (--lane, --medal, …) is preserved for backward compatibility
     and re-resolves through the tier-2 tokens above. */
  --accent:    var(--mh-primary);
  --accent-h:  var(--mh-primary-hover);
  --accent2:   var(--mh-primary);
  --accent2-h: var(--mh-primary-hover);
  --accent3:   var(--mh-tertiary);
  --gold:      var(--mh-tertiary);
  --gold-h:    var(--mh-prim-tertiary-200);
  --panel:     var(--mh-surface-variant);
  --panel2:    var(--mh-surface-container);
  --panel-h:   var(--mh-surface-container-high);
  --border:    var(--mh-outline-variant);
  --border-h:  var(--mh-outline);
  --bg-soft:   var(--mh-surface-variant);

  /* Typography stacks — every face here is intentional */
  --font-display: 'Big Shoulders Display', 'Impact', 'Oswald', sans-serif;
  --font-serif:   'Fraunces', 'Source Serif Pro', Georgia, serif;
  --font-body:    'Hanken Grotesk', 'Hanken Grotesk Fallback', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --font-mono:    'JetBrains Mono', ui-monospace, 'SF Mono', Menlo, monospace;

  /* Spacing scale (4px base) */
  --sp-1:  4px;   --sp-2:  8px;   --sp-3:  12px;  --sp-4:  16px;
  --sp-5:  20px;  --sp-6:  24px;  --sp-7:  32px;  --sp-8:  48px;
  --sp-9:  64px;  --sp-10: 96px;

  /* Radii — sharp by default. Soft only where ergonomically required. */
  --radius:    4px;
  --radius-sm: 3px;
  --radius-md: 6px;
  --radius-lg: 10px;
  --radius-pill: 999px;

  /* Shadows — depth-by-elevation, not depth-by-decoration. Re-pointed
     at the tier-2 --mh-elevation-{1,2,3} tokens defined in theme_tokens. */
  --shadow-1: var(--mh-elevation-1);
  --shadow-2: var(--mh-elevation-2);
  --shadow-3: var(--mh-elevation-3);
  --shadow-lane:  0 0 0 1px var(--lane-glow), 0 8px 26px var(--lane-glow);
  --shadow-medal: 0 0 0 1px var(--medal-glow), 0 8px 26px var(--medal-glow);
  /* legacy */
  --shadow:    var(--shadow-2);
  --shadow-h:  var(--shadow-3);

  --transition:      150ms cubic-bezier(0.4,0,0.2,1);
  --transition-slow: 320ms cubic-bezier(0.85,0,0.15,1);
}

* { box-sizing: border-box; }
html, body { margin: 0; padding: 0; }
html { background: var(--bg-deep); }
body {
  font-family: var(--font-body);
  background:
    /* One subtle radial lift at top centre — stadium-light fall-off.
       Light mode swaps the cream tint for a faint ink tint so the lift
       and the grid lattice stay visible on the paper page. */
    radial-gradient(1400px 600px at 50% -10%, rgba(245,242,232,0.04), transparent 70%),
    /* Faint 40px grid lattice — pit-wall / scoreboard substrate */
    linear-gradient(rgba(245,242,232,0.022) 1px, transparent 1px) 0 0 / 40px 40px,
    linear-gradient(90deg, rgba(245,242,232,0.022) 1px, transparent 1px) 0 0 / 40px 40px,
    var(--bg);
  background-attachment: fixed;
  color: var(--ink);
  font-size: 15px;
  line-height: 1.55;
  letter-spacing: -0.005em;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  /* Slashed-zero + tabular figures + ligatures everywhere by default */
  font-feature-settings: 'ss01' 1, 'tnum' 0, 'liga' 1, 'calt' 1;
  font-variant-numeric: oldstyle-nums;
}
a {
  /* Dark: pure lane-yellow (unchanged). Light: a dark-olive brand tone
     (--mh-link) — lane-yellow text is illegible on the paper page. */
  color: var(--lane);
  text-decoration: none;
  transition: color var(--transition);
  text-underline-offset: 0.18em;
  text-decoration-thickness: 1px;
}
a:hover { color: var(--lane-h); text-decoration: underline; text-decoration-color: var(--lane); }
::selection { background: var(--lane); color: var(--lane-ink); }

/* TOPNAV — pit-wall masthead: condensed wordmark + mono control panel */
header.topnav {
  display: flex;
  align-items: stretch;
  gap: 0;
  padding: 0 var(--sp-7);
  height: 64px;
  border-bottom: 1px solid var(--hairline);
  background: rgba(10,11,17,0.92);
  /* No blur — glass is banned by every audit. Solid pit-wall (dark) /
     solid paper (light) instead. */
  position: sticky;
  top: 0;
  z-index: 100;
}
header.topnav::after {
  content: ''; position: absolute; left: 0; right: 0; bottom: -1px;
  height: 1px;
  background: var(--lane);
  opacity: 0.40;
  pointer-events: none;
}
header.topnav .brand {
  font-family: var(--font-display);
  font-weight: 900;
  font-size: 22px;
  letter-spacing: 0.02em;
  text-transform: uppercase;
  color: var(--ink);
  display: flex;
  align-items: center;
  gap: 12px;
  margin-right: var(--sp-8);
  text-decoration: none;
  flex-shrink: 0;
  transition: color var(--transition);
  position: relative;
}
header.topnav .brand:hover { color: var(--lane); }
header.topnav .brand svg { flex-shrink: 0; display: block; }
/* Vertical hairline separator after wordmark — broadsheet detail */
header.topnav .brand::after {
  content: '';
  position: absolute; right: calc(var(--sp-8) * -0.5);
  top: 18px; bottom: 18px;
  width: 1px; background: var(--hairline);
}
header.topnav nav {
  display: flex; align-items: stretch; gap: 0; flex: 1;
  padding-left: var(--sp-2);
}
header.topnav nav a {
  position: relative;
  display: inline-flex; align-items: center;
  font-family: var(--font-mono);
  color: var(--ink-muted);
  padding: 0 var(--sp-4);
  font-size: 11px;
  font-weight: 500;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  transition: color var(--transition);
  white-space: nowrap;
  border-radius: 0;
}
header.topnav nav a:hover {
  color: var(--ink);
  background: transparent;
  text-decoration: none;
}
header.topnav nav a.active {
  color: var(--lane);
  background: transparent;
}
header.topnav nav a.active::after {
  content: '';
  position: absolute;
  left: var(--sp-4); right: var(--sp-4);
  bottom: 0;
  height: 2px;
  background: var(--lane);
  border-radius: 0;
  box-shadow: 0 0 16px var(--lane-glow);
}
/* Tiny inline "live dot" for nav items that should pulse a status (use class) */
header.topnav nav a.live::before {
  content: '';
  width: 6px; height: 6px;
  border-radius: 50%;
  background: var(--lane);
  box-shadow: 0 0 10px var(--lane-glow);
  margin-right: 8px;
  animation: mh-pulse 1.6s ease-in-out infinite;
}
/* Invisible flex spacer — absorbs the free space between the primary nav links
   and the right-hand utility / account cluster (notifications + active-org
   menu, or the signed-out auth links), pushing the cluster to the right edge.
   This replaces the old backend "online" pill's margin-left:auto, which used
   to carry that role before the pill was removed. */
.mh-nav-spacer { margin-left: auto; }
/* === UI 1.14 — Notifications inbox (bell + unread badge + dropdown) ===
   Masthead-consistent: mono labels, --chrome rule, --lane accent. The panel
   is position:fixed and JS-anchored under the bell so the scrollable /
   hamburger nav can never clip it. */
.mh-notif {
  position: relative;
  display: inline-flex; align-items: center; align-self: center;
  flex-shrink: 0; margin-left: 6px;
}
.mh-notif-btn {
  position: relative;
  display: inline-flex; align-items: center; justify-content: center;
  width: 34px; height: 30px; padding: 0;
  background: transparent;
  border: 1px solid var(--chrome);
  border-radius: 2px;
  color: var(--ink-muted);
  cursor: pointer;
  transition: border-color var(--transition), color var(--transition);
}
.mh-notif-btn:hover,
.mh-notif-btn[aria-expanded="true"] { border-color: var(--lane); color: var(--ink); }
.mh-notif-btn svg { width: 17px; height: 17px; display: block; }
.mh-notif-badge {
  position: absolute; top: -6px; right: -6px;
  min-width: 16px; height: 16px; padding: 0 4px;
  display: inline-flex; align-items: center; justify-content: center;
  font-family: var(--font-mono);
  font-size: 10px; font-weight: 700; line-height: 1;
  color: #0A0B11;
  background: var(--lane);
  border-radius: 9px;
  box-shadow: 0 0 0 2px var(--bg), 0 0 10px var(--lane-glow);
  pointer-events: none;
}
.mh-notif-badge[hidden] { display: none; }
.mh-notif-panel {
  position: fixed; top: 0; right: 0;   /* JS sets the real top/right */
  width: 360px; max-width: calc(100vw - 24px);
  max-height: min(70vh, 480px);
  display: flex; flex-direction: column;
  background: var(--surface, var(--panel, #14171F));
  border: 1px solid var(--chrome);
  border-radius: 6px;
  box-shadow: 0 18px 50px -12px rgba(0,0,0,0.7), 0 0 0 1px rgba(0,0,0,0.3);
  z-index: 1200;
  overflow: hidden;
  animation: mh-notif-in 0.16s ease-out;
}
.mh-notif-panel[hidden] { display: none; }
@keyframes mh-notif-in {
  from { opacity: 0; transform: translateY(-6px); }
  to   { opacity: 1; transform: translateY(0); }
}
.mh-notif-head {
  display: flex; align-items: center; justify-content: space-between;
  padding: 11px 14px;
  border-bottom: 1px solid var(--chrome);
  flex-shrink: 0;
}
.mh-notif-h-title {
  font-family: var(--font-mono);
  font-size: 11px; font-weight: 600;
  letter-spacing: 0.16em; text-transform: uppercase;
  color: var(--ink);
}
.mh-notif-readall {
  background: transparent; border: 0;
  font-family: var(--font-mono);
  font-size: 10.5px; letter-spacing: 0.06em;
  color: var(--ink-muted);
  cursor: pointer; padding: 2px 4px;
  transition: color var(--transition);
}
.mh-notif-readall:hover { color: var(--lane); }
.mh-notif-readall:disabled { opacity: 0.35; cursor: default; }
.mh-notif-list { overflow-y: auto; flex: 1; }
.mh-notif-item {
  display: flex; gap: 10px; align-items: flex-start;
  width: 100%; text-align: left;
  padding: 11px 14px;
  background: transparent; border: 0;
  border-bottom: 1px solid rgba(245,242,232,0.07);
  cursor: pointer; color: var(--ink); font: inherit;
  transition: background var(--transition);
}
.mh-notif-item:hover { background: rgba(245,242,232,0.04); }
.mh-notif-item.is-unread { background: color-mix(in oklab, var(--lane) 5%, transparent); }
.mh-notif-item.is-unread:hover { background: color-mix(in oklab, var(--lane) 9%, transparent); }
.mh-notif-dot {
  flex-shrink: 0; width: 8px; height: 8px; border-radius: 50%;
  margin-top: 5px; background: var(--ink-faint);
}
.mh-notif-item[data-level="success"] .mh-notif-dot { background: var(--good); box-shadow: 0 0 8px rgba(94,227,154,0.5); }
.mh-notif-item[data-level="warning"] .mh-notif-dot { background: var(--warn); }
.mh-notif-item[data-level="error"]   .mh-notif-dot { background: var(--bad);  box-shadow: 0 0 8px rgba(255,107,107,0.5); }
.mh-notif-item.is-read .mh-notif-dot { background: var(--ink-faint); box-shadow: none; }
.mh-notif-text { min-width: 0; flex: 1; }
.mh-notif-t {
  display: block;
  font-size: 13px; font-weight: 600; line-height: 1.3;
  color: var(--ink); overflow-wrap: anywhere;
}
.mh-notif-item.is-read .mh-notif-t { color: var(--ink-muted); font-weight: 500; }
.mh-notif-m {
  display: block; margin-top: 2px;
  font-size: 12px; line-height: 1.4;
  color: var(--ink-muted); overflow-wrap: anywhere;
}
.mh-notif-time {
  display: block; margin-top: 4px;
  font-family: var(--font-mono);
  font-size: 10px; letter-spacing: 0.04em;
  color: var(--ink-faint); text-transform: uppercase;
}
.mh-notif-empty {
  display: none;
  flex-direction: column; align-items: center; justify-content: center;
  gap: 6px; padding: 34px 20px 38px; text-align: center;
}
.mh-notif-panel.is-empty .mh-notif-empty { display: flex; }
.mh-notif-panel.is-empty .mh-notif-list { display: none; }
.mh-notif-empty svg { width: 26px; height: 26px; color: var(--ink-faint); opacity: 0.7; }
.mh-notif-empty-t { font-size: 13px; font-weight: 600; color: var(--ink-muted); }
.mh-notif-empty-s { font-size: 11.5px; color: var(--ink-faint); max-width: 220px; line-height: 1.4; }

/* === Active-org account menu (signed-in) — the chip is a dropdown trigger ===
   Replaces the old chip's "review brand setup" shortcut. Mirrors the
   notifications dropdown: a JS-anchored position:fixed panel the scrollable /
   hamburger nav can never clip. Progressive enhancement — with no JS the menu
   items render inline (never hidden); .mh-js collapses them into the dropdown. */
.mh-orgmenu {
  position: relative;
  display: inline-flex; align-items: center; align-self: center;
  flex-shrink: 0; margin-left: 8px;
}
.mh-orgmenu-btn {
  display: inline-flex; align-items: center; gap: 8px;
  border: 1px solid var(--chrome, var(--border, rgba(245,242,232,0.14)));
  border-radius: 999px; color: var(--ink); cursor: pointer;
  font: inherit; background: rgba(245,242,232,0.03);
  transition: border-color var(--transition), color var(--transition);
}
.mh-orgmenu-btn:hover,
.mh-orgmenu-btn[aria-expanded="true"] { border-color: var(--lane); color: var(--ink); }
.mh-orgmenu-name {
  font-weight: 600; letter-spacing: 0.01em;
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}
/* The caret only makes sense as a dropdown affordance, so it ships only when
   JS can actually open the menu. */
.mh-orgmenu-caret { display: none; flex-shrink: 0; opacity: 0.7; transition: transform var(--transition); }
.mh-js .mh-orgmenu-caret { display: block; }
.mh-orgmenu-btn[aria-expanded="true"] .mh-orgmenu-caret { transform: rotate(180deg); }
/* No-JS fallback: the items sit inline as a small run of mono nav links. */
.mh-orgmenu-panel { display: inline-flex; align-items: center; }
.mh-orgmenu-item {
  font-family: var(--font-mono); font-size: 11px; font-weight: 500;
  letter-spacing: 0.14em; text-transform: uppercase; color: var(--ink-muted);
  padding: 0 var(--sp-4); white-space: nowrap; text-decoration: none;
  display: inline-flex; align-items: center;
  transition: color var(--transition), background var(--transition);
}
.mh-orgmenu-item:hover { color: var(--ink); }
.mh-orgmenu-item.active { color: var(--lane); }
/* JS present: collapse into a real dropdown anchored under the chip. */
.mh-js .mh-orgmenu-panel {
  position: fixed; top: 0; right: 0;   /* JS sets the real top/right */
  display: none;                       /* shown on .is-open */
  flex-direction: column; align-items: stretch;
  width: 220px; max-width: calc(100vw - 24px);
  background: var(--surface, var(--panel, #14171F));
  border: 1px solid var(--chrome);
  border-radius: 6px;
  box-shadow: 0 18px 50px -12px rgba(0,0,0,0.7), 0 0 0 1px rgba(0,0,0,0.3);
  z-index: 1200; overflow: hidden; padding: 6px;
  animation: mh-notif-in 0.16s ease-out;
}
.mh-js .mh-orgmenu-panel.is-open { display: flex; }
.mh-js .mh-orgmenu-item {
  font-size: 11px; font-weight: 600; letter-spacing: 0.10em;
  padding: 9px 12px; border-radius: 4px;
}
.mh-js .mh-orgmenu-item:hover { background: rgba(245,242,232,0.05); color: var(--ink); }

/* MAIN */
main.wrap { max-width: 1200px; margin: 0 auto; padding: 36px 28px 96px; }

/* FOOTER — masthead rail */
.mh-footer {
  border-top: 1px solid var(--lane);
  margin-top: var(--sp-9);
  background: var(--bg-deep);
  position: relative;
}
.mh-footer-inner {
  max-width: 1200px; margin: 0 auto;
  padding: var(--sp-7) var(--sp-7) var(--sp-8);
  display: grid;
  grid-template-columns: auto 1fr auto;
  gap: var(--sp-7);
  align-items: center;
}
.mh-footer-brand {
  display: inline-flex; align-items: center; gap: 10px;
  font-family: var(--font-display);
  font-weight: 900;
  font-size: 15px;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--ink);
}
.mh-footer-brand svg { color: var(--lane); }
.mh-footer-center {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--sp-3);
}
.mh-footer-tag {
  font-family: var(--font-serif);
  font-style: italic;
  font-variation-settings: 'opsz' 72;
  font-size: 15px;
  color: var(--ink-dim);
  text-align: center;
}
.mh-footer-meta {
  display: inline-flex; align-items: center; gap: var(--sp-3);
  flex-wrap: wrap;
  font-family: var(--font-mono);
  font-size: 10.5px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--ink-muted);
}
.mh-footer-meta a {
  color: var(--ink-muted);
  transition: color var(--transition);
}
.mh-footer-meta a:hover { color: var(--lane); text-decoration: none; }
.mh-footer-sep { color: var(--ink-faint); }
@media (max-width: 860px) {
  .mh-footer-inner {
    grid-template-columns: 1fr;
    gap: var(--sp-4);
    text-align: center;
  }
  /* Let the stacked grid tracks shrink to the viewport — the mono meta row's
     min-content (a non-wrapping link strip) was otherwise blowing the footer
     past the phone viewport and forcing a horizontal scroll on every page. */
  .mh-footer-inner > * { min-width: 0; }
  .mh-footer-brand, .mh-footer-meta { justify-content: center; }
}

/* HUD READOUT — live local time + deployment/system status rail (UI 1.5).
   A mono blueprint strip at the foot of the masthead: a live local clock on
   the left, a deployment status line (reachability · build · UTC reference)
   on the right. Fed by the /healthz reachability poll plus a client-side
   clock — no new backend surface. Since the header "online" pill was removed,
   this is now the sole reachability indicator. Sits inside .mh-footer so the
   print rule hides it too. */
.mh-hud {
  border-top: 1px solid var(--chrome);
  background: var(--bg-deep);
}
.mh-hud-inner {
  max-width: 1200px;
  margin: 0 auto;
  padding: 9px var(--sp-7);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--sp-4);
  font-family: var(--font-mono);
  font-size: 10px;
  line-height: 1.2;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--ink-muted);
}
.mh-hud-group {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  min-width: 0;
}
.mh-hud-group--system { flex-wrap: wrap; justify-content: flex-end; }
.mh-hud-field {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  white-space: nowrap;
}
.mh-hud-label { color: var(--ink-faint); }
.mh-hud-val   { color: var(--ink-dim); }
.mh-hud-clock { font-variant-numeric: tabular-nums; letter-spacing: 0.12em; }
.mh-hud-tz    { color: var(--ink-faint); }
.mh-hud-sep   { color: var(--ink-faint); opacity: 0.55; }
.mh-hud-dot {
  width: 6px; height: 6px; border-radius: 50%;
  background: var(--ink-faint);
  flex-shrink: 0;
  transition: background 0.3s, box-shadow 0.3s;
}
/* Reachability states — toggled on .mh-hud by the /healthz poll. (This is the
   sole reachability indicator now that the header "online" pill was removed.) */
.mh-hud--online  .mh-hud-dot { background: #5EE39A; box-shadow: 0 0 8px rgba(94,227,154,0.55); }
.mh-hud--offline .mh-hud-dot { background: #FF6B6B; box-shadow: 0 0 8px rgba(255,107,107,0.55); }
.mh-hud--offline .mh-hud-status { color: #FF6B6B; }
@media (max-width: 860px) {
  .mh-hud-inner {
    flex-direction: column;
    gap: 7px;
    padding: 9px var(--sp-5);
  }
  .mh-hud-group--system { justify-content: center; }
}

/* HEADINGS — clear hierarchy, no ambiguity between h1 and section title */
h1 {
  font-family: var(--font-display);
  font-size: clamp(40px, 5.2vw, 64px);
  font-weight: 900;
  letter-spacing: -0.01em;
  text-transform: uppercase;
  margin: 0 0 var(--sp-3);
  color: var(--ink);
  line-height: 0.95;
}
h2 {
  font-family: var(--font-display);
  font-size: clamp(22px, 2.4vw, 28px);
  font-weight: 800;
  letter-spacing: 0;
  text-transform: uppercase;
  margin: 0 0 var(--sp-3);
  color: var(--ink);
  line-height: 1.05;
}
h3 {
  font-family: var(--font-mono);
  font-size: 10.5px; font-weight: 500;
  text-transform: uppercase; letter-spacing: 0.18em;
  color: var(--ink-muted);
  margin: var(--sp-6) 0 var(--sp-3);
}
p { margin: 0 0 var(--sp-3); }
p:last-child { margin-bottom: 0; }

/* Editorial italic — serif emphasis inside copy. Reserved + earned. */
.editorial, em.editorial, .ed-italic {
  font-family: var(--font-serif);
  font-style: italic;
  font-weight: 400;
  font-variation-settings: 'opsz' 144, 'SOFT' 50;
  letter-spacing: -0.005em;
  color: var(--ink);
  font-feature-settings: 'liga' 1, 'dlig' 1, 'ss01' 1;
  text-transform: none;
}
/* Lede — pulled-together body copy under hero / section openings */
.lede {
  font-family: var(--font-serif);
  font-style: normal;
  font-variation-settings: 'opsz' 72;
  font-size: clamp(17px, 1.6vw, 21px);
  font-weight: 400;
  line-height: 1.45;
  letter-spacing: -0.005em;
  color: var(--ink-dim);
  max-width: 56ch;
}
/* Strap — bracketed mono metadata above a section. The defining typographic
   tell of MediaHub: [ MEET / SAT 14 SEP / LANE 4 ] */
.strap {
  display: inline-flex; align-items: center;
  flex-wrap: wrap;
  min-width: 0;
  font-family: var(--font-mono);
  font-size: 10.5px;
  font-weight: 500;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--ink-muted);
  gap: 8px;
  padding: 4px 0;
}
.strap > * { word-break: break-word; overflow-wrap: anywhere; }
.strap::before, .strap::after { content: '['; color: var(--lane); opacity: 0.7; }
.strap::after { content: ']'; }
.strap .sep { color: var(--ink-faint); font-weight: 400; }
.strap.live { color: var(--lane); }
.strap.live::before, .strap.live::after { opacity: 1; }

/* Display numeral — for hero stats / step numbers / lane numbers */
.display-num {
  font-family: var(--font-display);
  font-weight: 900;
  letter-spacing: -0.02em;
  font-variant-numeric: tabular-nums lining-nums;
  font-feature-settings: 'ss01' 1, 'tnum' 1, 'lnum' 1;
  line-height: 0.85;
  color: var(--ink);
}
.display-num.lane { color: var(--lane); }
.display-num.medal { color: var(--medal); }

/* Result row — N..............T.TT (broadsheet leader-dots) */
.result-row {
  display: flex; align-items: baseline;
  font-family: var(--font-body);
  font-size: 15px;
  gap: 8px;
  padding: 6px 0;
  border-bottom: 1px dashed var(--hairline);
}
.result-row .nm { color: var(--ink); font-weight: 500; }
.result-row .dots {
  flex: 1; overflow: hidden; color: var(--ink-faint);
  letter-spacing: 3px; min-width: 24px;
  white-space: nowrap;
  user-select: none;
}
.result-row .dots::before {
  content: '. . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . . .';
}
.result-row .tm {
  font-family: var(--font-mono);
  font-variant-numeric: tabular-nums;
  font-feature-settings: 'tnum' 1, 'ss01' 1;
  color: var(--ink); font-weight: 600;
}
.result-row .tag { margin-left: 8px; }

/* CARDS — sharp, paper-on-pit-wall */
.card {
  background: var(--surface);
  border: 1px solid var(--hairline);
  border-radius: var(--radius);
  padding: var(--sp-6);
  margin-bottom: var(--sp-5);
  box-shadow: var(--shadow-1);
  position: relative;
}
.card h2 { margin: 0 0 var(--sp-3); }
.card p { color: var(--ink-dim); margin: 0 0 var(--sp-3); }
.card p:last-child { margin-bottom: 0; }

/* Cornered card — L-bracket corners in lane yellow. For highlights / featured */
.card.cornered { padding: var(--sp-7); border-color: var(--rule); }
.card.cornered::before, .card.cornered::after {
  content: ''; position: absolute; width: 12px; height: 12px;
  border-color: var(--lane); border-style: solid;
}
.card.cornered::before { top: -1px; left: -1px; border-width: 2px 0 0 2px; }
.card.cornered::after  { bottom: -1px; right: -1px; border-width: 0 2px 2px 0; }
.card.cornered.medal::before, .card.cornered.medal::after { border-color: var(--medal); }

/* BUTTONS — flat lane-yellow, broadcast-control aesthetic */
.btn {
  display: inline-flex; align-items: center; justify-content: center; gap: 10px;
  background: var(--lane); color: var(--lane-ink);
  border: 0; padding: 11px 22px;
  /* Touch-target minimum so .btn (and every inline-styled variant on
     /pack, /sponsor-post, /upload, /make) clears the 44px tap-area
     guideline on every viewport, even when an inline `padding:6px`
     override tries to shrink it. */
  min-height: 44px;
  font-family: var(--font-body);
  font-size: 13px; font-weight: 700;
  border-radius: var(--radius-sm); cursor: pointer;
  transition: background var(--transition), transform var(--transition), box-shadow var(--transition);
  text-decoration: none;
  letter-spacing: 0.01em;
  position: relative;
  isolation: isolate;
  white-space: nowrap;
}
.btn:hover {
  background: var(--lane-h); color: var(--lane-ink);
  transform: translateY(-1px); box-shadow: var(--shadow-lane);
  text-decoration: none;
}
.btn:active { transform: translateY(0); background: var(--lane-deep); }
.btn:focus-visible {
  outline: 2px solid var(--lane);
  outline-offset: 3px;
}
.btn.secondary { background: transparent; color: var(--ink); border: 1px solid var(--chrome); }
.btn.secondary:hover {
  background: rgba(245,242,232,0.04);
  color: var(--ink);
  border-color: var(--lane);
  box-shadow: none;
  transform: translateY(-1px);
}
.btn.ghost { background: transparent; color: var(--ink-dim); padding: 8px 12px; }
.btn.ghost:hover { color: var(--lane); background: transparent; transform: none; box-shadow: none; }
.btn.danger { background: transparent; color: var(--bad); border: 1px solid rgba(255,107,107,0.30); }
.btn.danger:hover { background: var(--bad-bg); border-color: var(--bad); box-shadow: none; }
.btn.medal { background: var(--medal); color: var(--medal-ink); }
.btn.medal:hover { background: var(--medal-h); box-shadow: var(--shadow-medal); }
/* Per-card approve control: outline = still to do, filled = done. The fill
   only ever appears once the card IS approved, so an untouched card can't
   read as already approved. */
.btn.mh-wf-approve { border-color: rgba(61,220,151,0.45); color: var(--good); }
.btn.mh-wf-approve:hover { border-color: var(--good); background: rgba(61,220,151,0.08); box-shadow: none; }
.btn.mh-wf-approve.is-on { background: var(--good); color: var(--lane-ink); border-color: var(--good); cursor: default; }
.btn.mh-wf-approve.is-on:hover { background: var(--good); transform: none; box-shadow: none; }
/* UI 1.25 — emoji reaction chips on generated cards + the review queue.
   Quiet pills that sit beside the approve strip; the active ("you reacted")
   state picks up the lane accent so a viewer can spot their own taps, and the
   count only shows once at least one reaction lands. */
.mh-reactions { display: inline-flex; gap: 6px; align-items: center; flex-wrap: wrap; }
.mh-react-btn {
  display: inline-flex; align-items: center; gap: 5px;
  min-height: 30px; padding: 4px 10px;
  background: rgba(245,242,232,0.04);
  color: var(--ink-dim);
  border: 1px solid var(--hairline);
  border-radius: 999px;
  font-family: var(--font-body);
  font-size: 12px; font-weight: 600; line-height: 1;
  cursor: pointer;
  transition: background var(--transition), border-color var(--transition),
              transform var(--transition), color var(--transition);
}
.mh-react-btn:hover { background: rgba(245,242,232,0.07); border-color: var(--chrome); transform: translateY(-1px); }
.mh-react-btn:active { transform: translateY(0); }
.mh-react-btn:focus-visible { outline: 2px solid var(--lane); outline-offset: 2px; }
.mh-react-btn .mh-react-emoji { font-size: 14px; line-height: 1; }
.mh-react-btn .mh-react-count { font-variant-numeric: tabular-nums; min-width: 7px; text-align: center; color: var(--ink-dim); }
.mh-react-btn .mh-react-count[hidden] { display: none; }
.mh-react-btn.is-on { background: color-mix(in oklab, var(--lane) 10%, transparent); border-color: color-mix(in oklab, var(--lane) 45%, transparent); color: var(--lane); }
.mh-react-btn.is-on .mh-react-count { color: var(--lane); }
.btn.large { padding: 14px 28px; font-size: 14px; }
/* Mono / scoreboard button — for editorial CTAs like "Open review queue" */
.btn.mono {
  font-family: var(--font-mono);
  text-transform: uppercase;
  letter-spacing: 0.14em;
  font-size: 11px;
  font-weight: 600;
  padding: 12px 20px;
}
/* No more .btn.gradient — lane yellow does the heavy lift */

/* LAYOUT */
.row { display: flex; gap: 18px; flex-wrap: wrap; }
.row > * { flex: 1; min-width: 240px; }
.grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 18px; }
.grid-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 18px; }
@media (max-width: 860px) {
  .grid-2, .grid-3 { grid-template-columns: 1fr; }
  .row { flex-direction: column; }
  /* Inline-styled equivalents of .grid-2/.grid-3 — style="grid-template-columns:
     1fr 1fr" (and the 1fr 1fr 1fr / repeat(3,…) variants) — don't inherit the
     class collapse above, so they would stay multi-column and overflow narrow
     screens (this was the /sponsors add-sponsor + exposure-report two-up, and
     the same two-column pattern recurs on settings / billing / organisation
     panels). Collapse them to a single column too. Inline styles outrank a
     class selector, so !important is required here — the same technique the
     .mh-palette-grid collapse (below) already uses. */
  [style*="grid-template-columns:1fr 1fr"],
  [style*="grid-template-columns: 1fr 1fr"],
  [style*="grid-template-columns:repeat(3,"],
  [style*="grid-template-columns: repeat(3,"] {
    grid-template-columns: 1fr !important;
  }
}
.divider { height: 1px; background: var(--border); margin: 20px 0; }
.muted { color: var(--ink-muted); }
.dim   { color: var(--ink-dim); }
.empty { padding: 56px 24px; text-align: center; color: var(--ink-muted); font-size: 14px; }

/* TABLES */
table { width: 100%; border-collapse: collapse; font-size: 14px; }
table th { text-align: left; padding: 10px 14px; font-size: 11px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.08em; color: var(--ink-muted); border-bottom: 1px solid var(--border); }
table td { padding: 12px 14px; border-bottom: 1px solid var(--border); vertical-align: top; }
table tbody tr:nth-child(odd) { background: rgba(255,255,255,0.015); }
table tbody tr:hover { background: rgba(255,255,255,0.03); }

/* TAGS — broadcast lower-third chips */
.tag {
  display: inline-flex; align-items: center; gap: 5px;
  padding: 3px 8px 3px 8px;
  border-radius: 2px;
  font-family: var(--font-mono);
  font-size: 10px; font-weight: 500;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  background: rgba(245,242,232,0.04);
  color: var(--ink-dim);
  border: 1px solid var(--hairline);
  white-space: nowrap;
  line-height: 1.4;
}
.tag.lane  { background: color-mix(in oklab, var(--lane) 10%, transparent); color: var(--lane);  border-color: color-mix(in oklab, var(--lane) 40%, transparent); }
.tag.live  { background: color-mix(in oklab, var(--lane) 10%, transparent); color: var(--lane);  border-color: color-mix(in oklab, var(--lane) 50%, transparent); }
.tag.live::before {
  content: '';
  width: 5px; height: 5px;
  border-radius: 50%;
  background: var(--lane);
  box-shadow: 0 0 8px var(--lane);
  animation: mh-pulse 1.4s ease-in-out infinite;
}
.tag.good  { background: var(--good-bg);  color: var(--good); border-color: rgba(94,227,154,0.30); }
.tag.warn  { background: var(--warn-bg);  color: var(--warn); border-color: rgba(255,180,84,0.30); }
.tag.bad   { background: var(--bad-bg);   color: var(--bad);  border-color: rgba(255,107,107,0.30); }
.tag.info  { background: var(--info-bg);  color: var(--info); border-color: rgba(77,163,255,0.30); }
.tag.medal { background: rgba(244,213,141,0.10); color: var(--medal); border-color: rgba(244,213,141,0.40); }
.tag.medal::before {
  content: '★'; color: var(--medal); font-family: var(--font-body);
  font-size: 9px; letter-spacing: 0;
}
/* legacy alias */
.tag.gold { background: rgba(244,213,141,0.10); color: var(--medal); border-color: rgba(244,213,141,0.40); }
/* A `<p class="tag">` is a block-level NOTE banner (a full sentence), not an
   inline status pill — so it must wrap and never exceed its container. The base
   `.tag` is `white-space:nowrap`, which on a phone pushed the /athletes consent
   banner ~860px past the right edge. Block usage opts back into normal wrapping. */
p.tag { white-space: normal; max-width: 100%; }

/* FORMS — mono scoreboard labels, lane-yellow focus */
label {
  display: block;
  margin: var(--sp-4) 0 var(--sp-2);
  color: var(--ink-muted);
  font-family: var(--font-mono);
  font-size: 10.5px;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.18em;
}
/* `<label class="req">…</label>` adds a lane-yellow asterisk for required
   fields so users see what they have to fill in before they hit submit. */
label.req::after {
  content: " *";
  color: var(--lane);
  font-weight: 700;
  margin-left: 2px;
}
/* `<label class="mh-choice">` opts out of the global mono-uppercase rule
   when the label wraps a radio / checkbox + text. Used by the organisation
   form's tone / platform pickers. */
label.mh-choice {
  display: inline-flex; align-items: center; gap: 8px;
  margin: 0 var(--sp-4) var(--sp-2) 0;
  cursor: pointer;
  color: var(--ink);
  font-family: var(--font-body);
  font-size: 13px;
  font-weight: 400;
  letter-spacing: 0;
  text-transform: none;
}
label.mh-choice-block { display: flex; margin: 0 0 var(--sp-2); }
label.mh-choice input { margin: 0; }
/* Inline form-feedback slot under inputs */
.mh-field-error {
  display: block;
  margin-top: var(--sp-2);
  color: var(--bad);
  font-family: var(--font-mono);
  font-size: 11px;
  letter-spacing: 0.10em;
  text-transform: uppercase;
}
input[type=text], input[type=file], input[type=email], input[type=password], input[type=url], input[type=number], textarea, select {
  background: rgba(245,242,232,0.025); color: var(--ink);
  border: 1px solid var(--chrome);
  border-radius: var(--radius-sm); padding: 11px 14px;
  /* 44px touch-target floor for every text/file/email/number field. */
  min-height: 44px;
  font-size: 14px; font-family: var(--font-body); width: 100%;
  transition: border-color var(--transition), box-shadow var(--transition), background var(--transition);
  appearance: none;
}
input[type=text]:hover, input[type=email]:hover, textarea:hover, select:hover {
  border-color: var(--rule);
}
input[type=text]:focus, input[type=email]:focus, input[type=password]:focus, input[type=url]:focus, input[type=number]:focus, textarea:focus, select:focus {
  outline: none; border-color: var(--lane);
  box-shadow: 0 0 0 2px color-mix(in oklab, var(--lane) 18%, transparent);
  background: rgba(245,242,232,0.04);
}
input[type=checkbox], input[type=radio] {
  /* Bump native checkbox/radio from the browser's ~13px default so it
     reads as a real control and sits inside a 44px tap area when
     paired with the label rule below. */
  width: 18px; height: 18px;
  margin-right: 8px; accent-color: var(--lane);
}
textarea { min-height: 120px; resize: vertical; line-height: 1.5; }
select { cursor: pointer; }
/* Open <select> dropdown legibility: the native option popup renders on a
   light OS background, but options inherit the theme's light --ink colour →
   light-on-light (the unreadable grey text). Pin a readable dark-on-cream pair
   on the options themselves so every dropdown list stays clear when open. */
select option { background-color: #f5f2e8; color: #14160f; }

/* Custom-styled file input — replaces ugly native OS button */
input[type=file] { padding: 7px 10px; cursor: pointer; }
input[type=file]::file-selector-button {
  background: var(--lane);
  color: var(--lane-ink);
  border: 0;
  border-radius: 2px;
  padding: 7px 14px;
  font-family: var(--font-mono);
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.14em;
  cursor: pointer;
  margin-right: 14px;
  transition: background var(--transition);
}
input[type=file]::file-selector-button:hover {
  background: var(--lane-h);
}
input[type=color] {
  /* Native colour wells need 44px so the swatch is comfortable to tap
     on phone / tablet. Width stays compact so the hex input next to it
     dominates the row. */
  height: 44px; min-width: 44px; padding: 2px; cursor: pointer;
  background: rgba(245,242,232,0.04); border-color: var(--chrome);
}
/* Pair the bumped checkbox with a 44px-tall click target on the wrapping
   label. Covers /organisation/setup's `palette_use_fourth` row plus the
   mh-choice tone / platform pickers. */
label.mh-choice, label:has(> input[type=checkbox]), label:has(> input[type=radio]) {
  min-height: 44px;
  padding-top: 6px; padding-bottom: 6px;
}

/* STATS — pit-wall scoreboard. Display-font numerals, mono labels, side-rail accent */
.stat-block { display: flex; gap: var(--sp-3); flex-wrap: wrap; }
.stat {
  position: relative;
  background: var(--surface);
  border: 1px solid var(--hairline);
  border-radius: var(--radius);
  padding: var(--sp-4) var(--sp-5) var(--sp-4) var(--sp-6);
  min-width: 110px;
  transition: border-color var(--transition), transform var(--transition);
  overflow: hidden;
}
.stat::before {
  content: '';
  position: absolute; left: 0; top: 12px; bottom: 12px;
  width: 3px;
  background: var(--ink-faint);
  border-radius: 0;
}
.stat:hover { border-color: var(--rule); transform: translateY(-1px); }
.stat:hover::before { background: var(--lane); }
.stat .l {
  display: block;
  font-family: var(--font-mono);
  font-size: 10px; font-weight: 500;
  text-transform: uppercase; letter-spacing: 0.20em;
  color: var(--ink-muted); margin-bottom: var(--sp-2);
}
.stat .v {
  display: block;
  font-family: var(--font-display);
  font-size: 44px; font-weight: 900;
  letter-spacing: -0.02em;
  font-variant-numeric: tabular-nums lining-nums;
  font-feature-settings: 'tnum' 1, 'lnum' 1, 'ss01' 1;
  color: var(--ink); line-height: 0.9;
}
.stat .delta {
  display: inline-block;
  margin-left: 8px;
  font-family: var(--font-mono);
  font-size: 11px; font-weight: 500;
  vertical-align: super;
  color: var(--ink-muted);
}
/* Semantic stat variants */
.stat.live::before  { background: var(--lane); box-shadow: 0 0 12px var(--lane-glow); }
.stat.live .v       { color: var(--lane); }
.stat.medal::before { background: var(--medal); box-shadow: 0 0 12px var(--medal-glow); }
.stat.medal .v      { color: var(--medal); }
.stat.warn::before  { background: var(--warn); }
.stat.good::before  { background: var(--good); }
.stat.bad::before   { background: var(--bad);  }
/* Old "elite" → medal alias */
.stat.elite::before { background: var(--medal); box-shadow: 0 0 12px var(--medal-glow); }
.stat.elite .v      { color: var(--medal); }

/* KV */
.kv { display: grid; grid-template-columns: 180px 1fr; gap: 6px 16px; font-size: 14px; }
.kv .k { color: var(--ink-muted); font-size: 12px; font-weight: 500; }

/* PROGRESS LOG */
.progress-log {
  background: rgba(0,0,0,0.3);
  color: #9EB3C8;
  border: 1px solid var(--border); border-radius: 10px; padding: 16px;
  font-family: ui-monospace, 'SF Mono', Menlo, monospace;
  font-size: 12px; white-space: pre-wrap; max-height: 360px; overflow-y: auto; line-height: 1.7;
}

/* CODE */
code, pre { font-family: ui-monospace, 'SF Mono', Menlo, monospace; background: rgba(255,255,255,0.05); padding: 2px 7px; border-radius: 5px; font-size: 12.5px; color: var(--accent); }
pre { padding: 16px; overflow-x: auto; color: var(--ink-dim); border: 1px solid var(--border); border-radius: 10px; }
pre code { background: none; padding: 0; color: inherit; }

/* === Animations === */
@keyframes mh-spin { to { transform: rotate(360deg); } }
/* Alias used by inline loading indicators rendered from JS strings — must
   stay global so spinners rotate on every page, not just ones that happen
   to embed a scoped copy. */
@keyframes spin { to { transform: rotate(360deg); } }
@keyframes mh-pulse { 0%, 100% { opacity: 1; } 50% { opacity: 0.55; } }
@keyframes mh-fade-in { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
@keyframes mh-slide-in { from { opacity: 0; transform: translateX(24px); } to { opacity: 1; transform: translateX(0); } }
/* mh-shimmer + mh-aurora keyframes deleted in round-6 cleanup — the
   `.skeleton` class and the old body::before aurora that consumed them
   were already gone. */

/* Page entry */
main.wrap { animation: mh-fade-in 0.35s ease-out; position: relative; z-index: 1; }
main.wrap > .card { animation: mh-fade-in 0.4s ease-out backwards; }
main.wrap > .card:nth-of-type(1) { animation-delay: 0.05s; }
main.wrap > .card:nth-of-type(2) { animation-delay: 0.10s; }
main.wrap > .card:nth-of-type(3) { animation-delay: 0.15s; }
main.wrap > .card:nth-of-type(4) { animation-delay: 0.20s; }
main.wrap > .card:nth-of-type(5) { animation-delay: 0.25s; }

/* Shared page-header entrance. Almost every surface opens with a `.mh-hero`
   block (eyebrow -> headline -> lede); give those three a gentle staggered rise
   so the *whole site* — not just the landing page — settles in with the same
   editorial cadence. The home hero keeps its bespoke word-cycle / odometer
   treatment, so it's excluded here. Pure CSS load animation (no persistent
   hidden state -> nothing can get stuck), and it stands down under
   prefers-reduced-motion via the reset below. */
body:not([data-page="home"]) main.wrap .mh-hero > .mh-hero-eyebrow,
body:not([data-page="home"]) main.wrap .mh-hero > h1,
body:not([data-page="home"]) main.wrap .mh-hero > .lede {
  animation: mh-fade-in 0.5s var(--ease-out, ease-out) backwards;
}
body:not([data-page="home"]) main.wrap .mh-hero > .mh-hero-eyebrow { animation-delay: 0.04s; }
body:not([data-page="home"]) main.wrap .mh-hero > h1 { animation-delay: 0.12s; }
body:not([data-page="home"]) main.wrap .mh-hero > .lede { animation-delay: 0.20s; }
@media (prefers-reduced-motion: reduce) {
  body:not([data-page="home"]) main.wrap .mh-hero > .mh-hero-eyebrow,
  body:not([data-page="home"]) main.wrap .mh-hero > h1,
  body:not([data-page="home"]) main.wrap .mh-hero > .lede { animation: none; }
}

/* Single static lane-yellow wash at the top edge — broadcast lower-third feel.
   The softness is baked into the radial gradient itself (centre lifted above the
   viewport with a generous falloff) instead of an 80px `filter: blur()`. A blur
   that large over a fixed, full-width layer is a heavy raster that the browser
   pays on first paint of EVERY page — and keeps as a needless extra GPU layer —
   for a glow a soft gradient already gives. Paint-once, no perceptible change. */
body::before {
  content: ''; position: fixed;
  top: 0; left: 0; right: 0; height: 360px;
  background:
    radial-gradient(ellipse 78% 118% at 50% -22%, var(--lane-glow), transparent 72%);
  opacity: 0.18;
  pointer-events: none; z-index: 0;
}

/* Signed-in brand backdrop — the active org's PRIMARY logo as a large, softly
   blurred crest CENTRED and STILL behind the page content, in a faint pool of the
   club's brand colour (.mh-bg-wash). A MODEST, tightly-banded blur keeps the crest
   IDENTIFIABLE as the club's logo (soft-focus, never dissolved into an anonymous
   blob) while softening its edges so it sits behind the headline without knifing
   through the text. Crucially the blur is a FIXED rule on the mode classes below —
   NOT an inline per-logo value — so it can never be dropped if a logo's adaptive
   numbers are odd (a bad inline filter value voids the whole filter, incl. the
   blur). The deterministic logo_bg_treatment analysis still picks the mode per
   logo, so it's future-proof for any team's upload:
     • .mh-bg-mark--img — a COLOURFUL logo, blurred from its real artwork → a soft
       glow in the club's own colours;
     • .mh-bg-mark--ko  — a MONOCHROME logo (black/navy/grey/white/single-ink) or
       an SVG we can't measure, blurred from its shape painted in one light brand-
       tinted ink (--mh-bg-ink) → a soft light glow that always reads on dark.
   Only --op (adaptive opacity) is inline. z-index:0 — behind all content. */
.mh-bg-canvas {
  position: fixed; inset: 0; z-index: 0; pointer-events: none; overflow: hidden;
  /* Light, brand-tinted ink for the monochrome knockout glow so even a near-black
     logo reads as a soft glow (first value is the no-color-mix fallback). */
  --mh-bg-ink: #e9eef5;
  --mh-bg-ink: color-mix(in oklab, var(--mh-bg-brand, #cfe0ff) 40%, #eef3f9);
}
/* Brand-coloured ambient wash, pooled at centre behind the crest. The builder
   omits this element entirely when the org has no brand colour. */
.mh-bg-wash {
  position: absolute; inset: 0;
  background: radial-gradient(50% 54% at 50% 50%,
    color-mix(in oklab, var(--mh-bg-brand, transparent) 18%, transparent) 0%,
    color-mix(in oklab, var(--mh-bg-brand, transparent) 7%, transparent) 42%,
    transparent 72%);
}
.mh-bg-marks {
  position: absolute; inset: 0;
}
.mh-bg-mark {
  position: absolute;
  /* Per-logo --op (inline, from logo_bg_treatment) × a placement factor --opf;
     --opf lives only in the stylesheet so the mobile query below can override it. */
  opacity: calc(var(--op, 0.5) * var(--opf, 0.6));
  transform: translate(-50%, -50%);
}
/* Colourful logo — its real artwork, softly blurred. The blur amount is the
   per-logo adaptive --mh-blur (busier crests blur more), with a fixed fallback so
   it can never be dropped even if --mh-blur is unset/odd. */
.mh-bg-mark--img {
  background-repeat: no-repeat; background-position: center;
  background-size: contain;            /* preserve ANY uploaded logo's aspect ratio */
  filter: blur(var(--mh-blur, 14px)) brightness(1.12);
}
/* Monochrome / SVG logo — its shape in one light brand-tinted ink, softly blurred. */
.mh-bg-mark--ko {
  background-color: var(--mh-bg-ink);
  -webkit-mask-repeat: no-repeat; mask-repeat: no-repeat;
  -webkit-mask-position: center; mask-position: center;
  -webkit-mask-size: contain; mask-size: contain;   /* preserve aspect ratio */
  filter: blur(var(--mh-blur, 14px));
}
@media (max-width: 720px) {
  /* Calmer behind dense mobile text. */
  .mh-bg-mark { --opf: 0.5; }
}

/* Card hover. Interactive cards (links / [data-interactive]) lift a touch and
   deepen their shadow on hover — the same tactile feedback the activity-feed
   rows and bento tiles use, applied site-wide so every clickable card on every
   surface feels alive, not just the landing page. The lift is gated to
   fine-pointer + motion-allowed so touch and the reduced-motion cohort keep the
   flat, static card; non-interactive info cards never move (correct affordance). */
.card { transition: background var(--transition), border-color var(--transition),
                    box-shadow var(--transition), transform var(--transition); }
a.card, .card[data-interactive] { cursor: pointer; }
a.card:hover, .card[data-interactive]:hover {
  border-color: var(--rule);
  background: var(--surface-2);
}
@media (prefers-reduced-motion: no-preference) and (hover: hover) and (pointer: fine) {
  a.card:hover, .card[data-interactive]:hover {
    transform: translateY(-2px);
    box-shadow: var(--shadow-2, var(--shadow-1));
  }
  a.card:active, .card[data-interactive]:active { transform: translateY(0); }
}

/* Loading overlay */
#mh-loader {
  position: fixed; inset: 0;
  /* Light: a translucent paper scrim so the (now dark) loader text
     stays readable; dark: the original deep-ink scrim. */
  background: rgba(11,18,32,0.78);
  backdrop-filter: blur(10px); -webkit-backdrop-filter: blur(10px);
  z-index: 9999;
  display: none; align-items: center; justify-content: center;
  opacity: 0; transition: opacity 0.25s ease;
}
#mh-loader.show { display: flex; opacity: 1; }
.mh-loader-inner {
  display: flex; flex-direction: column; align-items: center; gap: 22px;
  padding: 36px 48px;
  animation: mh-fade-in 0.4s ease-out;
}
.mh-spinner {
  width: 56px; height: 56px;
  border-radius: 50%;
  border: 2px solid var(--hairline);
  border-top-color: var(--lane);
  border-right-color: var(--lane);
  animation: mh-spin 0.8s cubic-bezier(0.6,0,0.4,1) infinite;
  position: relative;
  box-shadow: 0 0 24px var(--lane-glow);
}
.mh-spinner::after {
  content: ''; position: absolute; inset: 6px;
  border-radius: 50%;
  border: 1px dashed var(--lane);
  opacity: 0.35;
  animation: mh-spin 2s linear infinite reverse;
}
.mh-loader-text {
  font-family: var(--font-display);
  font-size: 24px;
  color: var(--ink);
  font-weight: 800;
  letter-spacing: 0.02em;
  text-transform: uppercase;
  text-align: center;
}
.mh-loader-sub {
  font-family: var(--font-mono);
  font-size: 11px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--ink-dim);
  max-width: 360px; text-align: center;
  animation: mh-pulse 2.4s ease-in-out infinite;
}

/* U.6 — branded render/generation progress (the giant-numeral loading state).
   Replaces the generic spinner on the long render/generation waits (motion,
   reels, graphics). The percentage is an honest eased time-estimate for the
   opaque renders, and a real fraction where the backend reports one; it only
   reaches 100 when the real result lands (MH.renderProgress.complete). Reuses
   the .display-num motif for the numeral. */
.mh-render-prog { padding: 30px 18px 26px; text-align: center; animation: mh-fade-in 0.3s ease-out; }
.mh-render-prog-num { display: flex; align-items: flex-start; justify-content: center; gap: 4px; }
.mh-render-prog-pct { font-size: clamp(56px, 15vw, 116px); line-height: 0.82; color: var(--lane); }
.mh-render-prog-sign { font-family: var(--font-display); font-weight: 900; line-height: 1; font-size: clamp(20px, 5vw, 38px); color: var(--ink-dim); margin-top: 0.3em; }
.mh-render-prog[data-accent="medal"] .mh-render-prog-pct { color: var(--medal); }
.mh-render-prog-bar { height: 3px; width: min(280px, 78%); margin: 20px auto 0; background: rgba(255,255,255,0.08); border-radius: 999px; overflow: hidden; }
.mh-render-prog-fill { display: block; height: 100%; width: 0; border-radius: 999px; background: var(--lane); transition: width 0.4s cubic-bezier(0.4,0,0.2,1); }
.mh-render-prog[data-accent="medal"] .mh-render-prog-fill { background: var(--medal); }
.mh-render-prog-label { font-family: var(--font-mono); font-size: 12px; letter-spacing: 0.16em; text-transform: uppercase; color: var(--ink); margin-top: 18px; }
.mh-render-prog-sub { font-family: var(--font-mono); font-size: 10.5px; letter-spacing: 0.12em; text-transform: uppercase; color: var(--ink-muted); margin: 7px auto 0; max-width: 320px; line-height: 1.5; }
@media (prefers-reduced-motion: reduce) {
  .mh-render-prog { animation: none; }
  .mh-render-prog-fill { transition: none; }
}

/* Toast */
#mh-toast-container {
  position: fixed; top: 72px; right: 20px;
  z-index: 10000;
  display: flex; flex-direction: column; gap: 10px;
  pointer-events: none; max-width: 380px;
}
.mh-toast {
  background: var(--panel); border: 1px solid var(--border);
  border-radius: 12px; padding: 14px 16px; color: var(--ink);
  font-size: 14px; line-height: 1.45;
  box-shadow: 0 12px 36px rgba(0,0,0,0.5);
  pointer-events: auto;
  animation: mh-slide-in 0.32s cubic-bezier(0.34, 1.2, 0.64, 1);
  display: flex; align-items: flex-start; gap: 12px;
  min-width: 280px;
}
.mh-toast.success { border-color: rgba(34,197,94,0.45); }
.mh-toast.error   { border-color: rgba(244,63,94,0.45); }
.mh-toast.info    { border-color: color-mix(in oklab, var(--lane) 45%, transparent); }
.mh-toast .mh-toast-icon { width: 18px; height: 18px; flex-shrink: 0; margin-top: 1px; }
.mh-toast.success .mh-toast-icon { color: var(--good); }
.mh-toast.error   .mh-toast-icon { color: var(--bad); }
.mh-toast.info    .mh-toast-icon { color: var(--info); }
.mh-toast-close {
  background: none; border: 0; color: var(--ink-muted); cursor: pointer;
  padding: 0; margin-left: 4px; font-size: 18px; line-height: 1;
  transition: color var(--transition);
}
.mh-toast-close:hover { color: var(--ink); }

/* Button loading state */
.btn.loading { pointer-events: none; opacity: 0.72; position: relative; padding-right: 38px; }
.btn.loading::after {
  content: ''; position: absolute; right: 14px; top: 50%;
  width: 14px; height: 14px; margin-top: -7px;
  border: 2px solid currentColor; border-right-color: transparent;
  border-radius: 50%; animation: mh-spin 0.6s linear infinite;
}

/* Content card (AI-generated content output) — published-article aesthetic */
.mh-content-card {
  background: var(--surface);
  border: 1px solid var(--hairline);
  border-left: 2px solid var(--lane);
  border-radius: 0;
  padding: var(--sp-6);
  margin-bottom: var(--sp-4);
  position: relative;
  transition: border-color var(--transition), background var(--transition);
  /* A big meet stacks many of these in one scroll — skip layout+paint for the
     cards still well off-screen. `auto` makes the browser remember each card's
     real height after its first render, so the reserved estimate never causes a
     scroll jump on the way back. Unknown to old engines, which ignore it. */
  content-visibility: auto;
  contain-intrinsic-size: auto 220px;
}
/* Belt-and-braces: never let an off-screen card be skipped when printing. */
@media print { .mh-content-card { content-visibility: visible; } }
.mh-content-card:hover { background: var(--surface-2); border-left-color: var(--lane-h); }
.mh-content-card .mh-card-platform {
  display: inline-flex; align-items: center; gap: 8px;
  font-family: var(--font-mono);
  font-size: 10.5px; font-weight: 500;
  text-transform: uppercase; letter-spacing: 0.18em;
  color: var(--lane); margin-bottom: var(--sp-3);
}
.mh-content-card .mh-card-caption {
  font-family: var(--font-serif);
  font-variation-settings: 'opsz' 72;
  font-size: 16px; line-height: 1.55; color: var(--ink);
  white-space: pre-wrap; word-wrap: break-word;
}
.mh-content-card .mh-card-tags {
  margin-top: var(--sp-4); display: flex; flex-wrap: wrap; gap: 6px;
}
.mh-content-card .mh-card-tag {
  font-size: 10px; color: var(--ink-dim);
  background: transparent;
  border: 1px solid var(--hairline);
  border-radius: 2px; padding: 3px 8px;
  font-family: var(--font-mono);
  letter-spacing: 0.14em;
  text-transform: uppercase;
}
.mh-content-card .mh-card-confidence {
  position: absolute; top: var(--sp-6); right: var(--sp-6);
  font-family: var(--font-mono);
  font-size: 10.5px; color: var(--ink-muted);
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.10em;
}

/* ---- U.3 — explainability & confidence surfaces -------------------------- */
/* A self-explaining confidence chip (replaces the bare "conf: medium" tag).
   Confidence = how sure we are the FACTS are right — a different axis from
   the worthiness meter (the ranking). The title= carries the plain meaning. */
.mh-conf-chip {
  display: inline-flex; align-items: center; gap: 5px;
  font-size: 10.5px; font-weight: 600; letter-spacing: 0.02em;
  padding: 2px 9px; border-radius: 999px; white-space: nowrap;
  border: 1px solid var(--hairline); color: var(--ink-dim); cursor: help;
}
.mh-conf-chip .mh-conf-chip-dot {
  width: 7px; height: 7px; border-radius: 50%; background: currentColor; opacity: 0.9;
}
.mh-conf-chip.good { color: var(--good); border-color: rgba(94,227,154,0.35); background: var(--good-bg); }
.mh-conf-chip.warn { color: var(--warn); border-color: rgba(255,180,84,0.35); background: var(--warn-bg); }
.mh-conf-chip.bad  { color: var(--bad);  border-color: rgba(255,107,107,0.35); background: var(--bad-bg); }
.mh-conf-chip-pct { font-family: var(--font-mono); opacity: 0.8; }

/* The content-worthiness (ranking) meter — labelled so the bare 0–1 score
   isn't misread as a second confidence number. */
.mh-worth { display: inline-flex; align-items: center; gap: 6px; cursor: help; }
.mh-worth-label {
  font-size: 9.5px; text-transform: uppercase; letter-spacing: 0.12em; color: var(--ink-muted);
}
.mh-worth-track {
  width: 72px; height: 6px; border-radius: 3px;
  background: rgba(255,255,255,0.06); overflow: hidden;
}
.mh-worth-fill { display: block; height: 100%; background: var(--accent); }
.mh-worth-num {
  font-size: 11px; font-variant-numeric: tabular-nums; color: var(--ink-dim); min-width: 30px;
}

/* The plain-English ranking-factor breakdown (replaces the name/value/weight
   debug table). Each row leads with the ranker's own grounded plain_summary
   and shows how much that reason counted. */
.mh-factor-list {
  list-style: none; margin: 6px 0 0 0; padding: 0;
  display: flex; flex-direction: column; gap: 9px;
}
.mh-factor { display: grid; grid-template-columns: 104px 1fr 84px; gap: 12px; align-items: center; }
.mh-factor-name {
  font-size: 10px; text-transform: uppercase; letter-spacing: 0.08em; color: var(--ink-muted);
}
.mh-factor-why { font-size: 12.5px; color: var(--ink-dim); line-height: 1.35; }
.mh-factor-track {
  height: 6px; border-radius: 3px; background: rgba(255,255,255,0.06); overflow: hidden;
}
.mh-factor-fill { display: block; height: 100%; background: var(--lane); }
.mh-factor-mult { font-family: var(--font-mono); font-size: 11px; color: var(--lane); text-align: right; }
@media (max-width: 640px) {
  .mh-factor { grid-template-columns: 1fr; gap: 3px; }
  .mh-factor-track, .mh-factor-mult { max-width: 160px; }
}

/* "How to read these cards" — a side-anchored guide. A slim tab pinned to the
   right edge opens a slide-in dialog, so the explainer is always one click away
   without taking column space at the top of the review surface. Reduced-motion
   safe; closes on the ✕, a backdrop click, or Escape (controller is inlined
   beside the markup in _render_explainability_key). */
.mh-guide-tab {
  position: fixed; right: 0; top: 42%; transform: translateY(-50%);
  z-index: 90; display: inline-flex; align-items: center; gap: 9px;
  padding: 14px 9px; writing-mode: vertical-rl;
  background: var(--panel2); color: var(--ink-dim);
  border: 1px solid var(--chrome); border-right: 0;
  border-radius: 10px 0 0 10px; cursor: pointer;
  font-family: var(--font-mono); font-size: 10.5px; font-weight: 600;
  letter-spacing: 0.14em; text-transform: uppercase;
  box-shadow: -5px 0 20px rgba(0,0,0,0.28);
  transition: color 120ms ease, background 120ms ease, transform 120ms ease;
}
.mh-guide-tab:hover { color: var(--ink); background: var(--panel); transform: translateY(-50%) translateX(-3px); }
.mh-guide-tab:focus-visible { outline: 2px solid var(--lane); outline-offset: 2px; }
.mh-guide-tab-icon { writing-mode: horizontal-tb; font-size: 14px; color: var(--lane); }
.mh-guide-overlay {
  position: fixed; inset: 0; z-index: 1100; background: rgba(0,0,0,0.5);
  opacity: 0; transition: opacity 200ms ease;
}
.mh-guide-overlay.is-open { opacity: 1; }
.mh-guide-panel {
  position: fixed; top: 0; right: 0; bottom: 0; z-index: 1101;
  width: min(390px, 92vw);
  background: var(--panel); border-left: 1px solid var(--chrome);
  box-shadow: -18px 0 44px rgba(0,0,0,0.5);
  transform: translateX(100%);
  transition: transform 240ms cubic-bezier(0.16, 1, 0.3, 1);
  display: flex; flex-direction: column; overflow-y: auto;
}
.mh-guide-panel.is-open { transform: translateX(0); }
.mh-guide-panel-head {
  position: sticky; top: 0; z-index: 1;
  display: flex; align-items: center; justify-content: space-between; gap: 12px;
  padding: 17px 20px; background: var(--panel);
  border-bottom: 1px solid var(--hairline);
}
.mh-guide-panel-head h2 { margin: 0; font-size: 15px; display: flex; align-items: center; gap: 8px; }
.mh-guide-close {
  flex: none; width: 32px; height: 32px; border-radius: 8px;
  background: transparent; border: 1px solid var(--chrome);
  color: var(--ink-dim); font-size: 19px; line-height: 1; cursor: pointer;
  transition: color 120ms ease, border-color 120ms ease;
}
.mh-guide-close:hover { color: var(--ink); border-color: var(--lane); }
.mh-key-grid { padding: 16px 20px 24px; display: flex; flex-direction: column; gap: 14px; }
.mh-key-row { display: grid; grid-template-columns: 104px 1fr; gap: 14px; align-items: baseline; }
.mh-key-term {
  font-size: 11px; font-weight: 700; text-transform: uppercase;
  letter-spacing: 0.08em; color: var(--lane);
}
.mh-key-body { font-size: 12.5px; color: var(--ink-dim); line-height: 1.45; }
.mh-key-body b { color: var(--ink); font-weight: 600; }
@media (max-width: 640px) { .mh-key-row { grid-template-columns: 1fr; gap: 2px; } }
@media (prefers-reduced-motion: reduce) {
  .mh-guide-tab, .mh-guide-overlay, .mh-guide-panel { transition: none; }
}

/* The "why not" near-miss discoverability hint under the decision list. */
.mh-nearmiss-hint {
  margin-top: var(--sp-4); padding: 10px 14px;
  border: 1px solid var(--hairline); border-radius: var(--radius-sm);
  background: rgba(255,255,255,0.015);
  font-size: 12.5px; color: var(--ink-dim);
  display: flex; align-items: center; gap: 9px; flex-wrap: wrap;
}
.mh-nearmiss-hint a { color: var(--lane); }
.mh-nearmiss-hint .mh-nm-pip {
  display: inline-block; width: 7px; height: 7px; border-radius: 50%;
  background: var(--warn); flex: none;
}

/* ---- U.7 — "focus the facts" caption / explainability highlight ---------- */
/* Source-grounded entities (athlete / event / time / PB-medal-record) are
   pill-highlighted and sharp; the connective filler around them recedes to
   --ink-muted so the facts read first. The spans are injected server-side by
   _focus_facts_html() and only ever wrap text the structured achievement
   grounds — never a guess. Inspired by Pedro Duarte (ped.ro); supports U.3. */
.mh-focus { color: var(--ink-muted); }
.mh-fact {
  color: var(--ink);
  font-weight: 600;
  padding: 0 4px;
  border-radius: 4px;
  background: rgba(245, 242, 232, 0.06);   /* faint --ink wash */
  /* clone the pill across wrapped lines and keep the line box tight */
  -webkit-box-decoration-break: clone;
  box-decoration-break: clone;
}
/* Athlete — the person: the brightest neutral pill (the hero of the card). */
.mh-fact--athlete { background: rgba(245, 242, 232, 0.08); }
/* Event — the race: a quieter neutral pill. */
.mh-fact--event { background: rgba(245, 242, 232, 0.045); }
/* Time — the data: monospace + tabular figures with a faint gold edge. */
.mh-fact--time {
  font-family: var(--font-mono);
  font-variant-numeric: tabular-nums;
  background: color-mix(in oklab, var(--lane) 7%, transparent);
  box-shadow: inset 0 0 0 1px color-mix(in oklab, var(--lane) 18%, transparent);
}
/* PB / medal / record — the achievement itself: the brand gold-green, loudest. */
.mh-fact--pb {
  color: var(--lane);
  font-weight: 700;
  background: color-mix(in oklab, var(--lane) 12%, transparent);
  box-shadow: inset 0 0 0 1px color-mix(in oklab, var(--lane) 30%, transparent);
}

.mh-card-actions {
  margin-top: var(--sp-4); display: flex; gap: var(--sp-2); flex-wrap: wrap;
  padding-top: var(--sp-4); border-top: 1px solid var(--hairline);
}
.mh-card-actions button {
  background: transparent;
  border: 1px solid var(--chrome);
  color: var(--ink-dim);
  font-family: var(--font-mono);
  font-size: 10.5px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  padding: 6px 12px;
  /* Card action utility buttons (Copy caption, Copy reasoning, etc.)
     stay visually compact on desktop but must clear the 44px touch
     target on phone / tablet. The mobile bump happens in the
     `@media (max-width: 860px)` block further down. */
  min-height: 32px;
  border-radius: 2px;
  cursor: pointer;
  /* Explicit properties (house rule: never `transition: all`) — these buttons
     only change colour / border / fill across their hover + primary states. */
  transition: color var(--transition), border-color var(--transition),
              background-color var(--transition);
}
.mh-card-actions button:hover { color: var(--ink); border-color: var(--rule); }
.mh-card-actions button.primary { color: var(--lane); border-color: color-mix(in oklab, var(--lane) 30%, transparent); }
.mh-card-actions button.primary:hover { background: color-mix(in oklab, var(--lane) 8%, transparent); border-color: var(--lane); }
/* Achievement / medal variant — gold accent for PB / medal / first-time */
.mh-content-card.medal { border-left-color: var(--medal); }
.mh-content-card.medal .mh-card-platform { color: var(--medal); }
.mh-content-card.medal:hover { border-left-color: var(--medal-h); }

/* Disabled card / button visual state */
[aria-disabled="true"], .is-disabled {
  opacity: 0.45;
  cursor: not-allowed !important;
  pointer-events: none;
  filter: grayscale(0.3);
}
[aria-disabled="true"]:hover, .is-disabled:hover {
  transform: none !important; box-shadow: none !important;
}

/* === Upload pipeline progress UI — pit-wall stage panel === */
.mh-stages {
  display: flex; gap: 0; flex-wrap: wrap;
  margin: var(--sp-5) 0 var(--sp-6);
  border: 1px solid var(--hairline);
  border-radius: var(--radius);
  background: var(--surface);
}
.mh-stage {
  flex: 1; min-width: 130px;
  background: transparent;
  border: 0;
  border-right: 1px solid var(--hairline);
  border-radius: 0;
  padding: var(--sp-4) var(--sp-4);
  position: relative;
  transition: background var(--transition), color var(--transition);
}
.mh-stage:last-child { border-right: 0; }
.mh-stage .mh-stage-label {
  font-family: var(--font-mono);
  font-size: 10px; font-weight: 500;
  text-transform: uppercase; letter-spacing: 0.20em;
  color: var(--ink-muted); margin-bottom: var(--sp-2);
}
.mh-stage .mh-stage-text {
  font-family: var(--font-body);
  font-size: 13px; color: var(--ink-dim);
  line-height: 1.4;
}
.mh-stage[data-state="done"] {
  background: var(--good-bg);
}
.mh-stage[data-state="done"] .mh-stage-label { color: var(--good); }
.mh-stage[data-state="done"]::before {
  content: '✓'; position: absolute; top: 12px; right: 12px;
  color: var(--good); font-size: 13px; font-weight: 700;
}
.mh-stage[data-state="active"] {
  background: color-mix(in oklab, var(--lane) 5%, transparent);
  border-bottom: 2px solid var(--lane);
}
.mh-stage[data-state="active"] .mh-stage-label { color: var(--lane); }
.mh-stage[data-state="active"]::after {
  content: ''; position: absolute; top: 14px; right: 12px;
  width: 7px; height: 7px; border-radius: 50%;
  background: var(--lane);
  animation: mh-pulse 1.1s ease-in-out infinite;
  box-shadow: 0 0 12px var(--lane);
}
.mh-stage[data-state="error"] {
  background: var(--bad-bg);
}
.mh-stage[data-state="error"] .mh-stage-label { color: var(--bad); }
.mh-stage[data-state="error"]::before {
  content: '✕'; position: absolute; top: 12px; right: 12px;
  color: var(--bad); font-size: 13px; font-weight: 700;
}

.mh-progress-bar {
  position: relative; height: 3px;
  background: var(--hairline);
  border-radius: 0; overflow: hidden;
  margin: var(--sp-4) 0 var(--sp-2);
}
.mh-progress-bar > span {
  position: absolute; top: 0; left: 0; bottom: 0;
  background: var(--lane);
  border-radius: 0;
  transition: width 0.4s ease;
  width: 0;
}
.mh-progress-bar.indeterminate > span {
  width: 30% !important;
  animation: mh-progress-slide 1.6s cubic-bezier(0.4,0,0.2,1) infinite;
}
@keyframes mh-progress-slide {
  0%   { transform: translateX(-110%); }
  100% { transform: translateX(440%); }
}

/* Active-org chip — wide-viewport defaults. Lives outside the inline
   <a style="…"> so the @media (max-width: 1100px) override below can
   actually win (inline-style specificity beat the media query, so the
   chip used to stay full-size at 900–1099px and clip past the viewport
   edge). The base rule must come BEFORE the media query so source order
   doesn't reverse the precedence at narrow widths. */
#active-org-chip { font-size: 12px; line-height: 1; padding: 5px 10px; }
#active-org-chip .mh-orgmenu-name { max-width: 140px; }

/* === Responsive: nav scrollable, hide backend pill on narrow widths ===
   Audit found the topnav overflowed on every viewport between 721 and
   ~1100 px because the 9 signed-in items + brand + pill = ~1100 px wide.
   The scrollable-nav treatment now kicks in at 1100 px so iPads and
   small laptops stop showing the right-edge bleed. */
@media (max-width: 1100px) {
  header.topnav { padding: 0 16px; height: auto; flex-wrap: wrap; gap: 6px; }
  header.topnav .brand { margin-right: 14px; font-size: 18px; }
  header.topnav .brand::after { display: none; }
  header.topnav nav {
    width: 100%; gap: 0;
    overflow-x: auto;
    -webkit-overflow-scrolling: touch;
    scrollbar-width: none;
    padding-bottom: 4px;
  }
  header.topnav nav::-webkit-scrollbar { display: none; }
  header.topnav nav a {
    padding: 8px 12px; font-size: 11px;
    flex-shrink: 0;
  }
  /* Active-org menu shrinks on narrow widths so the brand chip + nav items
     both fit on one line under iPad / small-laptop viewports. `position:
     sticky; right: 8px` on the menu wrapper pins it to the right edge of the
     scrollable nav viewport — at 1024 px it used to render off-screen; sticky
     keeps it glued to the visible nav edge so the active organisation is always
     readable regardless of horizontal scroll position. The opaque background
     stops other nav items showing through as they scroll under. `!important`
     on the button is required because PR #106's responsive shrink had no
     effect against the base #active-org-chip rule without it. */
  .mh-orgmenu {
    position: sticky; right: 8px;
    background: var(--bg, #0A0B11);
    z-index: 2;
    /* Subtle shadow on the left so the menu reads as foreground when
       nav items scroll underneath. */
    box-shadow: -8px 0 12px -8px rgba(10,11,17,0.85);
  }
  #active-org-chip {
    font-size: 11px !important;
    padding: 4px 8px !important;
  }
  #active-org-chip .mh-orgmenu-name { max-width: 92px !important; }
}
/* Phone / tablet (≤860px): every interactive control needs the full
   44px tap area. Card-action utility buttons (Copy caption, etc.) and
   inline-styled .btn variants on /pack get their compact desktop sizing
   overridden here so the touch flow on /pack and /sponsor-post is
   usable on iPhone / iPad. */
@media (max-width: 860px) {
  .mh-card-actions button,
  .mh-card-actions .btn,
  .mh-card-actions a.btn {
    min-height: 44px;
    padding-top: 10px; padding-bottom: 10px;
  }
  /* The reel / newsletter strip on /pack uses inline `padding:6px` on
     download / preview buttons. Force the touch height there too. */
  .card .btn { min-height: 44px; }
}
/* Palette pickers on /organisation/setup: at 1024 px the 3-col grid
   leaves enough room for swatch + 7-char hex; under 540 px the hex
   input gets squeezed to ~30 px wide and #A30D2D is clipped. Drop to a
   single column so each picker has the full row width. */
@media (max-width: 540px) {
  .mh-palette-grid {
    grid-template-columns: 1fr !important;
  }
}
/* Wider 720px treatment: smaller spacing, table tweaks, stat squeeze */
@media (max-width: 720px) {
  main.wrap { padding: 24px 16px 80px; }
  .card { padding: 18px 16px; }
  .stat .v { font-size: 28px; }
  table { font-size: 12.5px; }
  table th, table td { padding: 8px 10px; }
  .kv { grid-template-columns: 1fr; gap: 2px 8px; }
  .kv .k { margin-top: 8px; }
  .mh-card-confidence { position: static !important; display: block; margin-bottom: 8px; }
  .mh-toast { min-width: 0; }
  #mh-toast-container { left: 12px; right: 12px; max-width: none; top: 60px; }
  /* Strap wraps onto new lines + breaks long filenames so user-supplied
     content can't blow the layout (was the cause of /review overflow). */
  .strap { flex-wrap: wrap; min-width: 0; }
  .strap > * { word-break: break-word; overflow-wrap: anywhere; min-width: 0; }
  /* Tables wrap a horizontal-scroll container automatically when wider
     than the viewport (caller wraps the table in .table-scroll). */
  .card > table { display: block; overflow-x: auto; -webkit-overflow-scrolling: touch; }
}
@media (max-width: 480px) {
  .row { gap: 12px; }
  .grid-2, .grid-3 { gap: 12px; }
  .stat-block { gap: 8px; }
  .stat { padding: 10px 12px; min-width: 0; flex: 1; }
  .mh-hero h1 { font-size: clamp(40px, 11vw, 64px); }
  /* Tighter hero chrome so the fold isn't dominated by whitespace on a phone. */
  .mh-hero { padding: 36px 16px 24px; margin-bottom: 24px; }
  /* Stacked full-bleed CTAs are easier to thumb than centred pills. */
  .mh-hero-ctas { flex-direction: column; align-items: stretch; }
  .mh-hero-ctas .btn { width: 100%; justify-content: center; }
}
/* Force inputs/selects to never overflow their container, even with inline
   max-widths. Covers every text-like control — including type=date / type=month
   / type=number / type=email, whose intrinsic min-width otherwise widened the
   /sponsors date pickers past a phone column. Checkbox / radio / range keep
   their fixed intrinsic size. */
input:not([type=checkbox]):not([type=radio]):not([type=range]),
textarea, select { max-width: 100%; }

/* === Hero (Holo-style) === */
.mh-hero {
  text-align: center;
  padding: 56px 24px 32px;
  position: relative;
  margin-bottom: 32px;
}
.mh-hero-eyebrow {
  display: inline-flex; align-items: center; gap: 8px;
  padding: 6px 14px; border-radius: 999px;
  background: color-mix(in oklab, var(--lane) 8%, transparent);
  border: 1px solid color-mix(in oklab, var(--lane) 20%, transparent);
  font-size: 12px; font-weight: 600;
  color: var(--accent);
  letter-spacing: 0.02em;
  margin-bottom: 22px;
  animation: mh-fade-in 0.6s ease-out;
}
.mh-hero-eyebrow .mh-pulse-dot {
  width: 7px; height: 7px; border-radius: 50%;
  background: var(--good);
  box-shadow: 0 0 8px rgba(34,197,94,0.6);
  animation: mh-pulse 1.6s ease-in-out infinite;
}
.mh-hero h1 {
  font-size: clamp(34px, 6vw, 60px);
  font-weight: 800;
  letter-spacing: -0.03em;
  line-height: 1.05;
  margin: 0 0 18px;
  max-width: 820px; margin-left: auto; margin-right: auto;
}
.mh-hero h1 .mh-gradient-text {
  background: linear-gradient(135deg, var(--accent) 0%, var(--lane) 60%, #f43f5e 100%);
  -webkit-background-clip: text; background-clip: text;
  color: transparent;
  -webkit-text-fill-color: transparent;
}
.mh-hero .mh-hero-sub {
  font-size: clamp(15px, 1.6vw, 18px);
  color: var(--ink-dim);
  max-width: 640px; margin: 0 auto 28px;
  line-height: 1.55;
}
.mh-hero-ctas {
  display: flex; gap: 12px; justify-content: center; flex-wrap: wrap;
  margin-bottom: 22px;
}
.mh-hero-ctas .btn {
  font-size: 15px; padding: 12px 22px;
}
.mh-hero-trust {
  display: flex; align-items: center; justify-content: center;
  gap: 18px; flex-wrap: wrap;
  font-size: 12px; color: var(--ink-muted);
  margin-top: 8px;
}
.mh-hero-trust > * { display: inline-flex; align-items: center; gap: 6px; }
.mh-hero-trust svg { width: 13px; height: 13px; }

/* Section heading — centred: titles sit on the page's centre line so the
   page reads tidy on wide screens (body content below stays left-aligned). */
.mh-section-title {
  font-family: var(--font-display);
  font-size: clamp(36px, 4.2vw, 56px);
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: -0.01em;
  text-align: center;
  margin: 0 auto var(--sp-7);
  max-width: 22ch;
  line-height: 0.95;
  color: var(--ink);
}
.mh-section-title em.editorial {
  font-family: var(--font-serif);
  font-style: italic;
  font-variation-settings: 'opsz' 144;
  font-weight: 400;
  font-size: 0.92em;
  color: var(--medal);
  padding: 0 0.05em;
  text-transform: none;
  letter-spacing: -0.01em;
}

/* === Hero (rebuilt home page) — sport-editorial cover === */
/* HERO — broadsheet masthead. No gradient text, no glass, no purple.
   Type carries the weight. Lane-yellow earns its keep on the CTA only.
   Centred: page titles sit on the page's centre line all the way down
   (headline, lede, actions, meta) so wide screens never read lopsided. */
.mh-hero {
  position: relative;
  text-align: center;
  padding: var(--sp-9) var(--sp-7) var(--sp-8);
  margin-bottom: var(--sp-8);
  border-radius: 0;
  background: transparent;
  border: 0;
  border-top: 1px solid var(--lane);
  border-bottom: 1px solid var(--hairline);
  overflow: visible;
  isolation: isolate;
}
/* Faint scoreboard grid behind the hero — earns "pit-wall" feel */
.mh-hero::before {
  content: '';
  position: absolute; inset: 0;
  background:
    linear-gradient(rgba(245,242,232,0.025) 1px, transparent 1px) 0 0 / 100% 64px,
    linear-gradient(90deg, rgba(245,242,232,0.018) 1px, transparent 1px) 0 0 / 64px 100%;
  pointer-events: none;
  mask-image: radial-gradient(ellipse 80% 70% at 30% 50%, black 30%, transparent 75%);
  -webkit-mask-image: radial-gradient(ellipse 80% 70% at 30% 50%, black 30%, transparent 75%);
  z-index: -1;
}
/* Lane-number watermark — huge faint display digit in the far-right corner */
.mh-hero::after {
  content: attr(data-lane);
  position: absolute;
  top: var(--sp-4); right: var(--sp-6);
  font-family: var(--font-display);
  font-weight: 900;
  font-size: clamp(140px, 22vw, 280px);
  line-height: 0.8;
  letter-spacing: -0.04em;
  color: var(--ink);
  opacity: 0.035;
  pointer-events: none;
  font-variant-numeric: tabular-nums;
  z-index: -1;
  white-space: nowrap;
}

.mh-hero-eyebrow {
  font-family: var(--font-mono);
  font-size: 11px; font-weight: 500;
  letter-spacing: 0.22em; text-transform: uppercase;
  color: var(--lane);
  display: inline-flex; align-items: center; gap: 10px;
  padding: 0;
  border: 0;
  border-radius: 0;
  margin: 0 0 var(--sp-6);
  background: transparent;
  position: relative;
}
.mh-hero-eyebrow::before {
  content: '';
  width: 28px; height: 1px;
  background: var(--lane);
  display: inline-block;
  margin-right: 4px;
}
.mh-hero-eyebrow::after {
  content: '●';
  color: var(--lane);
  font-size: 8px;
  animation: mh-pulse 1.6s ease-in-out infinite;
  margin-left: 4px;
}
/* Home masthead kicker: the default navy brand seed makes --lane vanish on
   the dark hero, so on the landing page only, paint the kicker in muted ink
   with a gold rule + live dot so the strap (and its pulse) actually read. */
body[data-page="home"] .mh-hero-eyebrow { color: var(--ink-muted); }
body[data-page="home"] .mh-hero-eyebrow::before { background: var(--medal); }
body[data-page="home"] .mh-hero-eyebrow::after { color: var(--medal); }
.mh-hero h1 {
  font-family: var(--font-display);
  font-size: clamp(56px, 9vw, 132px);
  font-weight: 900;
  letter-spacing: -0.015em;
  text-transform: uppercase;
  line-height: 0.88;
  margin: 0 auto var(--sp-6);
  max-width: 14ch;
  color: var(--ink);
  text-wrap: balance;
}
/* legacy .grad alias — now just sets lane colour, no gradient */
.mh-hero h1 .grad {
  color: var(--lane);
  display: inline;
  -webkit-text-fill-color: var(--lane);
}
/* Editorial italic — the strongest typographic move. Pulled-in serif. */
.mh-hero h1 .editorial,
.mh-hero h1 em.editorial {
  font-family: var(--font-serif);
  font-style: italic;
  font-variation-settings: 'opsz' 144, 'SOFT' 100, 'wght' 400;
  font-weight: 400;
  text-transform: none;
  letter-spacing: -0.01em;
  color: var(--medal);
  font-size: 0.9em;
  padding: 0 0.05em;
  display: inline;
  -webkit-text-fill-color: var(--medal);
}
/* U.9 — cycling hero accent word. The signed-out hero's content-type noun is
   the gold serif-italic accent (.editorial, above) and crossfades through what
   MediaHub makes (stories / reels / graphics / captions). The words stack in a
   single inline-grid cell so the box auto-sizes to the widest word and the
   trailing "out." never reflows as the word changes. The crossfade is pure CSS
   (opacity); a tiny inline script toggles .is-active. With no JavaScript the
   server-rendered first word stays shown; the global prefers-reduced-motion
   block below (and the script's matchMedia guard) keep it static when less
   motion is asked for. */
.mh-hero h1 .mh-word-cycle {
  display: inline-grid;
  justify-items: center;
  vertical-align: baseline;
}
.mh-hero h1 .mh-word-cycle-item {
  grid-area: 1 / 1;
  opacity: 0;
  transition: opacity 0.6s ease;
}
.mh-hero h1 .mh-word-cycle-item.is-active {
  opacity: 1;
}
/* Lede reads in the body face: the headline's display-caps + serif-italic
   pairing is the one editorial move per hero — a serif lede on top of it
   made four typographic voices compete in the first screenful. */
.mh-hero p.lede {
  font-family: var(--font-body);
  font-size: clamp(16px, 1.5vw, 20px);
  color: var(--ink-dim);
  margin: 0 auto var(--sp-7);
  max-width: 52ch;
  line-height: 1.55;
  font-weight: 400;
}
.mh-hero-actions {
  display: flex; gap: var(--sp-3); flex-wrap: wrap; align-items: center;
  justify-content: center;
  margin-top: var(--sp-6);
}

/* CTAs — flat lane yellow, sharp edges, broadcast voice */
.mh-cta-primary,
.mh-cta-secondary {
  display: inline-flex; align-items: center; gap: 10px;
  padding: 14px 26px;
  border-radius: var(--radius-sm);
  font-weight: 700;
  font-family: var(--font-body);
  font-size: 14px;
  text-decoration: none;
  border: 1px solid transparent;
  transition: transform var(--transition), box-shadow var(--transition), border-color var(--transition), background var(--transition);
  cursor: pointer;
  letter-spacing: 0.01em;
}
.mh-cta-primary {
  background: var(--lane);
  color: var(--lane-ink);
  box-shadow: 0 1px 0 rgba(0,0,0,0.10);
}
.mh-cta-primary:hover {
  transform: translateY(-1px);
  background: var(--lane-h);
  box-shadow: var(--shadow-lane);
  color: var(--lane-ink);
}
.mh-cta-secondary {
  background: transparent;
  color: var(--ink);
  border-color: var(--chrome);
}
.mh-cta-secondary:hover {
  background: rgba(245,242,232,0.04);
  border-color: var(--lane);
  color: var(--ink);
  transform: translateY(-1px);
}
/* Press + keyboard-focus parity with .btn — the hero CTAs are the most
   prominent primary actions in the app and were missing both: a press
   settles the hover lift (so the button feels responsive to the click),
   and a visible focus ring keeps them keyboard-navigable. */
.mh-cta-primary:active { transform: translateY(0); background: var(--lane-deep); box-shadow: none; }
.mh-cta-secondary:active { transform: translateY(0); background: rgba(245,242,232,0.07); }
.mh-cta-primary:focus-visible,
.mh-cta-secondary:focus-visible { outline: 2px solid var(--lane); outline-offset: 3px; }
@media (prefers-reduced-motion: reduce) {
  .mh-cta-primary, .mh-cta-secondary { transition: background var(--transition), box-shadow var(--transition), border-color var(--transition); }
  .mh-cta-primary:hover, .mh-cta-secondary:hover, .mh-cta-primary:active, .mh-cta-secondary:active { transform: none; }
}
.mh-hero-meta {
  margin-top: var(--sp-7);
  padding-top: var(--sp-4);
  border-top: 1px solid var(--hairline);
  font-family: var(--font-mono);
  font-size: 11px;
  letter-spacing: 0.10em;
  text-transform: uppercase;
  color: var(--ink-muted);
  display: flex; gap: var(--sp-5); flex-wrap: wrap;
  justify-content: center;
}
.mh-hero-meta .dot { color: var(--ink-faint); }
.mh-hero-meta b { color: var(--lane); font-weight: 500; font-variant-numeric: tabular-nums; }

/* === Sign-in profile cards === */
.mh-profile-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 16px;
  margin-bottom: 32px;
}
.mh-profile-card {
  position: relative;
  display: flex;
  flex-direction: column;
  padding: 22px;
  background:
    linear-gradient(180deg, rgba(255,255,255,0.02), transparent 60%),
    var(--panel);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  transition: transform var(--transition), border-color var(--transition), box-shadow var(--transition);
  text-decoration: none;
  color: inherit;
  min-height: 180px;
}
.mh-profile-card:hover {
  transform: translateY(-3px);
  border-color: var(--border-h);
  box-shadow: var(--shadow-h);
}
/* Holder for the unified logo chip, which self-frames (fixed size, contrast-
   aware backing, keyed logo or org-initials fallback — see .mh-logo-chip--lg in
   theme-base.css). The old 56px lane tile + onerror→initials plumbing is gone:
   the chip owns that now, so every card reads identically. */
.mh-profile-card .logo {
  display: flex;
  margin-bottom: var(--sp-4);
}
.mh-profile-card .display-name {
  font-family: var(--font-display);
  font-size: 22px;
  font-weight: 800;
  letter-spacing: 0;
  text-transform: uppercase;
  color: var(--ink);
  margin-bottom: 6px;
  line-height: 1.05;
}
.mh-profile-card .meta-line {
  font-family: var(--font-mono);
  font-size: 10.5px;
  letter-spacing: 0.10em;
  text-transform: uppercase;
  color: var(--ink-muted);
  display: flex; gap: var(--sp-2); flex-wrap: wrap;
  margin-bottom: var(--sp-4);
}
.mh-profile-card .meta-line .pill {
  padding: 3px 8px;
  background: color-mix(in oklab, var(--lane) 10%, transparent);
  border: 1px solid color-mix(in oklab, var(--lane) 30%, transparent);
  border-radius: 2px;
  color: var(--lane);
  font-weight: 500;
  font-family: var(--font-mono);
  letter-spacing: 0.14em;
}
.mh-profile-card .actions {
  margin-top: auto;
  display: flex; gap: var(--sp-2); flex-wrap: wrap;
}
.mh-profile-card .actions .btn-sign-in {
  flex: 1;
  text-align: center;
  padding: 10px 14px;
  background: var(--lane);
  color: var(--lane-ink);
  border: none;
  border-radius: var(--radius-sm);
  font-family: var(--font-body);
  font-weight: 700;
  font-size: 13px;
  text-decoration: none;
  cursor: pointer;
  transition: background var(--transition);
}
.mh-profile-card .actions .btn-sign-in:hover { background: var(--lane-h); }
.mh-profile-card .actions .btn-delete {
  padding: 10px 14px;
  background: transparent;
  border: 1px solid rgba(255,107,107,0.30);
  color: var(--bad);
  border-radius: var(--radius-sm);
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: background var(--transition), border-color var(--transition);
}
.mh-profile-card .actions .btn-delete:hover {
  background: var(--bad-bg);
  border-color: var(--bad);
}

/* === New org "+" tile — paper texture, sharp, lane-accented === */
.mh-new-profile {
  display: flex;
  flex-direction: column;
  align-items: center; justify-content: center;
  min-height: 180px;
  background:
    repeating-linear-gradient(45deg, color-mix(in oklab, var(--lane) 2.5%, transparent) 0 10px, transparent 10px 20px),
    var(--surface);
  border: 1px dashed var(--chrome);
  border-radius: var(--radius);
  color: var(--ink-dim);
  text-decoration: none;
  font-family: var(--font-mono);
  font-weight: 500;
  font-size: 11px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  text-align: center;
  padding: var(--sp-6);
  transition: var(--transition);
}
.mh-new-profile:hover {
  background:
    repeating-linear-gradient(45deg, color-mix(in oklab, var(--lane) 5%, transparent) 0 10px, transparent 10px 20px),
    var(--surface-2);
  border-color: var(--lane);
  color: var(--lane);
}
.mh-new-profile .plus {
  font-family: var(--font-display);
  font-size: 36px;
  margin-bottom: var(--sp-2);
  color: var(--lane);
  font-weight: 900;
  line-height: 1;
}

/* === Template gallery cards — bento grid with sharper edge === */
.mh-template-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: var(--sp-3);
  margin-bottom: var(--sp-8);
}
.mh-template {
  display: flex; flex-direction: column;
  gap: var(--sp-2);
  padding: var(--sp-6);
  background: var(--surface);
  border: 1px solid var(--hairline);
  border-radius: var(--radius);
  text-decoration: none;
  position: relative;
  overflow: hidden;
  transition: background var(--transition), border-color var(--transition);
}
.mh-template::before {
  content: ''; position: absolute; top: 0; left: 0; right: 0;
  height: 1px;
  background: var(--lane);
  opacity: 0;
  transition: opacity var(--transition);
}
.mh-template:hover {
  background: var(--surface-2);
  border-color: var(--rule);
  text-decoration: none;
}
.mh-template:hover::before { opacity: 1; }
/* The Create ("Add input") and Settings grids are tile-LINKS — they had a
   hover state but no keyboard focus ring (a tabbing volunteer saw nothing)
   and no pressed state. Add both, reusing the lane focus ring used on .btn. */
.mh-template:focus-visible { outline: 2px solid var(--lane); outline-offset: 3px; }
.mh-template:focus-visible::before { opacity: 1; }
.mh-template:active { background: var(--surface-3); }
.mh-template-icon {
  width: 40px; height: 40px;
  border-radius: 0;
  background: transparent;
  border: 1px solid var(--chrome);
  display: inline-flex; align-items: center; justify-content: center;
  color: var(--lane); flex-shrink: 0;
  margin-bottom: var(--sp-3);
  transition: border-color var(--transition);
}
.mh-template:hover .mh-template-icon { border-color: var(--lane); }
.mh-template-icon svg { width: 20px; height: 20px; }
.mh-template h3, .mh-template h2 {
  font-family: var(--font-display);
  font-size: 18px; font-weight: 800; color: var(--ink);
  letter-spacing: 0.01em; margin: 0 0 var(--sp-1);
  text-transform: uppercase;
}
.mh-template p {
  font-family: var(--font-body);
  font-size: 13px; color: var(--ink-dim);
  line-height: 1.5; margin: 0 0 var(--sp-3);
  flex: 1;
}
.mh-template-cta {
  font-family: var(--font-mono);
  font-size: 11px; font-weight: 500;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--lane);
  display: inline-flex; align-items: center; gap: 8px;
  margin-top: auto;
}
.mh-template-cta::after {
  content: '→';
  font-family: var(--font-body);
  font-size: 13px;
  letter-spacing: 0;
}

/* === UI 1.10 — Template / archetype gallery ============================== */
.mh-arch-note {
  font-family: var(--font-body);
  font-size: 13px; color: var(--ink-dim); line-height: 1.55;
  max-width: 64ch; margin: 0 0 var(--sp-5);
}
/* Filter chips — server-nav links, JS-upgraded to instant client filtering. */
.mh-arch-filters {
  display: flex; flex-wrap: wrap; gap: var(--sp-2);
  margin-bottom: var(--sp-6);
}
.mh-arch-chip {
  display: inline-flex; align-items: center; gap: 8px;
  padding: 8px 14px;
  font-family: var(--font-mono);
  font-size: 11px; font-weight: 600;
  letter-spacing: 0.12em; text-transform: uppercase;
  color: var(--ink-dim);
  background: var(--surface);
  border: 1px solid var(--hairline);
  border-radius: 999px;
  text-decoration: none;
  cursor: pointer;
  transition: color var(--transition), border-color var(--transition),
              background var(--transition);
}
.mh-arch-chip:hover { color: var(--ink); border-color: var(--rule); text-decoration: none; }
.mh-arch-chip:focus-visible { outline: 2px solid var(--lane); outline-offset: 2px; }
.mh-arch-chip.is-active {
  color: var(--lane-ink, #0A0B11);
  background: var(--lane);
  border-color: var(--lane);
}
.mh-arch-chip-n {
  font-size: 10px; opacity: 0.7;
  font-variant-numeric: tabular-nums;
}
.mh-arch-chip.is-active .mh-arch-chip-n { opacity: 0.85; }
/* Visually-hidden text (count read-out for screen readers). */
.mh-arch-sr {
  position: absolute; width: 1px; height: 1px;
  padding: 0; margin: -1px; overflow: hidden;
  clip: rect(0 0 0 0); white-space: nowrap; border: 0;
}
/* Card grid */
.mh-arch-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(230px, 1fr));
  gap: var(--sp-4);
  margin-bottom: var(--sp-7);
}
.mh-arch-card {
  display: flex; flex-direction: column;
  background: var(--surface);
  border: 1px solid var(--hairline);
  border-radius: var(--radius);
  overflow: hidden;
  transition: border-color var(--transition), background var(--transition);
}
.mh-arch-card:hover { border-color: var(--rule); background: var(--surface-2); }
.mh-arch-card.is-hidden { display: none; }
.mh-arch-thumb {
  padding: var(--sp-4) var(--sp-4) 0;
}
.mh-arch-svg {
  display: block; width: 100%; height: auto;
  border: 1px solid var(--hairline);
  border-radius: 6px;
  background: var(--bg);
}
.mh-arch-body {
  display: flex; flex-direction: column;
  padding: var(--sp-3) var(--sp-4) var(--sp-4);
}
.mh-arch-head {
  display: flex; align-items: center; justify-content: space-between;
  gap: 10px; margin-bottom: 4px;
}
.mh-arch-title {
  font-family: var(--font-display);
  font-size: 16px; font-weight: 800; color: var(--ink);
  letter-spacing: 0.01em; margin: 0;
  text-transform: uppercase;
}
.mh-arch-tag {
  flex: 0 0 auto;
  font-family: var(--font-mono);
  font-size: 9.5px; font-weight: 600;
  letter-spacing: 0.1em; text-transform: uppercase;
  color: var(--ink-dim);
  padding: 3px 8px;
  border: 1px solid var(--rule);
  border-radius: 999px;
  white-space: nowrap;
}
.mh-arch-tag[data-cat="photo"] { color: #7fd4ff; border-color: rgba(127,212,255,0.32); }
.mh-arch-tag[data-cat="data"] { color: var(--lane); border-color: color-mix(in oklab, var(--lane) 32%, transparent); }
.mh-arch-tag[data-cat="editorial"] { color: #f6a5d0; border-color: rgba(246,165,208,0.32); }
.mh-arch-slug {
  font-family: var(--font-mono);
  font-size: 10.5px; color: var(--ink-muted, var(--ink-dim));
  opacity: 0.7;
  margin-bottom: var(--sp-2);
  word-break: break-all;
}
.mh-arch-summary {
  font-family: var(--font-body);
  font-size: 13px; color: var(--ink-dim);
  line-height: 1.5; margin: 0 0 var(--sp-2);
}
.mh-arch-when {
  font-family: var(--font-body);
  font-size: 12.5px; color: var(--ink-dim);
  line-height: 1.5; margin: auto 0 0;
  padding-top: var(--sp-2);
  border-top: 1px solid var(--hairline);
}
.mh-arch-when-label {
  display: inline-block;
  font-family: var(--font-mono);
  font-size: 9.5px; font-weight: 600;
  letter-spacing: 0.12em; text-transform: uppercase;
  color: var(--lane);
  margin-right: 6px;
}
.mh-arch-empty {
  font-family: var(--font-body);
  font-size: 14px; color: var(--ink-dim);
  padding: var(--sp-6); text-align: center;
  border: 1px dashed var(--rule); border-radius: var(--radius);
  margin-bottom: var(--sp-7);
}
/* Bottom CTA strip back into the Create flow. */
.mh-arch-cta {
  display: flex; align-items: center; justify-content: space-between;
  gap: var(--sp-4); flex-wrap: wrap;
  padding: var(--sp-5) var(--sp-6);
  background: var(--surface);
  border: 1px solid var(--hairline);
  border-radius: var(--radius);
}
.mh-arch-cta-text { display: flex; flex-direction: column; gap: 4px; }
.mh-arch-cta-text strong {
  font-family: var(--font-display); font-size: 16px; color: var(--ink);
  text-transform: uppercase; letter-spacing: 0.01em;
}
.mh-arch-cta-text span { font-family: var(--font-body); font-size: 13px; color: var(--ink-dim); }
/* Used by the template gallery page's own studio link. */
.mh-arch-gallery-link {
  display: flex; align-items: center; justify-content: space-between;
  gap: var(--sp-3); flex-wrap: wrap;
  margin-bottom: var(--sp-5);
  padding: 12px 16px;
  background: var(--surface);
  border: 1px solid var(--hairline);
  border-radius: var(--radius);
  text-decoration: none;
  transition: border-color var(--transition), background var(--transition);
}
.mh-arch-gallery-link:hover { border-color: var(--rule); background: var(--surface-2); text-decoration: none; }
.mh-arch-gallery-link .mh-agl-text { display: flex; flex-direction: column; gap: 2px; }
.mh-arch-gallery-link .mh-agl-title {
  font-family: var(--font-display); font-size: 14px; font-weight: 800;
  color: var(--ink); text-transform: uppercase; letter-spacing: 0.02em;
}
.mh-arch-gallery-link .mh-agl-sub { font-family: var(--font-body); font-size: 12.5px; color: var(--ink-dim); }
.mh-arch-gallery-link .mh-agl-cta {
  font-family: var(--font-mono); font-size: 11px; font-weight: 500;
  letter-spacing: 0.16em; text-transform: uppercase; color: var(--lane);
  white-space: nowrap;
}
/* Schematic preview parts — scoped to .mh-arch-svg so the short class names
   never leak. gd = brand ground, sf = surface/secondary zone, ac = accent,
   ik/ik2 = muted/stronger type bars, ph = photo placeholder, ln = hairline,
   acln = accent seam, paper/dk/dkln = light editorial ground + dark ink on it,
   onac = ink on the accent panel, ln-f = ruled cell outline. */
.mh-arch-svg .gd { fill: var(--surface-3); }
.mh-arch-svg .sf { fill: var(--bg); }
.mh-arch-svg .ac { fill: var(--lane); }
.mh-arch-svg .ik { fill: rgba(245,242,232,0.30); }
.mh-arch-svg .ik2 { fill: rgba(245,242,232,0.58); }
.mh-arch-svg .ph { fill: rgba(245,242,232,0.10); }
.mh-arch-svg .onac { fill: rgba(10,11,17,0.78); }
.mh-arch-svg .ln { fill: none; stroke: rgba(245,242,232,0.22); stroke-width: 1; }
.mh-arch-svg .acln { fill: none; stroke: var(--lane); stroke-width: 2; }
.mh-arch-svg .ln-f { fill: none; stroke: rgba(245,242,232,0.22); stroke-width: 1; }
.mh-arch-svg .paper { fill: rgba(245,242,232,0.92); }
.mh-arch-svg .dk { fill: rgba(10,11,17,0.55); }
.mh-arch-svg .dkln { fill: none; stroke: rgba(10,11,17,0.40); stroke-width: 1; }
@media (max-width: 560px) {
  .mh-arch-grid { grid-template-columns: repeat(auto-fill, minmax(150px, 1fr)); }
}

/* === Provider badge on home — broadcast pill === */
.mh-provider-badge {
  display: inline-flex; align-items: center; gap: 10px;
  padding: 8px 14px;
  background: var(--good-bg);
  border: 1px solid rgba(94,227,154,0.30);
  border-radius: 2px;
  font-family: var(--font-mono);
  font-size: 11px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  margin-top: var(--sp-2);
  color: var(--ink-dim);
}
.mh-provider-badge.warn {
  background: var(--warn-bg);
  border-color: rgba(255,180,84,0.30);
  color: var(--ink);
}
.mh-provider-badge.warn strong { color: var(--warn); }
.mh-provider-badge .mh-provider-dot {
  width: 7px; height: 7px; border-radius: 50%;
  background: var(--good);
  box-shadow: 0 0 6px rgba(94,227,154,0.6);
}
.mh-provider-badge.warn .mh-provider-dot { background: var(--warn); box-shadow: 0 0 6px rgba(255,180,84,0.6); }

/* Skip-to-content link — visible only when focused */
.mh-skip-link {
  position: absolute;
  left: var(--sp-4);
  top: -200px;
  z-index: 200;
  padding: 10px 14px;
  background: var(--lane);
  color: var(--lane-ink);
  font-family: var(--font-mono);
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  text-decoration: none;
  border-radius: var(--radius-sm);
  transition: top var(--transition);
}
.mh-skip-link:focus,
.mh-skip-link:focus-visible {
  top: var(--sp-3);
  outline: 2px solid var(--ink);
  outline-offset: 2px;
}

/* Stronger universal focus indicator — used to be a faint 18% glow that
   barely registered on dark surfaces. WCAG 2.4.11 requires >= 3:1 against
   adjacent colour with >= 2 CSS px thickness. */
:focus-visible {
  outline: 2px solid var(--lane);
  outline-offset: 2px;
  border-radius: 2px;
}
input[type=text]:focus-visible,
input[type=email]:focus-visible,
input[type=password]:focus-visible,
input[type=url]:focus-visible,
input[type=number]:focus-visible,
textarea:focus-visible,
select:focus-visible {
  outline-offset: 1px;
}

/* === UI 1.29 — Sticky chaptered scroll-spy nav (Linear-style) ============ */
/* A side chapter rail that highlights the section currently in view on long
   pages — wired by a caller via _layout(chapters=…). Pure CSS sticky
   positioning; the active state is driven by an IntersectionObserver in
   MH.bindChapterNav. Desktop-only affordance: hidden below 1240px, and with
   JS off it stays a plain list of in-page anchors (never a load-bearing
   control). On a chaptered page the wrap widens into a two-column grid so the
   rail sits in its own gutter column and the reading column keeps ~its
   original width. */
.mh-chapter-nav { display: none; }
/* JS hides the rail (setAttribute('hidden')) when no chapter ids resolve; the
   >=1240px `display:block` below would otherwise beat the UA [hidden] rule and
   render an empty rail with dead anchors, so keep [hidden] winning. */
.mh-chapter-nav[hidden] { display: none; }
.mh-chapnav-content { min-width: 0; }

/* Offset every chapter anchor so a click — or a no-JS "#id" jump — lands the
   section clear of the 64px sticky masthead instead of behind it. */
main.wrap.mh-has-chapnav [id^="mh-ch-"] { scroll-margin-top: 84px; }

@media (min-width: 1240px) {
  main.wrap.mh-has-chapnav {
    max-width: 1560px;
    display: grid;
    /* TOC | centred content | empty mirror column. The empty right column makes
       the content sit in the VIEWPORT centre (so it lines up with the centred
       brand backdrop), while the "On this page" nav tucks into the far-left
       margin. */
    grid-template-columns: 180px minmax(0, 1fr) 180px;
    column-gap: 36px;
    align-items: start;
  }
  .mh-chapter-nav {
    display: block;
    position: sticky;
    top: 88px;
    align-self: start;
    max-height: calc(100vh - 112px);
    overflow-y: auto;
    overscroll-behavior: contain;
    padding: 2px 4px 10px 0;
  }
  .mh-chapter-nav::-webkit-scrollbar { width: 6px; }
  .mh-chapter-nav::-webkit-scrollbar-thumb {
    background: var(--hairline); border-radius: 999px;
  }
}

.mh-chapter-nav-eyebrow {
  margin: 0 0 12px;
  padding: 0 0 10px 16px;
  font-family: var(--font-mono);
  font-size: 10.5px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--ink-faint);
  border-bottom: 1px solid var(--hairline);
}
.mh-chapter-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  position: relative;
}
/* The vertical rule the active marker rides on. */
.mh-chapter-nav-list::before {
  content: "";
  position: absolute;
  left: 0; top: 6px; bottom: 6px;
  width: 1px;
  background: var(--hairline);
}
.mh-chapter-nav-list > li { margin: 0; }
.mh-chapter-nav a {
  position: relative;
  display: flex;
  align-items: baseline;
  gap: 10px;
  padding: 8px 0 8px 16px;
  margin-left: -1px;
  border-left: 2px solid transparent;
  color: var(--ink-muted);
  text-decoration: none;
  line-height: 1.3;
  transition: color var(--transition), border-color var(--transition);
}
.mh-chapter-nav a:hover { color: var(--ink); }
.mh-chapter-nav a:focus-visible { outline-offset: -2px; }
.mh-chapter-num {
  flex: 0 0 auto;
  font-family: var(--font-mono);
  font-size: 10px;
  letter-spacing: 0.04em;
  color: var(--ink-faint);
  transition: color var(--transition);
}
.mh-chapter-label { font-size: 13px; font-weight: 500; }
.mh-chapter-nav a.is-active {
  color: var(--ink);
  border-left-color: var(--lane);
}
.mh-chapter-nav a.is-active .mh-chapter-num { color: var(--lane); }
.mh-chapter-nav a.is-active .mh-chapter-label { font-weight: 600; }

/* Reduced motion — kill all keyframe animation, freeze pulse dots,
   stop the spinner. Round-1 audit had only zero'd duration; this also
   forces iteration count to 1 and explicitly disables looping pulses. */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
  .mh-spinner,
  .mh-spinner::after,
  .mh-hero-eyebrow::after,
  .tag.live::before,
  header.topnav nav a.live::before,
  .mh-stage[data-state="active"]::after {
    animation: none !important;
  }
}
"""

# Prepend the Adaptive Theming Engine's token foundation (Phase 1.6 Stage A)
# so BASE_CSS's :root block can reference the tier-2 semantic role tokens.
# See src/mediahub/web/theme_tokens.py for the three-tier vocabulary, the
# @property registrations, and the academic citations.
#
# Append the responsive guardrails layer last so guardrails always sit
# final in the cascade — never overriding existing MediaHub rules but
# providing safe fallbacks, user-preference handling, and opt-in modern
# utilities. See src/mediahub/web/responsive_guardrails.py for the full
# rationale.
#
# Final cascade order:
#   THEME_TOKENS_CSS  →  BASE_CSS (legacy aliases re-point at --mh-*)  →
#   THEME_COMPONENTS_CSS (polish layer — overrides BASE_CSS component
#       rules: split-property transitions, scale-on-press, dropzone,
#       custom select arrow, modal blur, mobile nav, table-stack, etc.)
#   RESPONSIVE_GUARDRAILS_CSS (must remain LAST — see
#       tests/test_theme_tokens.py::test_guardrails_appended_last).
#       The guardrails are exclusively @supports / pref-media-query
#       gated or .mh-* utilities, so they neither shadow nor conflict
#       with the components layer.
from mediahub.web.theme_tokens import (  # noqa: E402
    THEME_TOKENS_CSS as _MH_TT_CSS,
    THEME_COMPONENTS_CSS as _MH_TC_CSS,
    THEME_MOTION_CSS as _MH_MOTION_CSS,
)
from mediahub.web.responsive_guardrails import RESPONSIVE_GUARDRAILS_CSS as _MH_RG_CSS  # noqa: E402
from mediahub.web.pipeline_diagram import (  # noqa: E402
    PIPELINE_DIAGRAM_CSS as _MH_PL_CSS,
    pipeline_diagram_section_html as _pipeline_diagram_section_html,
)
from mediahub.web.content_intro import (  # noqa: E402
    CONTENT_INTRO_CSS as _MH_CI_CSS,
    presentation_for as _ct_presentation_for,
    render_content_intro as _render_content_intro,
    render_plan_intro as _render_plan_intro,
)
from mediahub.web.cadence_heatmap import (  # noqa: E402
    CADENCE_HEATMAP_CSS as _MH_CAD_CSS,
    cadence_panel_html as _cadence_panel_html,
    window_start as _cadence_window_start,
)
from mediahub.web import code_highlight as _code_hl  # noqa: E402

# I4 fix — persona cards ("Built for the people who already post the
# results"). The inline SVGs use stroke="currentColor", so the icon glyph
# only shows up if .mh-audience-icon carries a visible `color`. Paint it in
# neutral ink, NOT --lane: the default house brand seed resolves --lane to a
# dark navy that vanishes on the dark card, so the affordance must not depend
# on the accent's lightness (same rule as .mh-faq-icon). It rides with the
# components layer (a class + descendant selector out-specifies the bare
# `svg` reset in the guardrails, which set no colour outside @media print),
# so the icons stay legible against the dark --surface card background while
# RESPONSIVE_GUARDRAILS_CSS remains the cascade's final layer (see
# test_theme_tokens::test_guardrails_appended_last).
_MH_AUDIENCE_ICON_CSS = "\n.mh-audience-icon { color: var(--ink-dim); }\n.mh-audience-icon svg { color: var(--ink-dim); }\n"
# Motion / effect kit + the U.8 pipeline-diagram CSS + the UI 1.17
# cadence-heatmap CSS ride AFTER the components layer (so they can elevate
# existing component primitives) but BEFORE the guardrails, which must stay the
# cascade's final layer (test_theme_tokens::test_guardrails_appended_last).
BASE_CSS = (
    _MH_TT_CSS
    + BASE_CSS
    + _MH_TC_CSS
    + _MH_AUDIENCE_ICON_CSS
    + _MH_MOTION_CSS
    + _MH_PL_CSS
    + _MH_CI_CSS
    + _MH_CAD_CSS
    + _MH_RG_CSS
)


# Per-file content-hash fingerprint for a static asset. It rides the asset URL
# as `?v=…` so the long SEND_FILE_MAX_AGE_DEFAULT browser cache can hold the file
# across navigations, yet a deploy that changes the file ships a new URL and busts
# that cache immediately. A content hash (not file mtime) means every replica
# computes the same value, so a load-balanced fleet agrees on the URL. Every
# behaviour-bearing static JS must carry this buster or a returning browser can
# run week-stale JS against new server code on an auto-deploying trunk. Falls back
# to a constant only if the file is unreadable. Computed once per file and cached.
_STATIC_VER_CACHE: dict[str, str] = {}
_STATIC_DIR = Path(__file__).resolve().parent / "static"


def _static_ver(filename: str) -> str:
    """Short sha256 of a file under ``static/`` for cache-busting ``?v=``."""
    cached = _STATIC_VER_CACHE.get(filename)
    if cached is not None:
        return cached
    try:
        ver = hashlib.sha256((_STATIC_DIR / filename).read_bytes()).hexdigest()[:10]
    except OSError:
        ver = "static"
    _STATIC_VER_CACHE[filename] = ver
    return ver


# Back-compat alias — the UI kit's buster is now just one file's content hash.
_UI_KIT_VER = _static_ver("js/ui-kit.js")


# U.9 — cycling hero accent word. The content types MediaHub makes, in the
# order the signed-out landing hero crossfades through them. The first word is
# the one the server renders active (so it shows with no JavaScript and is the
# one a screen reader announces); the rest are aria-hidden decorative cycles.
_HERO_CONTENT_WORDS = ("stories", "reels", "graphics", "captions")

# The script that drives the crossfade. It only toggles `.is-active`; the
# crossfade itself is the CSS opacity transition on `.mh-word-cycle-item`. It
# is a no-op when the visitor asks for reduced motion (matchMedia guard) and
# when there is nothing to cycle, and it pauses while the tab is backgrounded
# so it isn't running a timer off-screen. Inline is fine: the CSP allows
# 'unsafe-inline' scripts and the rest of the app already uses inline scripts.
_HERO_WORD_CYCLE_JS = """<script>
(function(){
  var mq = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)');
  if (mq && mq.matches) return;
  var box = document.querySelector('[data-mh-word-cycle]');
  if (!box) return;
  var items = box.querySelectorAll('.mh-word-cycle-item');
  if (items.length < 2) return;
  var i = 0, timer = null;
  function step(){
    items[i].classList.remove('is-active');
    i = (i + 1) % items.length;
    items[i].classList.add('is-active');
  }
  function start(){ if (timer === null) { timer = window.setInterval(step, 2600); } }
  function stop(){ if (timer !== null) { window.clearInterval(timer); timer = null; } }
  document.addEventListener('visibilitychange', function(){
    if (document.hidden) { stop(); } else { start(); }
  });
  start();
})();
</script>"""


def _hero_word_cycle_html() -> str:
    """The signed-out hero's cycling content-type accent (U.9).

    Returns the ``<span class="mh-word-cycle">`` carrying one
    ``.editorial`` (gold serif-italic) word per content type. The first word
    is rendered ``is-active`` so it is the one shown with no JavaScript and the
    one a screen reader reads; the rest are ``aria-hidden`` decorative cycles.
    The words are fixed constants — no user input — so no escaping is needed.
    """
    spans = []
    for k, word in enumerate(_HERO_CONTENT_WORDS):
        cls = "editorial mh-word-cycle-item" + (" is-active" if k == 0 else "")
        hidden = "" if k == 0 else ' aria-hidden="true"'
        spans.append(f'<span class="{cls}"{hidden}>{word}</span>')
    return '<span class="mh-word-cycle" data-mh-word-cycle>' + "".join(spans) + "</span>"


def _logo_chip_html(
    src_url: str,
    alt: str = "",
    *,
    height: int = 96,
    dominant_hex: Optional[str] = None,
    surface_hex: Optional[str] = None,
    force_chip: bool = False,
    force_bare: bool = False,
    extra_attrs: str = "",
    size: str = "",
    tone: str = "",
    brand_hex: str = "",
    initials: str = "",
) -> str:
    """Render an uploaded logo with the chip-vs-bare decision.

    Phase 1.6 Stage F:
      F1 — default to a neutral chip behind every uploaded logo
      F2 — auto-detect "safe to drop chip" via ΔE2000 + APCA gates

    The chip's neutral-background styling lives in theme-base.css
    (.mh-logo-chip class); this helper picks the wrapping
    structure. Reads the active profile's derived palette for the
    surface colour (so a re-themed chrome uses the correct
    surface) and the logo's AI dominant colour for the gates.

    Parameters
    ----------
    src_url : str
        The logo URL (already HTML-escape-safe — callers pass
        the output of ``url_for`` or pre-escaped).
    alt : str
        Alt text for the ``<img>``. Will be HTML-escaped.
    height : int
        Max-height for the logo image in CSS px.
    dominant_hex : str | None
        The logo's dominant non-neutral colour, typically
        ``logo_meta['ai_dominant_colours'][0]``. If None, the
        helper falls back to safe-by-default chip mode.
    surface_hex : str | None
        Surface colour the logo will sit on. Defaults to the
        active profile's resolved surface, or ``#0A0B11`` (the
        Stage A default).
    force_chip / force_bare : bool
        Override the auto-detection. ``force_chip=True`` is used
        for grids / thumbnails where visual consistency matters
        more than per-logo lightness.
    extra_attrs : str
        Already-escaped attribute fragment appended to the
        ``<img>`` element (e.g. additional inline style).
    size : str
        ``"sm"`` / ``"md"`` / ``"lg"``. When set, render the ELEVATED chrome
        chip: a fixed-size, contrast-aware framed chip with a built-in initials
        fallback (overrides ``height`` and the bare/chip auto-detect). Empty →
        the legacy chip/bare behaviour above.
    tone : str
        ``"light"`` / ``"dark"`` — the backing the logo reads best on
        (``brand.logos.logo_chip_tone``). Only used in elevated mode.
    brand_hex : str
        Org primary hex — a subtle on-brand tint of the backing. Elevated mode.
    initials : str
        Fallback text shown when the logo can't load (``onerror``) or ``src_url``
        is empty. Elevated mode. Do NOT pass an ``onerror`` in ``extra_attrs``
        in elevated mode — the chip wires its own.
    """
    safe_src = _h(src_url)
    safe_alt = _h(alt or "")

    # Elevated chrome chip (opt-in via ``size``): a fixed-size, contrast-aware
    # framed chip with a built-in initials fallback — used by the nav avatar, the
    # sign-in picker tiles and the settings preview so EVERY club's mark reads at
    # the same size and weight whatever its colour / shape / format. ``src_url``
    # is the KEYED ``?bg=1&chip=1`` silhouette (opaque backgrounds removed, and an
    # unrenderable logo 404s so ``onerror`` swaps in the initials). ``tone`` is the
    # backing the logo reads best on (brand.logos.logo_chip_tone); ``brand_hex``
    # tints the backing subtly. Always framed (never bare) for a standardised look.
    if size:
        _sz = size if size in ("sm", "md", "lg") else "md"
        _tone = tone if tone in ("light", "dark") else "light"
        classes = f"mh-logo-chip mh-logo-chip--{_sz} mh-logo-chip--{_tone}"
        chip_style = ""
        if brand_hex and re.match(r"^#[0-9A-Fa-f]{3,8}$", brand_hex):
            chip_style = f' style="--chip-brand:{_h(brand_hex)}"'
        has_img = bool(src_url)
        if not has_img:
            classes += " is-empty"  # no logo → show the initials straight away
        out = [f'<span class="{classes}"{chip_style} aria-hidden="true">']
        if has_img:
            _lazy = "" if _sz == "sm" else ' loading="lazy" decoding="async"'
            out.append(
                f'<img class="mh-logo-chip__img" src="{safe_src}" alt="{safe_alt}"{_lazy}'
                " onerror=\"this.closest('.mh-logo-chip').classList.add('is-empty')\""
                f"{extra_attrs} />"
            )
        out.append(f'<span class="mh-logo-chip__initials">{_h(initials or "?")}</span>')
        out.append("</span>")
        return "".join(out)

    if force_chip and force_bare:
        force_chip = False  # bare wins on contradiction

    if force_bare:
        decision_mode = "bare"
    elif force_chip or dominant_hex is None:
        decision_mode = "chip"
    else:
        if surface_hex is None:
            surface_hex = _active_surface_hex()
        try:
            from mediahub.theming.logo_chip import decide_logo_chip

            decision = decide_logo_chip(dominant_hex, surface_hex)
            decision_mode = decision.mode
        except Exception:
            decision_mode = "chip"

    img_tag = (
        f'<img src="{safe_src}" alt="{safe_alt}" '
        f'style="max-height:{int(height)}px;max-width:100%;'
        f'object-fit:contain;display:block"{extra_attrs} />'
    )
    if decision_mode == "bare":
        return img_tag
    return f'<span class="mh-logo-chip">{img_tag}</span>'


def _active_surface_hex() -> str:
    """Resolved value of the active theme's --mh-surface, or
    ``#0A0B11`` (Stage A default) when no profile is active or the
    derived palette is missing.

    Stage F uses the dark-scheme surface because MediaHub's chrome
    is dark-only today; Stage J may revisit when light-mode visual
    design ships."""
    try:
        from flask import current_app

        get_active = getattr(current_app, "active_profile", None)
        if not get_active:
            return "#0A0B11"
        prof = get_active()
    except (RuntimeError, Exception):
        return "#0A0B11"
    if not prof:
        return "#0A0B11"
    try:
        kit = prof.get_brand_kit()
        palette = kit.ensure_derived_palette() or {}
    except Exception:
        return "#0A0B11"
    roles = palette.get("roles") or {}
    dark = roles.get("dark") or {}
    surface = dark.get("surface")
    return surface if isinstance(surface, str) and surface.startswith("#") else "#0A0B11"


def _repair_summary_text(theme_json: Optional[dict]) -> Optional[str]:
    """Phase 1.6 Stage H3 — plain-English summary of any repair-loop
    adjustments.

    Returns:
        None when ``was_repaired`` is False or the theme JSON is
        missing the data we need.
        A one-sentence string when the repair loop ran AND at least
        one status anchor moved from its canonical hue.
    """
    if not isinstance(theme_json, dict) or not theme_json.get("was_repaired"):
        return None
    palettes = theme_json.get("palettes") or {}
    try:
        from mediahub.theming.palette import STATUS_ANCHORS
    except Exception:
        return None
    deltas = []
    for name, (canonical_hue, _) in STATUS_ANCHORS.items():
        ramp = palettes.get(name) or {}
        actual_hue = ramp.get("hue")
        if isinstance(actual_hue, (int, float)):
            offset = ((float(actual_hue) - canonical_hue + 180.0) % 360.0) - 180.0
            if abs(offset) >= 1.0:
                deltas.append((name, canonical_hue, float(actual_hue), offset))
    if not deltas:
        return (
            "MediaHub ran additional accessibility checks during palette "
            "derivation; no status anchors needed to move. See decision "
            "trace below for full details."
        )
    parts = []
    for name, _canon, _actual, offset in deltas:
        sign = "+" if offset > 0 else ""
        parts.append(f"{name} (rotated {sign}{offset:.0f}°)")
    listing = ", ".join(parts)
    return (
        f"Your brand seed was close enough to our standard status anchors "
        f"that we adjusted {listing} to keep them distinguishable for "
        f"colour-blind viewers and to satisfy our contrast gates. "
        f"See the decision trace below for the precise gate that fired."
    )


def _theme_audit_panel_html(theme_json: Optional[dict]) -> str:
    """Phase 1.6 Stage H2 — render the "Why does my theme look like
    this?" expandable panel.

    Returns an empty string when ``theme_json`` is None or missing
    the keys required to render. The block is server-side HTML; no
    JS required — uses the native ``<details>`` element so the
    panel works in print, in keyboard-only navigation, and in
    every browser.
    """
    if not isinstance(theme_json, dict):
        return ""

    seed_hex = theme_json.get("seed_hex") or ""
    seed_source = theme_json.get("seed_source") or "unknown"
    seed_hct = theme_json.get("seed_hct") or []
    palettes = theme_json.get("palettes") or {}
    detail = theme_json.get("quality_detail") or {}
    harmonic = theme_json.get("harmonic_fit") or detail.get("harmonic_fit") or {}
    decision_trace = theme_json.get("decision_trace") or []
    was_repaired = bool(theme_json.get("was_repaired"))

    # markupsafe.escape returns Markup objects whose `+` operator
    # HTML-escapes adjacent str operands. Force plain str everywhere
    # so the structural HTML (the literal angle brackets) survives.
    def esc(s) -> str:
        return str(_h(s))

    # Swatch row
    def _swatch(name: str, hex_value: str) -> str:
        return (
            f'<span title="{esc(name)}: {esc(hex_value)}" '
            f'style="display:inline-flex;align-items:center;gap:6px;'
            f"margin-right:14px;margin-bottom:6px;font-size:11px;"
            f'color:var(--mh-on-surface-variant)">'
            f'<span style="display:inline-block;width:22px;height:22px;'
            f"border-radius:4px;background:{esc(hex_value)};"
            f'border:1px solid var(--mh-outline-variant)"></span>'
            f"{esc(name)}</span>"
        )

    swatches_html = ""
    swatch_order = (
        ("primary", "primary"),
        ("secondary", "secondary"),
        ("tertiary", "tertiary"),
        ("neutral", "neutral"),
        ("error", "error"),
        ("success", "success"),
        ("warning", "warning"),
        ("info", "info"),
    )
    for label, palette_name in swatch_order:
        ramp = palettes.get(palette_name) or {}
        tones = ramp.get("tones") or {}
        hex_value = tones.get("400") or tones.get("500") or tones.get("50") or ""
        if hex_value:
            swatches_html += _swatch(label, hex_value)

    # Contrast pairs (top 8 most-relevant text role pairs).
    contrast_rows: list[str] = []
    for c in (detail.get("contrast") or [])[:12]:
        passed = c.get("passes_apca", False)
        symbol = "✓" if passed else "✗"
        colour_var = "--mh-success" if passed else "--mh-error"
        contrast_rows.append(
            f'<tr><td style="padding:4px 8px;font-family:var(--font-mono);'
            f'font-size:11px">{esc(c.get("scheme", ""))}</td>'
            f'<td style="padding:4px 8px;font-size:12px">{esc(c.get("role_pair", ""))}</td>'
            f'<td style="padding:4px 8px;font-family:var(--font-mono);'
            f'font-size:11px;text-align:right">{c.get("apca_lc", 0):.1f}</td>'
            f'<td style="padding:4px 8px;font-family:var(--font-mono);'
            f'font-size:11px;text-align:right">{c.get("wcag2_ratio", 0):.2f}</td>'
            f'<td style="padding:4px 8px;text-align:center;'
            f'color:var({colour_var});font-weight:600">{symbol}</td></tr>'
        )

    # Brand vs status ΔE
    status_rows: list[str] = []
    for s in detail.get("status_distance") or []:
        passed = s.get("passes_hard", False)
        symbol = "✓" if passed else "✗"
        colour_var = "--mh-success" if passed else "--mh-error"
        status_rows.append(
            f'<tr><td style="padding:4px 8px;font-size:12px">'
            f"{esc(s.get('status_name', ''))}</td>"
            f'<td style="padding:4px 8px;font-family:var(--font-mono);'
            f'font-size:11px">{esc(s.get("status_hex", ""))}</td>'
            f'<td style="padding:4px 8px;font-family:var(--font-mono);'
            f'font-size:11px;text-align:right">{s.get("delta_e_2000", 0):.1f}</td>'
            f'<td style="padding:4px 8px;text-align:center;'
            f'color:var({colour_var});font-weight:600">{symbol}</td></tr>'
        )

    # CVD checks
    cvd_rows: list[str] = []
    for c in detail.get("cvd") or []:
        passed = c.get("distinguishable", False)
        symbol = "✓" if passed else "✗"
        colour_var = "--mh-success" if passed else "--mh-warning"
        cvd_rows.append(
            f'<tr><td style="padding:4px 8px;font-size:12px">{esc(c.get("cvd", ""))}</td>'
            f'<td style="padding:4px 8px;font-size:12px">{esc(c.get("pair", ""))}</td>'
            f'<td style="padding:4px 8px;font-family:var(--font-mono);'
            f'font-size:11px;text-align:right">{c.get("delta_e_2000", 0):.1f}</td>'
            f'<td style="padding:4px 8px;text-align:center;'
            f'color:var({colour_var});font-weight:600">{symbol}</td></tr>'
        )

    # Harmonic fit
    if harmonic and harmonic.get("template"):
        harmonic_html = (
            f'<p style="margin:0;font-size:12px;color:var(--mh-on-surface)">'
            f"Best template: <b>{esc(harmonic['template'])}</b> @ "
            f"<code>{harmonic.get('rotation', 0):.1f}°</code>, "
            f"energy = <code>{harmonic.get('energy', 0):.1f}</code> "
            f"across <code>{harmonic.get('hue_count', 0)}</code> hues "
            f"(Cohen-Or 2006; lower energy = more harmonic)."
            f"</p>"
        )
    else:
        harmonic_html = (
            '<p class="dim" style="margin:0;font-size:12px">'
            "No harmonic fit recorded (older derivation).</p>"
        )

    # Decision trace as <pre>
    trace_text = "\n".join(decision_trace) if decision_trace else "(no trace recorded)"
    trace_html = (
        '<pre style="margin:0;padding:10px 12px;background:var(--mh-surface);'
        "border:1px solid var(--mh-outline-variant);border-radius:6px;"
        "font-family:var(--font-mono);font-size:11px;line-height:1.45;"
        "color:var(--mh-on-surface-variant);max-height:240px;overflow:auto;"
        'white-space:pre-wrap;word-break:break-word">' + esc(trace_text) + "</pre>"
    )

    seed_hct_str = ""
    if isinstance(seed_hct, (list, tuple)) and len(seed_hct) >= 3:
        seed_hct_str = f"HCT(H={seed_hct[0]:.1f}°, C={seed_hct[1]:.1f}, T={seed_hct[2]:.1f})"

    repaired_note = ""
    if was_repaired:
        repaired_note = (
            '<p class="dim" style="margin:6px 0 0;font-size:11px">'
            "⚙ This palette went through the repair loop — see the "
            "callout above for the plain-English summary, or the "
            "decision trace below for the full sequence.</p>"
        )

    return (
        '<details class="mh-theme-audit" style="margin:18px 0 0;'
        "border:1px solid var(--mh-outline-variant);border-radius:8px;"
        'background:var(--mh-surface-variant);overflow:hidden">'
        '<summary style="cursor:pointer;padding:12px 16px;font-size:13px;'
        'font-weight:600;color:var(--mh-on-surface);user-select:none">'
        "Why does my theme look like this?"
        '<span class="muted" style="font-weight:400;font-size:12px;'
        'margin-left:8px">Engine decisions, contrast checks, '
        "accessibility audit</span>"
        "</summary>"
        '<div style="padding:0 16px 16px 16px;'
        'border-top:1px solid var(--mh-outline-variant)">'
        '<h4 style="margin:14px 0 4px;font-size:12px;text-transform:uppercase;'
        'letter-spacing:0.12em;color:var(--mh-on-surface-muted)">Captured seed</h4>'
        f'<p style="margin:0;font-size:13px;color:var(--mh-on-surface)">'
        f"Seed <code>{esc(seed_hex)}</code> from "
        f"<code>{esc(seed_source)}</code>; {seed_hct_str}.</p>"
        f"{repaired_note}"
        '<h4 style="margin:14px 0 4px;font-size:12px;text-transform:uppercase;'
        'letter-spacing:0.12em;color:var(--mh-on-surface-muted)">Derived palette</h4>'
        f'<div style="margin-top:4px">{swatches_html}</div>'
        '<h4 style="margin:14px 0 4px;font-size:12px;text-transform:uppercase;'
        'letter-spacing:0.12em;color:var(--mh-on-surface-muted)">'
        "Contrast checks (APCA Lc · WCAG 2.x)</h4>"
        '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;'
        'font-size:11.5px">'
        '<thead><tr style="border-bottom:1px solid var(--mh-outline-variant)">'
        '<th style="padding:4px 8px;text-align:left">scheme</th>'
        '<th style="padding:4px 8px;text-align:left">role pair</th>'
        '<th style="padding:4px 8px;text-align:right">Lc</th>'
        '<th style="padding:4px 8px;text-align:right">ratio</th>'
        '<th style="padding:4px 8px;text-align:center">ok</th>'
        "</tr></thead><tbody>" + "".join(contrast_rows) + "</tbody></table></div>"
        '<h4 style="margin:14px 0 4px;font-size:12px;text-transform:uppercase;'
        'letter-spacing:0.12em;color:var(--mh-on-surface-muted)">'
        "Brand seed vs status anchors (CIEDE2000)</h4>"
        '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;'
        'font-size:11.5px">'
        '<thead><tr style="border-bottom:1px solid var(--mh-outline-variant)">'
        '<th style="padding:4px 8px;text-align:left">anchor</th>'
        '<th style="padding:4px 8px;text-align:left">hex</th>'
        '<th style="padding:4px 8px;text-align:right">ΔE2000</th>'
        '<th style="padding:4px 8px;text-align:center">ok</th>'
        "</tr></thead><tbody>" + "".join(status_rows) + "</tbody></table></div>"
        '<h4 style="margin:14px 0 4px;font-size:12px;text-transform:uppercase;'
        'letter-spacing:0.12em;color:var(--mh-on-surface-muted)">'
        "Colour-vision-deficiency simulation (Machado 2009)</h4>"
        '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;'
        'font-size:11.5px">'
        '<thead><tr style="border-bottom:1px solid var(--mh-outline-variant)">'
        '<th style="padding:4px 8px;text-align:left">cvd</th>'
        '<th style="padding:4px 8px;text-align:left">pair</th>'
        '<th style="padding:4px 8px;text-align:right">sim ΔE2000</th>'
        '<th style="padding:4px 8px;text-align:center">ok</th>'
        "</tr></thead><tbody>" + "".join(cvd_rows) + "</tbody></table></div>"
        '<h4 style="margin:14px 0 4px;font-size:12px;text-transform:uppercase;'
        'letter-spacing:0.12em;color:var(--mh-on-surface-muted)">'
        "Harmonic fit (Cohen-Or 2006)</h4>"
        + harmonic_html
        + '<h4 style="margin:14px 0 4px;font-size:12px;text-transform:uppercase;'
        'letter-spacing:0.12em;color:var(--mh-on-surface-muted)">Decision trace</h4>'
        + trace_html
        + "</div></details>"
    )


def _colour_accessibility_panel_html(role_vars: Optional[dict]) -> str:
    """G1.18 — a collapsed "Colour accessibility" report beside the theme audit.

    Renders the deterministic ``quality.colour_audit`` verdict for the brand's
    resolved ``--mh-*`` role set: the APCA/WCAG summary from ``audit_roles`` plus
    the colourblind-preview swatch strip (``swatches_svg``). Read-only and
    engine-free — it explains, it never changes what renders. Returns "" when no
    usable role set is available.
    """
    if not isinstance(role_vars, dict) or not role_vars:
        return ""
    try:
        from mediahub.quality import colour_audit as _ca

        audit = _ca.audit_roles(role_vars)
        summary = audit.to_summary()
        explain = audit.explain()
        swatch_svg = _ca.swatches_svg(role_vars)
    except Exception:
        return ""

    verdict_ok = bool(summary.get("passes")) and bool(summary.get("cvd_safe"))
    verdict_label = "Passes" if verdict_ok else "Needs attention"
    verdict_var = "--mh-success" if verdict_ok else "--mh-error"
    warnings = summary.get("warnings") or []
    warn_html = ""
    if warnings:
        items = "".join(f"<li>{_h(w)}</li>" for w in warnings[:12])
        warn_html = (
            '<ul style="margin:8px 0 0;padding-left:18px;font-size:12px;'
            f'color:var(--mh-on-surface-variant)">{items}</ul>'
        )
    # swatches_svg is safe-by-construction (validated hex + fixed labels, every
    # text node XML-escaped) so it embeds inline without re-escaping.
    return (
        '<details style="margin-top:14px;border:1px solid var(--mh-outline-variant);'
        'border-radius:8px;padding:0 12px">'
        '<summary style="cursor:pointer;padding:10px 0;font-size:13px;font-weight:600;'
        'color:var(--mh-on-surface)">Colour accessibility '
        f'<span style="color:var({verdict_var});font-weight:600">&middot; {verdict_label}</span>'
        "</summary>"
        '<div style="padding:0 0 12px">'
        f'<p style="font-size:12px;color:var(--mh-on-surface-variant);'
        f'margin:0 0 10px;line-height:1.5">{_h(explain)}</p>'
        f"{warn_html}"
        f'<div style="overflow-x:auto;margin-top:12px">{swatch_svg}</div>'
        "</div></details>"
    )


def _theme_repair_callout_html(theme_json: Optional[dict]) -> str:
    """Phase 1.6 Stage H3 — render the non-blocking warning callout
    when the repair loop fired.

    Returns an empty string when no callout is warranted (palette
    didn't need repair, or theme JSON is missing).
    """
    text = _repair_summary_text(theme_json)
    if not text:
        return ""
    safe_text = str(_h(text))
    return (
        f'<div class="mh-theme-warning" role="status" '
        f'style="margin:14px 0 0;padding:12px 16px;'
        f"border-radius:6px;border:1px solid var(--mh-warning);"
        f"background:rgba(255,180,84,0.10);font-size:13px;"
        f'color:var(--mh-on-surface)">'
        f'<strong style="display:block;margin-bottom:4px;'
        f'color:var(--mh-warning)">'
        f"Theme adjusted for accessibility"
        f"</strong>"
        f"{safe_text}"
        f"</div>"
    )


def _adaptive_theme_enabled() -> bool:
    """Phase 1.6 Stage J1 — the cutover safety lever.

    Returns True (the default) when the adaptive theming
    pipeline should inject its inline <style id="mh-theme-seed">
    override into rendered pages. Returns False when the operator
    has set ``MEDIAHUB_ADAPTIVE_THEME=0`` (also accepts
    ``false``/``off``/``no``) — in which case every render falls
    through to the static Stage A cascade as if Stages D-J had
    never shipped.

    The flag is purely a *visible-cascade* control: the on-disk
    theme JSON (Stage G), the audit panel (Stage H2), and the
    repair callout (Stage H3) all keep working regardless,
    because they're independent of the CSS override.
    """
    import os as _os

    value = _os.environ.get("MEDIAHUB_ADAPTIVE_THEME", "")
    return value.strip().lower() not in ("0", "false", "off", "no")


def _default_theme_json() -> Optional[dict]:
    """Phase 1.6 Stage J2 — pre-derived default theme.

    Lazily derives a DerivedTheme from BrandKit.generic_default()'s
    seeds (#0E2A47 navy + #C9A227 gold) the first time it's called,
    then caches the result for the life of the process.

    Returns None on any derivation failure so callers can fall
    back to the static Stage A cascade cleanly. Side-effect:
    Stage G's hook in ensure_derived_palette() writes
    DATA_DIR/themes/default.json on first call, making the
    default theme available to motion / email / static
    renderers exactly like a real profile's theme.

    Cached at module level (not per-call) so the ~50ms first-
    call cost is amortised across the life of the worker.
    """
    return _default_theme_json_cached()


@functools.lru_cache(maxsize=1)
def _default_theme_json_cached() -> Optional[dict]:
    try:
        from mediahub.brand.kit import BrandKit

        kit = BrandKit.generic_default()
        return kit.ensure_derived_palette()
    except Exception:
        return None


def _theme_seed_style_block() -> str:
    """Return the inline <style id="mh-theme-seed"> block carrying
    the active organisation's brand-seed override.

    Phase 1.6 Stage E introduced the per-org override; Stage J
    extended it with a feature-flag rollback (J1) and a generic-
    default fallback for unconfigured deployments (J2).

    Three-tier resolution:
      1. ``MEDIAHUB_ADAPTIVE_THEME=0`` → return "" (Stage J1
         rollback to Stage A cascade)
      2. Active organisation pinned → use profile.brand_kit.
         derived_palette (Stages D-G)
      3. No active organisation → use _default_theme_json()
         (Stage J2 — unconfigured-first-run benefits from the
         pipeline)

    Returns an empty string in case 1 or when the chosen tier
    fails to resolve a valid seed (defence in depth).
    """
    import re as _re

    # Tier 1 — rollback flag
    if not _adaptive_theme_enabled():
        return ""

    # Tier 2 — active profile (the Stage E original behaviour)
    palette = None
    secondary_hex = ""
    accent_hex = ""
    try:
        from flask import current_app

        get_active = getattr(current_app, "active_profile", None)
        if get_active:
            prof = get_active()
            if prof:
                try:
                    from mediahub.brand.palette import effective_palette

                    eff = effective_palette(
                        manual=getattr(prof, "brand_palette_manual", {}) or {},
                        extracted=getattr(prof, "brand_palette_extracted", {}) or {},
                    )
                except Exception:
                    eff = {}
                # Only override the chrome when the org has SOME
                # explicit brand signal. Without this guard, brand-new
                # profiles whose AI capture failed (no LLM key, DNS
                # error, blocked socials) would still drive the seed
                # off ``ClubProfile.brand_primary`` — and that field
                # defaults to ``#A30D2D`` (legacy red), so the user
                # saw a red theme they never picked. We treat any
                # of these as "the user has a brand pinned":
                #   - manual override set (any slot)
                #   - AI-extracted slot set (any slot)
                #   - brand_kit dict has a primary_colour explicitly
                #   - legacy ``brand_primary`` differs from the class
                #     default (someone actively set it)
                bk_dict = dict(getattr(prof, "brand_kit", {}) or {})
                _CLUB_PROFILE_DEFAULT_PRIMARY = "#A30D2D"
                explicit_legacy_primary = (
                    getattr(prof, "brand_primary", "") or ""
                ).strip() not in ("", _CLUB_PROFILE_DEFAULT_PRIMARY)
                has_confirmed_primary = bool(
                    eff.get("primary")
                    or eff.get("secondary")
                    or eff.get("accent")
                    or bk_dict.get("primary_colour")
                    or explicit_legacy_primary
                )
                if has_confirmed_primary:
                    try:
                        kit = prof.get_brand_kit()
                        palette = kit.ensure_derived_palette()
                    except Exception:
                        palette = None
                    secondary_hex = (eff.get("secondary") or "").strip()
                    accent_hex = (eff.get("accent") or "").strip()
    except (RuntimeError, Exception):
        palette = None

    # Tier 3 — generic-default fallback (Stage J2)
    if not isinstance(palette, dict):
        palette = _default_theme_json()

    if not isinstance(palette, dict):
        return ""

    seed_hex = palette.get("seed_hex")
    if not isinstance(seed_hex, str):
        return ""
    if not _re.fullmatch(r"#[0-9A-Fa-f]{6,8}", seed_hex):
        return ""

    overrides = [f"--mh-brand-seed: {seed_hex};"]
    # Re-derive the on-colour (button/label ink) from the LIVE seed so the
    # recoloured chrome stays legible whatever the club's brand lightness.
    # --lane-ink aliases --mh-on-primary, and --mh-primary resolves to the
    # raw seed (brand tone 400) — so without this, a dark brand seed (the
    # signed-out navy default, a maroon/navy club) keeps the static near-
    # black ink and the primary CTA renders dark-on-dark (~1.3:1, a WCAG
    # fail). brand_on_color reuses the deterministic contrast science to
    # pick paper-cream vs paper-black; for the lane-yellow default it
    # returns the existing near-black, so nothing changes there.
    try:
        from mediahub.theming.contrast import brand_on_color as _brand_on_color
    except Exception:
        _brand_on_color = None
    if _brand_on_color is not None:
        overrides.append(f"--mh-on-primary: {_brand_on_color(seed_hex[:7])};")
    # Secondary → tertiary ramp (the "medal gold" slot). Honouring the
    # user's secondary here means a navy+gold org sees navy chrome AND
    # gold medal/accent ribbons instead of the MediaHub default cream.
    if secondary_hex and _re.fullmatch(r"#[0-9A-Fa-f]{6,8}", secondary_hex):
        overrides.append(f"--mh-tertiary-seed: {secondary_hex};")
        # On-tertiary (--medal-ink) must track a custom secondary too, so a
        # dark secondary doesn't break medal/achievement text. The default
        # medal-gold keeps its themed ink (this branch is simply skipped).
        if _brand_on_color is not None:
            overrides.append(f"--mh-on-tertiary: {_brand_on_color(secondary_hex[:7])};")
    # Accent is a third brand colour with no dedicated seed in
    # theme-base.css yet; expose it as a custom property so component
    # code that wants it can opt in via var(--mh-brand-accent).
    if accent_hex and _re.fullmatch(r"#[0-9A-Fa-f]{6,8}", accent_hex):
        overrides.append(f"--mh-brand-accent: {accent_hex};")

    return f'<style id="mh-theme-seed">:root {{ {" ".join(overrides)} }}</style>'


# Self-contained "Create graphic" panel script for pages OTHER than the meet
# review page (which has its own richer createGraphic with motion + add-to-pack).
# U.6 — the branded render/generation loading state (inspired by Lusion). One
# reusable controller, `MH.renderProgress(container, opts)`, shared by every long
# render/generation wait (motion, reels, graphics). It paints a large editorial
# %-numeral (reusing the .display-num motif) over a minimal progress bar.
#
# Honesty: the renders are opaque (a blocking request, or a running/done poll),
# so the percentage is an eased *time estimate* that asymptotes BELOW 100 and
# only snaps to 100 when the real result lands (`complete()`). Where the backend
# does report real progress (variant batches: done/total), the caller feeds it
# via `setProgress` and the bar tracks the actual work. The number is monotonic
# and never claims "done" before the artefact exists.
#
# UI1.26 — every renderProgress wait also spawns a cursor-anchored mirror via
# MH.cursorReadout (ui-kit.js): a small "NN% · phase" chip that follows the
# pointer during the wait and disappears on complete()/stop(). It is opt-out
# (opts.cursor === false) and degrades safely if ui-kit.js hasn't loaded yet.
#
# Defined in <head> (before any body consumer, incl. on-load mhAutoGraphic) and
# kept as a module constant so tests can exercise the controller directly.
