# Roadmap 1.11 — the Charts & insights page JS. AI-supplied text is rendered via
# textContent only (never innerHTML), so a takeaway or headline can't inject markup.
_CHARTS_PAGE_JS = """
<script>
(function(){
  function out(){ return document.getElementById('mh-ai-out'); }
  function show(node){ var o=out(); o.innerHTML=''; o.style.display='block'; o.appendChild(node); }
  function msg(text){ var d=document.createElement('div'); d.className='card'; d.textContent=text; return d; }
  function busy(btn,on,label){ btn.disabled=on; if(on){ btn.dataset._t=btn.textContent; btn.textContent=label; } else { btn.textContent=btn.dataset._t||btn.textContent; } }
  function highlight(id){ document.querySelectorAll('.mh-chartpack-tile').forEach(function(t){ var on=t.getAttribute('data-chart-id')===id; t.style.outline=on?'2px solid var(--accent)':''; t.style.outlineOffset='2px'; }); }

  var recBtn=document.getElementById('mh-rec-btn');
  if(recBtn) recBtn.addEventListener('click', function(){
    busy(recBtn,true,'Thinking…');
    fetch('__REC_URL__',{method:'POST'}).then(function(r){return r.json();}).then(function(j){
      busy(recBtn,false);
      if(j.available===false){ show(msg(j.message||'AI is not configured on this deployment.')); return; }
      var rec=j.recommendation;
      if(!rec){ show(msg(j.message||'No recommendation available.')); return; }
      var card=document.createElement('div'); card.className='card';
      var h=document.createElement('div'); h.style.fontWeight='700'; h.textContent='Lead with: '+(rec.title||''); card.appendChild(h);
      if(rec.headline){ var hl=document.createElement('div'); hl.style.marginTop='4px'; hl.textContent=rec.headline; card.appendChild(hl); }
      if(rec.reason){ var rs=document.createElement('div'); rs.className='muted'; rs.style.marginTop='6px'; rs.style.fontSize='13px'; rs.textContent=rec.reason; card.appendChild(rs); }
      show(card); highlight(rec.chart_id);
      var tile=document.querySelector('.mh-chartpack-tile[data-chart-id="'+rec.chart_id+'"]');
      if(tile) tile.scrollIntoView({behavior:'smooth',block:'center'});
    }).catch(function(){ busy(recBtn,false); show(msg('Could not reach the recommender. Try again.')); });
  });

  var insBtn=document.getElementById('mh-ins-btn');
  if(insBtn) insBtn.addEventListener('click', function(){
    busy(insBtn,true,'Writing…');
    fetch('__INS_URL__',{method:'POST'}).then(function(r){return r.json();}).then(function(j){
      busy(insBtn,false);
      if(j.available===false){ show(msg(j.message||'AI is not configured on this deployment.')); return; }
      var ins=j.insights||{}; var items=ins.takeaways||[];
      if(!items.length){ show(msg(ins.summary||'No takeaways generated.')); return; }
      var card=document.createElement('div'); card.className='card';
      if(ins.summary){ var s=document.createElement('div'); s.style.fontWeight='700'; s.style.marginBottom='8px'; s.textContent=ins.summary; card.appendChild(s); }
      var ul=document.createElement('ul'); ul.style.margin='0'; ul.style.paddingLeft='18px';
      items.forEach(function(t){
        var li=document.createElement('li'); li.style.marginBottom='6px'; li.textContent=t.text||'';
        var n=(t.sources||[]).length;
        if(n){ var sp=document.createElement('span'); sp.className='muted'; sp.style.fontSize='11px'; sp.style.marginLeft='6px'; sp.textContent='('+n+' source'+(n===1?'':'s')+')'; li.appendChild(sp); }
        ul.appendChild(li);
      });
      card.appendChild(ul); show(card);
    }).catch(function(){ busy(insBtn,false); show(msg('Could not reach the writer. Try again.')); });
  });

  // Per-chart grounded caption: fetch, show in the tile, offer copy-to-clipboard.
  document.addEventListener('click', function(ev){
    var btn = ev.target.closest ? ev.target.closest('.mh-cap-btn') : null;
    if(!btn) return;
    var tile = btn.closest('.mh-chartpack-tile'); if(!tile) return;
    var out = tile.querySelector('.mh-cap-out'); if(!out) return;
    busy(btn, true, 'Writing…');
    fetch(btn.getAttribute('data-cap-url'), {method:'POST', headers:{'Content-Type':'application/json'}, body:'{}'}).then(function(r){return r.json();}).then(function(j){
      busy(btn, false);
      out.style.display='block'; out.textContent='';
      if(j.available===false || !j.caption){ out.textContent = j.message || 'AI captions are not configured on this deployment.'; return; }
      var p=document.createElement('div'); p.textContent=j.caption; out.appendChild(p);
      var copy=document.createElement('button'); copy.className='btn secondary'; copy.style.cssText='font-size:11px;padding:3px 10px;margin-top:8px'; copy.textContent='Copy';
      copy.addEventListener('click', function(){ navigator.clipboard && navigator.clipboard.writeText(j.caption); copy.textContent='Copied'; });
      out.appendChild(copy);
    }).catch(function(){ busy(btn,false); out.style.display='block'; out.textContent='Could not reach the caption writer. Try again.'; });
  });

  // D-33 — download a chart PNG via fetch+blob so a raster failure (e.g. no
  // Chromium on the worker) renders inline with an SVG fallback, instead of the
  // anchor navigating the whole page onto a raw JSON error. Shows a busy state.
  document.addEventListener('click', function(ev){
    var btn = ev.target.closest ? ev.target.closest('.mh-chart-dl') : null;
    if(!btn) return;
    ev.preventDefault();
    var tile = btn.closest('.mh-chartpack-tile');
    var msg = tile ? tile.querySelector('.mh-chart-export-msg') : null;
    var url = btn.getAttribute('data-dl-url');
    var svg = btn.getAttribute('data-svg-fallback');
    var name = btn.getAttribute('data-dl-name') || 'chart.png';
    if(msg){ msg.style.display='none'; msg.textContent=''; }
    busy(btn, true, '…');
    fetch(url).then(function(r){
      if(!r.ok) throw new Error('unavailable');
      return r.blob();
    }).then(function(blob){
      busy(btn, false);
      var obj = URL.createObjectURL(blob);
      var a = document.createElement('a');
      a.href = obj; a.download = name;
      document.body.appendChild(a); a.click(); document.body.removeChild(a);
      setTimeout(function(){ URL.revokeObjectURL(obj); }, 4000);
    }).catch(function(){
      busy(btn, false);
      if(msg){
        msg.style.display = 'block';
        msg.textContent = 'PNG export is not available on this deployment right now. ';
        var link = document.createElement('a');
        link.href = svg; link.setAttribute('download', '');
        link.textContent = 'Download the vector (SVG) instead';
        msg.appendChild(link);
      }
    });
  });
})();
</script>
"""


# --------------------------------------------------------------------------- #
# Shared product-story sections (the "how it works / what it does" explainer).
#
# These were once built inline in the home() route and shown to everyone. They
# are product story, not session state, so they render byte-identically wherever
# they are used. As of the signed-in home rebuild they serve two surfaces:
#   * the signed-OUT landing page (home()) — the marketing/explainer body, and
#   * the in-app Help page (help_page()) — the same explainer, reached from the
#     account menu, so a signed-in club can look up "how does this work?" without
#     the homepage having to carry the sales pitch.
# The signed-IN home no longer renders them (it is a content-creation workspace),
# which is why they live at module scope and are called from both routes.
# --------------------------------------------------------------------------- #
def _home_io_headline_html() -> str:
    """UI 1.3 — inline-media display headline: a results sheet → story, feed and
    reel, each output inlined as a real first-party sample SVG (no external
    fetch). One upload, four posting-ready formats, every fact from the file."""

    def _inline_thumb(filename: str, kind: str, alt: str) -> str:
        src = url_for("static", filename="samples/" + filename)
        return (
            f'<span class="mh-inline-thumb-wrap mh-inline-thumb-wrap--{kind}">'
            f'<img class="mh-inline-thumb mh-inline-thumb--{kind}" '
            f'src="{src}" width="144" height="200" '
            f'loading="lazy" decoding="async" alt="{_h(alt)}" />'
            "</span>"
        )

    return (
        '<section class="mh-pipeline" aria-labelledby="mh-pipeline-h">'
        '<div class="mh-section-eyebrow-strip"><span class="label">Input &rarr; output</span></div>'
        '<h2 id="mh-pipeline-h" class="mh-pipeline-headline">'
        "From a results sheet "
        + _inline_thumb("results-sheet.svg", "results", "Event 14, 100m freestyle finishing times")
        + " to a story "
        + _inline_thumb("story-card.svg", "story", "Tom Davies, personal best, 52.41")
        + ", a feed graphic "
        + _inline_thumb("feed-graphic.svg", "feed", "Top three, county finals podium")
        + " and a reel "
        + _inline_thumb("reel.svg", "reel", "Match-day highlights, 15-second cut")
        + "."
        "</h2>"
        '<p class="mh-pipeline-sub">One upload, four posting-ready formats. '
        "Every name, time and place comes straight from the file you "
        "uploaded. Nothing is invented, and nothing posts without you.</p>"
        "</section>"
    )


def _home_engine_bento_html() -> str:
    """UI 1.2 — the "what the engine does" bento: real, deterministic sample
    outputs (story card, reel poster, feed graphic, the detected-&-ranked
    intelligence read-out, the brand-kit application and the moment taxonomy),
    rendered as first-party inline SVG that consume the live brand tokens."""
    return (
        '<section class="mh-section" id="mh-ch-engine">'
        '<div class="mh-section-eyebrow-strip mh-reveal"><span class="label">What the engine does</span></div>'
        + _reveal_lines(
            [
                "A results sheet in.",
                'A <em class="editorial">weekend</em> of content out.',
            ]
        )
        + '<div class="mh-bento mh-reveal-group">'
        + '<div class="mh-bento-tile feature is-story">'
        + _sample_graphics.story_card_svg()
        + "</div>"
        + '<div class="mh-bento-tile is-reel">'
        + _sample_graphics.reel_poster_svg()
        + "</div>"
        + '<div class="mh-bento-tile is-feed">'
        + _sample_graphics.feed_graphic_svg()
        + "</div>"
        + '<div class="mh-bento-tile wide is-rank">'
        + _sample_graphics.detected_ranked_svg()
        + "</div>"
        + '<div class="mh-bento-tile is-brand">'
        + _sample_graphics.brand_kit_svg()
        + "</div>"
        + '<div class="mh-bento-tile is-moments">'
        + _sample_graphics.moments_svg()
        + "</div>"
        + "</div>"
        + '<p class="mh-bento-caption">Real sample output — every name, '
        "time and place comes from the file you upload, set in your club’s "
        "palette and type. Nothing is invented.</p>"
        "</section>"
    )


