    def _settings_card_specs(is_dev: bool, signed_in: bool) -> list[tuple[str, str, str, str]]:
        """(title, description, icon_key, href) for the settings tiles.

        12 cards for everyone, a 13th (Developer) only when an operator is
        signed in. A "Pricing & plans" tile is added when signed into a club
        profile, because Pricing leaves the top bar for signed-in users and
        lives here instead (grouped with Billing & plan).
        """
        cards: list[tuple[str, str, str, str]] = [
            (
                "Organisation & brand",
                "Logos, palette, tone and the brand the engine applies to every card.",
                "org",
                url_for("organisation_setup"),
            ),
            (
                "Brand platform",
                "Multiple kits (sponsor / event / team co-brands), token locks, "
                "brand check and palette import — one home for your identity.",
                "brand",
                url_for("brand_home_page"),
            ),
            (
                "Templates",
                "The 12 card styles your packs are composed from — the engine "
                "picks the right one per moment.",
                "templates",
                url_for("template_gallery"),
            ),
            (
                "Typography & fonts",
                "Browse the font catalogue, get an AI pairing, and upload your "
                "club's own brand typeface.",
                "typography",
                url_for("settings_section", section="typography"),
            ),
            (
                "Audio & voiceover",
                "Music and sound-effect library, voices, name pronunciation, "
                "your own audio, and consent settings.",
                "audio",
                url_for("settings_section", section="audio"),
            ),
            (
                "Team members",
                "Invite teammates and manage who can see and approve content.",
                "members",
                url_for("organisation_members_page"),
            ),
            (
                "Activity",
                "Every run for this organisation — status, matches, and one-click delete.",
                "activity",
                url_for("settings_section", section="activity"),
            ),
            (
                "Auto scheduling",
                "Queueing approved cards straight onto your social channels — coming soon.",
                "schedule",
                url_for("settings_section", section="scheduling"),
            ),
            (
                "Autonomy",
                "Per-content-type publishing levels — what may post without a human — coming soon.",
                "autonomy",
                url_for("settings_section", section="autonomy"),
            ),
            (
                "Club data",
                "Club records and asking questions of your own processed results.",
                "clubdata",
                url_for("settings_section", section="clubdata"),
            ),
            (
                "Privacy & data",
                "What this system stores, athletes & consent, cache clearing, and run deletion.",
                "privacy",
                url_for("settings_section", section="privacy"),
            ),
            (
                "Billing & plan",
                "Your plan, invoices and upgrades.",
                "billing",
                url_for("billing_page"),
            ),
        ]
        # Pricing leaves the top bar once signed into a club profile — surface
        # it here, right after Billing & plan, so signed-in users keep a
        # one-click route to compare plans. Signed-out visitors use the top nav.
        if signed_in:
            cards.append(
                (
                    "Pricing & plans",
                    "Compare plans and what each tier unlocks.",
                    "pricing",
                    url_for("pricing_page"),
                )
            )
        cards += [
            (
                "Sponsors",
                "Manage sponsors and the sponsor-safe content they appear in.",
                "sponsors",
                url_for("sponsors_page"),
            ),
            (
                "AI governance",
                "AI usage and quota headroom, who can use which AI feature, and provenance.",
                "privacy",
                url_for("settings_section", section="governance"),
            ),
            (
                "Account",
                "Two-factor security, data export, and account deletion.",
                "account",
                url_for("settings_section", section="account"),
            ),
            (
                "System status",
                "Whether the site is operational right now.",
                "status",
                url_for("settings_section", section="status"),
            ),
        ]
        if is_dev:
            cards.append(
                (
                    "Developer",
                    "Deployment health, operator dashboards, and uptime detail.",
                    "dev",
                    url_for("settings_section", section="developer"),
                )
            )
        return cards

    def _render_settings_page() -> str:
        """Render the Settings landing — a grid of heading cards."""
        is_dev = _auth.is_dev_operator()
        signed_in = bool(_active_profile_id())
        tiles = ""
        for title, desc, icon_key, href in _settings_card_specs(is_dev, signed_in):
            icon = _SETTINGS_ICONS.get(icon_key, "")
            tiles += (
                f'<a href="{href}" class="mh-template mh-glow-border">'
                f'<div class="mh-template-icon">{icon}</div>'
                '<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;margin-bottom:var(--sp-1)">'
                f'<h2 style="margin:0">{_h(title)}</h2>'
                "</div>"
                f"<p>{_h(desc)}</p>"
                '<span class="mh-template-cta">Open</span>'
                "</a>"
            )
        body = (
            '<section class="mh-hero" data-lane="" style="padding-top:var(--sp-7);padding-bottom:var(--sp-5);margin-bottom:var(--sp-5)">'
            '<span class="mh-hero-eyebrow">Settings</span>'
            '<h1>Operations &amp; <em class="editorial">data</em></h1>'
            '<p class="lede">Pick a heading to manage it. Each card opens its own '
            "page so nothing is buried in one long scroll.</p>"
            "</section>"
            f'<div class="mh-template-grid mh-reveal-group">{tiles}</div>'
        )
        return _layout("Settings", body, active="settings")

    def _render_settings_governance_section(prof: Optional[ClubProfile]) -> str:
        """AI governance for the active org (1.23): usage + quota headroom per
        feature, the role→feature permission matrix, and a provenance note."""
        if prof is None:
            return (
                '<div class="card"><p>Select or create a club first to see its '
                "AI usage and permissions.</p></div>"
            )
        from mediahub import governance
        from mediahub.governance import features as _gf
        from mediahub.collab import permissions as _cperms

        pid = prof.profile_id
        plan = _auth.current_plan()

        # Features whose routes don't yet record usage: their per-request
        # governance context is bound but nothing meters them, so their limits
        # would never enforce. Label them honestly rather than imply a live
        # count (caption / imagine / translate DO record and are metered).
        _unmetered_features = {
            _gf.FEATURE_BRAND,
            _gf.FEATURE_PALETTE,
            _gf.FEATURE_DESCRIBE,
            _gf.FEATURE_DNA,
            _gf.FEATURE_RESEARCH,
        }

        # --- Usage + quota per feature ---
        usage_rows = ""
        for spec in _gf.all_features():
            if spec.key in _unmetered_features:
                usage_rows += (
                    '<tr><td style="padding:8px 10px">'
                    f"<strong>{_h(spec.label)}</strong>"
                    f'<div style="font-size:12px;color:var(--ink-muted)">{_h(spec.description)}</div>'
                    "</td>"
                    '<td style="padding:8px 10px;text-align:right;color:var(--ink-muted)">&mdash;</td>'
                    '<td style="padding:8px 10px;color:var(--ink-muted)">Not yet metered</td></tr>'
                )
                continue
            if spec.key == _gf.FEATURE_IMAGINE:
                try:
                    q = _imagine.check_quota(pid)
                    used, limit = int(q.used), int(q.limit)
                    unlimited = bool(getattr(q, "unlimited", limit < 0))
                except Exception:
                    st = governance.check(pid, spec.key, plan=plan)
                    used, limit, unlimited = st.used, st.limit, not st.enforced
            else:
                st = governance.check(pid, spec.key, plan=plan)
                used, limit, unlimited = st.used, st.limit, not st.enforced

            if unlimited or limit < 0:
                limit_cell = "No limit &mdash; metered"
            else:
                pct = min(100, int(used * 100 / limit)) if limit else 0
                colour = (
                    "var(--mh-prim-error-500)"
                    if used >= limit
                    else ("var(--mh-prim-warning-500)" if pct >= 80 else "var(--accent)")
                )
                limit_cell = (
                    f"{used} / {limit}"
                    '<div style="height:8px;background:rgba(255,255,255,0.08);'
                    'border-radius:6px;margin-top:6px">'
                    f'<div style="height:8px;width:{pct}%;background:{colour};'
                    'border-radius:6px"></div></div>'
                )
            usage_rows += (
                '<tr><td style="padding:8px 10px">'
                f"<strong>{_h(spec.label)}</strong>"
                f'<div style="font-size:12px;color:var(--ink-muted)">{_h(spec.description)}</div>'
                "</td>"
                f'<td style="padding:8px 10px;text-align:right">{used}</td>'
                f'<td style="padding:8px 10px">{limit_cell}</td></tr>'
            )
        usage_card = (
            '<div class="card"><h2 style="margin-top:0;font-size:18px">AI usage this month</h2>'
            '<p style="color:var(--ink-muted);font-size:13px">A rolling 30-day window. Metered '
            "features (captions, imagery, translation) count every use and block only once a "
            "specific limit is set; features marked <em>not yet metered</em> run but aren&rsquo;t "
            "counted yet.</p>"
            '<table style="width:100%;border-collapse:collapse">'
            '<thead><tr style="text-align:left;color:var(--ink-muted);font-size:12px">'
            '<th style="padding:8px 10px">Feature</th>'
            '<th style="padding:8px 10px;text-align:right">Used</th>'
            '<th style="padding:8px 10px">Limit</th></tr></thead>'
            f"<tbody>{usage_rows}</tbody></table></div>"
        )

        # --- Role → feature permission matrix ---
        feats = _gf.all_features()
        head = "".join(
            f'<th style="padding:6px 8px;font-size:12px">{_h(s.label)}</th>' for s in feats
        )
        prows = ""
        for role in _cperms.assignable_roles():
            cells = ""
            for s in feats:
                ok = governance.can_use_feature(role, s.key, plan=plan)
                mark = (
                    '<span style="color:var(--mh-prim-success-400)">&#10003;</span>'
                    if ok
                    else '<span style="color:var(--ink-muted)">&mdash;</span>'
                )
                cells += f'<td style="padding:6px 8px;text-align:center">{mark}</td>'
            prows += (
                f'<tr><td style="padding:6px 8px"><strong>{_h(_cperms.role_label(role))}</strong>'
                f"</td>{cells}</tr>"
            )
        your_role = _active_role(pid)
        perms_card = (
            '<div class="card"><h2 style="margin-top:0;font-size:18px">Who can use AI</h2>'
            '<p style="color:var(--ink-muted);font-size:13px">Your role here is '
            f"<strong>{_h(_cperms.role_label(your_role))}</strong>. Content generation needs "
            "Editor; brand-defining AI needs the Owner.</p>"
            '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse">'
            '<thead><tr style="text-align:left;color:var(--ink-muted)">'
            f'<th style="padding:6px 8px">Role</th>{head}</tr></thead>'
            f"<tbody>{prows}</tbody></table></div></div>"
        )

        prov_card = (
            '<div class="card"><h2 style="margin-top:0;font-size:18px">Provenance</h2>'
            '<p style="color:var(--ink-muted);font-size:13px;margin-bottom:0">Every result card, '
            "reel and generated image is stamped with an honest provenance manifest &mdash; what "
            "made it, from what, and when. Result cards are recorded as deterministic composites of "
            "real photography; AI-generated images are marked as such.</p></div>"
        )

        # D-17 — a visible AI-availability row. Previously the only signal that
        # AI was off lived in a hover tooltip on a tiny dot (useless on a phone),
        # and nothing in Settings said whether a provider was live.
        try:
            from mediahub.media_ai.llm import active_provider as _active_prov
            from mediahub.media_ai.llm import is_available as _llm_available

            _ai_live = bool(_llm_available())
            _prov_label = (
                {
                    "gemini-api": "Google Gemini",
                    "anthropic-api": "Anthropic (Claude)",
                }.get(_active_prov())
                if _ai_live
                else ""
            )
        except Exception:
            _ai_live, _prov_label = False, ""
        if _ai_live:
            status_card = (
                '<div class="card"><h2 style="margin-top:0;font-size:18px">AI status</h2>'
                '<p style="font-size:13px;margin-bottom:0">'
                '<span class="tag good">Live</span> AI captions, imagery and translation are '
                "enabled"
                + (f" via <strong>{_h(_prov_label)}</strong>" if _prov_label else "")
                + ".</p></div>"
            )
        else:
            status_card = (
                '<div class="card" style="border-color:var(--mh-prim-warning-500)">'
                '<h2 style="margin-top:0;font-size:18px">AI status</h2>'
                '<p style="font-size:13px;margin-bottom:0">'
                '<span class="tag warn">Disabled</span> No AI provider is live on this deployment, '
                "so captions, imagery and translation will show an honest error rather than a made-up "
                "result. You can still review, edit and approve cards by hand. Ask your operator to "
                "configure a provider key to turn AI back on.</p></div>"
            )

        return status_card + usage_card + perms_card + prov_card

    # Detail pages behind the settings cards. ``developer`` is operator-only;
    # everything else is org-scoped and degrades gracefully with no org.
    @app.route("/settings/<section>")
    def settings_section(section):
        renderers = {
            "activity": ("Activity", lambda prof: _render_settings_activity_section(prof)),
            "audio": ("Audio & voiceover", lambda prof: _render_settings_audio_section(prof)),
            "scheduling": (
                "Auto scheduling",
                lambda prof: _render_settings_scheduling_section(prof),
            ),
            "autonomy": ("Autonomy", lambda prof: _render_settings_autonomy_section(prof)),
            "clubdata": ("Club data", lambda prof: _render_settings_clubdata_section()),
            "typography": (
                "Typography & fonts",
                lambda prof: _render_settings_typography_section(prof),
            ),
            "privacy": ("Privacy & data", lambda prof: _render_settings_privacy_section()),
            "governance": (
                "AI governance",
                lambda prof: _render_settings_governance_section(prof),
            ),
            "account": ("Account", lambda prof: _render_settings_account_section()),
            "status": ("System status", lambda prof: _render_settings_status_public_section()),
            "developer": ("Developer", lambda prof: _render_settings_developer_section()),
        }
        entry = renderers.get(section)
        if entry is None:
            return redirect(url_for("settings_page"))
        if section == "developer" and not _auth.is_dev_operator():
            return redirect(url_for("settings_page"))
        title, render = entry
        prof = _active_profile()
        back = (
            f'<a href="{url_for("settings_page")}" '
            'style="display:inline-flex;align-items:center;gap:6px;font-size:13px;'
            'color:var(--ink-muted);text-decoration:none;margin-bottom:14px">'
            "&larr; All settings</a>"
        )
        body = (
            '<section class="mh-hero" data-lane="" style="padding-top:var(--sp-6);padding-bottom:var(--sp-3);margin-bottom:var(--sp-2)">'
            '<span class="mh-hero-eyebrow">Settings</span>'
            f'<h1 style="margin-bottom:0">{_h(title)}</h1>'
            "</section>" + back + render(prof)
        )
        return _layout(f"{title} · Settings", body, active="settings")

    # ------------------------------------------------------------------
    # Typography & fonts (roadmap 1.9) — catalogue browse, AI pairing, and the
    # club custom-font upload (wired to typography.font_intake). Org-scoped to
    # the ACTIVE profile (no caller-supplied profile_id ⇒ no IDOR).
    # ------------------------------------------------------------------
    _TYPOGRAPHY_STATUS = {
        "font-added": (True, "Custom font added — it's now available on this club's cards."),
        "font-removed": (True, "Custom font removed."),
        "no-file": (False, "No font file was selected."),
        "no-attest": (False, "Tick the licence box to confirm you're allowed to embed this font."),
        "bad-font": (False, "That file isn't a usable font, or its licence forbids embedding."),
        "no-tooling": (False, "Font processing isn't available on this deployment right now."),
    }

    def _typography_banner(status: str) -> str:
        spec = _TYPOGRAPHY_STATUS.get(status or "")
        if not spec:
            return ""
        ok, text = spec
        colour = "#2ecc71" if ok else "#e74c3c"
        return (
            f'<div class="card" style="border-left:3px solid {colour};margin-bottom:14px">'
            f'<p style="margin:0">{_h(text)}</p></div>'
        )

    def _render_settings_typography_section(prof: Optional[ClubProfile]) -> str:
        if prof is None:
            return (
                '<div class="card"><p>Select or create a club first to manage its '
                "typography.</p></div>"
            )
        from mediahub.typography import catalog as _cat
        from mediahub.typography import font_intake as _fi
        from mediahub.graphic_renderer import text_effects as _fx

        pid = prof.profile_id
        banner = _typography_banner(request.args.get("status", ""))

        # --- Font catalogue (self-hosted, browsable) ---
        cards = ""
        for f in _cat.load_catalog():
            moods = ", ".join(f.mood_tags[:4])
            cards += (
                '<div class="card" style="padding:12px 14px">'
                f"<div style=\"font-family:'{_h(f.family)}',sans-serif;font-size:21px;"
                f'font-weight:700;line-height:1.1">{_h(f.family)}</div>'
                f'<div style="font-size:12px;color:var(--ink-dim);margin-top:4px">'
                f"{_h(f.klass)} · {_h(moods)}</div>"
                f'<div style="font-size:11px;color:var(--ink-muted);margin-top:2px">'
                f"{_h(f.licence)} · {_h(', '.join(f.surfaces))}</div>"
                "</div>"
            )
        catalogue = (
            '<div class="card"><h2 style="margin-top:0">Font catalogue</h2>'
            '<p style="color:var(--ink-dim)">The self-hosted typefaces available across your '
            "cards, reels and the app — never loaded from a third-party CDN.</p>"
            '<div class="mh-template-grid" '
            'style="grid-template-columns:repeat(auto-fill,minmax(190px,1fr))">'
            f"{cards}</div></div>"
        )

        # --- AI pairing ---
        pairing = (
            '<div class="card"><h2 style="margin-top:0">AI font pairing</h2>'
            '<p style="color:var(--ink-dim)">Ask the engine to pick a headline / body / numeral '
            "trio from the catalogue that fits your club.</p>"
            f'<form method="post" action="{url_for("typography_pair")}" '
            'style="display:flex;gap:10px;flex-wrap:wrap;align-items:center">'
            '<input name="mood" placeholder="desired feel — bold, editorial, technical…" '
            'style="flex:1;min-width:220px;padding:8px 10px" maxlength="60">'
            '<button class="btn" type="submit">Suggest a pairing</button></form>'
            '<p style="font-size:12px;color:var(--ink-muted);margin-bottom:0">Uses your '
            "configured AI provider; shows an honest message if none is set.</p></div>"
        )

        # --- Club's own uploaded fonts ---
        try:
            records = _fi.list_fonts(pid)
        except Exception:
            records = []
        if records:
            rows = ""
            for r in records:
                rows += (
                    '<div class="card" style="display:flex;justify-content:space-between;'
                    'align-items:center;gap:12px;padding:10px 14px">'
                    f"<div><strong>{_h(r.family)}</strong> "
                    f'<span style="font-size:12px;color:var(--ink-dim)">{_h(r.role)} · '
                    f"{r.weight} · {r.woff2_size // 1024} KB</span></div>"
                    f'<form method="post" action="'
                    f'{url_for("typography_remove_font", slug=r.slug)}" '
                    "onsubmit=\"return confirm('Remove this font?')\">"
                    '<button class="btn ghost" type="submit">Remove</button></form></div>'
                )
            owned = rows
        else:
            owned = (
                '<p style="color:var(--ink-dim)">No custom fonts yet — upload your club\'s '
                "brand typeface below.</p>"
            )
        role_opts = "".join(f'<option value="{_h(r)}">{_h(r)}</option>' for r in _fi.ALLOWED_ROLES)
        upload = (
            '<div class="card"><h2 style="margin-top:0">Your club fonts</h2>'
            + owned
            + '<hr style="margin:14px 0;border:none;border-top:1px solid var(--line,#2a2a2a)">'
            f'<form method="post" action="{url_for("typography_upload_font")}" '
            'enctype="multipart/form-data">'
            '<input type="file" name="font_file" accept=".ttf,.otf,.woff,.woff2" required '
            'style="display:block;margin-bottom:10px">'
            '<label style="display:inline-block;margin-bottom:10px;font-size:13px">Role '
            f'<select name="role" style="margin-left:6px">{role_opts}</select></label>'
            '<label style="display:flex;gap:8px;align-items:flex-start;margin-bottom:12px;'
            'font-size:13px;max-width:560px"><input type="checkbox" name="attest" value="1" '
            "required><span>I confirm this club is licensed to embed this font — it owns the "
            "licence, or the font is open-licensed (e.g. OFL). MediaHub self-hosts it for this "
            "club only.</span></label>"
            '<button class="btn" type="submit">Upload font</button></form></div>'
        )

        # --- Text-effect vocabulary (informational) ---
        chips = "".join(
            '<span style="display:inline-block;padding:4px 10px;margin:3px;border-radius:999px;'
            'background:var(--panel,#1c1c1c);font-size:12px">'
            f"{_h(_fx.EFFECT_LABELS.get(n, n))}</span>"
            for n in _fx.TEXT_EFFECTS
            if n != "none"
        )
        effects = (
            '<div class="card"><h2 style="margin-top:0">Text effects</h2>'
            '<p style="color:var(--ink-dim)">Per-text effects the engine can apply to headlines, '
            "results and labels — each one legibility-checked automatically, and downgraded to a "
            f"readable outline if it would hurt contrast.</p><div>{chips}</div></div>"
        )

        return banner + catalogue + pairing + upload + effects

    @app.route("/settings/typography/font/upload", methods=["POST"])
    def typography_upload_font():
        prof = _active_profile()
        if prof is None:
            return redirect(url_for("settings_page"))
        from mediahub.typography import font_intake as _fi

        f = request.files.get("font_file")
        if not f or not f.filename:
            return redirect(url_for("settings_section", section="typography", status="no-file"))
        if not request.form.get("attest"):
            return redirect(url_for("settings_section", section="typography", status="no-attest"))
        role = (request.form.get("role") or "display").strip()
        if role not in _fi.ALLOWED_ROLES:
            role = "display"
        try:
            data = f.read() or b""
        except Exception:
            data = b""
        if not data:
            return redirect(url_for("settings_section", section="typography", status="no-file"))
        try:
            _fi.intake_font(data, profile_id=prof.profile_id, role=role)
        except _fi.FontToolingUnavailable:
            return redirect(url_for("settings_section", section="typography", status="no-tooling"))
        except Exception as e:  # validation / embedding / parse — honest, not fatal
            log.info("typography font upload rejected: %s", str(e)[:200])
            return redirect(url_for("settings_section", section="typography", status="bad-font"))
        return redirect(url_for("settings_section", section="typography", status="font-added"))

    @app.route("/settings/typography/font/<slug>/remove", methods=["POST"])
    def typography_remove_font(slug):
        prof = _active_profile()
        if prof is None:
            return redirect(url_for("settings_page"))
        from mediahub.typography import font_intake as _fi

        try:
            _fi.remove_font(prof.profile_id, slug)
        except Exception:
            pass
        return redirect(url_for("settings_section", section="typography", status="font-removed"))

    @app.route("/settings/typography/pair", methods=["POST"])
    def typography_pair():
        prof = _active_profile()
        name = prof.display_name if prof else ""
        mood = (request.form.get("mood") or "").strip()[:60]
        back = url_for("settings_section", section="typography")
        from mediahub.brand import design_tokens as _dt
        from mediahub.brand.type_pairing import PairingContext

        try:
            result = _dt.ai_type_pairing(PairingContext(club_name=name, mood=mood))
        except Exception as e:
            body = (
                '<section class="mh-hero"><span class="mh-hero-eyebrow">Typography</span>'
                '<h1 style="margin-bottom:0">AI pairing</h1></section>'
                '<div class="card"><p style="color:#e74c3c">AI pairing is unavailable: '
                f"{_h(str(e)[:200])}</p>"
                f'<a class="btn" href="{back}">Back to typography</a></div>'
            )
            return _layout("Typography · pairing", body, active="settings")
        corrected = (
            '<p style="font-size:12px;color:var(--ink-muted)">(adjusted to the nearest '
            "catalogue faces)</p>"
            if result.get("corrected")
            else ""
        )
        body = (
            '<section class="mh-hero"><span class="mh-hero-eyebrow">Typography</span>'
            '<h1 style="margin-bottom:0">Suggested pairing</h1></section>'
            '<div class="card"><p style="font-size:15px">'
            f"<strong>Headline:</strong> {_h(result['headline_family'])}<br>"
            f"<strong>Body:</strong> {_h(result['body_family'])}<br>"
            f"<strong>Numerals:</strong> {_h(result['numeral_family'])}</p>"
            f'<p style="color:var(--ink-dim)">{_h(result["reason"])}</p>{corrected}'
            f'<a class="btn" href="{back}">Back to typography</a></div>'
        )
        return _layout("Typography · pairing", body, active="settings")

    # ------------------------------------------------------------------
    # Audio engine (roadmap 1.8) — library, voices, pronunciation lexicon,
    # own-audio upload + rights, and consent-gated voice features.
    # ------------------------------------------------------------------
    _AUDIO_UPLOAD_SUFFIXES = {".mp3", ".m4a", ".aac", ".wav", ".ogg", ".opus", ".flac"}
    _AUDIO_MIME = {
        ".mp3": "audio/mpeg",
        ".m4a": "audio/mp4",
        ".aac": "audio/aac",
        ".wav": "audio/wav",
        ".ogg": "audio/ogg",
        ".opus": "audio/opus",
        ".flac": "audio/flac",
    }
    _AUDIO_UPLOAD_MAX_BYTES = 25 * 1024 * 1024  # 25 MB — clips/beds, not albums

    def _audio_back_or_json(payload: dict, status: int = 200, *, flash_status: str = ""):
        from flask import request as _req

        wants_json = (
            _req.headers.get("Accept", "").find("application/json") != -1
            or _req.headers.get("X-Requested-With") == "XMLHttpRequest"
        )
        if wants_json:
            return jsonify(payload), status
        # D-14: a browser form POST must never land on a bare JSON error page.
        # Redirect back with a friendly banner instead — the styled error card
        # the graceful pages use — keeping the JSON body only for JSON callers.
        if payload.get("error"):
            emsg = payload.get("message") or "That didn't work — check the file and try again."
            return redirect(url_for("settings_section", section="audio", status="error", emsg=emsg))
        # D-7: a form POST navigates back to the audio settings; carry a status
        # so the section can confirm the action ("Track added" / "Track removed")
        # instead of a silent redirect the volunteer can't tell worked.
        if flash_status:
            return redirect(url_for("settings_section", section="audio", status=flash_status))
        return redirect(url_for("settings_section", section="audio"))

    @app.route("/api/audio/library")
    def api_audio_library():
        """List the audio catalogue (bundled CC0 pool + operator directories)."""
        from flask import request as _req

        try:
            from mediahub.audio import load_library
        except Exception as e:
            return jsonify({"error": "audio_unavailable", "detail": str(e)}), 503
        lib = load_library()
        tracks = lib.tracks(
            kind=(_req.args.get("kind") or None),
            mood=(_req.args.get("mood") or None),
            platform=(_req.args.get("platform") or None),
        )
        return jsonify({"ok": True, "tracks": [t.to_dict() for t in tracks]})

    @app.route("/api/audio/track/<track_id>")
    def api_audio_track(track_id):
        """Serve a catalogue track file for in-browser preview.

        Only library tracks (bundled + operator directories) are addressable by
        id here — they are deployment-global, not per-org, so there is no IDOR
        surface, and the id resolves to a known file (no path traversal).
        """
        try:
            from mediahub.audio import load_library
        except Exception as e:
            return jsonify({"error": "audio_unavailable", "detail": str(e)}), 503
        track = load_library().get(track_id)
        if track is None or not Path(track.path).is_file():
            return jsonify({"error": "not_found"}), 404
        mime = _AUDIO_MIME.get(Path(track.path).suffix.lower(), "application/octet-stream")
        return send_file(str(track.path), mimetype=mime, as_attachment=False)

    @app.route("/api/audio/voices")
    def api_audio_voices():
        """The voice catalogue + the active TTS provider status."""
        try:
            from mediahub.audio import list_voices
            from mediahub.visual import voiceover as _vo
        except Exception as e:
            return jsonify({"error": "audio_unavailable", "detail": str(e)}), 503
        try:
            status = _vo.tts_provider_status()
        except Exception:
            status = {}
        return jsonify({"ok": True, "voices": [v.to_dict() for v in list_voices()], "tts": status})

    @app.route("/api/audio/lexicon", methods=["GET", "POST"])
    def api_audio_lexicon():
        """Per-organisation pronunciation lexicon CRUD (org-scoped).

        GET returns the org's map; POST with ``op=set`` (written+spoken) or
        ``op=remove`` (written) mutates it. Form posts redirect back to the
        Audio settings page; XHR/JSON callers get JSON.
        """
        from flask import request as _req

        pid = _active_profile_id()
        if not pid:
            return jsonify(
                {"error": "no_org", "message": "Choose an organisation to manage a lexicon."}
            ), 403
        try:
            from mediahub.audio.voice import OrgLexicon
        except Exception as e:
            return jsonify({"error": "audio_unavailable", "detail": str(e)}), 503
        lex = OrgLexicon(pid)
        if _req.method == "GET":
            return jsonify({"ok": True, "entries": lex.entries()})
        op = (_req.form.get("op") or _req.values.get("op") or "set").strip().lower()
        try:
            if op == "remove":
                lex.remove((_req.form.get("written") or "").strip())
            else:
                lex.set(
                    (_req.form.get("written") or "").strip(),
                    (_req.form.get("spoken") or "").strip(),
                )
        except ValueError as e:
            return _audio_back_or_json({"error": "invalid", "message": str(e)}, 400)
        return _audio_back_or_json({"ok": True, "entries": lex.entries()})

    @app.route("/api/audio/upload", methods=["POST"])
    def api_audio_upload():
        """Upload an organisation's own audio with a licence attestation (1.8).

        Stored org-scoped under DATA_DIR, fingerprinted, and recorded in the
        rights ledger. Optionally loudness-levelled/denoised via clean.py when
        ``enhance=1`` is set (e.g. a browser voice recording).
        """
        from flask import request as _req

        pid = _active_profile_id()
        if not pid:
            return _audio_back_or_json(
                {"error": "no_org", "message": "Choose an organisation to upload audio."}, 403
            )
        f = _req.files.get("file")
        if not f:
            return _audio_back_or_json(
                {"error": "no_file", "message": "Choose an audio file first."}, 400
            )
        ext = Path(f.filename or "clip.wav").suffix.lower()
        if ext not in _AUDIO_UPLOAD_SUFFIXES:
            allowed = ", ".join(sorted(s.lstrip(".").upper() for s in _AUDIO_UPLOAD_SUFFIXES))
            return _audio_back_or_json(
                {
                    "error": "bad_type",
                    "message": f"That file type isn't supported. Use one of: {allowed}.",
                },
                415,
            )
        try:
            from mediahub.audio import rights as _rights
            from mediahub.audio.library import Licence
        except Exception as e:
            return _audio_back_or_json(
                {
                    "error": "audio_unavailable",
                    "detail": str(e),
                    "message": "Audio isn't available.",
                },
                503,
            )

        import uuid as _uuid

        upload_dir = DATA_DIR / "audio_uploads" / pid
        upload_dir.mkdir(parents=True, exist_ok=True)
        asset_id = _uuid.uuid4().hex[:12]
        dest = upload_dir / f"{asset_id}{ext}"
        f.save(str(dest))
        try:
            if dest.stat().st_size > _AUDIO_UPLOAD_MAX_BYTES:
                dest.unlink(missing_ok=True)
                return _audio_back_or_json(
                    {"error": "too_large", "message": "That audio is over the 25 MB limit."}, 413
                )
        except OSError:
            return _audio_back_or_json(
                {
                    "error": "save_failed",
                    "message": "We couldn't save that file — please try again.",
                },
                500,
            )

        # Optional one-tap clean-up (denoise + loudness) for recordings.
        if (_req.form.get("enhance") or "").strip().lower() in {"1", "true", "on", "yes"}:
            try:
                from mediahub.audio import clean as _clean

                cleaned = upload_dir / f"{asset_id}_clean.wav"
                _clean.enhance_voice(dest, cleaned)
                dest.unlink(missing_ok=True)
                dest = cleaned
            except Exception:
                pass  # keep the original on any cleanup failure — never lose the upload

        platforms = tuple(
            p.strip().lower() for p in (_req.form.get("platforms") or "").split(",") if p.strip()
        )
        licence = Licence(
            name=(_req.form.get("licence_name") or "operator-supplied").strip(),
            url=(_req.form.get("licence_url") or "").strip(),
            attribution=(_req.form.get("attribution") or "").strip(),
            source="operator upload",
            commercial_ok=(_req.form.get("commercial_ok") or "").strip().lower()
            in {"1", "true", "on", "yes"},
        )
        check = _rights.check_upload(dest)
        rec = _rights.attest_upload(
            dest,
            asset_id=asset_id,
            profile_id=pid,
            licence=licence,
            platforms=platforms or _rights.PLATFORMS,
            attested_by=pid,
            notes=(_req.form.get("notes") or "").strip(),
        )
        return _audio_back_or_json(
            {
                "ok": True,
                "asset": rec.to_dict(),
                "duplicate": check.is_duplicate,
                "fingerprint_method": check.fingerprint.method,
            },
            flash_status="audio_added",
        )

    @app.route("/api/audio/upload/<asset_id>")
    def api_audio_upload_file(asset_id):
        """D-7: serve one of the active org's own uploaded audio files for
        in-browser preview. Tenant-scoped by the rights ledger's profile_id —
        an id owned by another org 404s (no IDOR), and the filename resolves to
        a basename inside the org's own directory (no path traversal)."""
        from flask import send_file

        from mediahub.audio import rights as _rights

        pid = _active_profile_id()
        if not pid:
            abort(404)
        rec = _rights.RightsLedger().get(asset_id)
        if rec is None or rec.profile_id != pid:
            abort(404)
        path = DATA_DIR / "audio_uploads" / pid / Path(rec.filename).name
        if not path.is_file():
            abort(404)
        return send_file(str(path))

    @app.route("/api/audio/upload/<asset_id>/delete", methods=["POST"])
    def api_audio_upload_delete(asset_id):
        """D-7: remove one of the active org's own uploaded audio files and its
        rights-ledger row. Tenant-scoped exactly like the preview route."""
        from mediahub.audio import rights as _rights

        pid = _active_profile_id()
        if not pid:
            return _audio_back_or_json({"error": "no_org"}, 403)
        led = _rights.RightsLedger()
        rec = led.get(asset_id)
        if rec is None or rec.profile_id != pid:
            return _audio_back_or_json({"error": "not_found"}, 404)
        try:
            (DATA_DIR / "audio_uploads" / pid / Path(rec.filename).name).unlink(missing_ok=True)
        except OSError:
            pass
        led.delete(asset_id)
        return _audio_back_or_json({"ok": True}, flash_status="audio_removed")

    @app.route("/api/audio/voice-consent", methods=["GET", "POST"])
    def api_audio_voice_consent():
        """Grant/revoke the consent that gates voice cloning/changer (org-scoped)."""
        from flask import request as _req

        pid = _active_profile_id()
        if not pid:
            return jsonify({"error": "no_org"}), 403
        try:
            from mediahub.audio.consent import FEATURES, ConsentStore
        except Exception as e:
            return jsonify({"error": "audio_unavailable", "detail": str(e)}), 503
        store = ConsentStore()
        if _req.method == "GET":
            return jsonify(
                {
                    "ok": True,
                    "features": list(FEATURES),
                    "active": [r.to_dict() for r in store.active(pid)],
                }
            )
        feature = (_req.form.get("feature") or "").strip().lower()
        action = (_req.form.get("action") or "grant").strip().lower()
        try:
            if action == "revoke":
                store.revoke(pid, feature, by=pid)
            else:
                store.grant(
                    pid,
                    feature,
                    voice_owner=(_req.form.get("voice_owner") or "").strip(),
                    consent_ref=(_req.form.get("consent_ref") or "").strip(),
                    granted_by=pid,
                )
        except ValueError as e:
            return _audio_back_or_json({"error": "invalid", "message": str(e)}, 400)
        return _audio_back_or_json({"ok": True})

    @app.route("/api/audio/suggest")
    def api_audio_suggest():
        """Suggest a track for a mood/kind — AI when available, else deterministic.

        Always 200 (never 5xx — a bare GET to this advisory endpoint must not
        pollute uptime): returns the AI mood-matched pick when a provider is
        configured, otherwise the deterministic library pick. ``method`` says
        which path produced the suggestion ("ai" / "deterministic" / "none").
        """
        from flask import request as _req

        try:
            from mediahub.audio import load_library
            from mediahub.audio.select import select_or_default
        except Exception as e:
            return jsonify({"ok": False, "available": False, "detail": str(e)})
        lib = load_library()
        mood = (_req.args.get("mood") or "").strip()
        kind = (_req.args.get("kind") or "music").strip()
        sel = select_or_default(
            lib, content_key=(mood or "suggest"), kind=kind, mood_hint=(mood or None)
        )
        return jsonify(
            {
                "ok": True,
                "available": sel.track is not None,
                "method": sel.method,
                "arc": sel.arc,
                "track": sel.track.to_dict() if sel.track else None,
            }
        )

    def _render_settings_audio_section(prof: Optional[ClubProfile]) -> str:
        """Audio engine settings — library, voices, lexicon, uploads, consent."""
        from mediahub.audio import list_voices, load_library
        from mediahub.audio.consent import FEATURES, ConsentStore
        from mediahub.audio.voice import OrgLexicon

        pid = _active_profile_id()
        lib = load_library()

        # --- Music & SFX library (with inline preview players) ---
        track_rows = ""
        for t in lib.all():
            mood = ", ".join(t.mood) if t.mood else "—"
            badge = "CC0" if t.licence.spdx == "CC0-1.0" else _h(t.licence.name)
            src = url_for("api_audio_track", track_id=t.id)
            track_rows += (
                '<div class="card" style="padding:12px 14px;display:flex;align-items:center;'
                'gap:12px;flex-wrap:wrap">'
                f'<div style="flex:1;min-width:180px"><strong>{_h(t.title)}</strong>'
                f'<div class="dim" style="font-size:12px">{_h(t.kind)} · {_h(mood)} · '
                f'energy {t.energy} · <span class="tag">{badge}</span></div></div>'
                f'<audio controls preload="none" src="{src}" style="height:34px"></audio>'
                "</div>"
            )
        library_html = (
            '<h2 style="font-size:18px;margin:24px 0 6px">Music &amp; sound effects</h2>'
            # F-3: customer copy, no env-var names — uploading their own tracks is
            # the customer action; the reel-bed default is an operator setting.
            '<p class="dim" style="margin:0 0 12px">MediaHub ships its own licence-clean '
            "(CC0) pool so reels have sound out of the box. Prefer your own music? "
            "Upload your licensed tracks under &ldquo;Upload your own audio&rdquo; below.</p>"
            f'<div style="display:grid;gap:8px">{track_rows}</div>'
        )

        # --- Voice catalogue ---
        voice_rows = ""
        for v in list_voices():
            # F-3: "built-in"/"premium" reads for a customer; "local"/"online" is
            # deployment jargon (and the on-server backend is never "local" in
            # customer copy, per the fonts/cutout naming rule).
            tag = "built-in" if v.local else "premium"
            voice_rows += (
                '<li style="margin-bottom:4px">'
                f"<strong>{_h(v.name or v.id)}</strong> "
                f'<span class="dim">· {_h(v.language)} · {_h(v.provider)} ({tag})'
                f"{(' · ' + _h(v.description)) if v.description else ''}</span></li>"
            )
        voices_html = (
            '<h2 style="font-size:18px;margin:28px 0 6px">Voices</h2>'
            '<p class="dim" style="margin:0 0 8px">Voiceover speaks the approved caption '
            "verbatim — no AI script. The built-in voice is the zero-cost default; Welsh and "
            "other premium voices are available too.</p>"
            f'<ul style="margin:0 0 4px;padding-left:18px">{voice_rows}</ul>'
        )

        # --- Per-org pronunciation lexicon ---
        if pid:
            entries = OrgLexicon(pid).entries()
            rows = ""
            for written, spoken in sorted(entries.items()):
                rows += (
                    '<div style="display:flex;align-items:center;gap:10px;margin-bottom:6px">'
                    f'<code style="flex:1">{_h(written)} → {_h(spoken)}</code>'
                    f'<form method="post" action="{url_for("api_audio_lexicon")}" '
                    'style="margin:0">'
                    '<input type="hidden" name="op" value="remove">'
                    f'<input type="hidden" name="written" value="{_h(written)}">'
                    '<button class="btn btn-ghost" style="padding:4px 10px">Remove</button>'
                    "</form></div>"
                )
            if not rows:
                rows = '<p class="dim" style="margin:0 0 8px">No name overrides yet.</p>'
            lexicon_html = (
                '<h2 style="font-size:18px;margin:28px 0 6px">Name pronunciation</h2>'
                '<p class="dim" style="margin:0 0 12px">Teach MediaHub how your swimmers\' '
                "names are said — once. Every voiceover then gets them right (no AI guessing).</p>"
                f"{rows}"
                f'<form method="post" action="{url_for("api_audio_lexicon")}" '
                'style="display:flex;gap:8px;flex-wrap:wrap;margin-top:10px">'
                '<input type="hidden" name="op" value="set">'
                '<input name="written" placeholder="Written (e.g. Saoirse)" required '
                'style="flex:1;min-width:160px;padding:8px">'
                '<input name="spoken" placeholder="Say it (e.g. Seer-sha)" required '
                'style="flex:1;min-width:160px;padding:8px">'
                '<button class="btn btn-primary">Add</button></form>'
            )
        else:
            lexicon_html = (
                '<h2 style="font-size:18px;margin:28px 0 6px">Name pronunciation</h2>'
                '<p class="dim">Choose an organisation to manage its pronunciation lexicon.</p>'
            )

        # --- Upload own audio + browser recorder ---
        if pid:
            _types_hint = ", ".join(sorted(s.lstrip(".").upper() for s in _AUDIO_UPLOAD_SUFFIXES))
            upload_html = (
                '<h2 style="font-size:18px;margin:28px 0 6px">Upload your own audio</h2>'
                '<p class="dim" style="margin:0 0 12px">Add a track you hold the licence for. '
                "We fingerprint it and record your licence attestation in the rights ledger.</p>"
                f'<form method="post" action="{url_for("api_audio_upload")}" '
                'enctype="multipart/form-data" style="display:grid;gap:8px;max-width:560px">'
                '<input type="file" id="mh-audio-file" name="file" accept="audio/*" required>'
                f'<span class="dim" style="font-size:12px">{_types_hint} · up to 25 MB.</span>'
                '<input name="licence_name" placeholder="Licence (e.g. Licensed, CC-BY)" '
                'style="padding:8px">'
                '<input name="attribution" placeholder="Attribution (if required)" '
                'style="padding:8px">'
                '<label style="font-size:13px"><input type="checkbox" name="commercial_ok" '
                'value="1" checked> I confirm this is cleared for commercial club use</label>'
                '<label style="font-size:13px"><input type="checkbox" name="enhance" value="1"> '
                "Clean up (denoise + level) — recommended for recordings</label>"
                '<div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center">'
                '<button class="btn btn-primary" type="submit">Upload</button>'
                '<button class="btn btn-ghost" type="button" id="mh-rec-btn">● Record</button>'
                '<span id="mh-rec-status" class="dim" style="font-size:12px"></span>'
                "</div></form>"
            )
        else:
            upload_html = ""

        # --- Your uploaded audio (D-7: list + preview + remove) ---
        uploads_html = ""
        if pid:
            from mediahub.audio import rights as _rights

            up_rows = ""
            for rec in _rights.RightsLedger().list_for_profile(pid):
                fpath = DATA_DIR / "audio_uploads" / pid / Path(rec.filename).name
                if not fpath.is_file():
                    continue  # a ledger row whose file is gone (cleaned/removed) — skip
                src = url_for("api_audio_upload_file", asset_id=rec.asset_id)
                lic = _h(rec.licence.name or "operator-supplied")
                when = _h((rec.attested_at or "")[:10])
                del_url = url_for("api_audio_upload_delete", asset_id=rec.asset_id)
                up_rows += (
                    '<div class="card" style="padding:12px 14px;display:flex;align-items:center;'
                    'gap:12px;flex-wrap:wrap">'
                    f'<div style="flex:1;min-width:180px"><strong>{_h(rec.filename)}</strong>'
                    f'<div class="dim" style="font-size:12px">{lic}'
                    f'{(" · " + when) if when else ""}</div></div>'
                    f'<audio controls preload="none" src="{src}" style="height:34px"></audio>'
                    f'<form method="post" action="{del_url}" style="margin:0" '
                    "onsubmit=\"return confirm('Remove this uploaded track?')\">"
                    '<button class="btn btn-ghost" style="padding:4px 10px">Remove</button>'
                    "</form></div>"
                )
            if up_rows:
                uploads_html = (
                    '<h2 style="font-size:18px;margin:28px 0 6px">Your uploaded audio</h2>'
                    '<p class="dim" style="margin:0 0 12px">Tracks you\'ve added for this '
                    "organisation — preview or remove them here.</p>"
                    f'<div style="display:grid;gap:8px">{up_rows}</div>'
                )
            else:
                uploads_html = (
                    '<h2 style="font-size:18px;margin:28px 0 6px">Your uploaded audio</h2>'
                    '<p class="dim" style="margin:0 0 12px">No uploads yet — add a track above '
                    "and it'll appear here to preview or remove.</p>"
                )

        # D-7: confirm the upload/remove that a form POST just performed, so the
        # volunteer sees it worked instead of a silent redirect.
        _audio_flash = (request.args.get("status") or "").strip()
        banner_html = ""
        if _audio_flash == "audio_added":
            banner_html = (
                '<div class="card" style="border-left:2px solid var(--good);margin-bottom:14px">'
                '<strong style="color:var(--good)">Track added.</strong> '
                'It\'s listed under "Your uploaded audio" below.</div>'
            )
        elif _audio_flash == "audio_removed":
            banner_html = (
                '<div class="card" style="border-left:2px solid var(--warn);margin-bottom:14px">'
                "Track removed.</div>"
            )
        elif _audio_flash == "error":
            # D-14: an upload validation error, rendered as a styled card instead
            # of a bare JSON page. The message is server-supplied; escape it.
            _emsg = _h((request.args.get("emsg") or "").strip()[:300]) or "That upload didn't work."
            banner_html = (
                '<div class="card" style="border-left:2px solid var(--bad);margin-bottom:14px">'
                f'<strong style="color:var(--bad)">Upload failed.</strong> {_emsg}</div>'
            )

        # --- Voice consent (cloning / changer; off by default) ---
        if pid:
            store = ConsentStore()
            consent_rows = ""
            for feat in FEATURES:
                on = store.is_enabled(pid, feat)
                state = (
                    '<span class="tag" style="background:var(--accent);color:#0b0f17">enabled</span>'
                    if on
                    else '<span class="tag">off</span>'
                )
                if on:
                    btn = (
                        f'<form method="post" action="{url_for("api_audio_voice_consent")}" '
                        'style="margin:0"><input type="hidden" name="action" value="revoke">'
                        f'<input type="hidden" name="feature" value="{_h(feat)}">'
                        '<button class="btn btn-ghost" style="padding:4px 10px">Revoke</button>'
                        "</form>"
                    )
                else:
                    btn = (
                        f'<form method="post" action="{url_for("api_audio_voice_consent")}" '
                        'style="margin:0;display:flex;gap:6px;flex-wrap:wrap">'
                        '<input type="hidden" name="action" value="grant">'
                        f'<input type="hidden" name="feature" value="{_h(feat)}">'
                        '<input name="voice_owner" placeholder="Voice owner" '
                        'style="padding:4px 8px">'
                        '<input name="consent_ref" placeholder="Consent reference" '
                        'style="padding:4px 8px">'
                        '<button class="btn btn-ghost" style="padding:4px 10px">'
                        "Enable with consent</button></form>"
                    )
                label = "Voice cloning" if feat == "clone" else "Voice changer"
                consent_rows += (
                    '<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;'
                    'margin-bottom:8px"><div style="flex:1;min-width:160px">'
                    f"<strong>{_h(label)}</strong> {state}</div>{btn}</div>"
                )
            consent_html = (
                '<h2 style="font-size:18px;margin:28px 0 6px">Voice cloning &amp; changer</h2>'
                '<p class="dim" style="margin:0 0 12px">Off by default. Enable only with the '
                "recorded consent of the voice's owner — every grant and revocation is "
                f"audited.</p>{consent_rows}"
            )
        else:
            consent_html = ""

        recorder_js = (
            "<script>(function(){var b=document.getElementById('mh-rec-btn');"
            "if(!b||!navigator.mediaDevices)return;var rec,chunks=[],on=false;"
            "var st=document.getElementById('mh-rec-status');"
            "b.addEventListener('click',function(){if(on){rec&&rec.stop();return;}"
            "navigator.mediaDevices.getUserMedia({audio:true}).then(function(s){"
            "rec=new MediaRecorder(s);chunks=[];rec.ondataavailable=function(e){chunks.push(e.data);};"
            "rec.onstop=function(){var blob=new Blob(chunks,{type:'audio/webm'});"
            "var f=new File([blob],'recording.webm',{type:'audio/webm'});"
            "var dt=new DataTransfer();dt.items.add(f);"
            "document.getElementById('mh-audio-file').files=dt.files;"
            "s.getTracks().forEach(function(t){t.stop();});on=false;b.textContent='● Record';"
            "st.textContent='Recorded — review and Upload.';};rec.start();on=true;"
            "b.textContent='■ Stop';st.textContent='Recording…';}).catch(function(){"
            "st.textContent='Microphone unavailable.';});});})();</script>"
        )

        return (
            '<div style="max-width:760px">'
            + banner_html
            + '<p class="lede" style="margin-top:0">Sound for your videos — music, effects and '
            "voiceover — all rights-clean and explainable.</p>"
            + library_html
            + voices_html
            + lexicon_html
            + upload_html
            + uploads_html
            + consent_html
            + (recorder_js if pid else "")
            + "</div>"
        )

    def _render_settings_activity_section(prof: Optional[ClubProfile]) -> str:
        """Activity section — recent runs for the pinned org.

        Mirrors the standalone /activity page but degrades gracefully
        when no profile is pinned (Settings is reachable pre-org-setup).
        The settings sub-page supplies its own hero title, so this section
        carries no big header of its own.
        """
        section_header = ""
        if prof is None:
            return (
                f"{section_header}"
                '<p class="dim" style="margin-bottom:14px">'
                "Choose an organisation to see its recent runs here. "
                "Activity is scoped per-organisation so the data never "
                "leaks between profiles.</p>"
                '<div class="card empty">No organisation pinned. '
                f'<a href="{url_for("sign_in_page")}">Choose organisation &rarr;</a></div>'
            )

        try:
            conn = _db()
            rows = conn.execute(
                "SELECT id, created_at, finished_at, status, profile_id, "
                "meet_name, our_swims, n_cards, n_queue, error, file_name "
                "FROM runs WHERE profile_id = ? "
                "ORDER BY created_at DESC LIMIT 100",
                (prof.profile_id,),
            ).fetchall()
            conn.close()
        except Exception:
            rows = []

        section_intro = (
            f'<p class="dim" style="margin-bottom:14px">Recent runs for '
            f"<b>{_h(prof.display_name)}</b>.</p>"
        )

        if not rows:
            return (
                f"{section_header}"
                f"{section_intro}"
                '<div class="card empty">No results yet for this organisation. '
                f'<a href="{url_for("make_page")}">Create your first piece of content &rarr;</a>'
                "</div>"
            )

        rows_html = ""
        n_errored = 0
        for r in rows:
            badge = {"done": "good", "running": "info", "queued": "info", "error": "bad"}.get(
                r["status"], ""
            )
            review_href = url_for("review", run_id=r["id"])
            delete_href = url_for("privacy_delete_run", run_id=r["id"])
            started = (r["created_at"] or "")[:19]
            started_iso = started.replace(" ", "T") + "Z" if started else ""
            rows_html += (
                f'<tr data-run-row="{_h(r["id"])}"><td data-label="Input"><a href="{review_href}">{_h(r["meet_name"] or r["file_name"] or r["id"])}</a></td>'
                f'<td data-label="Status"><span class="tag {badge}">{_h(r["status"])}</span></td>'
                f'<td data-label="Matched">{_h(r["our_swims"] or 0)}</td>'
                f'<td data-label="Queue / Total">{_h(r["n_queue"] or 0)} / {_h(r["n_cards"] or 0)}</td>'
                f'<td data-label="Started"><time class="mh-rel" datetime="{_h(started_iso)}">{_h(started)}</time></td>'
                f'<td><form method="post" action="{delete_href}" '
                f'class="mh-run-delete" data-run-id="{_h(r["id"])}" '
                f'style="display:inline" data-no-loader="1">'
                f'<input type="hidden" name="next" value="{_h(request.path)}">'
                f'<button class="btn danger" type="submit" '
                f'style="font-size:11px;padding:4px 10px">Delete</button>'
                f"</form></td></tr>"
            )
            if r["status"] == "error" and r["error"]:
                n_errored += 1
                err_text = str(r["error"])
                truncated = err_text[:600] + ("…" if len(err_text) > 600 else "")
                rows_html += (
                    f'<tr class="run-error-row" data-run-err="{_h(r["id"])}">'
                    '<td colspan="7" style="padding:6px 14px 14px 14px;'
                    'background:rgba(255,93,108,0.06);border-left:3px solid var(--mh-prim-error-500)">'
                    "<details>"
                    '<summary style="cursor:pointer;font-size:13px;font-weight:600;'
                    'color:var(--mh-prim-error-300)">Why did this run fail?</summary>'
                    '<pre style="margin:8px 0 0;padding:10px 12px;'
                    "background:rgba(0,0,0,0.25);border-radius:6px;"
                    'font-size:12px;white-space:pre-wrap;word-break:break-word">'
                    f"{_h(truncated)}</pre>"
                    "</details>"
                    "</td></tr>"
                )

        failure_callout = ""
        if n_errored:
            label = "1 run failed" if n_errored == 1 else f"{n_errored} runs failed"
            failure_callout = (
                '<div class="card" style="padding:12px 18px;margin-bottom:20px;'
                'background:rgba(255,93,108,0.06);border-left:3px solid var(--mh-prim-error-500)">'
                f"<b>{_h(label)}</b> in the last 100 runs. "
                "Expand <i>Why did this run fail?</i> on each row below to "
                "see the pipeline error.</div>"
            )

        # Delete in place + bulk clear: shared, delegated handler (mh-run-delete
        # removes a row via fetch; mh-clear-all-runs confirms then reloads).
        # No-JS falls back to the plain form POST (honours ``next``).
        return (
            f"{section_header}"
            f"{section_intro}"
            f"{failure_callout}"
            '<div class="card"><table class="mh-table-stack">'
            "<thead><tr><th>Input</th><th>Status</th>"
            "<th>Matched</th><th>Queue / Total</th>"
            "<th>Started</th><th></th></tr></thead>"
            f"<tbody>{rows_html}</tbody>"
            "</table></div>"
            f"{_RUN_DELETE_JS}"
        )

    def _render_settings_status_section() -> str:
        """Status section — uptime + last-incident, mirrors /status."""
        section_header = (
            '<h2 id="status" style="margin:40px 0 6px;font-size:22px;'
            'scroll-margin-top:80px">Status</h2>'
        )
        try:
            from mediahub.observability import uptime as _uptime

            s24 = _uptime.uptime_stats(window_hours=24)
            s7d = _uptime.uptime_stats(window_hours=24 * 7)
            s30 = _uptime.uptime_stats(window_hours=24 * 30)
            latest = _uptime.latest_heartbeat()
            gaps = _uptime.recent_gaps(window_hours=24 * 30, limit=5)
        except Exception:
            return f'{section_header}<div class="card empty">Status data not available.</div>'

        pill_label = "no data yet"
        pill_color = "#7a7a7a"
        if latest is not None:
            try:
                ts_raw = latest["ts"]
                if ts_raw.endswith("Z"):
                    ts_raw = ts_raw[:-1] + "+00:00"
                from datetime import datetime as _dt

                last_ts = _dt.fromisoformat(ts_raw)
                age_s = (datetime.now(timezone.utc) - last_ts).total_seconds()
            except (ValueError, TypeError):
                age_s = 99999
            if not latest.get("ok"):
                pill_label = "degraded"
                pill_color = "#ffaa3a"
            elif age_s <= 300:
                pill_label = "operational"
                pill_color = "#2cc97f"
            elif age_s <= 1800:
                pill_label = "stale (no heartbeat in 5–30 min)"
                pill_color = "#ffaa3a"
            else:
                pill_label = "unknown (last heartbeat > 30 min ago)"
                pill_color = "#ff5d6c"

        last_incident_html = (
            '<p class="dim" style="margin:0">No incidents recorded in the last 30 days.</p>'
        )
        if gaps:
            top = gaps[0]
            duration = _humanize_duration(top["duration_seconds"])
            when = _humanize_when(top["to_ts"])
            last_incident_html = (
                f'<p style="margin:0"><b>Last incident:</b> {_h(when)} '
                f"(silent for {_h(duration)})</p>"
                f'<p class="dim" style="margin:4px 0 0;font-size:12px">'
                f"Detected from a gap in heartbeats between "
                f"{_h(top['from_ts'][:19])} and {_h(top['to_ts'][:19])} UTC.</p>"
            )

        version_label = APP_VERSION
        return (
            f"{section_header}"
            '<p class="dim" style="margin-bottom:14px">Live operational health '
            "of this MediaHub deployment.</p>"
            '<div class="card" style="display:flex;align-items:center;gap:14px;'
            'padding:18px 22px;margin-bottom:14px">'
            f'<span style="display:inline-block;width:14px;height:14px;'
            f'border-radius:50%;background:{pill_color};flex:0 0 auto"></span>'
            f'<div style="flex:1"><div style="font-size:18px;font-weight:600">'
            f"Backend &mdash; {_h(pill_label)}</div>"
            f'<div class="dim" style="font-size:13px;margin-top:2px">'
            f"Version <code>{_h(version_label)}</code>"
            + (
                f" &middot; last heartbeat {_h(_humanize_when(latest['ts']))} "
                f"({_h((latest.get('source') or '').lower())})"
                if latest
                else ""
            )
            + "</div></div></div>"
            '<div class="card" style="padding:18px 22px;margin-bottom:14px">'
            '<table style="width:100%"><thead>'
            "<tr><th>Window</th><th>Uptime</th><th>Heartbeats</th>"
            "<th>Downtime</th></tr></thead><tbody>"
            f"<tr><td><b>24 hours</b></td>"
            f"<td>{_format_uptime_pct(s24)}</td>"
            f"<td>{_h(s24.get('samples', 0))}</td>"
            f"<td>{_h(_humanize_duration(s24.get('downtime_seconds', 0))) if s24.get('has_data') else '&mdash;'}</td></tr>"
            f"<tr><td><b>7 days</b></td>"
            f"<td>{_format_uptime_pct(s7d)}</td>"
            f"<td>{_h(s7d.get('samples', 0))}</td>"
            f"<td>{_h(_humanize_duration(s7d.get('downtime_seconds', 0))) if s7d.get('has_data') else '&mdash;'}</td></tr>"
            f"<tr><td><b>30 days</b></td>"
            f"<td>{_format_uptime_pct(s30)}</td>"
            f"<td>{_h(s30.get('samples', 0))}</td>"
            f"<td>{_h(_humanize_duration(s30.get('downtime_seconds', 0))) if s30.get('has_data') else '&mdash;'}</td></tr>"
            "</tbody></table>"
            f"{_uptime_tracking_note(s24, s7d, s30)}</div>"
            f'<div class="card" style="padding:14px 22px">'
            f"{last_incident_html}</div>"
        )

    def _coming_soon_card(title: str, body: str) -> str:
        """A consistent "Coming soon" placeholder for a withdrawn surface."""
        return (
            '<div class="card" style="padding:22px 20px;max-width:640px">'
            '<div style="display:inline-flex;align-items:center;gap:8px;margin-bottom:10px">'
            '<span class="tag" style="background:var(--accent);color:#0b0f17;'
            'font-weight:700;letter-spacing:0.02em">Coming soon</span></div>'
            f'<h2 style="margin:0 0 6px 0;font-size:18px">{_h(title)}</h2>'
            f'<p class="dim" style="margin:0;line-height:1.55">{_h(body)}</p>'
            "</div>"
        )

    def _render_settings_autonomy_section(prof: Optional[ClubProfile]) -> str:
        """Autonomy settings — a Coming soon placeholder.

        Letting MediaHub publish approved content straight onto a social channel
        without a human (per-type autonomy levels, the publish gate, and the
        hourly cadence) has been withdrawn. Cards stay under human approval and
        export/download for manual posting; the controls return here when the
        capability is rebuilt.
        """
