        # crash-safe when the workflow store can't be reached.
        _wf_states: dict = {}
        try:
            _ws = _get_wf_store()
            if _ws is not None:
                _wf_states = _ws.load(run_id) or {}
        except Exception:
            _wf_states = {}
        # UI 1.25 — per-card reaction tallies for this run, in one query.
        _react_counts = _reaction_counts_for_run(run_id)

