                '<select id="mh-imagine-style" ' + _dis + ">" + _style_opts + "</select>"
                '<label for="mh-imagine-aspect">Aspect</label>'
                '<select id="mh-imagine-aspect" ' + _dis + ">"
                '<option value="1:1">Square (1:1)</option>'
