    # ---- W.14 + W.3 approval-seam hook --------------------------------------

    def _phase_w_after_status_change(
        pid: str, run_id: str, card_id: str, action: str, *, via: str = "web"
    ) -> None:
        """Telemetry + records-on-approval, fed by every approval surface.

        Best-effort by design: a telemetry or records failure must never
        block the approval itself.
        """
        # Outbound webhook (1.21): a single chokepoint for BOTH the web route and
        # the public API, so every approval fans out identically. Best-effort.
        if action == "approved":
            try:
                from mediahub import webhooks as _webhooks
                from mediahub.webhooks import events as _wh_events

                _webhooks.emit(
                    _wh_events.EVENT_CARD_APPROVED,
                    pid,
                    _wh_events.card_approved(pid, run_id, card_id, via=via),
                )
            except Exception:
                pass
        card = None
        try:
            data = _load_run(run_id) or {}
            for ra in (data.get("recognition_report") or {}).get("ranked_achievements") or []:
                a = ra.get("achievement") or {}
                if a.get("swim_id") == card_id:
                    card = ra
                    break
        except Exception:
            card = None
        try:
            from mediahub.observability.approval_telemetry import record_event

            a = (card or {}).get("achievement") or {}
            prof = load_profile(pid) if pid else None
            record_event(
                pid or "",
                run_id,
                card_id,
                action,
                achievement_type=a.get("type", ""),
                post_angle=(card or {}).get("post_angle") or a.get("post_angle", ""),
                tone=(getattr(prof, "tone", "") or "") if prof else "",
                quality_band=str((card or {}).get("quality_band") or ""),
                via=via,
            )
        except Exception:
            log.warning("approval telemetry failed", exc_info=True)
        if action == "approved" and card is not None:
            try:
                from mediahub.club_records import apply_approved_card

                a = card.get("achievement") or {}
                if a.get("type") == "club_record" and pid:
                    updated = apply_approved_card(pid, dict(card, run_id=run_id))
                    if updated:
                        log.info("club record table updated from approved card %s", card_id)
            except Exception:
                log.warning("club record approval hook failed", exc_info=True)

    # ---- W.12: print exports on the pack ------------------------------------

    @app.route("/pack/<run_id>/certificates.zip")
    def pack_certificates_zip(run_id: str):
        if not _can_access_run(run_id, _load_run(run_id), _active_profile_id()):
            abort(404)
        import io as _io
        import zipfile as _zip

        from mediahub.content_pack.builder import build_grouped_pack
        from mediahub.graphic_renderer.print_export import (
            CmykUnavailable,
            build_certificate_html,
            export_certificate_print_pdf,
            ghostscript_available,
            render_html_to_pdf,
        )

        data = _load_run(run_id)
        if not data:
            abort(404)
        pid = _run_owner_profile_id(run_id) or ""
        prof = load_profile(pid) if pid else None
        pack = build_grouped_pack(data, pid, RUNS_DIR)
        approved = [
            item
            for group in ("main_feed", "stories", "needs_review")
            for item in (pack.get(group) or [])
            if item.get("wf_status") in ("approved", "posted") and not item.get("consent_blocked")
        ]
        if not approved:
            return (
                _layout(
                    "Certificates",
                    '<div class="card"><h2>No approved cards yet</h2>'
                    '<p class="dim">Certificates are printed from approved achievements '
                    "only — approve some cards first, then come back.</p></div>",
                ),
                200,
            )
        brand = {
            "primary": getattr(prof, "brand_primary", "#0A2540") if prof else "#0A2540",
            "secondary": getattr(prof, "brand_secondary", "#000000") if prof else "#000000",
        }
        meet = data.get("meet") or {}
        meet_name = meet.get("name") or data.get("file_name") or run_id
        meet_date = str(meet.get("start_date") or "")
        # G1.17: print-production mode (?print=1) adds bleed + crop marks; an
        # optional ?cmyk=1 converts to DeviceCMYK via Ghostscript when present.
        print_mode = (request.args.get("print") or "").strip().lower() in _TRUTHY
        bleed_mm = _clamp_float(request.args.get("bleed"), default=3.0, lo=0.0, hi=10.0)
        crop_marks = (request.args.get("marks") or "1").strip().lower() in _TRUTHY
        colour_bar = (
            request.args.get("colorbar") or request.args.get("colourbar") or "1"
        ).strip().lower() in _TRUTHY
        want_cmyk = (request.args.get("cmyk") or "").strip().lower() in _TRUTHY
        do_cmyk = print_mode and want_cmyk and ghostscript_available()
        cmyk_note = None
        if print_mode and want_cmyk and not do_cmyk:
            cmyk_note = (
                "CMYK conversion was requested but Ghostscript is not installed on "
                "the server, so these PDFs are RGB (the 3mm bleed and crop marks are "
                "intact). Most digital print shops convert RGB to CMYK with their own "
                "press/paper ICC profile, which is more accurate than a generic "
                "conversion would be.\n"
            )
        out_dir = DATA_DIR / "print_exports" / run_id
        out_dir.mkdir(parents=True, exist_ok=True)
        rgb_fallbacks: list = []  # certs where gs failed mid-run and RGB shipped
        buf = _io.BytesIO()
        with _zip.ZipFile(buf, "w", _zip.ZIP_DEFLATED) as zf:
            for i, item in enumerate(approved):
                a = item.get("achievement") or {}
                name = a.get("swimmer_name") or "Swimmer"
                facts = a.get("raw_facts") or {}
                time_str = facts.get("new_time") or facts.get("time") or facts.get("time_str") or ""
                cert_kwargs = dict(
                    swimmer_name=name,
                    event_label=a.get("event", ""),
                    time_str=str(time_str),
                    achievement_headline=a.get("headline", "Achievement"),
                    meet_name=meet_name,
                    meet_date=meet_date,
                    club_name=(prof.display_name if prof else pid or "Our club"),
                    brand=brand,
                    detail_line=a.get("angle_hint", ""),
                )
                safe_name = re.sub(r"[^A-Za-z0-9._-]+", "-", f"{name}-{a.get('event', '')}")
                pdf_path = out_dir / f"cert-{i:02d}.pdf"
                if print_mode:
                    try:
                        export_certificate_print_pdf(
                            pdf_path,
                            bleed_mm=bleed_mm,
                            crop_marks=crop_marks,
                            colour_bar=colour_bar,
                            cmyk=do_cmyk,
                            **cert_kwargs,
                        )
                    except CmykUnavailable as e:
                        # Ghostscript failed mid-run: the RGB print PDF (bleed +
                        # crop marks intact) is already rendered and print-ready
                        # — ship it and say so, mirroring print_ready/engine.py.
                        rgb_fallbacks.append(f"{i + 1:02d}-{safe_name}.pdf: {e}")
                else:
                    render_html_to_pdf(build_certificate_html(**cert_kwargs), pdf_path)
                zf.writestr(f"certificates/{i + 1:02d}-{safe_name}.pdf", pdf_path.read_bytes())
            if rgb_fallbacks:
                cmyk_note = (cmyk_note or "") + (
                    "CMYK conversion failed at run time for these certificates, so "
                    "they are RGB (the bleed and crop marks are intact):\n"
                    + "\n".join(rgb_fallbacks)
                    + "\n"
                )
            if cmyk_note:
                zf.writestr("certificates/CMYK-NOTE.txt", cmyk_note)
        buf.seek(0)
        kind = "print" if print_mode else "certificates"
        return send_file(
            buf,
            mimetype="application/zip",
            as_attachment=True,
            download_name=f"{kind}-{run_id}.zip",
        )

    @app.route("/pack/<run_id>/print/separations.json")
    def pack_print_separations(run_id: str):
        """G1.17: the CMYK separations report for a run's brand colours.

        Machine-readable breakdown a club can hand to a print shop: each brand
        role's hex + uncalibrated CMYK percentages, the default print geometry,
        and whether the server can do a true DeviceCMYK conversion.
        """
        if not _can_access_run(run_id, _load_run(run_id), _active_profile_id()):
            abort(404)
        from mediahub.graphic_renderer.print_export import (
            cmyk_separations,
            geometry_for,
            ghostscript_available,
        )

        pid = _run_owner_profile_id(run_id) or ""
        prof = load_profile(pid) if pid else None
        brand = {
            "primary": getattr(prof, "brand_primary", "#0A2540") if prof else "#0A2540",
            "secondary": getattr(prof, "brand_secondary", "#000000") if prof else "#000000",
        }
        geom = geometry_for("A4")
        return jsonify(
            {
                "run_id": run_id,
                "colour_mode": "CMYK (uncalibrated device preview)",
                "ghostscript_available": ghostscript_available(),
                "geometry": {
                    "paper": "A4",
                    "trim_mm": [geom.trim_w_mm, geom.trim_h_mm],
                    "bleed_mm": geom.bleed_mm,
                    "crop_mark_mm": geom.mark_len_mm,
                    "media_mm": [geom.media_w_mm, geom.media_h_mm],
                },
                "separations": cmyk_separations(brand),
            }
        )

    # ---- W.6: entry-file parsing for the event preview -----------------------

    @app.route("/api/event-preview/parse-entries", methods=["POST"])
    def api_event_preview_parse_entries():
        """Turn an uploaded entry file into prefilled preview-form fields.

        LENEX entries parse natively; CSV/TSV/plain text pass through with
        light normalisation; anything unreadable returns an honest error.
        Zero typing is the goal (W.6)."""
        f = request.files.get("file")
        if f is None or not f.filename:
            return jsonify({"ok": False, "error": "No file uploaded."}), 400
        data = f.read()
        name = (f.filename or "").lower()
        meet_name = ""
        entries_text = ""
        n_rows = 0
        try:
            if name.endswith((".lef", ".lxf")) or b"<LENEX" in data[:2048].upper():
                from mediahub.interpreter.lenex_parser import (
                    parse_lenex,
                    parse_lenex_entries,
                )

                rows = parse_lenex_entries(data)
                try:
                    meet_name = parse_lenex(data).meet_name or ""
                except Exception:
                    meet_name = ""
                lines = []
                for r in rows:
                    bits = [
                        r.get("swimmer_name") or "",
                        f"{r.get('distance_m') or ''}{(' ' + r['stroke']) if r.get('stroke') else ''}".strip(),
                        r.get("entry_time") or "",
                    ]
                    lines.append(" — ".join(b for b in bits if b))
                entries_text = "\n".join(lines)
                n_rows = len(rows)
            else:
                text = data.decode("utf-8", errors="replace")
                cleaned = [ln.strip() for ln in text.splitlines() if ln.strip()]
                if not cleaned:
                    return jsonify(
                        {"ok": False, "error": "Couldn't read any entries from that file."}
                    ), 422
                entries_text = "\n".join(cleaned[:400])
                n_rows = len(cleaned)
        except Exception:
            log.warning("entry-file parse failed", exc_info=True)
            return jsonify(
                {
                    "ok": False,
                    "error": (
                        "Couldn't read that entry file. Try the LENEX (.lef/.lxf) "
                        "export from the meet organiser, or paste the entries as text."
                    ),
                }
            ), 422
        return jsonify(
            {"ok": True, "meet_name": meet_name, "entries_text": entries_text, "rows": n_rows}
        )

    # =====================================================================
    # Document engine (roadmap 1.15): meet programmes / season reports /
    # sponsor proposals / AGM decks, PPTX·DOCX·PDF exports, PDF utilities,
    # and the deck presenter surface (notes, timer, autoplay, phone remote).
    # Thin routes — all logic lives in the `documents` package.
    # =====================================================================
    def _doc_brand_kit(pid):
        if not pid:
            return None
        try:
            return _v8_brand_kit_for(pid)
        except Exception:
            return None

    def _doc_club_name(pid, brand_kit) -> str:
        name = getattr(brand_kit, "display_name", "") or ""
        if name:
            return name
        try:
            prof = _active_profile()
        except Exception:
            prof = None
        return getattr(prof, "display_name", "") or getattr(prof, "name", "") or ""

    def _safe_filename(title: str, ext: str) -> str:
        slug = re.sub(r"[^A-Za-z0-9_-]+", "-", str(title or "document")).strip("-").lower()
        return f"{slug or 'document'}.{ext}"

    def _doc_recent_runs(pid, limit=60):
        out = []
        try:
            conn = _db()
            rows = conn.execute(
                "SELECT id, meet_name, n_achievements FROM runs "
                "WHERE profile_id = ? AND status = 'done' "
                "ORDER BY created_at DESC LIMIT ?",
                (pid, int(limit)),
            ).fetchall()
            for r in rows:
                # Clean a stale HY-TEK banner title (pre-QA-002 runs) at render
                # time so the Sites/Documents source pickers show the real name.
                meet = _clean_stored_meet_title(r["meet_name"]) or "Meet"
                out.append((r["id"], meet, r["n_achievements"] or 0))
        except Exception:
            pass
        return out

    def _doc_load_owned(doc_id):
        """(pid, spec) for a document owned by the active org, else (pid, None)."""
        pid = _active_profile_id()
        if not pid:
            return None, None
        from mediahub.documents import store as _docstore

        return pid, _docstore.load_document(pid, doc_id)

    def _doc_facts_for(pid, brand_kit, *, scope, run_id):
        from mediahub.documents.grounding import facts_from_run, facts_from_runs

        club = _doc_club_name(pid, brand_kit)
        if scope == "meet":
            run_data = _load_run(run_id)
            if run_data is None or not _can_access_run(run_id, run_data, pid):
                return None
            return facts_from_run(run_data, club_name=club, run_id=run_id)
        # season scope — every processed run for the org
        runs, ids = [], []
        for rid, _name, _n in _doc_recent_runs(pid):
            rd = _load_run(rid)
            if rd is not None and _can_access_run(rid, rd, pid):
                runs.append(rd)
                ids.append(rid)
        if not runs:
            return None
        return facts_from_runs(runs, club_name=club, period=time.strftime("%Y"), run_ids=ids)

    # ------------------------------------------------------------------ #
    # Email & newsletter composer (roadmap 1.17)
    # ------------------------------------------------------------------ #
    # Email-safe branded HTML auto-assembled from the period's approved
    # content. Export-first: download / copy the HTML for the club's own list
    # tool, or publish a hosted web version. No direct send (a provider adapter
    # behind the publish gate is a later, flagged build — roadmap-explicit).

    _NL_RANGES = (
        ("this_month", "This month"),
        ("last_month", "Last month"),
        ("last_30", "Last 30 days"),
        ("this_season", "This season"),
    )

    def _nl_load_owned(newsletter_id):
        """(pid, spec) for a newsletter owned by the active org, else (pid, None)."""
        pid = _active_profile_id()
        if not pid:
            return None, None
        from mediahub.email_design import store as _ns

        return pid, _ns.load_newsletter(pid, newsletter_id)

    def _nl_range(preset, body):
        """Resolve a range preset (or a custom start/end) to (start, end) dates."""
        from datetime import date as _date
        from datetime import timedelta as _td

        def _iso(v):
            try:
                return _date.fromisoformat(str(v)[:10])
            except (TypeError, ValueError):
                return None

        today = _date.today()
        if preset == "custom":
            return (_iso(body.get("start")) or today.replace(day=1)), (
                _iso(body.get("end")) or today
            )
        if preset == "last_month":
            last_prev = today.replace(day=1) - _td(days=1)
            return last_prev.replace(day=1), last_prev
        if preset == "last_30":
            return today - _td(days=30), today
        if preset == "this_season":
            yr = today.year if today.month >= 9 else today.year - 1
            return _date(yr, 9, 1), today
        return today.replace(day=1), today  # this_month (default)

    def _nl_resolve_images(spec, resolver):
        """Return a copy of ``spec`` with each card's image ``src`` filled from
        its ``card_ref`` via ``resolver(run_id, card_id) -> url`` — so a card
        image is only ever served behind the right access check, never baked in."""
        from mediahub.email_design.models import NewsletterSpec

        data = spec.to_dict()
        for sec in data.get("sections", []):
            for b in sec.get("blocks", []):
                p = b.get("props", {})
                if b.get("kind") == "card" and not p.get("src") and p.get("card_ref"):
                    run_id, _, card_id = str(p["card_ref"]).partition("/")
                    if run_id and card_id:
                        url = resolver(run_id, card_id) or ""
                        if url:
                            p["src"] = url
        return NewsletterSpec.from_dict(data)

    def _nl_card_refs(spec) -> set:
        """The (run_id, card_id) pairs a newsletter spec's card blocks reference —
        the only card images its token/preview may unlock (snapshot scoping)."""
        refs: set = set()
        for sec in spec.to_dict().get("sections", []):
            for b in sec.get("blocks", []):
                p = b.get("props", {})
                if b.get("kind") == "card" and p.get("card_ref"):
                    run_id, _, card_id = str(p["card_ref"]).partition("/")
                    if run_id and card_id:
                        refs.add((run_id, card_id))
        return refs

    def _nl_card_image_path(pid: str, run_id: str, card_id: str):
        """Newsletter-scoped card image: approved + tenant + consent gated, but
        WITHOUT the public wall's own exclusion/recency gates — a newsletter is
        its own surface, so a wall-excluded or older-run card still renders."""
        from mediahub.web import public_wall as _pw

        if str(card_id) not in _pw._approved_card_ids(run_id):
            return None
        return _pw.rendered_card_png(pid, run_id, card_id)

    def _nl_unavailable_src(reason: str) -> str:
        """An inline SVG placeholder for the editor preview so an unavailable
        card image is explained, never a silent blank."""
        import base64 as _b64

        svg = (
            '<svg xmlns="http://www.w3.org/2000/svg" width="600" height="120">'
            '<rect width="100%" height="100%" fill="#1a1d21"/>'
            '<text x="50%" y="45%" fill="#9aa3ab" font-family="sans-serif" font-size="16" '
            'text-anchor="middle">Image unavailable</text>'
            f'<text x="50%" y="72%" fill="#6d757d" font-family="sans-serif" font-size="13" '
            f'text-anchor="middle">{reason}</text></svg>'
        )
        return "data:image/svg+xml;base64," + _b64.b64encode(svg.encode("utf-8")).decode("ascii")

